INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-65d0241c866b', 'A-1. EDD Claims Examiner', 'California Local Unique Compliance', 'California Local Unique', 'A-1. EDD Claims Examiner — Employment Development Department (EDD). **Codes:** Unemp. Ins. Code (UIC) div. 1-7; Cal. Code Regs. tit. 22 div. 1; Lab. Code 1088-1099. **Documents Audited:** UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.', 'A-1. EDD Claims Examiner', 'Employment Development Department (EDD). **Codes:** Unemp. Ins. Code (UIC) div. 1-7; Cal. Code Regs. tit. 22 div. 1; Lab. Code 1088-1099. **Documents Audited:** UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.', '', '', '', 'UI claims determinations, disability insurance (SDI/PFL) approvals/denials, DE 2501 certifications, employer tax contribution filings (DE 9/DE 9C), notice of determination letters, overpayment assessments, appeal decisions, base period wage records, benefit audit worksheets, identity verification documents.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-df937195738b', 'A-2. EDD Tax Auditor', 'California Local Unique Compliance', 'California Local Unique', 'A-2. EDD Tax Auditor — EDD Tax Branch. **Codes:** UIC 976-977, 986-986.1, 1088-1089; RTC 19542. **Documents Audited:** Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.', 'A-2. EDD Tax Auditor', 'EDD Tax Branch. **Codes:** UIC 976-977, 986-986.1, 1088-1089; RTC 19542. **Documents Audited:** Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.', '', '', '', 'Employer payroll tax audit reports, worker classification determinations (ABC test per AB 5), quarterly contribution returns, penalty assessment notices, voluntary plan certifications, information-sharing agreements with FTB/IRS, jeopardy assessments.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8dad18b35e42', 'A-3. CEC Energy Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-3. CEC Energy Analyst — California Energy Commission. **Codes:** PRC 25000-25986; Cal. Code Regs. tit. 20 1601-1609 (Title 24 Part 6 energy standards); PUC 454.5. **Documents Audited:** Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.', 'A-3. CEC Energy Analyst', 'California Energy Commission. **Codes:** PRC 25000-25986; Cal. Code Regs. tit. 20 1601-1609 (Title 24 Part 6 energy standards); PUC 454.5. **Documents Audited:** Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.', '', '', '', 'Building energy efficiency compliance certificates (CF-1R/CF-2R/CF-3R), power plant siting applications (AFC), renewable portfolio standard reports, integrated energy policy reports, appliance efficiency certifications, demand forecast documents, CEQA functional equivalency reviews, SB 100 compliance filings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-dedee371e8f4', 'A-4. CEC Siting Specialist', 'California Local Unique Compliance', 'California Local Unique', 'A-4. CEC Siting Specialist — California Energy Commission, Siting Division. **Codes:** PRC 25500-25542; Warren-Alquist Act; Cal. Code Regs. tit. 20 1701-1770. **Documents Audited:** Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.', 'A-4. CEC Siting Specialist', 'California Energy Commission, Siting Division. **Codes:** PRC 25500-25542; Warren-Alquist Act; Cal. Code Regs. tit. 20 1701-1770. **Documents Audited:** Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.', '', '', '', 'Applications for certification (AFC) for thermal power plants 50MW+, compliance monitoring reports, facility amendment requests, small power plant exemption applications, transmission corridor designations, decommissioning plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b3e083c024ca', 'A-5. FPPC Enforcement Counsel', 'California Local Unique Compliance', 'California Local Unique', 'A-5. FPPC Enforcement Counsel — Fair Political Practices Commission. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.', 'A-5. FPPC Enforcement Counsel', 'Fair Political Practices Commission. **Codes:** Gov. Code 81000-91015 (Political Reform Act); Cal. Code Regs. tit. 2 18110-18997. **Documents Audited:** Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.', '', '', '', 'Campaign disclosure statements (Form 460/461/496/497), statements of economic interest (Form 700), lobbyist registration/reports (Form 601/602/603/625), enforcement complaint files, audit reports, advice letters, penalty assessments, behested payment reports (Form 803), slate mailer filings.');
