INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3e2aeb0e8436', 'A-7. FTB Tax Auditor', 'California Local Unique Compliance', 'California Local Unique', 'A-7. FTB Tax Auditor — Franchise Tax Board. **Codes:** RTC 17001-24991 (Personal Income Tax Law), 23001-24691 (Corporation Tax Law); Cal. Code Regs. tit. 18. **Documents Audited:** Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collec', 'A-7. FTB Tax Auditor', 'Franchise Tax Board. **Codes:** RTC 17001-24991 (Personal Income Tax Law), 23001-24691 (Corporation Tax Law); Cal. Code Regs. tit. 18. **Documents Audited:** Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collections correspondence, a', '', '', '', 'Personal income tax returns (Form 540), corporate tax returns (Form 100), S-corp returns (Form 100S), partnership returns (Form 565), LLC returns (Form 568), notice of proposed assessment (NPA), protest decisions, Offer in Compromise files, abatement requests, residency determination packages, audit workpapers, collections correspondence, amnesty filings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2673481de296', 'A-8. FTB Collections Officer', 'California Local Unique Compliance', 'California Local Unique', 'A-8. FTB Collections Officer — Franchise Tax Board, Collections Division. **Codes:** RTC 19001-19780; Gov. Code 12419.5; CCP 706.070-706.077. **Documents Audited:** Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).', 'A-8. FTB Collections Officer', 'Franchise Tax Board, Collections Division. **Codes:** RTC 19001-19780; Gov. Code 12419.5; CCP 706.070-706.077. **Documents Audited:** Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).', '', '', '', 'Earnings withholding orders, bank levies, liens (state tax liens filed with county recorder), offset notices (lottery/vendor intercepts), installment agreement documents, hardship determination files, interagency intercept notices (EDD/Controller).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-127c405bfcad', 'A-9. Governor''s Legal Affairs Secretary', 'California Local Unique Compliance', 'California Local Unique', 'A-9. Governor''s Legal Affairs Secretary — Governor''s Office. **Codes:** Cal. Const. Art. V; Gov. Code 12000-12080; Gov. Code 11340-11361 (APA). **Documents Audited:** Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.', 'A-9. Governor''s Legal Affairs Secretary', 'Governor''s Office. **Codes:** Cal. Const. Art. V; Gov. Code 12000-12080; Gov. Code 11340-11361 (APA). **Documents Audited:** Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.', '', '', '', 'Executive orders, proclamations of emergency, extradition warrants, judicial appointment packages, bill signing statements, clemency/pardon applications, regulatory review memoranda, appointments to boards/commissions, State of Emergency declarations, budget proposals.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-fc14dde18ce8', 'A-10. CDI Insurance Examiner', 'California Local Unique Compliance', 'California Local Unique', 'A-10. CDI Insurance Examiner — California Department of Insurance. **Codes:** Ins. Code 1-16111; Cal. Code Regs. tit. 10. **Documents Audited:** Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17', 'A-10. CDI Insurance Examiner', 'California Department of Insurance. **Codes:** Ins. Code 1-16111; Cal. Code Regs. tit. 10. **Documents Audited:** Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17).', '', '', '', 'Insurance rate filings, policy form approvals, annual financial statements (statutory accounting), market conduct examination reports, complaint files, license applications, surplus line broker filings, insurer solvency reports, advertising review files, claims handling practice audits (Fair Claims Settlement Practices Regulations tit. 10 2695.1-2695.17).');
