INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-caf25ac96189', 'A-15. Legislative Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-15. Legislative Analyst — Legislative Analyst''s Office (LAO). **Codes:** Gov. Code 9140-9149. **Documents Audited:** Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.', 'A-15. Legislative Analyst', 'Legislative Analyst''s Office (LAO). **Codes:** Gov. Code 9140-9149. **Documents Audited:** Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.', '', '', '', 'Fiscal impact analyses of proposed legislation, annual budget analyses ("Analysis of the Budget Bill"), ballot measure analyses, policy briefs, long-term fiscal outlook reports, CalFacts publications, initiative fiscal estimates for Attorney General.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6c00df7f5e79', 'A-16. Cal/OSHA Compliance Officer (Safety)', 'California Local Unique Compliance', 'California Local Unique', 'A-16. Cal/OSHA Compliance Officer (Safety) — Division of Occupational Safety and Health (Cal/OSHA). **Codes:** Lab. Code 6300-6719; Cal. Code Regs. tit. 8 (General Industry Safety Orders, Construction Safety Orders). **Documents Audited:** Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification ', 'A-16. Cal/OSHA Compliance Officer (Safety)', 'Division of Occupational Safety and Health (Cal/OSHA). **Codes:** Lab. Code 6300-6719; Cal. Code Regs. tit. 8 (General Industry Safety Orders, Construction Safety Orders). **Documents Audited:** Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification documents, serious injury/fatality investigat', '', '', '', 'Workplace inspection reports, citations and penalty assessments, Injury and Illness Prevention Program (IIPP) documents (Lab. Code 6401.7), employer accident/illness reports (Form 5020), appeal files before OSHAB, variance applications, abatement verification documents, serious injury/fatality investigation reports, heat illness prevention plans, COVID-19 prevention plans.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ed054ad54677', 'A-17. Cal/OSHA Industrial Hygienist', 'California Local Unique Compliance', 'California Local Unique', 'A-17. Cal/OSHA Industrial Hygienist — Cal/OSHA. **Codes:** Lab. Code 6350-6356, 142.3; Cal. Code Regs. tit. 8 5139-5223 (hazardous substances). **Documents Audited:** Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.', 'A-17. Cal/OSHA Industrial Hygienist', 'Cal/OSHA. **Codes:** Lab. Code 6350-6356, 142.3; Cal. Code Regs. tit. 8 5139-5223 (hazardous substances). **Documents Audited:** Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.', '', '', '', 'Exposure monitoring reports, permissible exposure limit (PEL) compliance records, respiratory protection program documents, hazard communication program audits, laboratory chemical hygiene plans, lead/asbestos exposure assessments, biological monitoring results.');
