INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a303c92815ce', 'A-21. State Water Board Water Rights Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-21. State Water Board Water Rights Analyst — SWRCB, Division of Water Rights. **Codes:** Wat. Code 1200-1851; Cal. Code Regs. tit. 23 div. 3. **Documents Audited:** Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.', 'A-21. State Water Board Water Rights Analyst', 'SWRCB, Division of Water Rights. **Codes:** Wat. Code 1200-1851; Cal. Code Regs. tit. 23 div. 3. **Documents Audited:** Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.', '', '', '', 'Water rights applications and permits, statements of diversion, water rights licenses, change petitions, water transfer approvals, instream flow dedications, curtailment notices during drought, water availability analyses, appropriative rights protests and hearings.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5d475e305708', 'A-22. State Treasurer Debt Manager', 'California Local Unique Compliance', 'California Local Unique', 'A-22. State Treasurer Debt Manager — California State Treasurer''s Office (STO). **Codes:** Gov. Code 16300-16430, 5000-5980 (Marks-Roos); Cal. Const. Art. XVI. **Documents Audited:** General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare p', 'A-22. State Treasurer Debt Manager', 'California State Treasurer''s Office (STO). **Codes:** Gov. Code 16300-16430, 5000-5980 (Marks-Roos); Cal. Const. Art. XVI. **Documents Audited:** General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare program audits, conduit bond post-issu', '', '', '', 'General obligation bond issuance documents, revenue bond official statements, Marks-Roos authority bond filings, CDIAC (California Debt and Investment Advisory Commission) annual debt reports, pooled money investment reports (PMIA), tax credit allocations (LIHTC via CTCAC), CalABLE program compliance, ScholarShare program audits, conduit bond post-issuance compliance.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9d2bf7cfbbfb', 'A-23. CDIAC Analyst', 'California Local Unique Compliance', 'California Local Unique', 'A-23. CDIAC Analyst — California Debt and Investment Advisory Commission (under Treasurer). **Codes:** Gov. Code 8855-8859.7. **Documents Audited:** Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.', 'A-23. CDIAC Analyst', 'California Debt and Investment Advisory Commission (under Treasurer). **Codes:** Gov. Code 8855-8859.7. **Documents Audited:** Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.', '', '', '', 'Report of proposed debt issuance (filed by all public agencies), report of final sale, annual debt transparency reports, Mello-Roos and marks-roos bond filings, refunding savings analyses, continuing disclosure compliance reviews.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-45aa65fc3c86', 'B-1. County Supervisor', 'California Local Unique Compliance', 'California Local Unique', 'B-1. County Supervisor — County Board of Supervisors. **Codes:** Gov. Code 25000-25009, 23000-23027; Cal. Const. Art. XI sec. 1. **Documents Audited:** Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.', 'B-1. County Supervisor', 'County Board of Supervisors. **Codes:** Gov. Code 25000-25009, 23000-23027; Cal. Const. Art. XI sec. 1. **Documents Audited:** Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.', '', '', '', 'Board resolutions and ordinances, budget adoption documents, general plan adoption records, county formation/boundary documents, franchise agreements, legislative body minutes, Brown Act compliance records, CEQA findings for county projects, intergovernmental agreements, emergency declarations.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f62069367eb1', 'B-2. County Clerk-Recorder', 'California Local Unique Compliance', 'California Local Unique', 'B-2. County Clerk-Recorder — County Clerk/Recorder''s Office. **Codes:** Gov. Code 26800-26832 (clerk), 27201-27383 (recorder); Elec. Code 1000-1501; Fam. Code 350-500 (marriage). **Documents Audited:** Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercia', 'B-2. County Clerk-Recorder', 'County Clerk/Recorder''s Office. **Codes:** Gov. Code 26800-26832 (clerk), 27201-27383 (recorder); Elec. Code 1000-1501; Fam. Code 350-500 (marriage). **Documents Audited:** Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercial Code filings (county level)', '', '', '', 'Real property deeds and liens, vital records (birth/death/marriage certificates), fictitious business name statements, notary bonds, maps and surveys, oaths of office, election official certifications, recording fee schedules, document indexing and retrieval standards, California Uniform Commercial Code filings (county level), marriage license applications, passport applications.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-d6eb459c85cc', 'B-3. County Assessor', 'California Local Unique Compliance', 'California Local Unique', 'B-3. County Assessor — County Assessor''s Office. **Codes:** RTC 75-469.5 (Prop 13 assessment); Cal. Const. Art. XIIIA; Cal. Code Regs. tit. 18 1-1005. **Documents Audited:** Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property stat', 'B-3. County Assessor', 'County Assessor''s Office. **Codes:** RTC 75-469.5 (Prop 13 assessment); Cal. Const. Art. XIIIA; Cal. Code Regs. tit. 18 1-1005. **Documents Audited:** Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property statements (Form 571), Will', '', '', '', 'Property assessment rolls, change of ownership statements, new construction assessments, exemption claims (homeowner''s, veteran''s, church, welfare), Prop 8 temporary decline-in-value reviews, Prop 13 base year value calculations, supplemental/escape assessments, possessory interest valuations, business personal property statements (Form 571), Williamson Act valuations, assessment appeal hearing records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9f60c3ff0826', 'B-4. County Treasurer-Tax Collector', 'California Local Unique Compliance', 'California Local Unique', 'B-4. County Treasurer-Tax Collector — County Treasurer-Tax Collector Office. **Codes:** RTC 2601-4377 (tax collection); Gov. Code 27000-27092 (treasurer). **Documents Audited:** Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district ', 'B-4. County Treasurer-Tax Collector', 'County Treasurer-Tax Collector Office. **Codes:** RTC 2601-4377 (tax collection); Gov. Code 27000-27092 (treasurer). **Documents Audited:** Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district levy calculations.', '', '', '', 'Tax bills (secured/unsecured), delinquent property tax rolls, tax sale certificates, Teeter Plan participation documents, county investment pool reports (quarterly per Gov. Code 53646), installment plan agreements, treasury investment policy, redemption records, transient occupancy tax (TOT) filings, assessment district levy calculations.');
