INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-25263869fb36', 'B-11. County Social Services Eligibility Worker', 'California Local Unique Compliance', 'California Local Unique', 'B-11. County Social Services Eligibility Worker — County Department of Social Services (DSS). **Codes:** WIC 10000-18999 (CalWORKs), 14000-14199 (Medi-Cal), 18900-18927 (CalFresh); 42 USC 601+ (TANF federal); Cal. Code Regs. tit. 22 div. 3. **Documents Audited:** CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpaymen', 'B-11. County Social Services Eligibility Worker', 'County Department of Social Services (DSS). **Codes:** WIC 10000-18999 (CalWORKs), 14000-14199 (Medi-Cal), 18900-18927 (CalFresh); 42 USC 601+ (TANF federal); Cal. Code Regs. tit. 22 div. 3. **Documents Audited:** CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpayment/underpayment claims, fair hearing requests, coun', '', '', '', 'CalWORKs applications and redeterminations, CalFresh (SNAP) eligibility worksheets, Medi-Cal eligibility determinations (MAGI and non-MAGI), income verification documents, welfare-to-work participation records (WTW 2/WTW 73), overpayment/underpayment claims, fair hearing requests, county self-assessment reviews (CalWORKs Outcomes), In-Home Supportive Services (IHSS) assessments, General Assistance/General Relief applications.');
