INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3974b3c8045d', 'B-14. City Council Member', 'California Local Unique Compliance', 'California Local Unique', 'B-14. City Council Member — City Council (general law or charter city). **Codes:** Gov. Code 34000-45343 (Govt of Cities); Cal. Const. Art. XI sec. 3-5. **Documents Audited:** City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authori', 'B-14. City Council Member', 'City Council (general law or charter city). **Codes:** Gov. Code 34000-45343 (Govt of Cities); Cal. Const. Art. XI sec. 3-5. **Documents Audited:** City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authority agreements.', '', '', '', 'City ordinances and resolutions, general plan adoption/amendments, budget documents, Brown Act compliance records (agendas 72-hr posting, closed session reports), franchise agreements, annexation/detachment resolutions, conflict-of-interest declarations, city charter amendments, emergency declarations, joint powers authority agreements.');
