INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-af2fe0942b9c', 'B-16. City Clerk', 'California Local Unique Compliance', 'California Local Unique', 'B-16. City Clerk — City Clerk''s Office. **Codes:** Gov. Code 36800-36840; Elec. Code 1301-1304, 10200-10264. **Documents Audited:** Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business lice', 'B-16. City Clerk', 'City Clerk''s Office. **Codes:** Gov. Code 36800-36840; Elec. Code 1301-1304, 10200-10264. **Documents Audited:** Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business license records.', '', '', '', 'Ordinance and resolution files (codification), council meeting minutes, public records requests (CPRA compliance), FPPC filing officer duties (Form 700 repository), municipal election documents, conflict-of-interest code maintenance, records retention schedules, claims against city, bid opening records, oath of office filings, administrative citations, business license records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-15828e7eb267', 'B-17. City Attorney', 'California Local Unique Compliance', 'California Local Unique', 'B-17. City Attorney — City Attorney''s Office. **Codes:** Gov. Code 36500-36524 (general law cities); city charter; Cal. Rules Prof. Conduct 1.13 (organizational client). **Documents Audited:** Legal opinions to council/departments, ordinance/contract drafting reviews, litigation files, code enforcement prosecution files, Brown Act advisories, CEQA legal adequacy reviews, eminent domain proceedings, municipal bond counsel opinions, initiative/referendum legal analyses, claims investigation memora', 'B-17. City Attorney', 'City Attorney''s Office. **Codes:** Gov. Code 36500-36524 (general law cities); city charter; Cal. Rules Prof. Conduct 1.13 (organizational client). **Documents Audited:** Legal opinions to council/departments, ordinance/contract drafting reviews, litigation files, code enforcement prosecution files, Brown Act advisories, CEQA legal adequacy reviews, eminent domain proceedings, municipal bond counsel opinions, initiative/referendum legal analyses, claims investigation memoranda, public records re', '', '', '', 'Legal opinions to council/departments, ordinance/contract drafting reviews, litigation files, code enforcement prosecution files, Brown Act advisories, CEQA legal adequacy reviews, eminent domain proceedings, municipal bond counsel opinions, initiative/referendum legal analyses, claims investigation memoranda, public records request privilege logs, nuisance abatement legal actions.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e9e0f202dd90', 'B-18. City Planning Director', 'California Local Unique Compliance', 'California Local Unique', 'B-18. City Planning Director — City Planning/Zoning Department. **Codes:** Gov. Code 65000-66210 (Planning & Zoning Law); PRC 21000-21189.70 (CEQA); Gov. Code 65852.2 (ADU). **Documents Audited:** General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bon', 'B-18. City Planning Director', 'City Planning/Zoning Department. **Codes:** Gov. Code 65000-66210 (Planning & Zoning Law); PRC 21000-21189.70 (CEQA); Gov. Code 65852.2 (ADU). **Documents Audited:** General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bonus applications, ADU/JADU permi', '', '', '', 'General plan elements (7 mandatory elements + optional), specific plans, zoning ordinance amendments, conditional use permits, variance applications, subdivision maps (tentative/final), environmental impact reports (EIRs), negative declarations/MNDs, housing element compliance (HCD review), density bonus applications, ADU/JADU permits, SB 9 lot split applications, SB 10 urban infill resolutions, development agreements, Williamson Act contracts/non-renewal notices.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a22c7bc517c2', 'B-19. Chief Building Official', 'California Local Unique Compliance', 'California Local Unique', 'B-19. Chief Building Official — City/County Building Department. **Codes:** HSC 17920-17928, 18900-18944 (State Housing Law); Cal. Building Code (CBC/Title 24); Gov. Code 65850-65863.13. **Documents Audited:** Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, sei', 'B-19. Chief Building Official', 'City/County Building Department. **Codes:** HSC 17920-17928, 18900-18944 (State Housing Law); Cal. Building Code (CBC/Title 24); Gov. Code 65850-65863.13. **Documents Audited:** Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, seismic retrofit compliance, solar ', '', '', '', 'Building permit applications and approvals, plan check reports, inspection records (foundation through final), certificate of occupancy, Title 24 energy compliance (CF-1R/CF-2R), CalGreen compliance, ADA/accessibility compliance reports, unreinforced masonry building (URM) inventories, seismic retrofit compliance, solar permit applications (AB 2188), SB 35 streamlined permits, code violation notices and abatement orders, demolition permits.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-70789e083ee3', 'B-20. Fire Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-20. Fire Chief — City Fire Department or Fire Protection District. **Codes:** HSC 13000-13273 (State Fire Marshal); Cal. Fire Code (Title 24 Part 9); Gov. Code 51175-51189 (fire hazard zones). **Documents Audited:** Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/', 'B-20. Fire Chief', 'City Fire Department or Fire Protection District. **Codes:** HSC 13000-13273 (State Fire Marshal); Cal. Fire Code (Title 24 Part 9); Gov. Code 51175-51189 (fire hazard zones). **Documents Audited:** Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/alarm system plan c', '', '', '', 'Fire inspection reports, fire prevention plans, fire code violation notices, operational pre-fire plans, mutual/automatic aid agreements, fire investigation reports (arson), hazardous materials disclosure documents (HSC 25500-25520 CUPA), community risk assessments, fire sprinkler/alarm system plan checks, vegetation management plans (SRA/LRA), emergency response incident reports (NFIRS), firework permits, high-rise building inspection records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f161e0fdb797', 'B-21. Police Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-21. Police Chief — City Police Department. **Codes:** Pen. Code 830.1, 832, 13519-13519.14 (POST standards); Gov. Code 3300-3313 (POBR). **Documents Audited:** Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, communit', 'B-21. Police Chief', 'City Police Department. **Codes:** Pen. Code 830.1, 832, 13519-13519.14 (POST standards); Gov. Code 3300-3313 (POBR). **Documents Audited:** Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, community policing plans, SB ', '', '', '', 'Arrest reports, crime reports, use-of-force reports (AB 392/SB 230), body-worn camera footage logs, pursuit reports, internal affairs investigation files, civilian complaint disposition records, RIPA racial profiling data (Gov. Code 12525.5), towed vehicle reports, sex offender registration compliance, asset forfeiture records, community policing plans, SB 1421/AB 748 disclosure records, Brady list maintenance, military equipment use reports (AB 481), surveillance technology policies.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-575567de5f3f', 'B-22. Director of Public Works', 'California Local Unique Compliance', 'California Local Unique', 'B-22. Director of Public Works — City/County Public Works Department. **Codes:** SHC 1-33700 (Streets & Highways); PCC 20100-22045 (public contracts); Gov. Code 4525-4529 (A&E services). **Documents Audited:** Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compli', 'B-22. Director of Public Works', 'City/County Public Works Department. **Codes:** SHC 1-33700 (Streets & Highways); PCC 20100-22045 (public contracts); Gov. Code 4525-4529 (A&E services). **Documents Audited:** Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compliance, traffic signal warrant anal', '', '', '', 'Capital improvement project plans, prevailing wage compliance records (Lab. Code 1770-1781), bid solicitation/award documents, encroachment permits, street/sidewalk/sewer improvement plans, stormwater management plans (MS4 permits), pavement management program reports, ADA curb ramp compliance, traffic signal warrant analyses, public contract change orders, notice of completion filings, retention payment releases, Prop 218 assessment ballots.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6bff06824ee9', 'B-23. Water District General Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-23. Water District General Manager — Water District Board of Directors (formed under Wat. Code div. 12-20 or special act). **Codes:** Wat. Code 30000-38501 (county water districts), 34000-38501 (municipal water districts); HSC 116270-116755 (drinking water); Prop 218 (rates). **Documents Audited:** Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency pla', 'B-23. Water District General Manager', 'Water District Board of Directors (formed under Wat. Code div. 12-20 or special act). **Codes:** Wat. Code 30000-38501 (county water districts), 34000-38501 (municipal water districts); HSC 116270-116755 (drinking water); Prop 218 (rates). **Documents Audited:** Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency plans, water rate studies (Prop 218 compli', '', '', '', 'Water quality consumer confidence reports (CCR), source water assessments, water supply assessments (Gov. Code 66473.7), urban water management plans (Wat. Code 10610-10657), drought contingency plans, water rate studies (Prop 218 compliant), annual financial audits, SWRCB drinking water permits, distribution system monitoring, backflow prevention program records, lead and copper rule compliance, recycled water permits, water loss audits (SB 555).');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-65bea28673ec', 'B-24. Fire Protection District Chief', 'California Local Unique Compliance', 'California Local Unique', 'B-24. Fire Protection District Chief — Fire Protection District Board (HSC 13800-13970). **Codes:** HSC 13800-13970 (fire protection districts); Gov. Code 50075-50077.5 (special taxes); Cal. Fire Code Title 24 Part 9. **Documents Audited:** District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development ', 'B-24. Fire Protection District Chief', 'Fire Protection District Board (HSC 13800-13970). **Codes:** HSC 13800-13970 (fire protection districts); Gov. Code 50075-50077.5 (special taxes); Cal. Fire Code Title 24 Part 9. **Documents Audited:** District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development impact fee justification studies, annua', '', '', '', 'District formation/annexation documents, special tax/assessment levy records, ISO rating documentation, apparatus and equipment inventories, volunteer firefighter certifications, station response time reports, community wildfire protection plans, development impact fee justification studies, annual independent financial audits, Prop 4/Gann limit calculations, mutual aid agreements.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1223f099cb58', 'B-25. Sanitation District Engineer', 'California Local Unique Compliance', 'California Local Unique', 'B-25. Sanitation District Engineer — Sanitation/Sanitary District Board (HSC 6400-6830). **Codes:** HSC 5410-5476 (Porter-Cologne nexus), 6400-6830 (sanitary districts); Wat. Code 13000+; 40 CFR 122, 503 (federal NPDES). **Documents Audited:** NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, con', 'B-25. Sanitation District Engineer', 'Sanitation/Sanitary District Board (HSC 6400-6830). **Codes:** HSC 5410-5476 (Porter-Cologne nexus), 6400-6830 (sanitary districts); Wat. Code 13000+; 40 CFR 122, 503 (federal NPDES). **Documents Audited:** NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, connection fee studies, sewer system mas', '', '', '', 'NPDES permit compliance reports (DMRs), collection system monitoring reports, sanitary sewer management plans (SSMP), sanitary sewer overflow (SSO) reports, industrial pretreatment program records, biosolids management plans, capacity management plans, connection fee studies, sewer system master plans, CEQA documents for facility expansion.');
