INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-34088785f335', 'B-27. Mosquito Abatement District Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-27. Mosquito Abatement District Manager — Mosquito Abatement/Vector Control District Board (HSC 2000-2093). **Codes:** HSC 2000-2093 (mosquito abatement), 116110-116068 (vector control); FAC 12751-14102 (pesticide use). **Documents Audited:** Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification recor', 'B-27. Mosquito Abatement District Manager', 'Mosquito Abatement/Vector Control District Board (HSC 2000-2093). **Codes:** HSC 2000-2093 (mosquito abatement), 116110-116068 (vector control); FAC 12751-14102 (pesticide use). **Documents Audited:** Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification records for aerial/ground treatments, West Nile v', '', '', '', 'Mosquito surveillance reports, pesticide use reports (DPR filings), best management practices plans, service request logs, annual budget and audit, CEQA compliance for treatment activities, integrated pest management (IPM) plans, public notification records for aerial/ground treatments, West Nile virus monitoring data, special tax assessment records.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9f64c9fe3240', 'B-28. Cemetery District Manager', 'California Local Unique Compliance', 'California Local Unique', 'B-28. Cemetery District Manager — Cemetery District Board (HSC 8890-9068). **Codes:** HSC 7000-8030 (disposition of remains), 8890-9068 (cemetery districts); BPC 7600-7741 (Cemetery and Funeral Bureau). **Documents Audited:** Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transa', 'B-28. Cemetery District Manager', 'Cemetery District Board (HSC 8890-9068). **Codes:** HSC 7000-8030 (disposition of remains), 8890-9068 (cemetery districts); BPC 7600-7741 (Cemetery and Funeral Bureau). **Documents Audited:** Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transactions report, grave relocation or', '', '', '', 'Interment records, endowment care fund investment reports, plot sales contracts, annual financial audits, district formation/boundary documents, master plan for cemetery development, maintenance schedules, fee schedules, state controller''s special districts financial transactions report, grave relocation orders, environmental compliance for land expansion.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b76254641ba1', 'B-29. Library District Director', 'California Local Unique Compliance', 'California Local Unique', 'B-29. Library District Director — Library District Board (Educ. Code 19400-19605). **Codes:** Educ. Code 18010-18203 (county free libraries), 19400-19605 (library districts); Gov. Code 6250-6270 (CPRA as it applies to library records). **Documents Audited:** Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectua', 'B-29. Library District Director', 'Library District Board (Educ. Code 19400-19605). **Codes:** Educ. Code 18010-18203 (county free libraries), 19400-19605 (library districts); Gov. Code 6250-6270 (CPRA as it applies to library records). **Documents Audited:** Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectual freedom policies, interlibrary l', '', '', '', 'Collection development policies, library services plans, patron privacy protection policies (Gov. Code 6267), annual statistics for State Library reporting, grant compliance (LSTA/CLSA), ADA accessibility plans, technology plans, intellectual freedom policies, interlibrary loan agreements, Friends of Library/foundation audit records, bond/measure expenditure reports.');
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7ffa78b8d05a', 'B-30. School District Superintendent', 'California Local Unique Compliance', 'California Local Unique', 'B-30. School District Superintendent — School District Board of Trustees. **Codes:** Educ. Code 35000-35179 (superintendent), 42100-42652 (school finance); Cal. Const. Art. IX. **Documents Audited:** Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local p', 'B-30. School District Superintendent', 'School District Board of Trustees. **Codes:** Educ. Code 35000-35179 (superintendent), 42100-42652 (school finance); Cal. Const. Art. IX. **Documents Audited:** Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local plan area (SELPA) compliance, student re', '', '', '', 'Local Control Accountability Plan (LCAP), school accountability report cards (SARC), annual budget (adopted/interim), audit reports (Education Audits Appeal Panel standards), Williams settlement compliance (facilities, textbooks, teachers), collective bargaining agreements, special education local plan area (SELPA) compliance, student records (FERPA/EdC 49060-49079), mandatory reporter training records, Title IX compliance files, school safety plans, facilities master plans, developer fee justification studies, Brown Act compliance for board meetings.');
