UPDATE citizen_catalog SET standards_of_creation = ':; License applications must include premises diagram, ownership disclosure, background check authorization; Renewal filings per state-mandated cycle (annual/biennial); Posted license must match premises address and licensee name exactly; Conditional use permits must precede ABC approval', soc_controls = ':; S.o.C.-1: License access restricted to management; renewal calendar maintained; S.o.C.-2: Original license retained on-premises; copies authenticated; S.o.C.-3: Public posting of license number and type at point of sale' WHERE name = 'Alcohol Beverage Control Compliance Officer';
