UPDATE citizen_catalog SET standards_of_creation = ':; Server certification cards must bear issuer accreditation number; Training completed within state-mandated timeframe (e.g., CA: 60 days of hire); Certification renewal per state cycle (typically 3-5 years); Training records must include date, provider, score, certificate number', soc_controls = ':; S.o.C.-1: HR maintains certification roster; expiration alerts automated; S.o.C.-2: Training provider must be state-accredited; certificate serial tracked; S.o.C.-3: Certification status verifiable by enforcement upon request' WHERE name = 'Responsible Beverage Service Trainer';
