UPDATE citizen_catalog SET standards_of_creation = ':; Renewal application filed within statutory window (typically 30-90 days before expiration); Fee payment documented with receipt and confirmation number; Any ownership changes trigger new application, not renewal; Compliance history attached to renewal in states requiring clean record', soc_controls = ':; S.o.C.-1: Renewal calendar with 90/60/30-day alerts; S.o.C.-2: Payment receipts retained for audit period (typically 7 years); S.o.C.-3: Renewal status publicly verifiable through state ABC database' WHERE name = 'Liquor License Renewal Specialist';
