UPDATE citizen_catalog SET standards_of_creation = ':; CFPM certification from ANSI-CFP accredited provider (ServSafe, NRFSP, Prometric); At least one CFPM per establishment during all operating hours; HACCP plans documented with critical control points, limits, monitoring, corrective actions; Temperature logs maintained with time/date/initials', soc_controls = ':; S.o.C.-1: HACCP plans reviewed annually; staff access to food safety SOPs; S.o.C.-2: Temperature monitoring devices calibrated per manufacturer spec; logs immutable; S.o.C.-3: Health department inspection scores posted publicly (where required)' WHERE name = 'Food Safety Manager (CFPM)';
