UPDATE citizen_catalog SET standards_of_creation = ':; Inspection reports must use standardized form (FDA 3-purpose form or state equivalent); Violations classified as critical/non-critical with corrective timeline; Follow-up inspection documented within mandated timeframe; Inspector must hold REHS credential or equivalent state certification', soc_controls = ':; S.o.C.-1: Inspection scheduling randomized; inspector rotation policies; S.o.C.-2: Reports signed, dated, and delivered to permit holder at conclusion of inspection; S.o.C.-3: Inspection results publicly available (online databases, posted grades)' WHERE name = 'Health Inspector / Environmental Health Specialist (REHS)';
