INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-aff1a477f03e', 'Short-Term Rental Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Short-Term Rental Compliance Officer — Local Planning/Zoning; State Tax Authorities; Platform regulators', 'Short-Term Rental Compliance Officer', 'Local Planning/Zoning; State Tax Authorities; Platform regulators', ':; Local STR ordinances (city-specific registration, caps, zones); State TOT statutes applied to STR platforms; Local safety/habitability codes; Cal. Gov. Code § 65852.2 (ADU law intersections); Platform-specific compliance (Airbnb Community Compact, etc.)', ':; STR registration/permit obtained before listing; Registration number displayed on all platform listings; TOT registration with local tax authority; Safety equipment verified (smoke detectors, CO detectors, fire extinguisher); Neighbor notification where required by ordinance', ':; S.o.C.-1: Permit renewal tracked; occupancy limits monitored; insurance maintained; S.o.C.-2: Tax remittance documented monthly/quarterly; guest records retained per statute; S.o.C.-3: Registration number publicly visible on listing', 'Short-term rental (Airbnb) compliance documents, tourism board licensing');
UPDATE citizen_catalog SET standards_of_creation = ':; Public offering statement (POS) delivered before contract execution; POS must include: assessments, restrictions, exchange programs, cancellation rights; Rescission notice in bold/conspicuous type per state statute; Financial projections (if any) must comply with state securities law', soc_controls = ':; S.o.C.-1: POS version control; delivery receipt with date/time stamp; S.o.C.-2: Rescission period tracked per buyer; refund processed within statutory window; S.o.C.-3: Registration with state real estate commission publicly verifiable' WHERE name = 'Resort/Timeshare Disclosure Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4b099fcd405a', 'Resort/Timeshare Disclosure Compliance Specialist', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Resort/Timeshare Disclosure Compliance Specialist — State real estate commissions; FTC; State consumer protection', 'Resort/Timeshare Disclosure Compliance Specialist', 'State real estate commissions; FTC; State consumer protection', ':; State timeshare acts (e.g., Cal. Bus. & Prof. Code §§ 11210-11288); 15 U.S.C. § 3601 et seq. (Interstate Land Sales Full Disclosure Act — HUD); State rescission period statutes (typically 3-15 days); ARDA (American Resort Development Association) best practices', ':; Public offering statement (POS) delivered before contract execution; POS must include: assessments, restrictions, exchange programs, cancellation rights; Rescission notice in bold/conspicuous type per state statute; Financial projections (if any) must comply with state securities law', ':; S.o.C.-1: POS version control; delivery receipt with date/time stamp; S.o.C.-2: Rescission period tracked per buyer; refund processed within statutory window; S.o.C.-3: Registration with state real estate commission publicly verifiable', 'Resort/timeshare disclosure documents');
UPDATE citizen_catalog SET standards_of_creation = ':; Pool/spa operating permit issued after initial inspection; Water quality testing records (chlorine, pH, temperature) minimum 2x daily; Drain cover compliance certification from manufacturer or inspector; Lifeguard certifications current (ARC or equivalent)', soc_controls = ':; S.o.C.-1: Daily water quality logs maintained; chemical inventory tracked; S.o.C.-2: Permit renewed annually; inspection reports retained 3+ years; S.o.C.-3: Pool rules and emergency contact posted at pool area; permit visible' WHERE name = 'Pool/Spa Safety Compliance Inspector';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-693ce1414f7c', 'Pool/Spa Safety Compliance Inspector', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Pool/Spa Safety Compliance Inspector — State/County Health Departments; CDC; CPSC', 'Pool/Spa Safety Compliance Inspector', 'State/County Health Departments; CDC; CPSC', ':; Virginia Graeme Baker Pool and Spa Safety Act, 15 U.S.C. §§ 8001-8008; CPSC drain cover standards (ASME/ANSI A112.19.8-2007); State pool safety codes (e.g., Cal. Health & Safety Code §§ 115920-115929); CDC Model Aquatic Health Code (MAHC)', ':; Pool/spa operating permit issued after initial inspection; Water quality testing records (chlorine, pH, temperature) minimum 2x daily; Drain cover compliance certification from manufacturer or inspector; Lifeguard certifications current (ARC or equivalent)', ':; S.o.C.-1: Daily water quality logs maintained; chemical inventory tracked; S.o.C.-2: Permit renewed annually; inspection reports retained 3+ years; S.o.C.-3: Pool rules and emergency contact posted at pool area; permit visible', 'Pool/spa health permits, health department inspection reports');
UPDATE citizen_catalog SET standards_of_creation = ':; Written disclosure of known infestation history (where required by statute); Pest inspection reports from licensed pest control operator; Treatment records with EPA-registered product information; Guest complaint log with response actions documented', soc_controls = ':; S.o.C.-1: Inspection schedule maintained; complaint-response protocol documented; S.o.C.-2: Treatment records retained per EPA/state requirement; room-level tracking; S.o.C.-3: Disclosure provided to guest at check-in (where required)' WHERE name = 'Bed Bug Disclosure Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b428dfdf20f8', 'Bed Bug Disclosure Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Bed Bug Disclosure Compliance Officer — State/Local consumer protection agencies; EPA; State AG', 'Bed Bug Disclosure Compliance Officer', 'State/Local consumer protection agencies; EPA; State AG', ':; State bed bug disclosure statutes (e.g., Cal. Civ. Code § 1942.5(d)); Local bed bug ordinances (e.g., NYC Admin. Code § 27-2018.1); EPA-registered pesticide application requirements (FIFRA, 7 U.S.C. § 136 et seq.); FTC Act (deceptive practices if infestation concealed)', ':; Written disclosure of known infestation history (where required by statute); Pest inspection reports from licensed pest control operator; Treatment records with EPA-registered product information; Guest complaint log with response actions documented', ':; S.o.C.-1: Inspection schedule maintained; complaint-response protocol documented; S.o.C.-2: Treatment records retained per EPA/state requirement; room-level tracking; S.o.C.-3: Disclosure provided to guest at check-in (where required)', 'Bed bug disclosure documents, health department inspection reports');
UPDATE citizen_catalog SET standards_of_creation = ':; Event permit application filed within mandated lead time (typically 30-90 days); Site plan with emergency access routes, exits, capacity calculation; Insurance certificate (COI) naming jurisdiction as additional insured; Separate permits for: food service, alcohol, amplified sound, parking, road closure', soc_controls = ':; S.o.C.-1: Multi-agency permit tracking; timeline coordination; S.o.C.-2: All permits issued before event date; insurance COI verified; S.o.C.-3: Event permit posted on-site; emergency contacts displayed' WHERE name = 'Special Event Permit Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-154111f7baba', 'Special Event Permit Coordinator', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Special Event Permit Coordinator — Local Fire Marshal; Health Dept; ABC; Planning/Zoning; Police', 'Special Event Permit Coordinator', 'Local Fire Marshal; Health Dept; ABC; Planning/Zoning; Police', ':; Local special event ordinances; NFPA 102 (Assembly Seating); State temporary food facility permits (e.g., Cal. Health & Safety Code § 113818); State ABC temporary event permits (e.g., Cal. Bus. & Prof. Code § 24045.1); Local noise ordinances', ':; Event permit application filed within mandated lead time (typically 30-90 days); Site plan with emergency access routes, exits, capacity calculation; Insurance certificate (COI) naming jurisdiction as additional insured; Separate permits for: food service, alcohol, amplified sound, parking, road closure', ':; S.o.C.-1: Multi-agency permit tracking; timeline coordination; S.o.C.-2: All permits issued before event date; insurance COI verified; S.o.C.-3: Event permit posted on-site; emergency contacts displayed', 'Special event permits, catering permits, fire marshal inspection reports');
UPDATE citizen_catalog SET standards_of_creation = ':; Advertising claims substantiated before dissemination ("reasonable basis" standard); Substantiation file maintained per claim with supporting evidence; Endorsement disclosures clear and conspicuous per medium; Comparative advertising claims documented with testing methodology', soc_controls = ':; S.o.C.-1: Legal review of advertising before publication; claim substantiation files maintained; S.o.C.-2: Ad copy archived with publication date, medium, audience; 5+ year retention; S.o.C.-3: Consumer complaint mechanism accessible' WHERE name = 'FTC Compliance Officer (Advertising & Marketing)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-824671985cef', 'FTC Compliance Officer (Advertising & Marketing)', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'FTC Compliance Officer (Advertising & Marketing) — FTC Bureau of Consumer Protection', 'FTC Compliance Officer (Advertising & Marketing)', 'FTC Bureau of Consumer Protection', ':; 15 U.S.C. § 45 (FTC Act — Unfair or Deceptive Acts/Practices); 16 CFR Part 255 (Guides Concerning Use of Endorsements and Testimonials); 16 CFR Part 238 (Bait Advertising); 16 CFR Part 251 (Guide Concerning Use of the Word "Free"); FTC Dot Com Disclosures Guide (2013, updated); FTC Endorsement Guides (2023 revision)', ':; Advertising claims substantiated before dissemination ("reasonable basis" standard); Substantiation file maintained per claim with supporting evidence; Endorsement disclosures clear and conspicuous per medium; Comparative advertising claims documented with testing methodology', ':; S.o.C.-1: Legal review of advertising before publication; claim substantiation files maintained; S.o.C.-2: Ad copy archived with publication date, medium, audience; 5+ year retention; S.o.C.-3: Consumer complaint mechanism accessible', 'FTC compliance documents, price advertising compliance');
UPDATE citizen_catalog SET standards_of_creation = ':; Written cancellation notice provided in duplicate at time of sale; Notice in same language as sales presentation; Notice must state: date, seller name/address, 3-day cancellation right; Contract must contain cancellation provision in 10-point bold type', soc_controls = ':; S.o.C.-1: Sales rep training documented; compliance acknowledgment signed; S.o.C.-2: Cancellation notice delivery documented with buyer signature; retained 5+ years; S.o.C.-3: Buyer cancellation processed within 10 days of receipt' WHERE name = 'Door-to-Door Sales Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-835d0b5a8aca', 'Door-to-Door Sales Compliance Manager', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Door-to-Door Sales Compliance Manager — FTC; State consumer protection agencies', 'Door-to-Door Sales Compliance Manager', 'FTC; State consumer protection agencies', ':; 16 CFR Part 429 (FTC Cooling-Off Rule); State home solicitation statutes (e.g., Cal. Civ. Code §§ 1689.5-1689.14); FTC Business Opportunity Rule, 16 CFR Part 437', ':; Written cancellation notice provided in duplicate at time of sale; Notice in same language as sales presentation; Notice must state: date, seller name/address, 3-day cancellation right; Contract must contain cancellation provision in 10-point bold type', ':; S.o.C.-1: Sales rep training documented; compliance acknowledgment signed; S.o.C.-2: Cancellation notice delivery documented with buyer signature; retained 5+ years; S.o.C.-3: Buyer cancellation processed within 10 days of receipt', 'Door-to-door sales compliance (FTC Cooling-Off Rule)');
UPDATE citizen_catalog SET standards_of_creation = ':; Written DNC policy maintained; internal DNC list updated within 30 days; Prior express written consent documented before autodialed/prerecorded calls; Caller ID displays registered name and callback number; Telemarketer registration filed with state (where required)', soc_controls = ':; S.o.C.-1: DNC scrubbing before each campaign; consent records accessible; S.o.C.-2: Call records retained 24 months minimum; consent forms 5+ years; S.o.C.-3: Opt-out honored within 30 days; Do Not Call requests logged' WHERE name = 'Telemarketing Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-509e759cf2b2', 'Telemarketing Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Telemarketing Compliance Officer — FTC; FCC; State AGs', 'Telemarketing Compliance Officer', 'FTC; FCC; State AGs', ':; 16 CFR Part 310 (Telemarketing Sales Rule — TSR); 47 CFR Part 64.1200 (FCC TCPA Rules); 47 U.S.C. § 227 (Telephone Consumer Protection Act — TCPA); National Do Not Call Registry provisions; State telemarketing registration statutes', ':; Written DNC policy maintained; internal DNC list updated within 30 days; Prior express written consent documented before autodialed/prerecorded calls; Caller ID displays registered name and callback number; Telemarketer registration filed with state (where required)', ':; S.o.C.-1: DNC scrubbing before each campaign; consent records accessible; S.o.C.-2: Call records retained 24 months minimum; consent forms 5+ years; S.o.C.-3: Opt-out honored within 30 days; Do Not Call requests logged', 'Telemarketing compliance (TSR/TCPA)');
UPDATE citizen_catalog SET standards_of_creation = ':; Official rules published before promotion start; Rules must include: eligibility, entry method, prize description/value/odds, AMNB, drawing date, sponsor; No purchase necessary alternative clearly disclosed; Winner list available upon request (where required by state); State registration/bonding filed (NY, FL, RI for prizes > threshold)', soc_controls = ':; S.o.C.-1: Legal review of rules before launch; prize fulfillment tracked; S.o.C.-2: Entry records, rules, and winner selection documented; retained per state requirement; S.o.C.-3: Official rules publicly accessible throughout promotion' WHERE name = 'Sweepstakes & Contest Compliance Counsel';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3100ee02b577', 'Sweepstakes & Contest Compliance Counsel', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Sweepstakes & Contest Compliance Counsel — FTC; State AGs; State lottery/gaming commissions', 'Sweepstakes & Contest Compliance Counsel', 'FTC; State AGs; State lottery/gaming commissions', ':; 15 U.S.C. § 45 (FTC Act — deception); 18 U.S.C. §§ 1301-1307 (Federal lottery/mail fraud); 39 U.S.C. § 3005 (Postal lottery prohibition); State sweepstakes/contest statutes (e.g., Cal. Pen. Code § 319-332); FTC Guides Against Deceptive Advertising', ':; Official rules published before promotion start; Rules must include: eligibility, entry method, prize description/value/odds, AMNB, drawing date, sponsor; No purchase necessary alternative clearly disclosed; Winner list available upon request (where required by state); State registration/bonding filed (NY, FL, RI for prizes > threshold)', ':; S.o.C.-1: Legal review of rules before launch; prize fulfillment tracked; S.o.C.-2: Entry records, rules, and winner selection documented; retained per state requirement; S.o.C.-3: Official rules publicly accessible throughout promotion', 'Sweepstakes/contest rules');
UPDATE citizen_catalog SET standards_of_creation = ':; General Certificate of Conformity (GCC) for non-children''s products; Children''s Product Certificate (CPC) with third-party lab testing; § 15(b) reporting to CPSC within 24 hours of known substantial product hazard; Product tracking labels on children''s products per CPSIA § 103', soc_controls = ':; S.o.C.-1: Product testing records maintained; complaint tracking system; S.o.C.-2: Certificates and test reports retained 5+ years; lot/batch traceability; S.o.C.-3: § 15(b) reports filed via CPSC SaferProducts.gov' WHERE name = 'Consumer Product Safety Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-464585010464', 'Consumer Product Safety Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Consumer Product Safety Compliance Officer — CPSC (Consumer Product Safety Commission)', 'Consumer Product Safety Compliance Officer', 'CPSC (Consumer Product Safety Commission)', ':; 15 U.S.C. §§ 2051-2089 (Consumer Product Safety Act — CPSA); 15 U.S.C. §§ 1261-1278 (Federal Hazardous Substances Act); 15 U.S.C. §§ 1471-1477 (Poison Prevention Packaging Act); 16 CFR Parts 1101-1512 (CPSC Regulations); CPSIA (Consumer Product Safety Improvement Act of 2008)', ':; General Certificate of Conformity (GCC) for non-children''s products; Children''s Product Certificate (CPC) with third-party lab testing; § 15(b) reporting to CPSC within 24 hours of known substantial product hazard; Product tracking labels on children''s products per CPSIA § 103', ':; S.o.C.-1: Product testing records maintained; complaint tracking system; S.o.C.-2: Certificates and test reports retained 5+ years; lot/batch traceability; S.o.C.-3: § 15(b) reports filed via CPSC SaferProducts.gov', 'Consumer product safety (CPSC) documents, product recall notices');
UPDATE citizen_catalog SET standards_of_creation = ':; Full Report filed with CPSC within 24 hours of substantial hazard determination; Corrective Action Plan (CAP) submitted to CPSC; Consumer notification per CPSC-approved plan (press release, direct notice, social media); Monthly progress reports to CPSC during active recall', soc_controls = ':; S.o.C.-1: Recall team designated; communication plan pre-established; S.o.C.-2: Consumer response rate tracked; remedy fulfillment documented; S.o.C.-3: Recall notice on company website and CPSC.gov; retailer notification' WHERE name = 'Product Recall Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6e6c57e47601', 'Product Recall Coordinator', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Product Recall Coordinator — CPSC; FDA; NHTSA (for auto-related products)', 'Product Recall Coordinator', 'CPSC; FDA; NHTSA (for auto-related products)', ':; 15 U.S.C. § 2064 (CPSC substantial product hazard reporting); 16 CFR Part 1115 (Substantial Product Hazard Reporting); CPSC Recall Handbook; FDA 21 CFR Part 7 (FDA recall procedures); 49 U.S.C. § 30118 (NHTSA defect notification)', ':; Full Report filed with CPSC within 24 hours of substantial hazard determination; Corrective Action Plan (CAP) submitted to CPSC; Consumer notification per CPSC-approved plan (press release, direct notice, social media); Monthly progress reports to CPSC during active recall', ':; S.o.C.-1: Recall team designated; communication plan pre-established; S.o.C.-2: Consumer response rate tracked; remedy fulfillment documented; S.o.C.-3: Recall notice on company website and CPSC.gov; retailer notification', 'Product recall notices, consumer product safety documents');
UPDATE citizen_catalog SET standards_of_creation = ':; Written warranty labeled "Full" or "Limited" per Magnuson-Moss; Warranty terms disclosed pre-sale per FTC Pre-Sale Availability Rule (16 CFR § 702); Warranty document must state: what is covered, duration, how to obtain service, limitations; Disclaimer of implied warranties prohibited if written warranty provided', soc_controls = ':; S.o.C.-1: Warranty terms reviewed by legal; version control maintained; S.o.C.-2: Warranty claims tracked with resolution time; records retained per statute of limitations; S.o.C.-3: Warranty text available pre-purchase (in-store and online per 16 CFR § 702.3)' WHERE name = 'Warranty Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-522edfab4f0a', 'Warranty Compliance Specialist', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Warranty Compliance Specialist — FTC; State consumer protection agencies', 'Warranty Compliance Specialist', 'FTC; State consumer protection agencies', ':; 15 U.S.C. §§ 2301-2312 (Magnuson-Moss Warranty Act); 16 CFR Parts 700-703 (FTC Warranty Rules); UCC Article 2 §§ 2-312 through 2-318 (Implied Warranties); State lemon law statutes', ':; Written warranty labeled "Full" or "Limited" per Magnuson-Moss; Warranty terms disclosed pre-sale per FTC Pre-Sale Availability Rule (16 CFR § 702); Warranty document must state: what is covered, duration, how to obtain service, limitations; Disclaimer of implied warranties prohibited if written warranty provided', ':; S.o.C.-1: Warranty terms reviewed by legal; version control maintained; S.o.C.-2: Warranty claims tracked with resolution time; records retained per statute of limitations; S.o.C.-3: Warranty text available pre-purchase (in-store and online per 16 CFR § 702.3)', 'Warranty documents (Magnuson-Moss), lemon law documents');
UPDATE citizen_catalog SET standards_of_creation = ':; Scale/measuring device inspection certificate with calibration date; Net content declaration on packages per NIST Handbook 130; Unit pricing labels per state/local requirements; Random package inspections documented with statistical sampling', soc_controls = ':; S.o.C.-1: Device calibration schedule maintained; annual inspection; S.o.C.-2: Inspection certificates posted on devices; calibration records retained 3+ years; S.o.C.-3: Device seal/sticker visible to consumers' WHERE name = 'Weights & Measures Inspector';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4649c4301305', 'Weights & Measures Inspector', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Weights & Measures Inspector — NIST (National Institute of Standards and Technology); State Weights & Measures Divisions', 'Weights & Measures Inspector', 'NIST (National Institute of Standards and Technology); State Weights & Measures Divisions', ':; NIST Handbook 44 (Specifications, Tolerances, and Other Technical Requirements); NIST Handbook 130 (Uniform Laws and Regulations); State weights and measures statutes (e.g., Cal. Bus. & Prof. Code §§ 12001-12735); Fair Packaging and Labeling Act (15 U.S.C. §§ 1451-1461)', ':; Scale/measuring device inspection certificate with calibration date; Net content declaration on packages per NIST Handbook 130; Unit pricing labels per state/local requirements; Random package inspections documented with statistical sampling', ':; S.o.C.-1: Device calibration schedule maintained; annual inspection; S.o.C.-2: Inspection certificates posted on devices; calibration records retained 3+ years; S.o.C.-3: Device seal/sticker visible to consumers', 'Weights and measures inspection documents, unit pricing compliance');
UPDATE citizen_catalog SET standards_of_creation = ':; SAQ (Self-Assessment Questionnaire) completed annually by applicable type (A, B, C, D); ROC (Report on Compliance) for Level 1 merchants (>6M annual transactions); ASV (Approved Scanning Vendor) quarterly external scans; Penetration test annually and after significant changes', soc_controls = ':; S.o.C.-1: Cardholder data environment (CDE) segmented; access logged; S.o.C.-2: SAQ/ROC retained with acquiring bank; scan reports retained 2+ years; S.o.C.-3: Attestation of Compliance (AOC) provided to requesting parties' WHERE name = 'PCI-DSS Compliance Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-407fe945b7c0', 'PCI-DSS Compliance Analyst', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'PCI-DSS Compliance Analyst — PCI SSC (Payment Card Industry Security Standards Council)', 'PCI-DSS Compliance Analyst', 'PCI SSC (Payment Card Industry Security Standards Council)', ':; PCI-DSS v4.0 (12 Requirements); PCI PA-DSS (Payment Application); PCI P2PE (Point-to-Point Encryption); Card brand compliance programs (Visa CISP, MC SDP, Amex DSOP); State data breach notification statutes', ':; SAQ (Self-Assessment Questionnaire) completed annually by applicable type (A, B, C, D); ROC (Report on Compliance) for Level 1 merchants (>6M annual transactions); ASV (Approved Scanning Vendor) quarterly external scans; Penetration test annually and after significant changes', ':; S.o.C.-1: Cardholder data environment (CDE) segmented; access logged; S.o.C.-2: SAQ/ROC retained with acquiring bank; scan reports retained 2+ years; S.o.C.-3: Attestation of Compliance (AOC) provided to requesting parties', 'PCI-DSS compliance documents, point-of-sale records, e-commerce terms and conditions');
UPDATE citizen_catalog SET standards_of_creation = ':; Written contract for sales of goods > $500 (statute of frauds); Contract must identify: parties, quantity, description, price, delivery terms; Warranty disclaimers must be conspicuous per UCC § 2-316; Modification agreements documented (no consideration required under UCC)', soc_controls = ':; S.o.C.-1: Sales contract templates reviewed by counsel; version control; S.o.C.-2: Executed contracts retained through statute of limitations (typically 4 years per UCC § 2-725); S.o.C.-3: Contract terms provided to buyer at time of sale' WHERE name = 'UCC Article 2 Sales Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-19cc87b0194e', 'UCC Article 2 Sales Compliance Specialist', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'UCC Article 2 Sales Compliance Specialist — State legislatures (UCC adoption); ALI/NCCUSL (Uniform Law Commission)', 'UCC Article 2 Sales Compliance Specialist', 'State legislatures (UCC adoption); ALI/NCCUSL (Uniform Law Commission)', ':; UCC Article 2 (Sales) — adopted in all 50 states with variations; UCC § 2-201 (Statute of Frauds — contracts > $500); UCC § 2-302 (Unconscionability); UCC § 2-313 to 2-318 (Warranties); Cal. Com. Code §§ 2101-2725', ':; Written contract for sales of goods > $500 (statute of frauds); Contract must identify: parties, quantity, description, price, delivery terms; Warranty disclaimers must be conspicuous per UCC § 2-316; Modification agreements documented (no consideration required under UCC)', ':; S.o.C.-1: Sales contract templates reviewed by counsel; version control; S.o.C.-2: Executed contracts retained through statute of limitations (typically 4 years per UCC § 2-725); S.o.C.-3: Contract terms provided to buyer at time of sale', 'UCC Article 2 sales documents, return/refund policy documents');
UPDATE citizen_catalog SET standards_of_creation = ':; Gift card expiration no earlier than 5 years from purchase/last load (federal minimum); Inactivity fees prohibited for 12 months; fee disclosures on card or packaging; CA: no expiration on gift cards; cash back for balances < $10 (Cal. Civ. Code § 1749.5); Loyalty program terms disclosed at enrollment; material changes with notice', soc_controls = ':; S.o.C.-1: Gift card liability tracked in accounting; escheat compliance calendar; S.o.C.-2: Fee and expiration disclosures documented; program terms archived; S.o.C.-3: Balance check mechanism available to consumers' WHERE name = 'Gift Card & Loyalty Program Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-edc77da0b9d0', 'Gift Card & Loyalty Program Compliance Manager', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Gift Card & Loyalty Program Compliance Manager — FTC; CFPB; State consumer protection agencies', 'Gift Card & Loyalty Program Compliance Manager', 'FTC; CFPB; State consumer protection agencies', ':; 15 U.S.C. § 1693l-1 (CARD Act — Gift Card Provisions, Reg. E); 12 CFR Part 1005 Subpart A (Reg. E — Electronic Fund Transfers); State gift card/certificate statutes (e.g., Cal. Civ. Code § 1749.5); State unclaimed property/escheat laws', ':; Gift card expiration no earlier than 5 years from purchase/last load (federal minimum); Inactivity fees prohibited for 12 months; fee disclosures on card or packaging; CA: no expiration on gift cards; cash back for balances < $10 (Cal. Civ. Code § 1749.5); Loyalty program terms disclosed at enrollment; material changes with notice', ':; S.o.C.-1: Gift card liability tracked in accounting; escheat compliance calendar; S.o.C.-2: Fee and expiration disclosures documented; program terms archived; S.o.C.-3: Balance check mechanism available to consumers', 'Gift card/loyalty program compliance');
UPDATE citizen_catalog SET standards_of_creation = ':; Terms and conditions accessible before purchase completion; Shipping date commitments per FTC Mail Order Rule (ship within stated time or 30 days); Return/refund policy conspicuously displayed; Privacy policy per CCPA/state requirements; Sales tax collected per state nexus thresholds', soc_controls = ':; S.o.C.-1: Terms updated for legal changes; version history maintained; S.o.C.-2: Order records retained per state requirement; shipping confirmations archived; S.o.C.-3: Terms, privacy policy, return policy publicly accessible on website' WHERE name = 'E-Commerce Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-0648543c3f0d', 'E-Commerce Compliance Manager', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'E-Commerce Compliance Manager — FTC; State AGs; International (where applicable)', 'E-Commerce Compliance Manager', 'FTC; State AGs; International (where applicable)', ':; 15 U.S.C. § 45 (FTC Act); 16 CFR Part 435 (FTC Mail/Internet/Telephone Order Rule); 15 U.S.C. §§ 7001-7006 (E-SIGN Act); CAN-SPAM Act (15 U.S.C. § 7701 et seq.); CCPA/CPRA (Cal. Civ. Code §§ 1798.100 et seq.); State internet sales tax (South Dakota v. Wayfair nexus rules)', ':; Terms and conditions accessible before purchase completion; Shipping date commitments per FTC Mail Order Rule (ship within stated time or 30 days); Return/refund policy conspicuously displayed; Privacy policy per CCPA/state requirements; Sales tax collected per state nexus thresholds', ':; S.o.C.-1: Terms updated for legal changes; version history maintained; S.o.C.-2: Order records retained per state requirement; shipping confirmations archived; S.o.C.-3: Terms, privacy policy, return policy publicly accessible on website', 'E-commerce terms and conditions, return/refund policy documents, price advertising compliance');
UPDATE citizen_catalog SET standards_of_creation = ':; Dealer license posted conspicuously at each location; Buyer''s Guide (window sticker) on every used vehicle per FTC Rule; Written purchase agreement with all material terms; Financing disclosures per TILA before consumer signs', soc_controls = ':; S.o.C.-1: License renewal tracked; salesperson license roster maintained; S.o.C.-2: Deal jackets retained per state requirement (typically 5-7 years); Buyer''s Guide copy in file; S.o.C.-3: Dealer license number on all advertising' WHERE name = 'Auto Dealer Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1eb2ed48fefc', 'Auto Dealer Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Auto Dealer Compliance Officer — State DMV; State BAR (Bureau of Automotive Repair); FTC; State dealer boards', 'Auto Dealer Compliance Officer', 'State DMV; State BAR (Bureau of Automotive Repair); FTC; State dealer boards', ':; State dealer licensing statutes (e.g., Cal. Veh. Code §§ 11700-11740); Cal. Bus. & Prof. Code §§ 9880-9889.68 (BAR — Automotive Repair Act); 16 CFR Part 455 (FTC Used Motor Vehicle Trade Regulation Rule); State advertising regulations for auto dealers; TILA/Reg. Z (12 CFR Part 1026 — dealer financing disclosures)', ':; Dealer license posted conspicuously at each location; Buyer''s Guide (window sticker) on every used vehicle per FTC Rule; Written purchase agreement with all material terms; Financing disclosures per TILA before consumer signs', ':; S.o.C.-1: License renewal tracked; salesperson license roster maintained; S.o.C.-2: Deal jackets retained per state requirement (typically 5-7 years); Buyer''s Guide copy in file; S.o.C.-3: Dealer license number on all advertising', 'Auto dealer licensing (DMV/BAR), used car buyer''s guide (FTC)');
UPDATE citizen_catalog SET standards_of_creation = ':; Repair orders documenting each attempt with symptom, diagnosis, repair performed; Manufacturer notification after statutory number of repair attempts; Buyback/replacement offer letter with calculation methodology; Arbitration decision in writing with findings', soc_controls = ':; S.o.C.-1: Repair attempt tracking per VIN; escalation protocol documented; S.o.C.-2: All repair orders, correspondence, and arbitration records retained 5+ years; S.o.C.-3: Consumer informed of lemon law rights in warranty booklet' WHERE name = 'Lemon Law Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ed2e7f6e7515', 'Lemon Law Compliance Specialist', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Lemon Law Compliance Specialist — State consumer protection agencies; FTC', 'Lemon Law Compliance Specialist', 'State consumer protection agencies; FTC', ':; Magnuson-Moss Warranty Act (15 U.S.C. §§ 2301-2312); State lemon laws (e.g., Cal. Civ. Code §§ 1793.2-1793.26 — Song-Beverly Consumer Warranty Act); State used car lemon laws (where applicable); Manufacturer dispute resolution programs (16 CFR Part 703)', ':; Repair orders documenting each attempt with symptom, diagnosis, repair performed; Manufacturer notification after statutory number of repair attempts; Buyback/replacement offer letter with calculation methodology; Arbitration decision in writing with findings', ':; S.o.C.-1: Repair attempt tracking per VIN; escalation protocol documented; S.o.C.-2: All repair orders, correspondence, and arbitration records retained 5+ years; S.o.C.-3: Consumer informed of lemon law rights in warranty booklet', 'Lemon law documents, warranty documents');
UPDATE citizen_catalog SET standards_of_creation = ':; Odometer disclosure statement on title or separate form at transfer; Title brand disclosed in writing before sale; NMVTIS check performed before titling (for dealers and insurers); CARFAX/AutoCheck reports (industry practice, not legally mandated)', soc_controls = ':; S.o.C.-1: Title review process before acquisition; brand check documented; S.o.C.-2: Odometer statements retained per federal requirement (5 years); S.o.C.-3: Title brand disclosed on Buyer''s Guide or separately' WHERE name = 'Vehicle History & Title Compliance Analyst';
