INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-cbcf648fdc14', 'Anti-Doping Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Anti-Doping Compliance Officer — USADA (U.S. Anti-Doping Agency); WADA (World Anti-Doping Agency); League drug programs', 'Anti-Doping Compliance Officer', 'USADA (U.S. Anti-Doping Agency); WADA (World Anti-Doping Agency); League drug programs', ':; World Anti-Doping Code (2021); USADA Protocol for Olympic Movement Testing; League-specific Joint Drug Agreements (MLB, NFL, NBA, NHL); International Standard for Testing and Investigations (ISTI); International Standard for Laboratories (ISL); Rodchenkov Anti-Doping Act, 18 U.S.C. §§ 2401-2404', ':; Test administered per WADA chain-of-custody protocol (DCO present, sealed A/B samples); Doping Control Form (DCF) completed and signed by athlete and DCO; Laboratory analysis by WADA-accredited lab; Results Management per WADA Code Article 7; TUE (Therapeutic Use Exemption) application filed per ISTUE', ':; S.o.C.-1: Whereabouts requirements for registered testing pool; chain of custody documented; S.o.C.-2: Test results retained per WADA Code (10 years minimum; samples 10 years); S.o.C.-3: Published sanctions per WADA Code; CAS appeals public', 'Anti-doping test results (USADA/WADA), sports medicine records');
