INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-748a20c671dd', 'Concussion Protocol Compliance Manager', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Concussion Protocol Compliance Manager — League medical staffs; Independent neurological consultants; NFLPA/MLBPA medical committees', 'Concussion Protocol Compliance Manager', 'League medical staffs; Independent neurological consultants; NFLPA/MLBPA medical committees', ':; NFL/NFLPA Game Day Concussion Protocol; MLB Concussion Protocol (7-Day IL); NBA Concussion Policy; NHL Concussion Evaluation and Management Protocol; State youth concussion laws (all 50 states + DC); NCAA Concussion Safety Protocol; Berlin Consensus Statement on Concussion in Sport (2023)', ':; Baseline neurological testing documented pre-season; Sideline concussion evaluation using SCAT6 (or league equivalent); Independent neurological consultant (INC) evaluation for NFL; Return-to-play protocol documented with stepwise progression; Medical clearance in writing from team physician and (where required) independent physician', ':; S.o.C.-1: Protocol compliance monitored by league; video review for missed evaluations; S.o.C.-2: All evaluations, test results, clearance documents retained per medical records law; S.o.C.-3: Protocol publicly available; aggregate injury data reported per CBA', 'Concussion protocol documents, sports medicine records');
UPDATE citizen_catalog SET standards_of_creation = ':; Emergency Action Plan (EAP) documented and tested annually; Security staffing plan per event type and capacity; Bag check / screening procedures documented; AED placement per AHA/league guidelines; staff CPR/AED certified; Post-event incident reports filed within 24 hours', soc_controls = ':; S.o.C.-1: Annual EAP drill documented; security staff training records maintained; S.o.C.-2: Incident reports retained per statute of limitations; surveillance footage per retention policy; S.o.C.-3: Fan code of conduct posted; emergency exits clearly marked' WHERE name = 'Venue Safety & Security Compliance Director';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f6a6fff9bb99', 'Venue Safety & Security Compliance Director', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Venue Safety & Security Compliance Director — DHS (Department of Homeland Security); Local police/fire; League security offices', 'Venue Safety & Security Compliance Director', 'DHS (Department of Homeland Security); Local police/fire; League security offices', ':; DHS SAFETY Act (6 U.S.C. §§ 441-444); NFPA 101 (Life Safety Code) / NFPA 102 (Assembly Seating); ADA Title III (42 U.S.C. §§ 12181-12189); State stadium safety statutes; NCS4 (National Center for Spectator Sports Safety and Security) Best Practices; League-specific security mandates', ':; Emergency Action Plan (EAP) documented and tested annually; Security staffing plan per event type and capacity; Bag check / screening procedures documented; AED placement per AHA/league guidelines; staff CPR/AED certified; Post-event incident reports filed within 24 hours', ':; S.o.C.-1: Annual EAP drill documented; security staff training records maintained; S.o.C.-2: Incident reports retained per statute of limitations; surveillance footage per retention policy; S.o.C.-3: Fan code of conduct posted; emergency exits clearly marked', 'Venue safety/security documents, fire marshal inspection reports');
UPDATE citizen_catalog SET standards_of_creation = ':; Medical records per state medical records standards; Player medical information access limited per CBA; Injury reports per league disclosure rules (e.g., NFL injury report — questionable/doubtful/out); Pre-participation physicals documented annually; HIPAA authorization for disclosure to team (where applicable)', soc_controls = ':; S.o.C.-1: Medical records separated from personnel files; access limited to medical staff per CBA; S.o.C.-2: Records retained per state medical records retention (typically 7-10 years post-treatment); S.o.C.-3: Injury reports filed per league deadlines; public disclosure per CBA rules' WHERE name = 'Sports Medicine Records Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-df5556ce0d8f', 'Sports Medicine Records Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Sports Medicine Records Compliance Officer — State medical boards; HIPAA (HHS OCR); League medical policies', 'Sports Medicine Records Compliance Officer', 'State medical boards; HIPAA (HHS OCR); League medical policies', ':; HIPAA Privacy Rule (45 CFR Part 164) — limited applicability per entity type; State medical records privacy statutes; CBA medical provisions (team physician access, second opinion rights); State physician licensing requirements; FMLA intersections for non-player staff', ':; Medical records per state medical records standards; Player medical information access limited per CBA; Injury reports per league disclosure rules (e.g., NFL injury report — questionable/doubtful/out); Pre-participation physicals documented annually; HIPAA authorization for disclosure to team (where applicable)', ':; S.o.C.-1: Medical records separated from personnel files; access limited to medical staff per CBA; S.o.C.-2: Records retained per state medical records retention (typically 7-10 years post-treatment); S.o.C.-3: Injury reports filed per league deadlines; public disclosure per CBA rules', 'Sports medicine records, concussion protocol documents');
