INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-16c277b37da9', 'Title IX Athletic Compliance Officer', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Title IX Athletic Compliance Officer — U.S. Department of Education Office for Civil Rights (OCR)', 'Title IX Athletic Compliance Officer', 'U.S. Department of Education Office for Civil Rights (OCR)', ':; 20 U.S.C. § 1681 (Title IX of Education Amendments of 1972); 34 CFR Part 106 (OCR Title IX Regulations); 1979 Policy Interpretation (Three-Part Test for athletic participation); 1996 OCR Clarification (Three-Part Test); 2003 Further Clarification; 2024 Title IX Final Rule (updated provisions)', ':; EADA Report (Equity in Athletics Disclosure Act) filed annually; Gender equity review documented (participation, scholarships, treatment — 13 program areas); Three-Part Test analysis: proportionality, history of expansion, full accommodation; Title IX coordinator designated and publicized; Grievance procedures published', ':; S.o.C.-1: Annual gender equity assessment; budget comparison by sport/gender; S.o.C.-2: EADA reports retained 3+ years; equity analyses archived; complaint files per OCR; S.o.C.-3: EADA report publicly available; Title IX coordinator contact published', 'Title IX athletic compliance, NCAA compliance documents, athletic scholarship documents');
