INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e27b5c534309', 'Sports Arbitration & Dispute Resolution Specialist', 'Hospitality Retail Media Sports Compliance', 'Hospitality Retail Media Sports', 'Sports Arbitration & Dispute Resolution Specialist — CAS; AAA (American Arbitration Association); League arbitrators', 'Sports Arbitration & Dispute Resolution Specialist', 'CAS; AAA (American Arbitration Association); League arbitrators', ':; CAS Code of Sports-Related Arbitration; AAA Commercial Arbitration Rules (supplementary for sports); Federal Arbitration Act (9 U.S.C. §§ 1-16); CBA arbitration provisions (league-specific); New York Convention (international enforcement)', ':; Request for Arbitration filed per applicable rules and deadlines; Arbitrator selection per applicable procedure (party-appointed or list); Hearing record (transcripts, exhibits, witness statements, briefs); Written award with reasoning per applicable rules; Enforcement petition (if needed) per FAA or New York Convention', ':; S.o.C.-1: Filing deadlines tracked; case management system maintained; S.o.C.-2: Arbitration files retained per institutional rules and statute of limitations; S.o.C.-3: Published awards per applicable confidentiality rules (CAS: published with consent)', 'Sports arbitration decisions, league disciplinary documents, player contracts');
UPDATE citizen_catalog SET standards_of_creation = 'Application must include premises description, occupancy classification, fire/life safety certification, zoning confirmation, and current business tax certificate. Annual renewal with inspection clearance.', soc_controls = 'SOC 2 Type II — CC6.1 (logical/physical access to license records), CC7.2 (monitoring of license status changes), CC8.1 (change management for license conditions). Retention: permanent during operation + 7 years post-closure.' WHERE name = 'Hotel Licensing Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7a96dfd6f9ef', 'Hotel Licensing Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Hotel Licensing Compliance Officer — California Department of Public Health (CDPH); Local City/County Business License Division', 'Hotel Licensing Compliance Officer', 'California Department of Public Health (CDPH); Local City/County Business License Division', '', 'Application must include premises description, occupancy classification, fire/life safety certification, zoning confirmation, and current business tax certificate. Annual renewal with inspection clearance.', 'SOC 2 Type II — CC6.1 (logical/physical access to license records), CC7.2 (monitoring of license status changes), CC8.1 (change management for license conditions). Retention: permanent during operation + 7 years post-closure.', 'Hotel operator license documents');
UPDATE citizen_catalog SET standards_of_creation = 'Monthly/quarterly TOT returns must include: gross room receipts, exempt receipts with documentation, net taxable receipts, tax calculated at applicable rate (typically 8–15.5%), and operator certification under penalty of perjury.', soc_controls = 'SOC 2 Type II — CC6.1 (access to financial records), CC7.1 (monitoring tax filing deadlines), PI1.1 (privacy of guest financial data). Retention: 7 years per Cal. CCP § 337 (statute of limitations on tax obligations).' WHERE name = 'Transient Occupancy Tax Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4868b66c8170', 'Transient Occupancy Tax Administrator', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Transient Occupancy Tax Administrator — Local City/County Tax Collector; California State Board of Equalization', 'Transient Occupancy Tax Administrator', 'Local City/County Tax Collector; California State Board of Equalization', '', 'Monthly/quarterly TOT returns must include: gross room receipts, exempt receipts with documentation, net taxable receipts, tax calculated at applicable rate (typically 8–15.5%), and operator certification under penalty of perjury.', 'SOC 2 Type II — CC6.1 (access to financial records), CC7.1 (monitoring tax filing deadlines), PI1.1 (privacy of guest financial data). Retention: 7 years per Cal. CCP § 337 (statute of limitations on tax obligations).', 'Transient occupancy tax (TOT) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Registration card must capture: guest full legal name, home address, vehicle license plate number (where required), dates of stay, room number, number of guests. Must be completed at check-in before room key issuance.', soc_controls = 'SOC 2 Type II — CC6.1 (physical/logical access restricted), PI1.1 (privacy controls per CIV § 53.5 — no third-party disclosure without judicial process), CC9.1 (risk assessment for law enforcement requests). Retention: varies by jurisdiction, typically 90 days to 3 years.' WHERE name = 'Guest Registration Records Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ab60794fe07b', 'Guest Registration Records Manager', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Guest Registration Records Manager — Local law enforcement (per municipal ordinance); California Legislature (CIV § 53.5)', 'Guest Registration Records Manager', 'Local law enforcement (per municipal ordinance); California Legislature (CIV § 53.5)', '', 'Registration card must capture: guest full legal name, home address, vehicle license plate number (where required), dates of stay, room number, number of guests. Must be completed at check-in before room key issuance.', 'SOC 2 Type II — CC6.1 (physical/logical access restricted), PI1.1 (privacy controls per CIV § 53.5 — no third-party disclosure without judicial process), CC9.1 (risk assessment for law enforcement requests). Retention: varies by jurisdiction, typically 90 days to 3 years.', 'Hotel guest registration records');
UPDATE citizen_catalog SET standards_of_creation = 'Permit application must include: proof of primary residence (for hosted rentals), property owner consent (if renter), liability insurance certificate ($500K+ typical minimum), platform listing numbers, occupancy limits, parking plan, contact information for local responsible party.', soc_controls = 'SOC 2 Type II — CC6.1 (access control for permit records), CC7.2 (monitoring platform listing compliance against permit conditions), CC8.1 (change management when property or host changes). Retention: permit term + 5 years.' WHERE name = 'Short-Term Rental Permit Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2c4301b5017d', 'Short-Term Rental Permit Compliance Specialist', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Short-Term Rental Permit Compliance Specialist — Local Planning/Zoning Department; Local Tax Authority', 'Short-Term Rental Permit Compliance Specialist', 'Local Planning/Zoning Department; Local Tax Authority', '', 'Permit application must include: proof of primary residence (for hosted rentals), property owner consent (if renter), liability insurance certificate ($500K+ typical minimum), platform listing numbers, occupancy limits, parking plan, contact information for local responsible party.', 'SOC 2 Type II — CC6.1 (access control for permit records), CC7.2 (monitoring platform listing compliance against permit conditions), CC8.1 (change management when property or host changes). Retention: permit term + 5 years.', 'Short-term rental (STR) permit documents, home-sharing host registration');
UPDATE citizen_catalog SET standards_of_creation = 'Tax filings must reconcile platform payout reports with occupancy records. Monthly/quarterly returns with gross rental receipts, platform-remitted TOT (if applicable), operator-owed TOT balance, and sworn certification.', soc_controls = 'SOC 2 Type II — CC6.1 (financial data access), A1.2 (availability of tax records for audit), PI1.1 (guest PII protection in tax records). Retention: 7 years minimum.' WHERE name = 'Short-Term Rental Tax Compliance Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-db8670863671', 'Short-Term Rental Tax Compliance Analyst', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Short-Term Rental Tax Compliance Analyst — Local Tax Authority; Franchise Tax Board; IRS', 'Short-Term Rental Tax Compliance Analyst', 'Local Tax Authority; Franchise Tax Board; IRS', '', 'Tax filings must reconcile platform payout reports with occupancy records. Monthly/quarterly returns with gross rental receipts, platform-remitted TOT (if applicable), operator-owed TOT balance, and sworn certification.', 'SOC 2 Type II — CC6.1 (financial data access), A1.2 (availability of tax records for audit), PI1.1 (guest PII protection in tax records). Retention: 7 years minimum.', 'STR tax compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Public offering statement must include: description of timeshare plan, duration of interest, financial obligations, management company details, exchange program terms, cancellation rights, current year budget, reserve fund status, and recorded declaration of covenants.', soc_controls = 'SOC 2 Type II — CC6.1 (access to purchaser records), CC7.1 (monitoring cancellation window compliance), CC8.1 (change management for offering amendments). Retention: life of timeshare plan + 7 years.' WHERE name = 'Timeshare Disclosure Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e561df99b19e', 'Timeshare Disclosure Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Timeshare Disclosure Compliance Officer — California Department of Real Estate (DRE); Federal Trade Commission (FTC)', 'Timeshare Disclosure Compliance Officer', 'California Department of Real Estate (DRE); Federal Trade Commission (FTC)', '', 'Public offering statement must include: description of timeshare plan, duration of interest, financial obligations, management company details, exchange program terms, cancellation rights, current year budget, reserve fund status, and recorded declaration of covenants.', 'SOC 2 Type II — CC6.1 (access to purchaser records), CC7.1 (monitoring cancellation window compliance), CC8.1 (change management for offering amendments). Retention: life of timeshare plan + 7 years.', 'Timeshare disclosure documents, resort fee disclosure documents');
UPDATE citizen_catalog SET standards_of_creation = 'Inspection report must document: date, inspector credentials, property address, occupancy classification, fire alarm system test results, sprinkler system status, means of egress adequacy, emergency lighting, fire extinguisher placement/inspection dates, kitchen hood suppression, fire department connection accessibility. Pass/fail determination with violation timeline.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring inspection schedules), CC8.1 (change management for fire system modifications), CC3.2 (communication of deficiencies to management). Retention: life of structure + 10 years.' WHERE name = 'Fire Marshal — Hospitality Division';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-0736527e8f44', 'Fire Marshal — Hospitality Division', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Fire Marshal — Hospitality Division — California State Fire Marshal (OSFM); Local Fire Authority Having Jurisdiction (AHJ)', 'Fire Marshal — Hospitality Division', 'California State Fire Marshal (OSFM); Local Fire Authority Having Jurisdiction (AHJ)', '', 'Inspection report must document: date, inspector credentials, property address, occupancy classification, fire alarm system test results, sprinkler system status, means of egress adequacy, emergency lighting, fire extinguisher placement/inspection dates, kitchen hood suppression, fire department connection accessibility. Pass/fail determination with violation timeline.', 'SOC 2 Type II — CC7.2 (monitoring inspection schedules), CC8.1 (change management for fire system modifications), CC3.2 (communication of deficiencies to management). Retention: life of structure + 10 years.', 'Fire marshal inspection documents');
UPDATE citizen_catalog SET standards_of_creation = 'Inspection certificate must include: conveyance ID, type (hydraulic/traction/escalator), inspection date, inspector QEI certification number, test results (safety devices, door restrictors, overspeed governors, buffers, emergency communications), load test date (if applicable), permit number, next inspection due date. Certificate must be posted in conveyance.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring inspection/permit expiration), CC8.1 (change management for modifications requiring new permit per Lab. Code § 7301.1), CC6.1 (access control for inspection records). Retention: life of conveyance + 5 years.' WHERE name = 'Certified Elevator Inspector';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b4f5bb6ee8e5', 'Certified Elevator Inspector', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Certified Elevator Inspector — California Division of Occupational Safety and Health (Cal/OSHA) — Elevator Unit', 'Certified Elevator Inspector', 'California Division of Occupational Safety and Health (Cal/OSHA) — Elevator Unit', '', 'Inspection certificate must include: conveyance ID, type (hydraulic/traction/escalator), inspection date, inspector QEI certification number, test results (safety devices, door restrictors, overspeed governors, buffers, emergency communications), load test date (if applicable), permit number, next inspection due date. Certificate must be posted in conveyance.', 'SOC 2 Type II — CC7.2 (monitoring inspection/permit expiration), CC8.1 (change management for modifications requiring new permit per Lab. Code § 7301.1), CC6.1 (access control for inspection records). Retention: life of conveyance + 5 years.', 'Elevator/escalator inspection certificates');
UPDATE citizen_catalog SET standards_of_creation = 'Comprehensive safety inspection report covering: structural integrity, electrical systems, plumbing, HVAC, emergency systems, stairwell condition, balcony/railing safety, seismic retrofit compliance, carbon monoxide detection (per HSC § 17926), smoke detection. Must cross-reference all open code violations.', soc_controls = 'SOC 2 Type II — CC7.1 (monitoring remediation timelines for violations), CC3.2 (communication of material deficiencies), CC8.1 (change management for structural modifications). Retention: life of structure.' WHERE name = 'Hotel Safety Inspection Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b9b2e22ffb62', 'Hotel Safety Inspection Coordinator', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Hotel Safety Inspection Coordinator — California Division of the State Architect (DSA); Local Building Department; Cal/OSHA', 'Hotel Safety Inspection Coordinator', 'California Division of the State Architect (DSA); Local Building Department; Cal/OSHA', '', 'Comprehensive safety inspection report covering: structural integrity, electrical systems, plumbing, HVAC, emergency systems, stairwell condition, balcony/railing safety, seismic retrofit compliance, carbon monoxide detection (per HSC § 17926), smoke detection. Must cross-reference all open code violations.', 'SOC 2 Type II — CC7.1 (monitoring remediation timelines for violations), CC3.2 (communication of material deficiencies), CC8.1 (change management for structural modifications). Retention: life of structure.', 'Hotel safety inspection documents');
UPDATE citizen_catalog SET standards_of_creation = 'Health permit application and inspection reports must include: water chemistry results (pH, chlorine/bromine levels, cyanuric acid, alkalinity, TDS), circulation system adequacy, drain cover compliance (VGBA), safety equipment inventory (ring buoys, shepherd''s hooks), depth markers, fencing/barrier compliance, CPR signage, emergency telephone, ADA accessibility for pool entry. Operating permit must be posted.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring daily water chemistry logs), CC7.1 (monitoring permit renewal deadlines), CC3.2 (communication of health code violations). Retention: 5 years minimum (daily logs); permit life + 3 years.' WHERE name = 'Environmental Health Specialist — Aquatic Facilities';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-d91502f468d1', 'Environmental Health Specialist — Aquatic Facilities', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Environmental Health Specialist — Aquatic Facilities — California Department of Public Health (CDPH); Local Environmental Health Department', 'Environmental Health Specialist — Aquatic Facilities', 'California Department of Public Health (CDPH); Local Environmental Health Department', '', 'Health permit application and inspection reports must include: water chemistry results (pH, chlorine/bromine levels, cyanuric acid, alkalinity, TDS), circulation system adequacy, drain cover compliance (VGBA), safety equipment inventory (ring buoys, shepherd''s hooks), depth markers, fencing/barrier compliance, CPR signage, emergency telephone, ADA accessibility for pool entry. Operating permit must be posted.', 'SOC 2 Type II — CC7.2 (monitoring daily water chemistry logs), CC7.1 (monitoring permit renewal deadlines), CC3.2 (communication of health code violations). Retention: 5 years minimum (daily logs); permit life + 3 years.', 'Pool/spa health permits');
UPDATE citizen_catalog SET standards_of_creation = 'Compliance documentation must include: CO detector installation locations (per room requirements), detector model/UL listing, installation date, battery replacement schedule, testing log, and integration with fire alarm system (if centrally monitored).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring testing schedule compliance), CC8.1 (change management for detector replacement). Retention: 5 years or life of device installation.' WHERE name = 'Carbon Monoxide and Gas Safety Compliance Inspector';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-186bff1dade4', 'Carbon Monoxide and Gas Safety Compliance Inspector', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Carbon Monoxide and Gas Safety Compliance Inspector — California State Fire Marshal; Local Fire AHJ; California Energy Commission', 'Carbon Monoxide and Gas Safety Compliance Inspector', 'California State Fire Marshal; Local Fire AHJ; California Energy Commission', '', 'Compliance documentation must include: CO detector installation locations (per room requirements), detector model/UL listing, installation date, battery replacement schedule, testing log, and integration with fire alarm system (if centrally monitored).', 'SOC 2 Type II — CC7.2 (monitoring testing schedule compliance), CC8.1 (change management for detector replacement). Retention: 5 years or life of device installation.', 'Hotel safety inspection documents (CO component)');
UPDATE citizen_catalog SET standards_of_creation = 'Bedbug compliance documentation must include: proactive inspection logs (frequency per local ordinance), treatment records from licensed pest control operator (Branch 2 license), pesticide application records (per Cal. Food & Agric. Code § 12973), guest notification templates (when infestation discovered), room quarantine protocols, post-treatment clearance reports, and disclosure to prospective guests of treatment history (per local ordinance).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring inspection frequency), CC3.2 (communication protocols for guest notification), CC8.1 (change management for treatment protocols). Retention: 3 years (pest control records per Cal. Food & Agric. Code § 12973); disclosure records 5 years.' WHERE name = 'Integrated Pest Management Compliance Officer — Lodging';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-45cbc47d8519', 'Integrated Pest Management Compliance Officer — Lodging', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Integrated Pest Management Compliance Officer — Lodging — California Structural Pest Control Board (SPCB); Local Health Department', 'Integrated Pest Management Compliance Officer — Lodging', 'California Structural Pest Control Board (SPCB); Local Health Department', '', 'Bedbug compliance documentation must include: proactive inspection logs (frequency per local ordinance), treatment records from licensed pest control operator (Branch 2 license), pesticide application records (per Cal. Food & Agric. Code § 12973), guest notification templates (when infestation discovered), room quarantine protocols, post-treatment clearance reports, and disclosure to prospective guests of treatment history (per local ordinance).', 'SOC 2 Type II — CC7.2 (monitoring inspection frequency), CC3.2 (communication protocols for guest notification), CC8.1 (change management for treatment protocols). Retention: 3 years (pest control records per Cal. Food & Agric. Code § 12973); disclosure records 5 years.', 'Bedbug disclosure/treatment documents');
UPDATE citizen_catalog SET standards_of_creation = 'Health permits, inspection reports, HACCP plans (where required), food handler certifications for all staff, temperature logs, equipment maintenance records. Permit must be posted in conspicuous location.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring health inspection schedule), CC7.1 (monitoring corrective action deadlines), CC3.2 (communication of critical violations). Retention: 3 years (inspection records); active + 1 year (handler certifications).' WHERE name = 'Certified Food Safety Manager — Hospitality';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-20ee83484b8d', 'Certified Food Safety Manager — Hospitality', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Certified Food Safety Manager — Hospitality — California Department of Public Health; Local Environmental Health', 'Certified Food Safety Manager — Hospitality', 'California Department of Public Health; Local Environmental Health', '', 'Health permits, inspection reports, HACCP plans (where required), food handler certifications for all staff, temperature logs, equipment maintenance records. Permit must be posted in conspicuous location.', 'SOC 2 Type II — CC7.2 (monitoring health inspection schedule), CC7.1 (monitoring corrective action deadlines), CC3.2 (communication of critical violations). Retention: 3 years (inspection records); active + 1 year (handler certifications).', 'Hotel food service health permits (part of hotel safety inspection documents)');
UPDATE citizen_catalog SET standards_of_creation = 'IIPP must include: responsible person designation, hazard identification procedures, training documentation (initial + annual), safety data sheets (SDS) for all chemicals used, personal protective equipment (PPE) assessment and provision records, ergonomic evaluation for repetitive tasks (lifting, bending, reaching), incident/injury logs (OSHA 300/300A).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring training compliance), CC6.1 (access control for SDS library), CC3.2 (communication of workplace injuries). Retention: IIPP — active + 3 years; SDS — indefinite; injury logs — 5 years (per 29 CFR § 1904.33).' WHERE name = 'Housekeeping Safety Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-58d2aa183aed', 'Housekeeping Safety Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Housekeeping Safety Compliance Officer — Cal/OSHA; California Department of Pesticide Regulation (for antimicrobials)', 'Housekeeping Safety Compliance Officer', 'Cal/OSHA; California Department of Pesticide Regulation (for antimicrobials)', '', 'IIPP must include: responsible person designation, hazard identification procedures, training documentation (initial + annual), safety data sheets (SDS) for all chemicals used, personal protective equipment (PPE) assessment and provision records, ergonomic evaluation for repetitive tasks (lifting, bending, reaching), incident/injury logs (OSHA 300/300A).', 'SOC 2 Type II — CC7.2 (monitoring training compliance), CC6.1 (access control for SDS library), CC3.2 (communication of workplace injuries). Retention: IIPP — active + 3 years; SDS — indefinite; injury logs — 5 years (per 29 CFR § 1904.33).', 'Housekeeping safety compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Water management plan must include: risk assessment of all water systems, monitoring points with temperature and disinfectant residual targets, remediation protocols, documentation of routine monitoring, and annual program review.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring sampling schedule), CC8.1 (change management for system modifications), CC3.2 (communication of positive test results). Retention: 5 years minimum.' WHERE name = 'Water Management Program Manager — Hospitality';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-aaf265b484a5', 'Water Management Program Manager — Hospitality', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Water Management Program Manager — Hospitality — ASHRAE; CDC; Local Health Department', 'Water Management Program Manager — Hospitality', 'ASHRAE; CDC; Local Health Department', '', 'Water management plan must include: risk assessment of all water systems, monitoring points with temperature and disinfectant residual targets, remediation protocols, documentation of routine monitoring, and annual program review.', 'SOC 2 Type II — CC7.2 (monitoring sampling schedule), CC8.1 (change management for system modifications), CC3.2 (communication of positive test results). Retention: 5 years minimum.', 'Hotel safety inspection documents (water safety component)');
UPDATE citizen_catalog SET standards_of_creation = 'Privacy program documentation must include: data inventory/mapping (all guest PII categories per CIV § 53.5(c): name, SSN, DOB, birthplace, address, phone, DL number, credit card number, auto plate number), privacy notice (CCPA compliant), data subject access request (DSAR) procedures, vendor data processing agreements, data retention schedule, breach response plan, law enforcement request protocol (CIV § 53.5 requires judicial process — no administrative requests honored).', soc_controls = 'SOC 2 Type II — CC6.1 (access controls for guest PII), PI1.1–PI1.5 (full Privacy criteria), CC6.6 (boundary protection for PCI environment), CC7.2 (monitoring for unauthorized access). Retention: per data category — active stay + minimum necessary period; breach records 5 years.' WHERE name = 'Data Protection Officer — Hospitality';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1e73af80c334', 'Data Protection Officer — Hospitality', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Data Protection Officer — Hospitality — California Attorney General (CCPA/CPRA enforcement); FTC', 'Data Protection Officer — Hospitality', 'California Attorney General (CCPA/CPRA enforcement); FTC', '', 'Privacy program documentation must include: data inventory/mapping (all guest PII categories per CIV § 53.5(c): name, SSN, DOB, birthplace, address, phone, DL number, credit card number, auto plate number), privacy notice (CCPA compliant), data subject access request (DSAR) procedures, vendor data processing agreements, data retention schedule, breach response plan, law enforcement request protocol (CIV § 53.5 requires judicial process — no administrative requests honored).', 'SOC 2 Type II — CC6.1 (access controls for guest PII), PI1.1–PI1.5 (full Privacy criteria), CC6.6 (boundary protection for PCI environment), CC7.2 (monitoring for unauthorized access). Retention: per data category — active stay + minimum necessary period; breach records 5 years.', 'Guest privacy/data protection documents');
UPDATE citizen_catalog SET standards_of_creation = 'Compliance documentation must include: CASp (Certified Access Specialist) inspection report, accessible room inventory (per 28 CFR § 36.302(e) — mobility vs. communication features), accessible path of travel documentation, barrier removal log (for existing facilities), reservation system configuration ensuring accessible room blocking, website accessibility audit (WCAG 2.1 AA), and public accommodations policy.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring barrier removal progress), CC8.1 (change management for renovations), CC3.2 (communication of ADA complaint response). Retention: CASp reports — indefinite; barrier removal records — permanent.' WHERE name = 'ADA Accessibility Compliance Specialist — Lodging';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f1b294ae6b66', 'ADA Accessibility Compliance Specialist — Lodging', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'ADA Accessibility Compliance Specialist — Lodging — U.S. Department of Justice — Civil Rights Division; California Division of the State Architect (DSA)', 'ADA Accessibility Compliance Specialist — Lodging', 'U.S. Department of Justice — Civil Rights Division; California Division of the State Architect (DSA)', '', 'Compliance documentation must include: CASp (Certified Access Specialist) inspection report, accessible room inventory (per 28 CFR § 36.302(e) — mobility vs. communication features), accessible path of travel documentation, barrier removal log (for existing facilities), reservation system configuration ensuring accessible room blocking, website accessibility audit (WCAG 2.1 AA), and public accommodations policy.', 'SOC 2 Type II — CC7.2 (monitoring barrier removal progress), CC8.1 (change management for renovations), CC3.2 (communication of ADA complaint response). Retention: CASp reports — indefinite; barrier removal records — permanent.', 'ADA accessibility compliance (lodging) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Required posted notices (per CIV § 1863), safe/vault availability notice, claims intake forms documenting: guest identity, property description, claimed value, circumstances of loss/damage, photographs, witness statements. Lien enforcement documents per CIV § 1861 (requires final judgment before enforcement). Eviction notice per CIV § 1865(c)(1) (signed by guest at check-in).', soc_controls = 'SOC 2 Type II — CC6.1 (access to claims records), CC3.2 (communication of claims status), CC9.1 (risk mitigation for property claims). Retention: claim records — statute of limitations + 3 years (minimum 7 years); lien records — until resolved + 5 years.' WHERE name = 'Innkeeper''s Liability Claims Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e744ab004c73', 'Innkeeper''s Liability Claims Manager', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Innkeeper''s Liability Claims Manager — California Legislature (Civil Code); Courts (case law)', 'Innkeeper''s Liability Claims Manager', 'California Legislature (Civil Code); Courts (case law)', '', 'Required posted notices (per CIV § 1863), safe/vault availability notice, claims intake forms documenting: guest identity, property description, claimed value, circumstances of loss/damage, photographs, witness statements. Lien enforcement documents per CIV § 1861 (requires final judgment before enforcement). Eviction notice per CIV § 1865(c)(1) (signed by guest at check-in).', 'SOC 2 Type II — CC6.1 (access to claims records), CC3.2 (communication of claims status), CC9.1 (risk mitigation for property claims). Retention: claim records — statute of limitations + 3 years (minimum 7 years); lien records — until resolved + 5 years.', 'Innkeeper''s liability documents, guest property loss/damage documents, hotel lien documents');
UPDATE citizen_catalog SET standards_of_creation = 'All advertised prices must include mandatory resort/destination/amenity fees (per SB 478 effective July 1, 2024). Disclosure documentation must include: itemized fee breakdown, services included in fee, fee amount displayed with equal or greater prominence as room rate, booking confirmation with total all-in price, and opt-out confirmation for optional fees.', soc_controls = 'SOC 2 Type II — CC3.2 (communication accuracy in advertising), CC7.2 (monitoring advertising compliance across channels), CC8.1 (change management for fee structure modifications). Retention: advertising materials 5 years; consumer complaints 5 years.' WHERE name = 'Resort Fee / Mandatory Fee Disclosure Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f6ef1f3f9041', 'Resort Fee / Mandatory Fee Disclosure Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Resort Fee / Mandatory Fee Disclosure Officer — Federal Trade Commission (FTC); California Attorney General', 'Resort Fee / Mandatory Fee Disclosure Officer', 'Federal Trade Commission (FTC); California Attorney General', '', 'All advertised prices must include mandatory resort/destination/amenity fees (per SB 478 effective July 1, 2024). Disclosure documentation must include: itemized fee breakdown, services included in fee, fee amount displayed with equal or greater prominence as room rate, booking confirmation with total all-in price, and opt-out confirmation for optional fees.', 'SOC 2 Type II — CC3.2 (communication accuracy in advertising), CC7.2 (monitoring advertising compliance across channels), CC8.1 (change management for fee structure modifications). Retention: advertising materials 5 years; consumer complaints 5 years.', 'Resort fee disclosure documents');
UPDATE citizen_catalog SET standards_of_creation = 'Insurance portfolio documentation must include: commercial general liability (CGL) policy ($1M/$2M minimum typical), property insurance, business interruption, workers'' compensation certificate, umbrella/excess liability, liquor liability (if applicable), cyber liability, terrorism coverage (TRIA), certificates of insurance for all subcontractors. Additional insured endorsements for franchisors, management companies, and property owners.', soc_controls = 'SOC 2 Type II — CC9.1 (risk assessment and insurance adequacy), CC6.1 (access to policy documents), CC7.2 (monitoring policy renewal and coverage gaps). Retention: policy period + statute of limitations (10+ years for bodily injury).' WHERE name = 'Hospitality Risk & Insurance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7cbb9bca7e0a', 'Hospitality Risk & Insurance Manager', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Hospitality Risk & Insurance Manager — California Department of Insurance (CDI); ISO (Insurance Services Office)', 'Hospitality Risk & Insurance Manager', 'California Department of Insurance (CDI); ISO (Insurance Services Office)', '', 'Insurance portfolio documentation must include: commercial general liability (CGL) policy ($1M/$2M minimum typical), property insurance, business interruption, workers'' compensation certificate, umbrella/excess liability, liquor liability (if applicable), cyber liability, terrorism coverage (TRIA), certificates of insurance for all subcontractors. Additional insured endorsements for franchisors, management companies, and property owners.', 'SOC 2 Type II — CC9.1 (risk assessment and insurance adequacy), CC6.1 (access to policy documents), CC7.2 (monitoring policy renewal and coverage gaps). Retention: policy period + statute of limitations (10+ years for bodily injury).', 'Hotel liability/insurance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Training program documentation must include: curriculum meeting all § 12950.3(c) requirements, training delivery records (date, duration, trainer credentials, attendees), new hire training within 6 months of employment, biennial refresher schedule, training acknowledgment forms signed by each employee, posting of National Human Trafficking Hotline information.', soc_controls = 'SOC 2 Type II — CC1.4 (training obligation management), CC7.2 (monitoring training completion rates and deadlines), CC3.2 (communication of reporting procedures). Retention: training records — duration of employment + 5 years.' WHERE name = 'Human Trafficking Prevention Compliance Officer — Hospitality';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3e899b1a1e2d', 'Human Trafficking Prevention Compliance Officer — Hospitality', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Human Trafficking Prevention Compliance Officer — Hospitality — California Department of Fair Employment and Housing (now Civil Rights Department — CRD)', 'Human Trafficking Prevention Compliance Officer — Hospitality', 'California Department of Fair Employment and Housing (now Civil Rights Department — CRD)', '', 'Training program documentation must include: curriculum meeting all § 12950.3(c) requirements, training delivery records (date, duration, trainer credentials, attendees), new hire training within 6 months of employment, biennial refresher schedule, training acknowledgment forms signed by each employee, posting of National Human Trafficking Hotline information.', 'SOC 2 Type II — CC1.4 (training obligation management), CC7.2 (monitoring training completion rates and deadlines), CC3.2 (communication of reporting procedures). Retention: training records — duration of employment + 5 years.', 'Human trafficking awareness compliance (SB 970) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Compliance documentation must include: workload standards (e.g., maximum square footage per shift — LA requires 4,000 sq ft), room cleaning time tracking, overtime authorization records, meal/rest break documentation, recall rights after layoff (by seniority), retention of workers upon property sale/transfer (where mandated), annual compliance certification to enforcing agency.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring workload compliance), CC1.4 (training on worker rights), CC3.2 (communication of complaint procedures to workers). Retention: payroll/workload records 4 years (per Cal. Labor Code § 1174).' WHERE name = 'Hotel Worker Protection Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-bc5bafd60367', 'Hotel Worker Protection Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Hotel Worker Protection Compliance Officer — Local City Labor Standards Enforcement (e.g., LA Bureau of Contract Administration; Long Beach; Oakland; Santa Monica)', 'Hotel Worker Protection Compliance Officer', 'Local City Labor Standards Enforcement (e.g., LA Bureau of Contract Administration; Long Beach; Oakland; Santa Monica)', '', 'Compliance documentation must include: workload standards (e.g., maximum square footage per shift — LA requires 4,000 sq ft), room cleaning time tracking, overtime authorization records, meal/rest break documentation, recall rights after layoff (by seniority), retention of workers upon property sale/transfer (where mandated), annual compliance certification to enforcing agency.', 'SOC 2 Type II — CC7.2 (monitoring workload compliance), CC1.4 (training on worker rights), CC3.2 (communication of complaint procedures to workers). Retention: payroll/workload records 4 years (per Cal. Labor Code § 1174).', 'Hotel worker protection ordinance compliance (local) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Compliance documentation must include: device procurement records (model, vendor, signal type), device assignment log (one device per worker per shift), testing/maintenance records (monthly minimum), signal coverage mapping (all guest rooms and work areas), response protocol (timed response with security dispatch), incident log (every activation with investigation notes), anti-retaliation policy posted and acknowledged.', soc_controls = 'SOC 2 Type II — CC6.1 (access to incident records — confidential), CC7.2 (monitoring device functionality and coverage), CC3.2 (communication of response protocols). Retention: device records 3 years; incident records 5 years minimum.' WHERE name = 'Employee Personal Safety Device Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7a760e100ed2', 'Employee Personal Safety Device Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Employee Personal Safety Device Compliance Officer — Local City Labor Standards (ordinance-specific)', 'Employee Personal Safety Device Compliance Officer', 'Local City Labor Standards (ordinance-specific)', '', 'Compliance documentation must include: device procurement records (model, vendor, signal type), device assignment log (one device per worker per shift), testing/maintenance records (monthly minimum), signal coverage mapping (all guest rooms and work areas), response protocol (timed response with security dispatch), incident log (every activation with investigation notes), anti-retaliation policy posted and acknowledged.', 'SOC 2 Type II — CC6.1 (access to incident records — confidential), CC7.2 (monitoring device functionality and coverage), CC3.2 (communication of response protocols). Retention: device records 3 years; incident records 5 years minimum.', 'Hotel employee panic button compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'WVPP must include: responsible person designation, employee participation mechanism, workplace violence hazard identification/assessment, incident reporting procedures, emergency response procedures, post-incident procedures, training records (initial + annual), violent incident log (separate from OSHA 300).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring plan review schedule — annual minimum), CC1.4 (training completion tracking), CC3.2 (communication of emergency procedures). Retention: WVPP — active + 5 years; incident logs — 5 years; training records — employment + 3 years.' WHERE name = 'Workplace Violence Prevention Plan Manager — Hospitality';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7f0a9dfd4126', 'Workplace Violence Prevention Plan Manager — Hospitality', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Workplace Violence Prevention Plan Manager — Hospitality — Cal/OSHA; California Legislature', 'Workplace Violence Prevention Plan Manager — Hospitality', 'Cal/OSHA; California Legislature', '', 'WVPP must include: responsible person designation, employee participation mechanism, workplace violence hazard identification/assessment, incident reporting procedures, emergency response procedures, post-incident procedures, training records (initial + annual), violent incident log (separate from OSHA 300).', 'SOC 2 Type II — CC7.2 (monitoring plan review schedule — annual minimum), CC1.4 (training completion tracking), CC3.2 (communication of emergency procedures). Retention: WVPP — active + 5 years; incident logs — 5 years; training records — employment + 3 years.', 'Housekeeping safety compliance documents (violence prevention component)');
UPDATE citizen_catalog SET standards_of_creation = 'Payroll records per Cal. Labor Code § 1174: employee name, address, SSN, occupation, hours worked daily, wages paid each pay period, deductions, piece rate (if applicable). Wage statements per § 226 with nine specific items. Wage theft notice per § 2810.5 at hire.', soc_controls = 'SOC 2 Type II — CC6.1 (access to payroll records), CC7.2 (monitoring pay period compliance), PI1.1 (employee PII protection). Retention: payroll records 4 years; wage statements 3 years.' WHERE name = 'Hospitality Wage & Hour Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9cbc6e44eabd', 'Hospitality Wage & Hour Compliance Specialist', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Hospitality Wage & Hour Compliance Specialist — California Labor Commissioner (DLSE); U.S. Department of Labor WHD', 'Hospitality Wage & Hour Compliance Specialist', 'California Labor Commissioner (DLSE); U.S. Department of Labor WHD', '', 'Payroll records per Cal. Labor Code § 1174: employee name, address, SSN, occupation, hours worked daily, wages paid each pay period, deductions, piece rate (if applicable). Wage statements per § 226 with nine specific items. Wage theft notice per § 2810.5 at hire.', 'SOC 2 Type II — CC6.1 (access to payroll records), CC7.2 (monitoring pay period compliance), PI1.1 (employee PII protection). Retention: payroll records 4 years; wage statements 3 years.', 'Hotel worker protection ordinance compliance documents (wage component)');
UPDATE citizen_catalog SET standards_of_creation = 'FDD with all 23 required Items per 16 CFR § 436.5 (including Item 19 financial performance representations, Item 20 franchisee information, Item 21 financial statements). Franchise agreement with brand standard compliance provisions. Property Improvement Plan (PIP) documentation. Quality assurance (QA) inspection reports per brand standard schedule.', soc_controls = 'SOC 2 Type II — CC6.1 (access to franchise proprietary information), CC7.2 (monitoring QA inspection schedule), CC8.1 (change management for brand standard updates), CC3.2 (communication of PIP deadlines). Retention: FDD — 7 years after offering; franchise agreement — term + 10 years; QA reports — 5 years.' WHERE name = 'Hotel Franchise Compliance Auditor';
