UPDATE citizen_catalog SET standards_of_creation = 'Rating application documentation, self-assessment against applicable criteria, mystery shopper/evaluator reports, corrective action plans for deficiencies, staff training records for service standards, guest satisfaction survey results and trend analysis, physical product maintenance schedules aligned to rating criteria.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring inspection/evaluation schedule), CC8.1 (change management for standard updates), CC3.2 (communication of rating changes). Retention: evaluation reports — 5 years; corrective actions — until resolved + 3 years.' WHERE name = 'Hotel Quality / Star-Diamond Rating Compliance Manager';
