UPDATE citizen_catalog SET standards_of_creation = 'Monthly owner reports per USALI format, annual budget approval documentation, capital expenditure approval records, operator performance benchmarking (RevPAR index, GOP margin), key money/incentive fee calculations, insurance compliance certificates, brand standard compliance verification.', soc_controls = 'SOC 2 Type II — CC6.1 (access to financial records — owner/operator separation), CC7.2 (monitoring reporting deadlines), CC3.2 (communication of material operational changes). Retention: HMA term + 7 years; financial reports 7 years.' WHERE name = 'Hotel Management Agreement (HMA) Compliance Officer';
