UPDATE citizen_catalog SET standards_of_creation = 'Host registration documentation must include: proof of primary residence (utility bills, voter registration, tax return), property owner authorization (if tenant-host), platform listing URL(s), liability insurance confirmation, emergency contact information, neighbor notification (where required), annual certification of continued eligibility.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring annual renewal and night-cap compliance), CC6.1 (access to registration records), CC3.2 (communication of violations to enforcement). Retention: registration period + 3 years.' WHERE name = 'Home-Sharing Host Registration Coordinator';
