UPDATE citizen_catalog SET standards_of_creation = 'Safety inspection checklist documenting: working smoke detector(s) in each bedroom and hallway, CO detector(s) per HSC § 17926, fire extinguisher (accessible, inspected), emergency egress (windows operable, path clear), pool barrier (if applicable), maximum occupancy posting, emergency information card (fire/police/hospital), first aid kit.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring annual inspection compliance), CC8.1 (change management for property modifications). Retention: inspection records — permit life + 3 years.' WHERE name = 'Short-Term Rental Safety Inspector';
