UPDATE citizen_catalog SET standards_of_creation = 'Property management agreement, DRE license verification, trust account records for guest deposits/owner disbursements, maintenance and repair logs, vendor management documentation, insurance verification per property, tax remittance records.', soc_controls = 'SOC 2 Type II — CC6.1 (access to financial trust records), CC7.2 (monitoring license renewal), CC9.1 (risk assessment per property). Retention: trust records 5 years; management agreements — term + 5 years.' WHERE name = 'Vacation Rental Property Manager — Regulatory Compliance';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5074fe7df002', 'Vacation Rental Property Manager — Regulatory Compliance', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Vacation Rental Property Manager — Regulatory Compliance — California Department of Real Estate (DRE); Local enforcement', 'Vacation Rental Property Manager — Regulatory Compliance', 'California Department of Real Estate (DRE); Local enforcement', '', 'Property management agreement, DRE license verification, trust account records for guest deposits/owner disbursements, maintenance and repair logs, vendor management documentation, insurance verification per property, tax remittance records.', 'SOC 2 Type II — CC6.1 (access to financial trust records), CC7.2 (monitoring license renewal), CC9.1 (risk assessment per property). Retention: trust records 5 years; management agreements — term + 5 years.', 'Short-term rental (STR) permit documents (management component)');
UPDATE citizen_catalog SET standards_of_creation = 'Environmental compliance documentation: Proposition 65 warnings posted, hazardous waste generator records, organic waste diversion plan per SB 1383, water conservation plan, energy benchmarking reports (per local ordinances — e.g., LA Existing Buildings Energy & Water Efficiency Ordinance), sustainability certification audit reports.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring regulatory filing deadlines), CC8.1 (change management for chemical inventory), CC3.2 (communication of environmental incidents). Retention: hazardous waste records — 3 years (per 22 CCR § 66262.40); energy reports — 5 years.' WHERE name = 'Hospitality Environmental Compliance Officer';
