UPDATE citizen_catalog SET standards_of_creation = 'Annual energy benchmarking report via ENERGY STAR Portfolio Manager, submission to local jurisdiction by deadline (typically April/June), disclosure to prospective buyers/tenants (where mandated), energy audit (per ASHRAE Level 1/2/3 where required).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring filing deadlines), CC6.1 (access to utility account data). Retention: benchmarking reports — 5 years; energy audits — 10 years.' WHERE name = 'Energy Benchmarking Compliance Officer — Hospitality';
