UPDATE citizen_catalog SET standards_of_creation = 'License application/renewal documentation, RBS certification for all servers (within 60 days of hire per AB 1221), LEAD (Licensee Education on Alcohol and Drugs) training records, responsible beverage service policy, incident log (intoxicated persons, minors, disturbances), license posted conspicuously per BPC § 24046.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring RBS certification deadlines), CC1.4 (training compliance), CC3.2 (communication of ABC discipline). Retention: license records — active + 7 years; training records — employment + 3 years; incident logs — 5 years.' WHERE name = 'Alcohol Beverage Control Compliance Manager — Hospitality';
