UPDATE citizen_catalog SET standards_of_creation = 'Seismic evaluation report (ASCE 41 Tier 1/2/3), retrofit design documents (if required), engineering certification of compliance, permit records, retrofit completion certificate, mandatory disclosure to guests (if in non-compliant URM building per local ordinance).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring retrofit deadlines), CC8.1 (change management for structural modifications), CC3.2 (communication of seismic risk status). Retention: permanent.' WHERE name = 'Seismic Retrofit Compliance Officer — Hotel/Lodging';
