UPDATE citizen_catalog SET standards_of_creation = 'PCI DSS Self-Assessment Questionnaire (SAQ) or Report on Compliance (ROC), network segmentation documentation, vulnerability scan results (quarterly ASV scans), penetration test reports (annual), incident response plan, data flow diagrams for cardholder data environment (CDE), vendor compliance attestations (POS vendor, payment processor, WiFi provider).', soc_controls = 'SOC 2 Type II — CC6.1 (logical access controls), CC6.6 (boundary protection), CC6.8 (vulnerability management), CC7.1 (intrusion detection), CC7.2 (monitoring), CC7.3 (evaluation of security events). Retention: PCI evidence — 1 year minimum; breach records — 5 years; scan results — 3 years.' WHERE name = 'Hospitality Cybersecurity & POS Compliance Officer';
