UPDATE citizen_catalog SET standards_of_creation = 'Reservation system configuration documentation proving: accessible room types are bookable by feature (mobility, hearing, both), rooms held until all standard rooms sold, room assignment guaranteed (not swapped at check-in), third-party booking platforms transmit accessibility requests, staff training on accessible room procedures.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring reservation system compliance), CC1.4 (training on ADA reservation requirements), CC8.1 (change management for system updates). Retention: system configuration records — active; complaint records — 5 years.' WHERE name = 'Accessible Room Reservation Compliance Officer';
