UPDATE citizen_catalog SET standards_of_creation = 'Building permit applications, plan check approval, ADA path of travel compliance plan (triggered by any alteration), contractor license verification, workers'' compensation certificates, asbestos/lead-based paint survey (for pre-1978 buildings), CEQA exemption or environmental review documentation, certificate of occupancy upon completion.', soc_controls = 'SOC 2 Type II — CC8.1 (change management for physical plant), CC7.2 (monitoring permit conditions), CC6.1 (access to construction documents). Retention: permanent (building records per California Building Code).' WHERE name = 'Hotel Construction & Renovation Compliance Officer';
