UPDATE citizen_catalog SET standards_of_creation = 'WiFi terms of service (presented at login portal), network architecture documentation showing separation of guest/staff/POS networks, no-blocking certification (personal hotspots), data collection disclosure in privacy policy, MAC address/browsing data retention limits, law enforcement request procedures aligned with CIV § 53.5 principles.', soc_controls = 'SOC 2 Type II — CC6.1/CC6.6 (network segmentation), CC7.1 (intrusion detection), PI1.1 (privacy of browsing data), CC3.2 (communication of WiFi terms). Retention: network logs — 90 days (typical); privacy complaints — 5 years.' WHERE name = 'Hotel Telecommunications & WiFi Compliance Officer';
