UPDATE citizen_catalog SET standards_of_creation = 'Property tax statements, Proposition 8 temporary reduction applications (during downturns), assessment appeal applications (Assessment Appeals Board — within 60 days of notice per RTC § 1603), income approach documentation (required for hotel valuations — income and expense statements, market RevPAR data), business personal property statements (Form 571).', soc_controls = 'SOC 2 Type II — CC6.1 (access to financial data), CC7.2 (monitoring appeal deadlines — 60 days, no extensions), CC3.2 (communication of assessment changes). Retention: 7 years minimum; assessment records — permanent.' WHERE name = 'Hospitality Real Property Tax Compliance Officer';
