INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-52adb312fb8a', 'Travel Loyalty Program Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Loyalty Program Regulatory Compliance Officer — CFPB; FTC; California AG', 'Travel Loyalty Program Regulatory Compliance Officer', 'CFPB; FTC; California AG', '', 'Program terms and conditions (clear, conspicuous, pre-enrollment), point valuation methodology documentation, devaluation notice procedures, expiration policy (compliant with state laws — California prohibits gift card expiration under § 1749.5 which may apply to certain loyalty currencies), financial incentive notice per CCPA § 1798.125(b), unclaimed property reporting for dormant accounts.', 'SOC 2 Type II — CC3.2 (communication of program changes), CC6.1 (access to member PII), PI1.1 (privacy of redemption/earning data), CC7.2 (monitoring unclaimed property reporting). Retention: member records — active + 7 years (unclaimed property); program change records — 7 years.', 'Travel loyalty program compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Cruise contract (passage contract) documentation, PVSA route compliance verification, passenger manifest (submitted to CBP), vessel safety certificate (USCG/flag state), financial responsibility certificate (FMC Form 27), crime reporting procedures per CVSSA, medical facility and personnel documentation, shore excursion safety documentation.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring vessel certification renewals), CC6.1 (access to passenger PII — manifest), CC3.2 (communication of safety procedures to passengers). Retention: passage contracts — 7 years; manifests — 5 years; safety records — life of vessel.' WHERE name = 'Passenger Vessel Services Act (PVSA) Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9e0aa349cbbc', 'Passenger Vessel Services Act (PVSA) Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Passenger Vessel Services Act (PVSA) Compliance Officer — U.S. Customs and Border Protection (CBP); U.S. Coast Guard; FMC', 'Passenger Vessel Services Act (PVSA) Compliance Officer', 'U.S. Customs and Border Protection (CBP); U.S. Coast Guard; FMC', '', 'Cruise contract (passage contract) documentation, PVSA route compliance verification, passenger manifest (submitted to CBP), vessel safety certificate (USCG/flag state), financial responsibility certificate (FMC Form 27), crime reporting procedures per CVSSA, medical facility and personnel documentation, shore excursion safety documentation.', 'SOC 2 Type II — CC7.2 (monitoring vessel certification renewals), CC6.1 (access to passenger PII — manifest), CC3.2 (communication of safety procedures to passengers). Retention: passage contracts — 7 years; manifests — 5 years; safety records — life of vessel.', 'Cruise line passenger documents (PVSA)');
UPDATE citizen_catalog SET standards_of_creation = 'Shore excursion operator vetting documentation, insurance verification per operator, safety briefing scripts, participant waivers (limited enforceability per 46 USC § 30509), emergency medical evacuation plans per port, incident reporting procedures, accessibility information per excursion.', soc_controls = 'SOC 2 Type II — CC9.1 (risk assessment per excursion/port), CC7.2 (monitoring operator insurance and permit status), CC3.2 (communication of safety information). Retention: operator records — contract term + 5 years; incident records — 7 years.' WHERE name = 'Shore Excursion Safety & Liability Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5cff0938b90d', 'Shore Excursion Safety & Liability Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Shore Excursion Safety & Liability Compliance Officer — Cruise line (contractual); Local jurisdiction at port of call', 'Shore Excursion Safety & Liability Compliance Officer', 'Cruise line (contractual); Local jurisdiction at port of call', '', 'Shore excursion operator vetting documentation, insurance verification per operator, safety briefing scripts, participant waivers (limited enforceability per 46 USC § 30509), emergency medical evacuation plans per port, incident reporting procedures, accessibility information per excursion.', 'SOC 2 Type II — CC9.1 (risk assessment per excursion/port), CC7.2 (monitoring operator insurance and permit status), CC3.2 (communication of safety information). Retention: operator records — contract term + 5 years; incident records — 7 years.', 'Cruise line passenger documents (excursion component)');
UPDATE citizen_catalog SET standards_of_creation = 'Client advisory documentation (passport validity requirements — 6-month rule, visa requirements by nationality/destination, WHTI exceptions for closed-loop cruises), visa facilitation records (if assisting), document verification checklists, travel advisory acknowledgments, health documentation requirements (vaccination records per destination).', soc_controls = 'SOC 2 Type II — CC6.1 (access to client passport/personal data), PI1.1 (privacy of travel documents), CC3.2 (accuracy of documentation advisories). Retention: client records — 7 years; advisory records — 5 years.' WHERE name = 'Travel Document & Passport/Visa Facilitation Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f99c9ce6d8f0', 'Travel Document & Passport/Visa Facilitation Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Document & Passport/Visa Facilitation Compliance Officer — U.S. Department of State; CBP; USCIS', 'Travel Document & Passport/Visa Facilitation Compliance Officer', 'U.S. Department of State; CBP; USCIS', '', 'Client advisory documentation (passport validity requirements — 6-month rule, visa requirements by nationality/destination, WHTI exceptions for closed-loop cruises), visa facilitation records (if assisting), document verification checklists, travel advisory acknowledgments, health documentation requirements (vaccination records per destination).', 'SOC 2 Type II — CC6.1 (access to client passport/personal data), PI1.1 (privacy of travel documents), CC3.2 (accuracy of documentation advisories). Retention: client records — 7 years; advisory records — 5 years.', 'Passport/visa facilitation documents, travel medical clearance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Safety management system documentation per ISO 21101, leader/guide competence records per ISO 21102, participant information package per ISO 21103, assumption of risk/liability waivers (per activity — limited enforceability under CIV § 1668), equipment inspection and maintenance logs, emergency action plans per activity/venue, incident/near-miss reporting system, participant medical screening forms.', soc_controls = 'SOC 2 Type II — CC9.1 (activity risk assessment), CC7.2 (monitoring guide certifications and equipment inspection schedules), CC1.4 (training/competence verification), CC3.2 (participant safety communication). Retention: safety records — 7 years; incident records — statute of limitations + 5 years; equipment logs — life of equipment + 3 years.' WHERE name = 'Adventure Tourism Safety & Risk Management Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8dff8ad604d9', 'Adventure Tourism Safety & Risk Management Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Adventure Tourism Safety & Risk Management Officer — ASTA; ISO Technical Committee 228; Cal/OSHA (employer obligations)', 'Adventure Tourism Safety & Risk Management Officer', 'ASTA; ISO Technical Committee 228; Cal/OSHA (employer obligations)', '', 'Safety management system documentation per ISO 21101, leader/guide competence records per ISO 21102, participant information package per ISO 21103, assumption of risk/liability waivers (per activity — limited enforceability under CIV § 1668), equipment inspection and maintenance logs, emergency action plans per activity/venue, incident/near-miss reporting system, participant medical screening forms.', 'SOC 2 Type II — CC9.1 (activity risk assessment), CC7.2 (monitoring guide certifications and equipment inspection schedules), CC1.4 (training/competence verification), CC3.2 (participant safety communication). Retention: safety records — 7 years; incident records — statute of limitations + 5 years; equipment logs — life of equipment + 3 years.', 'Adventure tourism liability waivers');
UPDATE citizen_catalog SET standards_of_creation = 'GSTC-recognized certification application, environmental impact assessment, sustainability management plan, carbon footprint calculation and offset documentation, community benefit-sharing agreements, wildlife interaction protocols (if applicable), waste management plan, water conservation documentation, supply chain sustainability audits, annual sustainability report.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring certification renewal and audit schedule), CC8.1 (change management for sustainability practices), CC3.2 (communication of sustainability claims — greenwashing prevention). Retention: certification records — active + 5 years; environmental data — 7 years.' WHERE name = 'Eco-Tourism & Sustainable Tourism Certification Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-41d69230f100', 'Eco-Tourism & Sustainable Tourism Certification Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Eco-Tourism & Sustainable Tourism Certification Officer — Global Sustainable Tourism Council (GSTC); Green Globe; Rainforest Alliance', 'Eco-Tourism & Sustainable Tourism Certification Officer', 'Global Sustainable Tourism Council (GSTC); Green Globe; Rainforest Alliance', '', 'GSTC-recognized certification application, environmental impact assessment, sustainability management plan, carbon footprint calculation and offset documentation, community benefit-sharing agreements, wildlife interaction protocols (if applicable), waste management plan, water conservation documentation, supply chain sustainability audits, annual sustainability report.', 'SOC 2 Type II — CC7.2 (monitoring certification renewal and audit schedule), CC8.1 (change management for sustainability practices), CC3.2 (communication of sustainability claims — greenwashing prevention). Retention: certification records — active + 5 years; environmental data — 7 years.', 'Eco-tourism certification documents');
UPDATE citizen_catalog SET standards_of_creation = 'Conditional use permit (if required), liability waivers (limited enforceability per CIV § 1668), premises safety inspection documentation, food handling permits (if serving/selling food), signage (assumption of risk, hazard identification), insurance certificates (farm liability, event liability, product liability), Williamson Act compatibility documentation (if applicable), employee training records for visitor interaction.', soc_controls = 'SOC 2 Type II — CC9.1 (risk assessment per activity — hayrides, U-pick, animal interaction), CC7.2 (monitoring permit compliance), CC3.2 (communication of hazards to visitors). Retention: permit records — active + 5 years; incident records — statute of limitations + 5 years.' WHERE name = 'Agritourism Liability & Regulatory Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7870a2ed2707', 'Agritourism Liability & Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Agritourism Liability & Regulatory Compliance Officer — California Department of Food and Agriculture; Local Planning; County Agricultural Commissioner', 'Agritourism Liability & Regulatory Compliance Officer', 'California Department of Food and Agriculture; Local Planning; County Agricultural Commissioner', '', 'Conditional use permit (if required), liability waivers (limited enforceability per CIV § 1668), premises safety inspection documentation, food handling permits (if serving/selling food), signage (assumption of risk, hazard identification), insurance certificates (farm liability, event liability, product liability), Williamson Act compatibility documentation (if applicable), employee training records for visitor interaction.', 'SOC 2 Type II — CC9.1 (risk assessment per activity — hayrides, U-pick, animal interaction), CC7.2 (monitoring permit compliance), CC3.2 (communication of hazards to visitors). Retention: permit records — active + 5 years; incident records — statute of limitations + 5 years.', 'Agritourism liability documents');
UPDATE citizen_catalog SET standards_of_creation = 'Section 106 compliance documentation (if federal nexus), CEQA cultural resources survey, historic preservation plan, interpretive program accuracy verification, access management plan (balancing preservation with public access), community engagement records (especially Native American consultation per PRC § 5097.9), visitor impact assessment, conservation monitoring records.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring compliance review schedules), CC8.1 (change management for any physical alterations), CC3.2 (accuracy of interpretive materials). Retention: compliance records — permanent; consultation records — 10 years minimum.' WHERE name = 'Heritage Tourism & Cultural Resource Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-176208c04375', 'Heritage Tourism & Cultural Resource Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Heritage Tourism & Cultural Resource Compliance Officer — National Park Service (NPS); State Historic Preservation Office (SHPO); California Office of Historic Preservation', 'Heritage Tourism & Cultural Resource Compliance Officer', 'National Park Service (NPS); State Historic Preservation Office (SHPO); California Office of Historic Preservation', '', 'Section 106 compliance documentation (if federal nexus), CEQA cultural resources survey, historic preservation plan, interpretive program accuracy verification, access management plan (balancing preservation with public access), community engagement records (especially Native American consultation per PRC § 5097.9), visitor impact assessment, conservation monitoring records.', 'SOC 2 Type II — CC7.2 (monitoring compliance review schedules), CC8.1 (change management for any physical alterations), CC3.2 (accuracy of interpretive materials). Retention: compliance records — permanent; consultation records — 10 years minimum.', 'Heritage tourism compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Site interpretation guidelines (factual accuracy, victim dignity, educational purpose), visitor behavior code, photography/media policies, community/survivor consultation records, guide training curriculum (sensitivity, historical accuracy, trauma-informed approach), revenue sharing with affected communities (where applicable), complaint/feedback management system.', soc_controls = 'SOC 2 Type II — CC3.2 (communication accuracy and sensitivity), CC1.4 (guide training verification), CC7.2 (monitoring community agreement compliance). Retention: interpretation materials — permanent; consultation records — 10 years; training records — 5 years.' WHERE name = 'Sensitive Site Tourism Ethics & Protocol Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9d1d97b6809e', 'Sensitive Site Tourism Ethics & Protocol Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Sensitive Site Tourism Ethics & Protocol Officer — ICOMOS (International Council on Monuments and Sites); UNWTO Ethics Committee', 'Sensitive Site Tourism Ethics & Protocol Officer', 'ICOMOS (International Council on Monuments and Sites); UNWTO Ethics Committee', '', 'Site interpretation guidelines (factual accuracy, victim dignity, educational purpose), visitor behavior code, photography/media policies, community/survivor consultation records, guide training curriculum (sensitivity, historical accuracy, trauma-informed approach), revenue sharing with affected communities (where applicable), complaint/feedback management system.', 'SOC 2 Type II — CC3.2 (communication accuracy and sensitivity), CC1.4 (guide training verification), CC7.2 (monitoring community agreement compliance). Retention: interpretation materials — permanent; consultation records — 10 years; training records — 5 years.', 'Dark tourism/sensitive site protocols');
UPDATE citizen_catalog SET standards_of_creation = 'Annual report to assessment district, financial statements (audited if over $2M in assessments), program performance metrics (visitor counts, economic impact), marketing expenditure documentation, board meeting minutes, conflict of interest disclosures, annual assessment levy and disbursement reconciliation.', soc_controls = 'SOC 2 Type II — CC6.1 (access to financial records), CC7.2 (monitoring reporting deadlines to city/county), CC3.2 (transparency of expenditures to assessed businesses). Retention: financial records — 7 years; board records — permanent; marketing materials — 5 years.' WHERE name = 'DMO Fiscal & Program Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f0d88ec4152f', 'DMO Fiscal & Program Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'DMO Fiscal & Program Compliance Officer — Local Government (funding authority); California Tourism Commission (Visit California)', 'DMO Fiscal & Program Compliance Officer', 'Local Government (funding authority); California Tourism Commission (Visit California)', '', 'Annual report to assessment district, financial statements (audited if over $2M in assessments), program performance metrics (visitor counts, economic impact), marketing expenditure documentation, board meeting minutes, conflict of interest disclosures, annual assessment levy and disbursement reconciliation.', 'SOC 2 Type II — CC6.1 (access to financial records), CC7.2 (monitoring reporting deadlines to city/county), CC3.2 (transparency of expenditures to assessed businesses). Retention: financial records — 7 years; board records — permanent; marketing materials — 5 years.', 'Destination marketing organization documents');
UPDATE citizen_catalog SET standards_of_creation = 'Grant application, award documentation, budget vs. actual reporting, drawdown requests with supporting documentation, performance reports (per grant milestones), single audit report (if threshold met), closeout documentation, equipment/property inventory (if purchased with grant funds), subrecipient monitoring records.', soc_controls = 'SOC 2 Type II — CC6.1 (access to grant financial records), CC7.2 (monitoring reporting deadlines — typically quarterly/annual), CC3.2 (communication of program outcomes to grantor). Retention: grant records — award end + 3 years (federal minimum per 2 CFR § 200.334); California — 7 years.' WHERE name = 'Tourism Grant Compliance & Reporting Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-d30eb4a0c051', 'Tourism Grant Compliance & Reporting Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Tourism Grant Compliance & Reporting Officer — EDA (Economic Development Administration); SBA; State granting agencies; Visit California', 'Tourism Grant Compliance & Reporting Officer', 'EDA (Economic Development Administration); SBA; State granting agencies; Visit California', '', 'Grant application, award documentation, budget vs. actual reporting, drawdown requests with supporting documentation, performance reports (per grant milestones), single audit report (if threshold met), closeout documentation, equipment/property inventory (if purchased with grant funds), subrecipient monitoring records.', 'SOC 2 Type II — CC6.1 (access to grant financial records), CC7.2 (monitoring reporting deadlines — typically quarterly/annual), CC3.2 (communication of program outcomes to grantor). Retention: grant records — award end + 3 years (federal minimum per 2 CFR § 200.334); California — 7 years.', 'Tourism board grant documents');
UPDATE citizen_catalog SET standards_of_creation = 'Program documentation (eligibility criteria, earning thresholds, trip details), tax reporting records (Form W-2/1099 for incentive travel value), per diem documentation, gift limit compliance tracking (if government attendees), anti-corruption certifications, attendee agreements, post-program ROI analysis, vendor selection documentation.', soc_controls = 'SOC 2 Type II — CC6.1 (access to participant compensation data), CC7.2 (monitoring tax reporting compliance), CC3.2 (communication of tax obligations to participants/employers). Retention: tax records — 7 years; program documentation — 5 years; anti-corruption records — 10 years.' WHERE name = 'Incentive Travel Program Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-976642d93fa0', 'Incentive Travel Program Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Incentive Travel Program Compliance Officer — IRS; DOL; SITE (Society for Incentive Travel Excellence)', 'Incentive Travel Program Compliance Officer', 'IRS; DOL; SITE (Society for Incentive Travel Excellence)', '', 'Program documentation (eligibility criteria, earning thresholds, trip details), tax reporting records (Form W-2/1099 for incentive travel value), per diem documentation, gift limit compliance tracking (if government attendees), anti-corruption certifications, attendee agreements, post-program ROI analysis, vendor selection documentation.', 'SOC 2 Type II — CC6.1 (access to participant compensation data), CC7.2 (monitoring tax reporting compliance), CC3.2 (communication of tax obligations to participants/employers). Retention: tax records — 7 years; program documentation — 5 years; anti-corruption records — 10 years.', 'Incentive travel compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'PNR data handling policy (collection, storage, transmission, deletion), APIS (Advance Passenger Information System) transmission procedures, EU adequacy compliance documentation, data retention schedules (EU-US Agreement limits), DSAR procedures for PNR data, data processing agreements with GDS (Global Distribution Systems — Amadeus, Sabre, Travelport), cross-border data transfer mechanisms (Standard Contractual Clauses if EU).', soc_controls = 'SOC 2 Type II — CC6.1 (access to PNR data — restricted), PI1.1–PI1.5 (privacy criteria), CC6.6 (boundary protection for data transmission), CC7.2 (monitoring retention limit compliance). Retention: per applicable framework — EU-US Agreement: 6 months active, 4.5 years dormant, then deleted; CCPA: as disclosed in privacy policy.' WHERE name = 'Travel Data / PNR Privacy Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-50ee1abaaf82', 'Travel Data / PNR Privacy Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Data / PNR Privacy Compliance Officer — DHS (CBP); EU Commission; California AG (CCPA/CPRA)', 'Travel Data / PNR Privacy Compliance Officer', 'DHS (CBP); EU Commission; California AG (CCPA/CPRA)', '', 'PNR data handling policy (collection, storage, transmission, deletion), APIS (Advance Passenger Information System) transmission procedures, EU adequacy compliance documentation, data retention schedules (EU-US Agreement limits), DSAR procedures for PNR data, data processing agreements with GDS (Global Distribution Systems — Amadeus, Sabre, Travelport), cross-border data transfer mechanisms (Standard Contractual Clauses if EU).', 'SOC 2 Type II — CC6.1 (access to PNR data — restricted), PI1.1–PI1.5 (privacy criteria), CC6.6 (boundary protection for data transmission), CC7.2 (monitoring retention limit compliance). Retention: per applicable framework — EU-US Agreement: 6 months active, 4.5 years dormant, then deleted; CCPA: as disclosed in privacy policy.', 'Travel data privacy (PNR) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Platform terms of service, display methodology documentation (no unfair bias per 14 CFR Part 255), full-fare price display verification, dark pattern audit results, privacy policy (CCPA-compliant), PCI DSS SAQ/ROC, cookie consent mechanism documentation, API data sharing agreements with suppliers, user account deletion procedures.', soc_controls = 'SOC 2 Type II — CC6.1 (access to booking data), CC6.6 (payment environment segmentation), PI1.1 (privacy of user search/booking data), CC3.2 (accuracy of displayed information), CC7.2 (monitoring price display compliance). Retention: booking records — 7 years; platform audit records — 5 years.' WHERE name = 'Travel Technology Platform Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-587f99f101b3', 'Travel Technology Platform Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Technology Platform Compliance Officer — DOT; FTC; California AG; EU Commission', 'Travel Technology Platform Compliance Officer', 'DOT; FTC; California AG; EU Commission', '', 'Platform terms of service, display methodology documentation (no unfair bias per 14 CFR Part 255), full-fare price display verification, dark pattern audit results, privacy policy (CCPA-compliant), PCI DSS SAQ/ROC, cookie consent mechanism documentation, API data sharing agreements with suppliers, user account deletion procedures.', 'SOC 2 Type II — CC6.1 (access to booking data), CC6.6 (payment environment segmentation), PI1.1 (privacy of user search/booking data), CC3.2 (accuracy of displayed information), CC7.2 (monitoring price display compliance). Retention: booking records — 7 years; platform audit records — 5 years.', 'Travel data privacy (PNR) documents (technology component)');
UPDATE citizen_catalog SET standards_of_creation = 'Travel risk management policy per ISO 31030, pre-trip risk assessment per destination (incorporating State Department and CDC advisories), traveler registration/tracking system, emergency assistance procedures, medical evacuation insurance verification, security briefing documentation, crisis communication plan, post-incident review procedures.', soc_controls = 'SOC 2 Type II — CC9.1 (risk assessment per destination), CC7.2 (monitoring advisory level changes), CC3.2 (communication of advisories to travelers), A1.2 (business continuity for travel disruptions). Retention: risk assessments — 5 years; incident records — 7 years; advisory tracking — 3 years.' WHERE name = 'Travel Risk & Duty of Care Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-86cabebcc3ea', 'Travel Risk & Duty of Care Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Risk & Duty of Care Compliance Officer — U.S. Department of State (travel advisories); ASTA; ISO 31030', 'Travel Risk & Duty of Care Compliance Officer', 'U.S. Department of State (travel advisories); ASTA; ISO 31030', '', 'Travel risk management policy per ISO 31030, pre-trip risk assessment per destination (incorporating State Department and CDC advisories), traveler registration/tracking system, emergency assistance procedures, medical evacuation insurance verification, security briefing documentation, crisis communication plan, post-incident review procedures.', 'SOC 2 Type II — CC9.1 (risk assessment per destination), CC7.2 (monitoring advisory level changes), CC3.2 (communication of advisories to travelers), A1.2 (business continuity for travel disruptions). Retention: risk assessments — 5 years; incident records — 7 years; advisory tracking — 3 years.', 'Foreign travel advisory compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Accessibility policy, website/app WCAG 2.1 AA audit, accessible tour/excursion inventory, accommodation request procedures, staff disability awareness training records, accessible transportation documentation, marketing materials in accessible formats, complaint/grievance procedures.', soc_controls = 'SOC 2 Type II — CC3.2 (communication of accessibility features — accurate), CC1.4 (staff training verification), CC7.2 (monitoring WCAG compliance), CC9.1 (accessibility risk assessment). Retention: audit reports — 5 years; complaint records — 5 years; training records — employment + 3 years.' WHERE name = 'Accessible Tourism Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b5589ea7938a', 'Accessible Tourism Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Accessible Tourism Compliance Officer — U.S. DOJ; U.S. DOT; UNWTO', 'Accessible Tourism Compliance Officer', 'U.S. DOJ; U.S. DOT; UNWTO', '', 'Accessibility policy, website/app WCAG 2.1 AA audit, accessible tour/excursion inventory, accommodation request procedures, staff disability awareness training records, accessible transportation documentation, marketing materials in accessible formats, complaint/grievance procedures.', 'SOC 2 Type II — CC3.2 (communication of accessibility features — accurate), CC1.4 (staff training verification), CC7.2 (monitoring WCAG compliance), CC9.1 (accessibility risk assessment). Retention: audit reports — 5 years; complaint records — 5 years; training records — employment + 3 years.', 'Tourism accessibility compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Medical clearance forms (cruise-specific, adventure-specific), vaccination records (International Certificate of Vaccination — Yellow Card/ICV), travel health advisories per destination, pre-departure health screening documentation, medication carriage documentation (controlled substance letters), fitness-to-travel certificates (airline/cruise requirements), travel insurance medical coverage verification.', soc_controls = 'SOC 2 Type II — CC6.1 (access to medical records — HIPAA-adjacent protections), PI1.1 (health data privacy), CC3.2 (accuracy of health advisories). Retention: medical clearance records — 7 years; vaccination records — permanent.' WHERE name = 'Travel Health & Medical Clearance Documentation Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-08ed505bf096', 'Travel Health & Medical Clearance Documentation Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Travel Health & Medical Clearance Documentation Officer — CDC (Division of Global Migration and Quarantine); WHO; Local Health Department', 'Travel Health & Medical Clearance Documentation Officer', 'CDC (Division of Global Migration and Quarantine); WHO; Local Health Department', '', 'Medical clearance forms (cruise-specific, adventure-specific), vaccination records (International Certificate of Vaccination — Yellow Card/ICV), travel health advisories per destination, pre-departure health screening documentation, medication carriage documentation (controlled substance letters), fitness-to-travel certificates (airline/cruise requirements), travel insurance medical coverage verification.', 'SOC 2 Type II — CC6.1 (access to medical records — HIPAA-adjacent protections), PI1.1 (health data privacy), CC3.2 (accuracy of health advisories). Retention: medical clearance records — 7 years; vaccination records — permanent.', 'Travel medical clearance documents');
UPDATE citizen_catalog SET standards_of_creation = 'State and local cannabis license verification (consumption lounge if applicable), age verification procedures (21+), consumption area documentation (ventilation, separation from non-consumption areas), product sourcing documentation (licensed supply chain), educational materials for tourists (legal limits, DUI laws, federal prohibition), signage requirements, employee training records.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring dual state/local license compliance), CC6.1 (access to customer records — limited per privacy), CC3.2 (communication of legal limitations). Retention: license records — active + 5 years; sales records — 7 years (tax purposes).' WHERE name = 'Cannabis Tourism Regulatory Compliance Officer';
