UPDATE citizen_catalog SET standards_of_creation = 'ABC license documentation (Type 02 winegrower, Type 23 craft distiller), tasting room operating permits, RBS training for all tasting room staff, responsible service policies (pour limits, cut-off procedures, transportation alternatives), food pairing requirements (per ABC conditions), event permits for harvest/release events, DTC (direct-to-consumer) shipping compliance per destination state.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring ABC compliance and RBS training), CC1.4 (staff training), CC3.2 (responsible service communication). Retention: license records — active + 7 years; training records — employment + 3 years.' WHERE name = 'Wine & Spirits Tourism Compliance Officer';
