UPDATE citizen_catalog SET standards_of_creation = 'Seller of travel registration (if package includes lodging + transport + tickets), ticket sourcing documentation (authorized reseller/direct purchase), package pricing transparency, cancellation/refund policies compliant with BPC § 17550.14, venue credential/access documentation, group logistics plans.', soc_controls = 'SOC 2 Type II — CC3.2 (accuracy of package descriptions), CC7.2 (monitoring ticket sourcing legitimacy), CC6.1 (access to customer payment data). Retention: package records — 7 years; event documentation — 5 years.' WHERE name = 'Sports Tourism & Event Travel Compliance Officer';
