UPDATE citizen_catalog SET standards_of_creation = 'Facility accreditation verification (JCI or equivalent), physician credential verification, informed consent documentation (in patient''s language), cost disclosure (all-in pricing), complication/follow-up care plan, travel insurance/medical evacuation documentation, seller of travel registration, advertising substantiation records.', soc_controls = 'SOC 2 Type II — CC6.1 (access to patient medical/personal data), PI1.1 (HIPAA-adjacent privacy protections), CC3.2 (accuracy of medical facility claims), CC9.1 (risk assessment per facility/procedure). Retention: medical facilitation records — 10 years; advertising records — 5 years.' WHERE name = 'Medical Tourism Facilitator Compliance Officer';
