UPDATE citizen_catalog SET standards_of_creation = 'Seller of travel registration, pilgrimage itinerary documentation, religious site access permits/coordination records, dietary accommodation documentation (halal, kosher, vegetarian), religious practice accommodation plans (prayer times, Sabbath observance), guide qualification (religious knowledge verification), health and safety provisions for large gatherings, trip cancellation provisions (religious calendar changes).', soc_controls = 'SOC 2 Type II — CC3.2 (accuracy of religious/cultural content), CC7.2 (monitoring religious calendar compliance), CC9.1 (risk assessment for mass gathering sites). Retention: package records — 7 years; religious authority coordination — 5 years.' WHERE name = 'Religious & Pilgrimage Tourism Compliance Officer';
