UPDATE citizen_catalog SET standards_of_creation = 'Parental/guardian consent forms, school authorization documentation, chaperone ratio documentation and background checks, student medical information cards, emergency contact protocols, FERPA-compliant information handling, itinerary with safety protocols per activity, insurance coverage verification (student accident insurance), accommodation vetting (child safeguarding), CSIET listing (for exchange programs).', soc_controls = 'SOC 2 Type II — CC6.1 (access to student records — FERPA restricted), PI1.1 (student privacy), CC7.2 (monitoring chaperone clearance and ratio compliance), CC9.1 (child safeguarding risk assessment). Retention: student records — FERPA requirements; trip records — 7 years; incident records — until student reaches 21 + statute of limitations.' WHERE name = 'Student & Educational Travel Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9307e8f3ccca', 'Student & Educational Travel Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Student & Educational Travel Compliance Officer — U.S. Department of Education; Cal DOE; CSIET (Council on Standards for International Educational Travel)', 'Student & Educational Travel Compliance Officer', 'U.S. Department of Education; Cal DOE; CSIET (Council on Standards for International Educational Travel)', '', 'Parental/guardian consent forms, school authorization documentation, chaperone ratio documentation and background checks, student medical information cards, emergency contact protocols, FERPA-compliant information handling, itinerary with safety protocols per activity, insurance coverage verification (student accident insurance), accommodation vetting (child safeguarding), CSIET listing (for exchange programs).', 'SOC 2 Type II — CC6.1 (access to student records — FERPA restricted), PI1.1 (student privacy), CC7.2 (monitoring chaperone clearance and ratio compliance), CC9.1 (child safeguarding risk assessment). Retention: student records — FERPA requirements; trip records — 7 years; incident records — until student reaches 21 + statute of limitations.', 'Group travel contract documents (educational component)');
UPDATE citizen_catalog SET standards_of_creation = 'Accessibility information database per destination/supplier, accommodation accessibility verification procedures (not just "accessible" label — specific features), airline wheelchair handling procedures (14 CFR § 382.121–133), cruise accessibility verification, adaptive equipment rental coordination, emergency evacuation procedures for travelers with disabilities, service animal documentation guidance (per 14 CFR § 382.72–80).', soc_controls = 'SOC 2 Type II — CC3.2 (accuracy of accessibility claims), CC6.1 (access to client medical/disability data), PI1.1 (disability information privacy), CC7.2 (monitoring supplier accessibility updates). Retention: client records — 7 years; supplier verification — annual refresh + 3 years.' WHERE name = 'Accessible Travel Planning Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-81895b803341', 'Accessible Travel Planning Specialist', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Accessible Travel Planning Specialist — U.S. DOT; U.S. DOJ; ASTA', 'Accessible Travel Planning Specialist', 'U.S. DOT; U.S. DOJ; ASTA', '', 'Accessibility information database per destination/supplier, accommodation accessibility verification procedures (not just "accessible" label — specific features), airline wheelchair handling procedures (14 CFR § 382.121–133), cruise accessibility verification, adaptive equipment rental coordination, emergency evacuation procedures for travelers with disabilities, service animal documentation guidance (per 14 CFR § 382.72–80).', 'SOC 2 Type II — CC3.2 (accuracy of accessibility claims), CC6.1 (access to client medical/disability data), PI1.1 (disability information privacy), CC7.2 (monitoring supplier accessibility updates). Retention: client records — 7 years; supplier verification — annual refresh + 3 years.', 'Tourism accessibility compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Permit application (typically 60–180 days before event), site plan, expected attendance, event schedule, security plan, traffic management plan, emergency action plan, insurance certificate, neighbor notification (where required), environmental review (CEQA categorical exemption or notice), fee payment and deposit documentation.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring multi-agency permit conditions), CC8.1 (change management for event modifications), CC3.2 (communication with regulatory agencies). Retention: permit records — 5 years post-event.' WHERE name = 'Special Event Permit Compliance Officer';
