UPDATE citizen_catalog SET standards_of_creation = 'Mass gathering permit application, public health plan (sanitation, potable water, communicable disease surveillance), emergency medical services plan (EMS staffing ratios per attendance), communication plan (PA system, emergency channels), evacuation plan, severe weather protocol, medical transport agreements, after-action report template.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring all permit conditions — multi-agency), CC9.1 (risk assessment per event), CC3.2 (real-time communication with public safety agencies), A1.2 (event continuity planning). Retention: permit records — 5 years; after-action reports — 7 years.' WHERE name = 'Mass Gathering Permit & Public Safety Compliance Officer';
