UPDATE citizen_catalog SET standards_of_creation = 'TFF permit application (per event, per vendor), menu/food item list, food source documentation (approved suppliers), food temperature control plan, handwashing station layout, waste water disposal plan, overhead protection/booth configuration, food handler certification for all operators (per HSC § 113947.1), community event organizer permit (if multiple vendors under one umbrella).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring vendor compliance at multi-vendor events), CC3.2 (communication of food safety requirements to vendors), CC6.1 (access to vendor permit records). Retention: permit records — 3 years; inspection records — 3 years.' WHERE name = 'Temporary Food Facility (TFF) Permit Compliance Officer';
