UPDATE citizen_catalog SET standards_of_creation = 'ABC temporary license application (filed 30+ days before event), event description (type, attendance, hours, premises diagram), server identification (all must have RBS certification per AB 1221), security plan for alcohol service area, age verification procedures (ID checking protocols), designated area for alcohol consumption, insurance documentation, nonprofit status verification (if Type 24045.1).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring application filing deadline and service hours), CC1.4 (RBS training verification for all servers), CC3.2 (communication of responsible service policies). Retention: license records — 5 years; incident records — 7 years.' WHERE name = 'Temporary Liquor License / Event Alcohol Permit Officer';
