UPDATE citizen_catalog SET standards_of_creation = 'Street closure permit application, traffic control plan (TCP) per MUTCD Part 6, detour routing plan, ADA-accessible pedestrian path during closure, emergency vehicle access plan, transit rerouting coordination (if applicable), parking impact mitigation, resident/business notification documentation, traffic control device inventory (barricades, cones, signs — per MUTCD specifications), post-event street restoration plan.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring setup/teardown timeline compliance), CC3.2 (communication with transit agencies and emergency services), CC9.1 (traffic safety risk assessment). Retention: permit records — 3 years; traffic incident records — 5 years.' WHERE name = 'Event Street Closure & Traffic Management Permit Officer';
