UPDATE citizen_catalog SET standards_of_creation = 'Noise variance application, sound monitoring plan (with dB limits per time/distance), sound level meter deployment documentation, stage orientation and speaker placement plan, noise barrier/mitigation measures, community notification records, sound check schedule, real-time monitoring log during event, worker hearing protection program (per OSHA if 85+ dBA TWA), post-event noise complaint records.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring real-time compliance with dB limits), CC3.2 (communication with neighbors and enforcement agencies), CC8.1 (change management — sound adjustments during event). Retention: variance records — 3 years; monitoring logs — 3 years; complaints — 5 years.' WHERE name = 'Event Sound & Noise Ordinance Compliance Officer';
