UPDATE citizen_catalog SET standards_of_creation = 'Event security plan (threat assessment, post assignments, communication protocols, response procedures), BSIS license verification for all security personnel, guard training records (40 hours per BPC § 7583.6), firearms permit verification (if armed security per BPC § 7596.1), law enforcement coordination documentation, access control plan (credentialing, perimeter control), surveillance system deployment documentation, incident action plan (ICS format).', soc_controls = 'SOC 2 Type II — CC6.1 (access control documentation), CC7.1 (security event monitoring), CC7.2 (monitoring guard licensing status), CC3.2 (communication with law enforcement). Retention: security plans — 5 years; incident reports — 7 years; guard records — employment + 5 years.' WHERE name = 'Event Security Plan & Operations Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b1833d52d059', 'Event Security Plan & Operations Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Security Plan & Operations Compliance Officer — Local Police Department; California Bureau of Security and Investigative Services (BSIS)', 'Event Security Plan & Operations Compliance Officer', 'Local Police Department; California Bureau of Security and Investigative Services (BSIS)', '', 'Event security plan (threat assessment, post assignments, communication protocols, response procedures), BSIS license verification for all security personnel, guard training records (40 hours per BPC § 7583.6), firearms permit verification (if armed security per BPC § 7596.1), law enforcement coordination documentation, access control plan (credentialing, perimeter control), surveillance system deployment documentation, incident action plan (ICS format).', 'SOC 2 Type II — CC6.1 (access control documentation), CC7.1 (security event monitoring), CC7.2 (monitoring guard licensing status), CC3.2 (communication with law enforcement). Retention: security plans — 5 years; incident reports — 7 years; guard records — employment + 5 years.', 'Event security plan documents');
UPDATE citizen_catalog SET standards_of_creation = 'Crowd management plan per ESA standards (capacity calculation, flow analysis, ingress/egress timing, queue management, density monitoring protocols), trained crowd management personnel documentation, communication system plan, escalation protocols (crowd crush prevention), signage and wayfinding documentation, barrier/fencing placement plan (avoid blind alleys), real-time crowd density monitoring technology deployment (if over 10,000 attendees), post-event crowd flow analysis.', soc_controls = 'SOC 2 Type II — CC7.2 (real-time crowd density monitoring), CC3.2 (communication of crowd management decisions), CC9.1 (risk assessment — crowd crush scenarios), A1.2 (event continuity during crowd emergencies). Retention: crowd plans — 5 years; monitoring data — 3 years; incident records — 7 years.' WHERE name = 'Crowd Management & Flow Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3bc262251810', 'Crowd Management & Flow Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Crowd Management & Flow Compliance Officer — Local Fire Marshal; NFPA; Event Safety Alliance (ESA)', 'Crowd Management & Flow Compliance Officer', 'Local Fire Marshal; NFPA; Event Safety Alliance (ESA)', '', 'Crowd management plan per ESA standards (capacity calculation, flow analysis, ingress/egress timing, queue management, density monitoring protocols), trained crowd management personnel documentation, communication system plan, escalation protocols (crowd crush prevention), signage and wayfinding documentation, barrier/fencing placement plan (avoid blind alleys), real-time crowd density monitoring technology deployment (if over 10,000 attendees), post-event crowd flow analysis.', 'SOC 2 Type II — CC7.2 (real-time crowd density monitoring), CC3.2 (communication of crowd management decisions), CC9.1 (risk assessment — crowd crush scenarios), A1.2 (event continuity during crowd emergencies). Retention: crowd plans — 5 years; monitoring data — 3 years; incident records — 7 years.', 'Crowd management plan documents');
UPDATE citizen_catalog SET standards_of_creation = 'Event medical plan (EMS staffing ratios, medical facility locations, equipment inventory, triage protocols, hospital transport agreements), local EMS agency approval documentation, physician medical director oversight (for events requiring ALS), medical staff credentialing records, medical supply inventory, patient care reporting procedures, mass casualty incident (MCI) plan, AED placement documentation, heat/weather illness protocols.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring medical staff credentialing), CC3.2 (communication with hospitals and EMS dispatch), CC6.1 (patient care record security — HIPAA considerations), CC9.1 (medical risk assessment per event type). Retention: medical plans — 5 years; patient care reports — 7 years; credentialing — active + 3 years.' WHERE name = 'Event Medical Plan & EMS Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-92d22f6591a9', 'Event Medical Plan & EMS Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Medical Plan & EMS Compliance Officer — Local EMS Agency; County Health Department; California EMSA', 'Event Medical Plan & EMS Compliance Officer', 'Local EMS Agency; County Health Department; California EMSA', '', 'Event medical plan (EMS staffing ratios, medical facility locations, equipment inventory, triage protocols, hospital transport agreements), local EMS agency approval documentation, physician medical director oversight (for events requiring ALS), medical staff credentialing records, medical supply inventory, patient care reporting procedures, mass casualty incident (MCI) plan, AED placement documentation, heat/weather illness protocols.', 'SOC 2 Type II — CC7.2 (monitoring medical staff credentialing), CC3.2 (communication with hospitals and EMS dispatch), CC6.1 (patient care record security — HIPAA considerations), CC9.1 (medical risk assessment per event type). Retention: medical plans — 5 years; patient care reports — 7 years; credentialing — active + 3 years.', 'Event medical plan documents');
UPDATE citizen_catalog SET standards_of_creation = 'OSFM public display permit application (per HSC § 12640), pyrotechnic operator license verification (per HSC § 12640.1), ATF Federal Explosives License (FEL) for storage/use, site-specific safety plan (fallout radius, audience separation distances per NFPA 1123/1126), insurance certificates ($1M+ minimum typical), fire suppression readiness documentation, product inventory and specification sheets, post-display site inspection report, unused product disposition records.', soc_controls = 'SOC 2 Type II — CC6.1 (access to explosive materials — ATF compliance), CC7.2 (monitoring license/permit validity), CC8.1 (change management for display modifications), CC9.1 (safety risk assessment per display). Retention: permit records — 5 years; operator records — active + 5 years; incident records — 10 years.' WHERE name = 'Pyrotechnics & Special Effects Permit Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-029fc85eb49a', 'Pyrotechnics & Special Effects Permit Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Pyrotechnics & Special Effects Permit Compliance Officer — California State Fire Marshal (OSFM); Local Fire AHJ; Cal/OSHA', 'Pyrotechnics & Special Effects Permit Compliance Officer', 'California State Fire Marshal (OSFM); Local Fire AHJ; Cal/OSHA', '', 'OSFM public display permit application (per HSC § 12640), pyrotechnic operator license verification (per HSC § 12640.1), ATF Federal Explosives License (FEL) for storage/use, site-specific safety plan (fallout radius, audience separation distances per NFPA 1123/1126), insurance certificates ($1M+ minimum typical), fire suppression readiness documentation, product inventory and specification sheets, post-display site inspection report, unused product disposition records.', 'SOC 2 Type II — CC6.1 (access to explosive materials — ATF compliance), CC7.2 (monitoring license/permit validity), CC8.1 (change management for display modifications), CC9.1 (safety risk assessment per display). Retention: permit records — 5 years; operator records — active + 5 years; incident records — 10 years.', 'Pyrotechnics/special effects permit documents, fireworks display permit documents');
UPDATE citizen_catalog SET standards_of_creation = 'Temporary structure permit, tent/membrane flame resistance certificate (NFPA 701 or CPAI-84), structural engineering certification for tents over specified size, fire extinguisher placement plan, exit signage/emergency lighting plan, cooking equipment clearance documentation (from tent structures), fire watch personnel assignment, inspection/approval from Fire Marshal before occupancy, generator placement documentation (exhaust/fuel separation).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring pre-event inspection completion), CC8.1 (change management for tent/structure modifications during event), CC3.2 (communication of fire safety violations — immediate correction). Retention: permit records — 3 years per event; flame certificates — 5 years; incident records — 7 years.' WHERE name = 'Event Fire Safety & Temporary Structure Inspection Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3c59c35f6974', 'Event Fire Safety & Temporary Structure Inspection Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Fire Safety & Temporary Structure Inspection Officer — Local Fire Marshal; OSFM; Cal/OSHA', 'Event Fire Safety & Temporary Structure Inspection Officer', 'Local Fire Marshal; OSFM; Cal/OSHA', '', 'Temporary structure permit, tent/membrane flame resistance certificate (NFPA 701 or CPAI-84), structural engineering certification for tents over specified size, fire extinguisher placement plan, exit signage/emergency lighting plan, cooking equipment clearance documentation (from tent structures), fire watch personnel assignment, inspection/approval from Fire Marshal before occupancy, generator placement documentation (exhaust/fuel separation).', 'SOC 2 Type II — CC7.2 (monitoring pre-event inspection completion), CC8.1 (change management for tent/structure modifications during event), CC3.2 (communication of fire safety violations — immediate correction). Retention: permit records — 3 years per event; flame certificates — 5 years; incident records — 7 years.', 'Festival/fair permit documents, special event permit documents (fire component)');
UPDATE citizen_catalog SET standards_of_creation = 'Threat and vulnerability assessment (TVA) per DHS methodology, vehicle mitigation plan (anti-ram barriers), suspicious package/person protocols, active threat response plan (Run-Hide-Fight framework), communication plan (public address, social media, law enforcement coordination), staff training documentation (active shooter awareness), protective security advisor coordination (PSA — DHS), post-incident continuity plan.', soc_controls = 'SOC 2 Type II — CC7.1 (threat monitoring), CC6.1 (access to security intelligence — need-to-know basis), CC3.2 (communication — tiered notification system), CC9.1 (threat/vulnerability risk matrix). Retention: TVA — 5 years (may be classified/FOUO); training records — 5 years; incident records — permanent.' WHERE name = 'Event Counter-Terrorism & Hostile Event Preparedness Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e05d0c97da9f', 'Event Counter-Terrorism & Hostile Event Preparedness Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Counter-Terrorism & Hostile Event Preparedness Officer — DHS; FBI (InfraGard); Local fusion center', 'Event Counter-Terrorism & Hostile Event Preparedness Officer', 'DHS; FBI (InfraGard); Local fusion center', '', 'Threat and vulnerability assessment (TVA) per DHS methodology, vehicle mitigation plan (anti-ram barriers), suspicious package/person protocols, active threat response plan (Run-Hide-Fight framework), communication plan (public address, social media, law enforcement coordination), staff training documentation (active shooter awareness), protective security advisor coordination (PSA — DHS), post-incident continuity plan.', 'SOC 2 Type II — CC7.1 (threat monitoring), CC6.1 (access to security intelligence — need-to-know basis), CC3.2 (communication — tiered notification system), CC9.1 (threat/vulnerability risk matrix). Retention: TVA — 5 years (may be classified/FOUO); training records — 5 years; incident records — permanent.', 'Event security plan documents (counter-terrorism component)');
UPDATE citizen_catalog SET standards_of_creation = 'License/rental agreement (not lease — preserves venue''s possessory interest), certificate of insurance required from event organizer, indemnification provisions, load-in/load-out schedule documentation, utility consumption documentation, damage deposit and inspection records, exclusive service provider compliance (union labor, in-house services), ADA compliance verification for each event configuration, prevailing wage compliance for setup contractors.', soc_controls = 'SOC 2 Type II — CC6.1 (access to contractual records), CC7.2 (monitoring insurance certificate validity), CC3.2 (communication of venue rules/policies to event organizers), CC8.1 (change management for event configuration changes). Retention: contracts — term + 7 years; insurance — 10 years; damage records — 5 years.' WHERE name = 'Convention Center Contract & Operations Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b4a9abd024f2', 'Convention Center Contract & Operations Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Convention Center Contract & Operations Compliance Officer — Convention Center Authority (typically public agency); Local government', 'Convention Center Contract & Operations Compliance Officer', 'Convention Center Authority (typically public agency); Local government', '', 'License/rental agreement (not lease — preserves venue''s possessory interest), certificate of insurance required from event organizer, indemnification provisions, load-in/load-out schedule documentation, utility consumption documentation, damage deposit and inspection records, exclusive service provider compliance (union labor, in-house services), ADA compliance verification for each event configuration, prevailing wage compliance for setup contractors.', 'SOC 2 Type II — CC6.1 (access to contractual records), CC7.2 (monitoring insurance certificate validity), CC3.2 (communication of venue rules/policies to event organizers), CC8.1 (change management for event configuration changes). Retention: contracts — term + 7 years; insurance — 10 years; damage records — 5 years.', 'Convention center contract documents');
UPDATE citizen_catalog SET standards_of_creation = 'Exhibitor agreement/contract, booth design approval (height, sight-line, electrical load), fire-resistant material certificates, insurance certificate (CGL naming show organizer and venue as additional insured), product liability documentation, sampling permit (if distributing food/beverage), business license verification, ADA accessibility within booth, lead retrieval/data privacy compliance (if scanning attendee badges), union labor compliance documentation (where required).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring exhibitor compliance during setup/show), CC6.1 (access to exhibitor data — financial), CC3.2 (communication of show rules), CC8.1 (change management for booth modifications). Retention: exhibitor agreements — 5 years; inspection records — 3 years; insurance — 7 years.' WHERE name = 'Trade Show Exhibitor Agreement & Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8394b1184d3c', 'Trade Show Exhibitor Agreement & Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Trade Show Exhibitor Agreement & Compliance Officer — Show organizer (contractual); IAEE (International Association of Exhibitions and Events); Local jurisdiction', 'Trade Show Exhibitor Agreement & Compliance Officer', 'Show organizer (contractual); IAEE (International Association of Exhibitions and Events); Local jurisdiction', '', 'Exhibitor agreement/contract, booth design approval (height, sight-line, electrical load), fire-resistant material certificates, insurance certificate (CGL naming show organizer and venue as additional insured), product liability documentation, sampling permit (if distributing food/beverage), business license verification, ADA accessibility within booth, lead retrieval/data privacy compliance (if scanning attendee badges), union labor compliance documentation (where required).', 'SOC 2 Type II — CC7.2 (monitoring exhibitor compliance during setup/show), CC6.1 (access to exhibitor data — financial), CC3.2 (communication of show rules), CC8.1 (change management for booth modifications). Retention: exhibitor agreements — 5 years; inspection records — 3 years; insurance — 7 years.', 'Trade show exhibitor agreements');
UPDATE citizen_catalog SET standards_of_creation = 'Entertainment permit documentation, occupancy certificate, ABC license (Type 47, 48, or temporary), music performance rights license (ASCAP + BMI + SESAC blanket), conditional use permit compliance documentation, sound attenuation records, insurance certificates, security staffing plan, accessibility documentation, annual renewal/inspection clearances.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring license renewals — multiple agencies), CC6.1 (access to licensing records), CC3.2 (communication of permit conditions to performers/promoters). Retention: license records — active + 7 years; performance rights — term + 5 years.' WHERE name = 'Concert & Performance Venue License Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9a33785c4fa8', 'Concert & Performance Venue License Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Concert & Performance Venue License Compliance Officer — Local Planning/Zoning; Fire Marshal; ABC; ASCAP/BMI/SESAC', 'Concert & Performance Venue License Compliance Officer', 'Local Planning/Zoning; Fire Marshal; ABC; ASCAP/BMI/SESAC', '', 'Entertainment permit documentation, occupancy certificate, ABC license (Type 47, 48, or temporary), music performance rights license (ASCAP + BMI + SESAC blanket), conditional use permit compliance documentation, sound attenuation records, insurance certificates, security staffing plan, accessibility documentation, annual renewal/inspection clearances.', 'SOC 2 Type II — CC7.2 (monitoring license renewals — multiple agencies), CC6.1 (access to licensing records), CC3.2 (communication of permit conditions to performers/promoters). Retention: license records — active + 7 years; performance rights — term + 5 years.', 'Concert venue license documents');
UPDATE citizen_catalog SET standards_of_creation = 'Venue safety certification, fire marshal occupancy approval, structural engineering certification (seating, press boxes, luxury suites), ADA accessible seating documentation (per 28 CFR § 36.302 — dispersed locations, lines of sight, companion seats), sports field/court safety standards compliance, medical facilities and staffing documentation, alcohol management program, patron code of conduct, ejection/trespass protocols, league facility inspection reports.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring multi-agency and league inspection schedules), CC6.1 (access to venue engineering records), CC9.1 (game-day risk assessment), CC3.2 (communication of safety protocols). Retention: engineering/safety records — permanent; inspection records — 5 years; incident records — 7 years.' WHERE name = 'Sports Venue Safety & Regulatory Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5da754a21226', 'Sports Venue Safety & Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Sports Venue Safety & Regulatory Compliance Officer — Local Building/Fire Department; League governing body; NCS4', 'Sports Venue Safety & Regulatory Compliance Officer', 'Local Building/Fire Department; League governing body; NCS4', '', 'Venue safety certification, fire marshal occupancy approval, structural engineering certification (seating, press boxes, luxury suites), ADA accessible seating documentation (per 28 CFR § 36.302 — dispersed locations, lines of sight, companion seats), sports field/court safety standards compliance, medical facilities and staffing documentation, alcohol management program, patron code of conduct, ejection/trespass protocols, league facility inspection reports.', 'SOC 2 Type II — CC7.2 (monitoring multi-agency and league inspection schedules), CC6.1 (access to venue engineering records), CC9.1 (game-day risk assessment), CC3.2 (communication of safety protocols). Retention: engineering/safety records — permanent; inspection records — 5 years; incident records — 7 years.', 'Sports venue safety documents');
UPDATE citizen_catalog SET standards_of_creation = 'Certificate of insurance (COI) documenting: CGL ($1M occurrence/$2M aggregate minimum), host liquor or liquor liability (if alcohol), workers'' compensation, auto liability (if event vehicles), additional insured endorsements (venue, sponsors, local government as permit condition), professional liability (for event organizers), event cancellation/postponement policy, excess/umbrella liability.', soc_controls = 'SOC 2 Type II — CC9.1 (risk assessment for insurance adequacy), CC7.2 (monitoring COI validity dates — especially for multi-day events), CC6.1 (access to policy documentation), CC3.2 (communication of insurance requirements to vendors/exhibitors). Retention: COIs — event date + 10 years (bodily injury statute of limitations); policies — term + 10 years.' WHERE name = 'Event Insurance & Risk Transfer Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-10197cd1357d', 'Event Insurance & Risk Transfer Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Insurance & Risk Transfer Compliance Officer — California Department of Insurance; Venue requirements; Local permit conditions', 'Event Insurance & Risk Transfer Compliance Officer', 'California Department of Insurance; Venue requirements; Local permit conditions', '', 'Certificate of insurance (COI) documenting: CGL ($1M occurrence/$2M aggregate minimum), host liquor or liquor liability (if alcohol), workers'' compensation, auto liability (if event vehicles), additional insured endorsements (venue, sponsors, local government as permit condition), professional liability (for event organizers), event cancellation/postponement policy, excess/umbrella liability.', 'SOC 2 Type II — CC9.1 (risk assessment for insurance adequacy), CC7.2 (monitoring COI validity dates — especially for multi-day events), CC6.1 (access to policy documentation), CC3.2 (communication of insurance requirements to vendors/exhibitors). Retention: COIs — event date + 10 years (bodily injury statute of limitations); policies — term + 10 years.', 'Event insurance/liability documents');
UPDATE citizen_catalog SET standards_of_creation = 'Cal/OSHA permit to operate (per Lab. Code § 7906 — each ride, each event), annual ride inspection certificate, operator training documentation, ride-specific inspection checklist (pre-opening daily), maintenance and repair log, incident/injury reporting per Lab. Code § 7924, insurance documentation (specific amusement ride liability), manufacturer maintenance manual compliance documentation, inflatable-specific anchoring and wind speed protocols.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring permit validity per ride per event), CC8.1 (change management for ride modifications), CC6.1 (access to maintenance/inspection records), CC9.1 (weather-related risk assessment — inflatables). Retention: permit records — 5 years per ride; inspection records — life of ride; incident records — 10 years.' WHERE name = 'Amusement Ride & Inflatable Device Inspection Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b6d1fbdb047e', 'Amusement Ride & Inflatable Device Inspection Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Amusement Ride & Inflatable Device Inspection Compliance Officer — California Division of Occupational Safety and Health (Cal/OSHA) — Amusement Ride Unit', 'Amusement Ride & Inflatable Device Inspection Compliance Officer', 'California Division of Occupational Safety and Health (Cal/OSHA) — Amusement Ride Unit', '', 'Cal/OSHA permit to operate (per Lab. Code § 7906 — each ride, each event), annual ride inspection certificate, operator training documentation, ride-specific inspection checklist (pre-opening daily), maintenance and repair log, incident/injury reporting per Lab. Code § 7924, insurance documentation (specific amusement ride liability), manufacturer maintenance manual compliance documentation, inflatable-specific anchoring and wind speed protocols.', 'SOC 2 Type II — CC7.2 (monitoring permit validity per ride per event), CC8.1 (change management for ride modifications), CC6.1 (access to maintenance/inspection records), CC9.1 (weather-related risk assessment — inflatables). Retention: permit records — 5 years per ride; inspection records — life of ride; incident records — 10 years.', 'Inflatable/amusement ride inspection documents');
UPDATE citizen_catalog SET standards_of_creation = 'Vendor permit verification checklist (health permit, business license, fire department approval, seller''s permit), commissary agreement documentation (per HSC § 113996), insurance certificates from each vendor, food handler certifications, vehicle inspection records, propane/generator safety compliance documentation, allergen disclosure documentation, vendor map/site plan showing spacing, fire lanes, and utility connections.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring vendor permit validity — each vendor at each event), CC3.2 (communication of event-specific vendor requirements), CC6.1 (access to vendor compliance documentation). Retention: vendor records — 3 years per event; health inspection — 3 years; insurance — 5 years.' WHERE name = 'Event Vendor & Mobile Food Facility Permit Coordinator';
