UPDATE citizen_catalog SET standards_of_creation = 'Event accessibility plan (accessible parking, path of travel, seating, restrooms, food service), sign language interpreter/CART arrangements, assistive listening device inventory, accessible event registration (online and in-person), service animal policy, accessible emergency evacuation procedures, accessibility coordinator contact published, accessible transportation to/from event, accessible information formats (large print, Braille, digital).', soc_controls = 'SOC 2 Type II — CC3.2 (communication of accessibility features — pre-event), CC7.2 (monitoring accommodation request fulfillment), CC1.4 (staff disability awareness training), CC9.1 (accessibility risk assessment per venue configuration). Retention: accommodation records — 5 years; complaint records — 5 years; plans — 3 years per event.' WHERE name = 'Event ADA Accessibility Compliance Officer';
