UPDATE citizen_catalog SET standards_of_creation = 'Interpreter/captioner procurement records (RID-certified or equivalent), service agreements, real-time captioning (CART) technology setup documentation, ASL interpreter team scheduling (per fatigue standards — 20–30 minute rotations), captioning accuracy targets (98%+), platform accessibility for virtual/hybrid events, attendee accommodation request log and fulfillment records.', soc_controls = 'SOC 2 Type II — CC3.2 (communication accuracy), CC7.2 (monitoring service quality during event), CC6.1 (access to accommodation request records). Retention: service agreements — 5 years; accommodation records — 5 years.' WHERE name = 'Event Communication Access Compliance Officer';
