UPDATE citizen_catalog SET standards_of_creation = 'WCAG 2.1 AA audit report for all event digital properties, accessible registration form documentation, event app accessibility testing records, virtual platform accessibility evaluation, alternative format production records (captions, audio descriptions, screen-reader compatible documents), Wi-Fi reliability for assistive technology, charging stations for mobility devices.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring digital accessibility — pre-launch testing), CC3.2 (communication of digital accessibility features), CC8.1 (change management for platform updates affecting accessibility). Retention: audit reports — 5 years; testing records — 3 years.' WHERE name = 'Event Digital Accessibility & Inclusion Technology Officer';
