UPDATE citizen_catalog SET standards_of_creation = 'Remote pilot certificate (14 CFR § 107.12), FAA waiver documentation (if over people/night/beyond visual line of sight), LAANC authorization (if in controlled airspace), event-specific flight plan, operator insurance ($1M+ typical for event work), risk assessment per flight, crew assignments (remote pilot in command, visual observers), battery management documentation, pre-flight checklist records, post-flight log, local authorization/notification records.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring FAA waiver conditions), CC6.1 (access to flight records), CC9.1 (risk assessment per flight — crowd proximity, weather), CC3.2 (communication with event security and ATC). Retention: flight records — 3 years (per 14 CFR § 107.49); waiver records — waiver term + 3 years; insurance — 5 years.' WHERE name = 'Unmanned Aircraft Systems (UAS) Event Operations Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7acab0dce1a9', 'Unmanned Aircraft Systems (UAS) Event Operations Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Unmanned Aircraft Systems (UAS) Event Operations Compliance Officer — Federal Aviation Administration (FAA); Local jurisdiction', 'Unmanned Aircraft Systems (UAS) Event Operations Compliance Officer', 'Federal Aviation Administration (FAA); Local jurisdiction', '', 'Remote pilot certificate (14 CFR § 107.12), FAA waiver documentation (if over people/night/beyond visual line of sight), LAANC authorization (if in controlled airspace), event-specific flight plan, operator insurance ($1M+ typical for event work), risk assessment per flight, crew assignments (remote pilot in command, visual observers), battery management documentation, pre-flight checklist records, post-flight log, local authorization/notification records.', 'SOC 2 Type II — CC7.2 (monitoring FAA waiver conditions), CC6.1 (access to flight records), CC9.1 (risk assessment per flight — crowd proximity, weather), CC3.2 (communication with event security and ATC). Retention: flight records — 3 years (per 14 CFR § 107.49); waiver records — waiver term + 3 years; insurance — 5 years.', 'Drone operation at events compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Filming/photography permit from local jurisdiction, venue authorization, talent/model releases (per CIV § 3344), crowd notification/signage (event photography occurring — consent by entry), minor photography consent (parental), drone aerial permit (if applicable — see C6-01), equipment placement plan (cables, cranes, camera platforms — safety review), insurance certificates, music synchronization licenses, location agreement.', soc_controls = 'SOC 2 Type II — CC6.1 (access to release forms/consent records), PI1.1 (privacy of individuals photographed/filmed), CC7.2 (monitoring permit conditions — shoot hours, locations), CC3.2 (notification to attendees about filming). Retention: permit records — 5 years; release forms — 7 years; content ownership records — life of copyright.' WHERE name = 'Event Filming & Photography Permit Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-0e591960d104', 'Event Filming & Photography Permit Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Filming & Photography Permit Compliance Officer — Local Film Commission/Office; State Film Commission; Property owner', 'Event Filming & Photography Permit Compliance Officer', 'Local Film Commission/Office; State Film Commission; Property owner', '', 'Filming/photography permit from local jurisdiction, venue authorization, talent/model releases (per CIV § 3344), crowd notification/signage (event photography occurring — consent by entry), minor photography consent (parental), drone aerial permit (if applicable — see C6-01), equipment placement plan (cables, cranes, camera platforms — safety review), insurance certificates, music synchronization licenses, location agreement.', 'SOC 2 Type II — CC6.1 (access to release forms/consent records), PI1.1 (privacy of individuals photographed/filmed), CC7.2 (monitoring permit conditions — shoot hours, locations), CC3.2 (notification to attendees about filming). Retention: permit records — 5 years; release forms — 7 years; content ownership records — life of copyright.', 'Event filming/photography permits');
