INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-cd2e8a1d26f9', 'Event Waste Diversion & Environmental Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Waste Diversion & Environmental Compliance Officer — CalRecycle; Local Waste Management Authority', 'Event Waste Diversion & Environmental Compliance Officer', 'CalRecycle; Local Waste Management Authority', '', 'Event waste management plan (recycling, composting, landfill — three-stream minimum), waste diversion rate targets (local requirements — e.g., SF requires 100% diversion goal), vendor requirements for compostable/recyclable serviceware, waste hauler contracts and diversion reporting, post-event waste audit report, hazardous waste management (batteries, e-waste, paint from build/strike), prohibited materials list (e.g., SF polystyrene ban), signage and bin placement plan.', 'SOC 2 Type II — CC7.2 (monitoring diversion rate compliance), CC3.2 (communication of waste sorting requirements to vendors/attendees), CC8.1 (change management for serviceware specifications). Retention: waste audit reports — 5 years; hauler records — 3 years; diversion reports — 5 years.', 'Event waste management/recycling compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Alcohol service plan (service area demarcation, ID check stations, drink limit management, intoxication monitoring), RBS certification for all servers and security at alcohol service points, age verification training documentation, designated driver / ride-share information, alcohol-free zone enforcement, wristband/ID system documentation, incident log (refusals, intoxicated persons, underage attempts), last-call procedures.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring service hours and server certification), CC1.4 (training verification), CC3.2 (communication of responsible service protocols), CC6.1 (incident log security). Retention: service records — 5 years per event; training — 3 years; incident logs — 7 years.' WHERE name = 'Event On-Site Alcohol Service Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-366841c82d07', 'Event On-Site Alcohol Service Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event On-Site Alcohol Service Compliance Officer — California ABC; Local law enforcement', 'Event On-Site Alcohol Service Compliance Officer', 'California ABC; Local law enforcement', '', 'Alcohol service plan (service area demarcation, ID check stations, drink limit management, intoxication monitoring), RBS certification for all servers and security at alcohol service points, age verification training documentation, designated driver / ride-share information, alcohol-free zone enforcement, wristband/ID system documentation, incident log (refusals, intoxicated persons, underage attempts), last-call procedures.', 'SOC 2 Type II — CC7.2 (monitoring service hours and server certification), CC1.4 (training verification), CC3.2 (communication of responsible service protocols), CC6.1 (incident log security). Retention: service records — 5 years per event; training — 3 years; incident logs — 7 years.', 'Temporary liquor license documents (on-site management component)');
UPDATE citizen_catalog SET standards_of_creation = 'Event sustainability management plan per ISO 20121, carbon footprint calculation (travel, energy, waste, catering — Scope 1/2/3), offset procurement documentation (verified offsets from recognized registries), sustainable procurement policy (local sourcing, fair trade), waste diversion documentation (cross-reference C6-03), energy efficiency measures, water conservation, social sustainability metrics, post-event sustainability report, third-party verification (if claiming carbon-neutral status).', soc_controls = 'SOC 2 Type II — CC3.2 (accuracy of sustainability claims — greenwashing prevention), CC7.2 (monitoring offset verification status), CC8.1 (change management for sustainability targets). Retention: sustainability reports — 7 years; offset certificates — offset period + 5 years; carbon calculations — 5 years.' WHERE name = 'Event Sustainability & Carbon Offset Verification Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-834d6f50b100', 'Event Sustainability & Carbon Offset Verification Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Sustainability & Carbon Offset Verification Officer — ISO; UNFCCC (carbon offset registries); Local green event programs', 'Event Sustainability & Carbon Offset Verification Officer', 'ISO; UNFCCC (carbon offset registries); Local green event programs', '', 'Event sustainability management plan per ISO 20121, carbon footprint calculation (travel, energy, waste, catering — Scope 1/2/3), offset procurement documentation (verified offsets from recognized registries), sustainable procurement policy (local sourcing, fair trade), waste diversion documentation (cross-reference C6-03), energy efficiency measures, water conservation, social sustainability metrics, post-event sustainability report, third-party verification (if claiming carbon-neutral status).', 'SOC 2 Type II — CC3.2 (accuracy of sustainability claims — greenwashing prevention), CC7.2 (monitoring offset verification status), CC8.1 (change management for sustainability targets). Retention: sustainability reports — 7 years; offset certificates — offset period + 5 years; carbon calculations — 5 years.', 'Event waste management/recycling compliance documents (sustainability component)');
UPDATE citizen_catalog SET standards_of_creation = 'Privacy policy (CCPA-compliant, GDPR-compliant if applicable), registration data collection notice (purpose limitation, retention period, sharing with sponsors), opt-in consent documentation (for sponsor lead sharing), badge scanning disclosure, PCI compliance for payment processing, data processing agreements with registration platform vendors, DSAR procedures, post-event data deletion schedule, marketing consent management (separate opt-in per CAN-SPAM/TCPA).', soc_controls = 'SOC 2 Type II — CC6.1 (access to attendee PII), PI1.1–PI1.5 (privacy criteria), CC6.6 (payment environment segmentation), CC7.2 (monitoring data retention/deletion schedule), CC3.2 (communication of privacy practices). Retention: registration data — per disclosed retention period; financial records — 7 years; consent records — 7 years.' WHERE name = 'Event Registration & Attendee Data Privacy Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-929af0589877', 'Event Registration & Attendee Data Privacy Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Registration & Attendee Data Privacy Compliance Officer — California AG (CCPA/CPRA); FTC; EU Commission (GDPR — for international events)', 'Event Registration & Attendee Data Privacy Compliance Officer', 'California AG (CCPA/CPRA); FTC; EU Commission (GDPR — for international events)', '', 'Privacy policy (CCPA-compliant, GDPR-compliant if applicable), registration data collection notice (purpose limitation, retention period, sharing with sponsors), opt-in consent documentation (for sponsor lead sharing), badge scanning disclosure, PCI compliance for payment processing, data processing agreements with registration platform vendors, DSAR procedures, post-event data deletion schedule, marketing consent management (separate opt-in per CAN-SPAM/TCPA).', 'SOC 2 Type II — CC6.1 (access to attendee PII), PI1.1–PI1.5 (privacy criteria), CC6.6 (payment environment segmentation), CC7.2 (monitoring data retention/deletion schedule), CC3.2 (communication of privacy practices). Retention: registration data — per disclosed retention period; financial records — 7 years; consent records — 7 years.', 'Event registration data privacy documents (cross-cutting)');
UPDATE citizen_catalog SET standards_of_creation = 'Broadcast/streaming rights agreements, music synchronization and public performance licenses (both traditional PRO + digital streaming rights), closed captioning production documentation, audio description (if applicable), platform terms compliance documentation, content moderation plan (for chat/comments), recording consent notices (performers, speakers, attendees), archive/VOD rights documentation, COPPA compliance (if child-directed content), territorial licensing documentation (international streaming).', soc_controls = 'SOC 2 Type II — CC6.1 (access to content and viewer data), CC3.2 (accuracy of rights clearance), CC7.2 (monitoring stream quality and captioning), PI1.1 (viewer data privacy). Retention: rights agreements — term + 7 years; content archives — per agreement; viewer data — per platform policy and CCPA.' WHERE name = 'Event Live-Streaming & Broadcast Regulatory Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1e02fc2c7c67', 'Event Live-Streaming & Broadcast Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Live-Streaming & Broadcast Regulatory Compliance Officer — FCC; Copyright Office; Platform terms (YouTube, Twitch, etc.)', 'Event Live-Streaming & Broadcast Regulatory Compliance Officer', 'FCC; Copyright Office; Platform terms (YouTube, Twitch, etc.)', '', 'Broadcast/streaming rights agreements, music synchronization and public performance licenses (both traditional PRO + digital streaming rights), closed captioning production documentation, audio description (if applicable), platform terms compliance documentation, content moderation plan (for chat/comments), recording consent notices (performers, speakers, attendees), archive/VOD rights documentation, COPPA compliance (if child-directed content), territorial licensing documentation (international streaming).', 'SOC 2 Type II — CC6.1 (access to content and viewer data), CC3.2 (accuracy of rights clearance), CC7.2 (monitoring stream quality and captioning), PI1.1 (viewer data privacy). Retention: rights agreements — term + 7 years; content archives — per agreement; viewer data — per platform policy and CCPA.', 'Event filming/photography permits (streaming component)');
UPDATE citizen_catalog SET standards_of_creation = 'Event network architecture documentation, WiFi deployment plan (separate public/operations/POS networks), PCI compliance documentation for all payment acceptance points, credential management plan (staff access to event systems), temporary infrastructure security hardening checklist, incident response plan (for event duration), backup connectivity plan, decommissioning/data destruction plan (post-event tear-down of temporary infrastructure).', soc_controls = 'SOC 2 Type II — CC6.1/CC6.6 (network segmentation and access control), CC7.1 (monitoring — event-duration security operations), CC7.2 (pre-event security testing), CC8.1 (change management for live event modifications), A1.2 (availability — redundant connectivity). Retention: network logs — 90 days post-event; PCI evidence — 1 year; incident records — 5 years; architecture docs — 3 years.' WHERE name = 'Event Cybersecurity & Temporary Network Operations Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f30e17aa1249', 'Event Cybersecurity & Temporary Network Operations Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Event Cybersecurity & Temporary Network Operations Officer — PCI SSC; NIST; California AG (breach notification)', 'Event Cybersecurity & Temporary Network Operations Officer', 'PCI SSC; NIST; California AG (breach notification)', '', 'Event network architecture documentation, WiFi deployment plan (separate public/operations/POS networks), PCI compliance documentation for all payment acceptance points, credential management plan (staff access to event systems), temporary infrastructure security hardening checklist, incident response plan (for event duration), backup connectivity plan, decommissioning/data destruction plan (post-event tear-down of temporary infrastructure).', 'SOC 2 Type II — CC6.1/CC6.6 (network segmentation and access control), CC7.1 (monitoring — event-duration security operations), CC7.2 (pre-event security testing), CC8.1 (change management for live event modifications), A1.2 (availability — redundant connectivity). Retention: network logs — 90 days post-event; PCI evidence — 1 year; incident records — 5 years; architecture docs — 3 years.', 'Event data security compliance documents (cross-cutting)');
UPDATE citizen_catalog SET standards_of_creation = 'Consolidated fair permit application (all agencies), Cal/OSHA ride permits per ride, TFF permits per food vendor, alcohol license (if applicable), entertainment permits, animal exhibition health certificates (if livestock — per Cal. Food & Ag. Code), midway safety plan, cash handling/ATM security plan, lost child protocol, animal care protocols (if petting zoo/livestock).', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring multi-vendor, multi-ride, multi-agency compliance simultaneously), CC9.1 (comprehensive risk assessment), CC3.2 (real-time communication with all agencies). Retention: fair records — 5 years; ride records — per Cal/OSHA; food records — 3 years.' WHERE name = 'Festival & Fair Comprehensive Permit Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1f6648025110', 'Festival & Fair Comprehensive Permit Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Festival & Fair Comprehensive Permit Compliance Officer — California Department of Food and Agriculture (state fairs); Local multi-agency', 'Festival & Fair Comprehensive Permit Compliance Officer', 'California Department of Food and Agriculture (state fairs); Local multi-agency', '', 'Consolidated fair permit application (all agencies), Cal/OSHA ride permits per ride, TFF permits per food vendor, alcohol license (if applicable), entertainment permits, animal exhibition health certificates (if livestock — per Cal. Food & Ag. Code), midway safety plan, cash handling/ATM security plan, lost child protocol, animal care protocols (if petting zoo/livestock).', 'SOC 2 Type II — CC7.2 (monitoring multi-vendor, multi-ride, multi-agency compliance simultaneously), CC9.1 (comprehensive risk assessment), CC3.2 (real-time communication with all agencies). Retention: fair records — 5 years; ride records — per Cal/OSHA; food records — 3 years.', 'Festival/fair permit documents');
UPDATE citizen_catalog SET standards_of_creation = 'Special use permit application (agency-specific — 180+ days advance for federal land), environmental assessment (NEPA/CEQA), fire prevention plan (CalFire review during fire season), wildlife impact assessment, sanitation plan (portable restrooms, grey water, waste pack-out), water source protection plan, search and rescue coordination, wilderness first aid/medical plan, erosion/vegetation protection plan, cultural resource survey, post-event restoration plan.', soc_controls = 'SOC 2 Type II — CC7.2 (monitoring permit conditions — environmental protections), CC8.1 (change management — weather/fire condition adaptations), CC9.1 (environmental and safety risk assessment), CC3.2 (communication with land management agency). Retention: permit records — 7 years; environmental assessments — permanent; restoration records — 5 years.' WHERE name = 'Outdoor & Wilderness Event Permit Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-affeebce1035', 'Outdoor & Wilderness Event Permit Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Outdoor & Wilderness Event Permit Compliance Officer — USFS (Forest Service); BLM; NPS; Cal. Department of Parks & Recreation; CalFire', 'Outdoor & Wilderness Event Permit Compliance Officer', 'USFS (Forest Service); BLM; NPS; Cal. Department of Parks & Recreation; CalFire', '', 'Special use permit application (agency-specific — 180+ days advance for federal land), environmental assessment (NEPA/CEQA), fire prevention plan (CalFire review during fire season), wildlife impact assessment, sanitation plan (portable restrooms, grey water, waste pack-out), water source protection plan, search and rescue coordination, wilderness first aid/medical plan, erosion/vegetation protection plan, cultural resource survey, post-event restoration plan.', 'SOC 2 Type II — CC7.2 (monitoring permit conditions — environmental protections), CC8.1 (change management — weather/fire condition adaptations), CC9.1 (environmental and safety risk assessment), CC3.2 (communication with land management agency). Retention: permit records — 7 years; environmental assessments — permanent; restoration records — 5 years.', 'Special event permit documents (outdoor component)');
UPDATE citizen_catalog SET standards_of_creation = 'Platform accessibility audit, privacy policy (jurisdictions of all attendees), data processing agreements with platform vendor, recording/consent notices, chat moderation policy, virtual networking data sharing consent, tax nexus analysis per attendee jurisdiction, digital content rights management, breakout room security protocols, attendee verification procedures, accessible presentation guidelines for speakers.', soc_controls = 'SOC 2 Type II — CC6.1 (access to virtual platform — authentication), PI1.1 (attendee data privacy across jurisdictions), CC6.6 (platform security assessment), CC7.2 (monitoring platform uptime and accessibility), CC3.2 (communication of participation terms). Retention: registration data — per privacy policy; recordings — per content agreement; platform logs — 1 year.' WHERE name = 'Virtual & Hybrid Event Regulatory Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-717c0a6492ec', 'Virtual & Hybrid Event Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Virtual & Hybrid Event Regulatory Compliance Officer — FTC; California AG; FCC; International privacy authorities', 'Virtual & Hybrid Event Regulatory Compliance Officer', 'FTC; California AG; FCC; International privacy authorities', '', 'Platform accessibility audit, privacy policy (jurisdictions of all attendees), data processing agreements with platform vendor, recording/consent notices, chat moderation policy, virtual networking data sharing consent, tax nexus analysis per attendee jurisdiction, digital content rights management, breakout room security protocols, attendee verification procedures, accessible presentation guidelines for speakers.', 'SOC 2 Type II — CC6.1 (access to virtual platform — authentication), PI1.1 (attendee data privacy across jurisdictions), CC6.6 (platform security assessment), CC7.2 (monitoring platform uptime and accessibility), CC3.2 (communication of participation terms). Retention: registration data — per privacy policy; recordings — per content agreement; platform logs — 1 year.', 'Event data privacy and virtual event compliance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Contribution tracking documentation (per attendee — name, address, employer, amount), FEC/FPPC reporting filings, solicitation disclosures ("Paid for by" requirements), venue rental at fair market value documentation (to avoid in-kind contribution), corporate/PAC participation limitations documentation, gift limit compliance for public official attendees, tax-exempt status considerations, event security plan (political events — heightened threat assessment), counter-protest management plan.', soc_controls = 'SOC 2 Type II — CC6.1 (access to donor/contribution data), CC7.2 (monitoring contribution limits and reporting deadlines), CC3.2 (communication of disclosure requirements), PI1.1 (donor privacy within legal disclosure obligations). Retention: FEC records — 3 years post-election; FPPC — 4 years; contribution records — 7 years; security plans — 5 years.' WHERE name = 'Political & Advocacy Event Regulatory Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4baa537de55c', 'Political & Advocacy Event Regulatory Compliance Officer', 'Hotels Tourism Events Compliance', 'Hotels Tourism Events', 'Political & Advocacy Event Regulatory Compliance Officer — Federal Election Commission (FEC); California Fair Political Practices Commission (FPPC); Local ethics commission', 'Political & Advocacy Event Regulatory Compliance Officer', 'Federal Election Commission (FEC); California Fair Political Practices Commission (FPPC); Local ethics commission', '', 'Contribution tracking documentation (per attendee — name, address, employer, amount), FEC/FPPC reporting filings, solicitation disclosures ("Paid for by" requirements), venue rental at fair market value documentation (to avoid in-kind contribution), corporate/PAC participation limitations documentation, gift limit compliance for public official attendees, tax-exempt status considerations, event security plan (political events — heightened threat assessment), counter-protest management plan.', 'SOC 2 Type II — CC6.1 (access to donor/contribution data), CC7.2 (monitoring contribution limits and reporting deadlines), CC3.2 (communication of disclosure requirements), PI1.1 (donor privacy within legal disclosure obligations). Retention: FEC records — 3 years post-election; FPPC — 4 years; contribution records — 7 years; security plans — 5 years.', 'Political event compliance documents (cross-cutting)');
UPDATE citizen_catalog SET standards_of_creation = 'Job postings must include EEO taglines and comply with OFCCP internet applicant rule (41 CFR 60-1.3); applicant flow logs must capture race/gender/disability/veteran data; EEO-1 Component 1 reports due annually by prescribed deadline; VETS-4212 reports due September 30 annually; affirmative action plans for federal contractors with 50+ employees and $50K+ contracts must contain workforce analysis, job group analysis, availability analysis, and placement goals per 41 CFR 60-2', soc_controls = 'Applicant data segregated from hiring managers; EEO data maintained separately from personnel files; affirmative action plan access restricted to compliance personnel; retention per OFCCP (2 years for contractors, 1 year EEOC); audit trail on all dispositioning decisions' WHERE name = 'Equal Employment Opportunity / OFCCP Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b08febe2c60b', 'Equal Employment Opportunity / OFCCP Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Equal Employment Opportunity / OFCCP Compliance Specialist — U.S. Equal Employment Opportunity Commission (EEOC); Office of Federal Contract Compliance Programs (OFCCP); California Civil Rights Department (CRD)', 'Equal Employment Opportunity / OFCCP Compliance Specialist', 'U.S. Equal Employment Opportunity Commission (EEOC); Office of Federal Contract Compliance Programs (OFCCP); California Civil Rights Department (CRD)', 'Title VII of the Civil Rights Act (42 USC 2000e); Executive Order 11246 (federal contractor affirmative action); 41 CFR Parts 60-1 through 60-741 (OFCCP regulations); Cal. Gov. Code 12940-12951 (FEHA employment discrimination); 29 CFR Part 1602 (EEO-1 reporting requirements); VEVRAA (38 USC 4212); Section 503 of the Rehabilitation Act (29 USC 793); 41 CFR 60-300 (VETS-4212 filing requirements)', 'Job postings must include EEO taglines and comply with OFCCP internet applicant rule (41 CFR 60-1.3); applicant flow logs must capture race/gender/disability/veteran data; EEO-1 Component 1 reports due annually by prescribed deadline; VETS-4212 reports due September 30 annually; affirmative action plans for federal contractors with 50+ employees and $50K+ contracts must contain workforce analysis, job group analysis, availability analysis, and placement goals per 41 CFR 60-2', 'Applicant data segregated from hiring managers; EEO data maintained separately from personnel files; affirmative action plan access restricted to compliance personnel; retention per OFCCP (2 years for contractors, 1 year EEOC); audit trail on all dispositioning decisions', 'Job posting compliance documents, application/resume screening compliance, EEO-1 reporting documents, VETS-4212 reporting, affirmative action plan documents (OFCCP), pay equity audit documents');
UPDATE citizen_catalog SET standards_of_creation = 'Standalone written disclosure required before obtaining consumer report (15 USC 1681b(b)(2)); pre-adverse action notice must include copy of report and FCRA summary of rights; adverse action notice must identify CRA with contact info; California requires 5-business-day waiting period under ICRAA before adverse action; individualized assessment required per EEOC guidance; Ban the Box compliance requires conditional offer before inquiry into conviction history (Cal. Gov. Code 12952)', soc_controls = 'Background check results stored separately from personnel files; access restricted to authorized HR personnel only; consumer report destruction per FCRA Disposal Rule (16 CFR 682); documentation of individualized assessment for any adverse decision; vendor (CRA) due diligence and contracts per FCRA permissible purpose requirements' WHERE name = 'Consumer Reporting Compliance Specialist (FCRA/ICRAA)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f9a1b26ac9da', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA)', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA) — Federal Trade Commission (FTC); Consumer Financial Protection Bureau (CFPB); California Department of Justice (for ICRAA)', 'Consumer Reporting Compliance Specialist (FCRA/ICRAA)', 'Federal Trade Commission (FTC); Consumer Financial Protection Bureau (CFPB); California Department of Justice (for ICRAA)', 'Fair Credit Reporting Act (15 USC 1681 et seq.); 16 CFR Part 698 (FTC FCRA rules); Cal. Civ. Code 1785.1-1785.36 (Consumer Credit Reporting Agencies Act); Cal. Civ. Code 1786-1786.60 (Investigative Consumer Reporting Agencies Act / ICRAA); Cal. Lab. Code 432.7 (restrictions on arrest/conviction records); Cal. Gov. Code 12952 (Fair Chance Act / Ban the Box); EEOC Enforcement Guidance on arrest/conviction records (2012, updated)', 'Standalone written disclosure required before obtaining consumer report (15 USC 1681b(b)(2)); pre-adverse action notice must include copy of report and FCRA summary of rights; adverse action notice must identify CRA with contact info; California requires 5-business-day waiting period under ICRAA before adverse action; individualized assessment required per EEOC guidance; Ban the Box compliance requires conditional offer before inquiry into conviction history (Cal. Gov. Code 12952)', 'Background check results stored separately from personnel files; access restricted to authorized HR personnel only; consumer report destruction per FCRA Disposal Rule (16 CFR 682); documentation of individualized assessment for any adverse decision; vendor (CRA) due diligence and contracts per FCRA permissible purpose requirements', 'Background check compliance documents (FCRA, Ban the Box, state laws), pre-employment drug testing documents');
UPDATE citizen_catalog SET standards_of_creation = 'I-9 Section 1 completed by employee no later than first day of employment; Section 2 completed by employer within 3 business days of start date; List A or List B + List C documents examined physically (or remotely per DHS-authorized alternative); I-9 retained for 3 years from hire or 1 year from separation (whichever later); E-Verify case created within 3 business days of start; reverification required only for documents with expiration (not for List B documents or US passports/green cards)', soc_controls = 'I-9 forms stored separately from personnel files; no over-documentation or document abuse (anti-discrimination); E-Verify records maintained per MOU retention schedule; audit trail for reverification; designated I-9 authorized representatives trained annually' WHERE name = 'Employment Eligibility Verification Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-15fe4f48e716', 'Employment Eligibility Verification Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Employment Eligibility Verification Specialist — U.S. Citizenship and Immigration Services (USCIS); Immigration and Customs Enforcement (ICE); U.S. Department of Justice, Immigrant and Employee Rights Section (IER)', 'Employment Eligibility Verification Specialist', 'U.S. Citizenship and Immigration Services (USCIS); Immigration and Customs Enforcement (ICE); U.S. Department of Justice, Immigrant and Employee Rights Section (IER)', 'Immigration and Nationality Act (8 USC 1324a -- employer sanctions); 8 CFR 274a.2 (Form I-9 requirements); E-Verify MOU and federal contractor E-Verify requirements (FAR 52.222-54); INA anti-discrimination provisions (8 USC 1324b); Cal. Lab. Code 1019 (restrictions on employer immigration-related actions); Cal. Lab. Code 1019.1 (immigration-related unfair practices); Cal. Gov. Code 7285 (California Values Act applicability to employers)', 'I-9 Section 1 completed by employee no later than first day of employment; Section 2 completed by employer within 3 business days of start date; List A or List B + List C documents examined physically (or remotely per DHS-authorized alternative); I-9 retained for 3 years from hire or 1 year from separation (whichever later); E-Verify case created within 3 business days of start; reverification required only for documents with expiration (not for List B documents or US passports/green cards)', 'I-9 forms stored separately from personnel files; no over-documentation or document abuse (anti-discrimination); E-Verify records maintained per MOU retention schedule; audit trail for reverification; designated I-9 authorized representatives trained annually', 'I-9 employment eligibility verification, E-Verify documents, new hire reporting documents');
UPDATE citizen_catalog SET standards_of_creation = 'Offer letters must not request salary history (Cal. Lab. Code 432.3); must provide pay scale for position upon reasonable request and in job postings for 15+ employees (SB 1162); Cal. Lab. Code 2810.5 notice must be provided at hire (rate of pay, pay period, employer name/address, workers'' comp carrier, paid sick leave); at-will disclaimers must not be contradicted by handbook or verbal representations; arbitration clauses subject to Cal. Lab. Code 432.6 (AB 51 -- voluntary consent requirement, currently enjoined/in litigation but compliance recommended)', soc_controls = 'Offer letter templates reviewed by legal annually; version control on all agreement templates; salary ranges documented and matched to job postings; signature/acceptance tracking; separate storage of executed agreements' WHERE name = 'Employment Offer / Agreement Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ffec321b026e', 'Employment Offer / Agreement Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Employment Offer / Agreement Compliance Specialist — California Labor Commissioner (DLSE); EEOC; State taxing authorities', 'Employment Offer / Agreement Compliance Specialist', 'California Labor Commissioner (DLSE); EEOC; State taxing authorities', 'Cal. Lab. Code 2922 (at-will employment); Cal. Lab. Code 432.3 (salary history ban); Cal. Lab. Code 1197.5 (Equal Pay Act); SB 1162 (Cal. Lab. Code 432.3(c) -- pay scale disclosure in job postings); Cal. Gov. Code 12940 (FEHA -- offer contingencies); Cal. Lab. Code 2810.5 (notice to employee at time of hire); applicable city/county fair chance and pay transparency ordinances (SF, LA, NYC equivalents)', 'Offer letters must not request salary history (Cal. Lab. Code 432.3); must provide pay scale for position upon reasonable request and in job postings for 15+ employees (SB 1162); Cal. Lab. Code 2810.5 notice must be provided at hire (rate of pay, pay period, employer name/address, workers'' comp carrier, paid sick leave); at-will disclaimers must not be contradicted by handbook or verbal representations; arbitration clauses subject to Cal. Lab. Code 432.6 (AB 51 -- voluntary consent requirement, currently enjoined/in litigation but compliance recommended)', 'Offer letter templates reviewed by legal annually; version control on all agreement templates; salary ranges documented and matched to job postings; signature/acceptance tracking; separate storage of executed agreements', 'Offer letter/employment agreement documents, non-compete/non-solicitation documents, arbitration agreement documents, employee invention assignment documents, trade secret protection documents');
UPDATE citizen_catalog SET standards_of_creation = 'Personnel file must be organized and available for employee inspection at reasonable times within 30 calendar days of written request; copies provided at employee''s cost or free if mailed; medical records maintained separately per ADA/FEHA/HIPAA; no inclusion of investigation records of other employees; CCPA privacy notices for employee data required; response to employee data requests within 45 days under CPRA', soc_controls = 'Personnel files in locked/secured storage (physical or encrypted digital); access restricted to HR and direct management with logged access; medical files physically separate from personnel files; retention schedules enforced with documented destruction; litigation hold procedures for anticipated claims' WHERE name = 'Personnel Records and Privacy Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-18dc3b8c9992', 'Personnel Records and Privacy Compliance Manager', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Personnel Records and Privacy Compliance Manager — California Labor Commissioner (DLSE); California Attorney General (CCPA enforcement); EEOC', 'Personnel Records and Privacy Compliance Manager', 'California Labor Commissioner (DLSE); California Attorney General (CCPA enforcement); EEOC', 'Cal. Lab. Code 1198.5 (employee right to inspect personnel file within 30 days; employer must make available for inspection or provide copy); Cal. Lab. Code 432 (employee right to copy of signed documents); Cal. Civ. Code 1798.100-1798.199 (CCPA/CPRA -- employee data as of Jan 1, 2023); Cal. Lab. Code 226(c) (pay record retention 3 years); 29 CFR 1602.14 (EEOC personnel record retention -- 1 year from separation); Cal. Gov. Code 12946 (FEHA -- 4 years retention); Cal. Lab. Code 1174 (payroll records 3 years)', 'Personnel file must be organized and available for employee inspection at reasonable times within 30 calendar days of written request; copies provided at employee''s cost or free if mailed; medical records maintained separately per ADA/FEHA/HIPAA; no inclusion of investigation records of other employees; CCPA privacy notices for employee data required; response to employee data requests within 45 days under CPRA', 'Personnel files in locked/secured storage (physical or encrypted digital); access restricted to HR and direct management with logged access; medical files physically separate from personnel files; retention schedules enforced with documented destruction; litigation hold procedures for anticipated claims', 'Personnel file compliance (state laws), employee privacy documents, employee monitoring disclosure documents, social media policy compliance, remote work/telecommuting agreements');
UPDATE citizen_catalog SET standards_of_creation = 'Handbook must include all California-mandated policies (harassment prevention, at-will disclaimer, paid sick leave, FMLA/CFRA, EEO, accommodation, lactation, crime victim leave, domestic violence leave, voting leave); policies must be reviewed and updated at least annually; signed acknowledgment of receipt from each employee; language accessible -- must be in language understood by employees (Cal. Lab. Code 1019); electronic distribution must ensure actual receipt and accessibility', soc_controls = 'Version control with effective dates; legal review before distribution; acknowledgment tracking system; archived prior versions for litigation defense; translation verification for multilingual workforces' WHERE name = 'Workplace Policy and Handbook Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-76ef9014221c', 'Workplace Policy and Handbook Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workplace Policy and Handbook Compliance Specialist — California DLSE; EEOC; National Labor Relations Board (NLRB); California CRD', 'Workplace Policy and Handbook Compliance Specialist', 'California DLSE; EEOC; National Labor Relations Board (NLRB); California CRD', 'Cal. Lab. Code 246 (paid sick leave policy); Cal. Gov. Code 12950 (FEHA poster/policy requirements); Cal. Gov. Code 12950.1 (sexual harassment prevention policy); SB 553 (Cal. Lab. Code 6401.9 -- workplace violence prevention plan required in handbook context); NLRA Section 7 (29 USC 157 -- handbook policies must not chill protected concerted activity per NLRB); Cal. Lab. Code 1102.5 (whistleblower policy); Cal. Lab. Code 98.6 (retaliation prohibition); Cal. Lab. Code 230-230.8 (leave rights disclosures); OSHA poster requirements; Cal. Lab. Code 2810.5 (wage theft prevention notice)', 'Handbook must include all California-mandated policies (harassment prevention, at-will disclaimer, paid sick leave, FMLA/CFRA, EEO, accommodation, lactation, crime victim leave, domestic violence leave, voting leave); policies must be reviewed and updated at least annually; signed acknowledgment of receipt from each employee; language accessible -- must be in language understood by employees (Cal. Lab. Code 1019); electronic distribution must ensure actual receipt and accessibility', 'Version control with effective dates; legal review before distribution; acknowledgment tracking system; archived prior versions for litigation defense; translation verification for multilingual workforces', 'Employee handbook/policy documents, social media policy compliance, remote work/telecommuting agreements, employee monitoring disclosure documents');
UPDATE citizen_catalog SET standards_of_creation = 'Performance evaluations must use consistent criteria applied uniformly across similarly situated employees; PIPs must state specific deficiencies, measurable improvement objectives, timeline (typically 30-90 days), resources/support provided, and consequences of failure; progressive discipline documents must establish clear escalation (verbal warning documented, written warning, final warning, termination); all documents must be contemporaneous -- backdated documents fail audit; manager must sign and date; employee must acknowledge receipt (signature or documented refusal)', soc_controls = 'Evaluation criteria reviewed for adverse impact annually; manager training on documentation; HR review before final adverse action; calibration sessions to ensure consistency across departments; retention per FEHA (4 years from action) or EEOC (1 year, or duration of charge/litigation)' WHERE name = 'Performance Evaluation and Corrective Action Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8d52d2b00159', 'Performance Evaluation and Corrective Action Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Performance Evaluation and Corrective Action Compliance Specialist — EEOC; California CRD; DLSE (for wage implications of performance-based pay)', 'Performance Evaluation and Corrective Action Compliance Specialist', 'EEOC; California CRD; DLSE (for wage implications of performance-based pay)', 'Title VII / FEHA (performance systems must not have disparate impact -- Griggs v. Duke Power, 401 US 424 (1971)); Cal. Gov. Code 12940(a) (discrimination in terms/conditions of employment includes evaluations); ADA/FEHA interactive process triggered when performance issues may relate to disability; 29 CFR 1607 (Uniform Guidelines on Employee Selection Procedures -- applies to performance evaluations used for employment decisions); Cal. Lab. Code 1102.5 (performance actions cannot constitute retaliation for protected activity)', 'Performance evaluations must use consistent criteria applied uniformly across similarly situated employees; PIPs must state specific deficiencies, measurable improvement objectives, timeline (typically 30-90 days), resources/support provided, and consequences of failure; progressive discipline documents must establish clear escalation (verbal warning documented, written warning, final warning, termination); all documents must be contemporaneous -- backdated documents fail audit; manager must sign and date; employee must acknowledge receipt (signature or documented refusal)', 'Evaluation criteria reviewed for adverse impact annually; manager training on documentation; HR review before final adverse action; calibration sessions to ensure consistency across departments; retention per FEHA (4 years from action) or EEOC (1 year, or duration of charge/litigation)', 'Performance evaluation documents, performance improvement plan (PIP) documents, progressive discipline documents, promotion/demotion documents, transfer documents');
UPDATE citizen_catalog SET standards_of_creation = 'Investigation must be prompt (initiated within days of complaint), thorough (all witnesses interviewed, documents collected), and impartial (investigator has no stake in outcome); investigation report must document: complaint received, scope defined, evidence collected, witness statements, credibility assessments, findings of fact, policy/law analysis, conclusion, and recommended action; complainant and respondent must receive notice of outcome; no retaliation documentation; investigation files maintained separately from personnel files', soc_controls = 'Investigator independence (not in reporting chain of complainant or respondent); privilege designation (attorney-directed vs. fact-finding) determined at outset; witness statements signed; evidence chain of custody; confidentiality admonitions documented; investigation file access restricted; external investigator engagement for C-suite complaints' WHERE name = 'Internal Investigations Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-362749b1342f', 'Internal Investigations Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Internal Investigations Compliance Specialist — EEOC; California CRD; DLSE; Cal-OSHA (for safety-related investigations)', 'Internal Investigations Compliance Specialist', 'EEOC; California CRD; DLSE; Cal-OSHA (for safety-related investigations)', 'Cal. Gov. Code 12940(k) (employer duty to investigate harassment/discrimination complaints); Cotran v. Rollins Hudig Hall International (1998) 17 Cal.4th 93 (good faith investigation standard for termination); Silva v. Lucky Stores (1998) 65 Cal.App.4th 256 (investigation methodology); Cal. Lab. Code 1102.5 (whistleblower investigation obligations); Sarbanes-Oxley 806 (18 USC 1514A -- whistleblower for public companies); Cal. Gov. Code 8547-8547.12 (California Whistleblower Protection Act -- public employers); EEOC Enforcement Guidance on Vicarious Employer Liability (1999)', 'Investigation must be prompt (initiated within days of complaint), thorough (all witnesses interviewed, documents collected), and impartial (investigator has no stake in outcome); investigation report must document: complaint received, scope defined, evidence collected, witness statements, credibility assessments, findings of fact, policy/law analysis, conclusion, and recommended action; complainant and respondent must receive notice of outcome; no retaliation documentation; investigation files maintained separately from personnel files', 'Investigator independence (not in reporting chain of complainant or respondent); privilege designation (attorney-directed vs. fact-finding) determined at outset; witness statements signed; evidence chain of custody; confidentiality admonitions documented; investigation file access restricted; external investigator engagement for C-suite complaints', 'Workplace investigation reports, whistleblower investigation documents, ethics investigation documents, code of conduct violation investigation documents, workplace bullying investigation documents, conflict of interest disclosure documents');
UPDATE citizen_catalog SET standards_of_creation = 'Federal WARN notice must include: expected date of mass layoff/plant closing, whether separation is permanent or temporary, bumping rights if applicable, name/contact of company official; California WARN: 60 days written notice regardless of exemptions; selection criteria for RIF must be documented with legitimate business justification; adverse impact analysis required before implementation; OWBPA disclosures for group terminations must include decisional unit, eligibility factors, ages of selected and non-selected employees, time limits (45 days consideration, 7 days revocation)', soc_controls = 'Legal review of selection criteria before implementation; disparate impact analysis by counsel; separation agreements reviewed individually; 45-day/21-day consideration periods tracked and enforced; revocation period tracked; no coercion documentation; signed acknowledgments of all notices; WARN notice proof of delivery retained' WHERE name = 'Workforce Reduction and WARN Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-fa68d57d6b7c', 'Workforce Reduction and WARN Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workforce Reduction and WARN Compliance Specialist — U.S. Department of Labor (DOL); California Employment Development Department (EDD); DLSE', 'Workforce Reduction and WARN Compliance Specialist', 'U.S. Department of Labor (DOL); California Employment Development Department (EDD); DLSE', 'WARN Act (29 USC 2101-2109); 20 CFR Part 639 (WARN regulations); Cal. Lab. Code 1400-1408 (California WARN Act -- broader than federal: 75 employees, no exemptions for natural disaster or faltering company); Cal. Lab. Code 1401 (60-day written notice to affected employees, EDD, and local workforce investment board); Cal. Lab. Code 1402 (penalties: back pay and benefits for each day of violation); OWBPA (29 USC 626(f) -- Older Workers Benefit Protection Act for RIF releases involving 40+ employees)', 'Federal WARN notice must include: expected date of mass layoff/plant closing, whether separation is permanent or temporary, bumping rights if applicable, name/contact of company official; California WARN: 60 days written notice regardless of exemptions; selection criteria for RIF must be documented with legitimate business justification; adverse impact analysis required before implementation; OWBPA disclosures for group terminations must include decisional unit, eligibility factors, ages of selected and non-selected employees, time limits (45 days consideration, 7 days revocation)', 'Legal review of selection criteria before implementation; disparate impact analysis by counsel; separation agreements reviewed individually; 45-day/21-day consideration periods tracked and enforced; revocation period tracked; no coercion documentation; signed acknowledgments of all notices; WARN notice proof of delivery retained', 'Reduction in force (RIF) documents, WARN Act notification documents, separation agreement/severance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Separation documents must clearly state reason for termination (voluntary resignation, involuntary termination for cause, layoff, mutual separation); response to EDD Notice of UI Claim Filing (DE 1101CZ) must be returned within 10 days with specific facts; if contesting, employer must provide documentation of misconduct connected to work; appeal hearing preparation requires contemporaneous documentation; final paycheck timing compliance (Cal. Lab. Code 201-203: immediately upon involuntary termination, 72 hours for resignation without notice, immediately if 72-hour notice of resignation given)', soc_controls = 'Separation checklist ensuring all final pay, benefits continuation notices, and property return documented; UI response tracking system with deadlines; documentation package for each separation maintained; hearing testimony preparation by knowledgeable representative; appeal deadline tracking (20 days from determination)' WHERE name = 'Unemployment Insurance Response and Separation Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-eb1e2b334c51', 'Unemployment Insurance Response and Separation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Unemployment Insurance Response and Separation Compliance Specialist — California Employment Development Department (EDD); U.S. Department of Labor (DOL)', 'Unemployment Insurance Response and Separation Compliance Specialist', 'California Employment Development Department (EDD); U.S. Department of Labor (DOL)', 'Cal. Unemp. Ins. Code 1026-1034 (employer registration and reporting); Cal. Unemp. Ins. Code 1085-1089 (employer contributions); Cal. Unemp. Ins. Code 1256-1256.8 (disqualification for misconduct -- employer burden of proof); Cal. Unemp. Ins. Code 1030 (employer response to UI claim within 10 days); Cal. Unemp. Ins. Code 1327 (determination process); FUTA (26 USC 3301-3311); 20 CFR Part 603 (confidentiality of UI information)', 'Separation documents must clearly state reason for termination (voluntary resignation, involuntary termination for cause, layoff, mutual separation); response to EDD Notice of UI Claim Filing (DE 1101CZ) must be returned within 10 days with specific facts; if contesting, employer must provide documentation of misconduct connected to work; appeal hearing preparation requires contemporaneous documentation; final paycheck timing compliance (Cal. Lab. Code 201-203: immediately upon involuntary termination, 72 hours for resignation without notice, immediately if 72-hour notice of resignation given)', 'Separation checklist ensuring all final pay, benefits continuation notices, and property return documented; UI response tracking system with deadlines; documentation package for each separation maintained; hearing testimony preparation by knowledgeable representative; appeal deadline tracking (20 days from determination)', 'Exit interview documents, unemployment insurance response documents, employment verification documents, separation agreement/severance documents');
UPDATE citizen_catalog SET standards_of_creation = 'Non-compete agreements are void and unenforceable in California -- any such agreement in an employment contract fails audit automatically; non-solicitation of customers generally void under Edwards progeny; non-solicitation of employees: narrowing but still unsettled; invention assignment clauses must carve out Cal. Lab. Code 2870 inventions with statutory notice; trade secret protections must define trade secrets with reasonable particularity; confidentiality agreements must not function as de facto non-competes', soc_controls = 'Annual review of all employment agreements for impermissible restrictive covenants; out-of-state agreements applied to California employees flagged; employee notification of void provisions per SB 699 (required notification to current and former employees); invention assignment notices per Lab. Code 2872 documented with signed acknowledgment' WHERE name = 'Attorney -- Post-Employment Restrictive Covenants';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-fef15f2bf821', 'Attorney -- Post-Employment Restrictive Covenants', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Attorney -- Post-Employment Restrictive Covenants — State Bar of California; California Legislature (strong public policy against restraints)', 'Attorney -- Post-Employment Restrictive Covenants', 'State Bar of California; California Legislature (strong public policy against restraints)', 'Cal. Bus. & Prof. Code 16600 (void restraint on engaging in lawful profession -- California near-total ban on non-competes); Cal. Bus. & Prof. Code 16600.5 (AB 1076 -- codified Edwards v. Arthur Andersen, no non-compete even with consideration); SB 699 (Cal. Bus. & Prof. Code 16600.5(a) -- employer cannot enforce out-of-state non-compete against California employee); Cal. Lab. Code 2870-2872 (employee invention assignment limitations -- cannot assign inventions made entirely on own time without employer resources); Cal. Civ. Code 3426-3426.11 (Uniform Trade Secrets Act -- only permissible post-employment restriction is trade secret protection); Defend Trade Secrets Act (18 USC 1836)', 'Non-compete agreements are void and unenforceable in California -- any such agreement in an employment contract fails audit automatically; non-solicitation of customers generally void under Edwards progeny; non-solicitation of employees: narrowing but still unsettled; invention assignment clauses must carve out Cal. Lab. Code 2870 inventions with statutory notice; trade secret protections must define trade secrets with reasonable particularity; confidentiality agreements must not function as de facto non-competes', 'Annual review of all employment agreements for impermissible restrictive covenants; out-of-state agreements applied to California employees flagged; employee notification of void provisions per SB 699 (required notification to current and former employees); invention assignment notices per Lab. Code 2872 documented with signed acknowledgment', 'Non-compete/non-solicitation documents, trade secret protection documents, employee invention assignment documents, arbitration agreement documents');
UPDATE citizen_catalog SET standards_of_creation = 'Pay equity audits must compare employees performing substantially similar work (not identical titles) using composite of skill, effort, responsibility, and working conditions; legitimate differentials (seniority, merit, quantity/quality of production, bona fide factor other than sex/race/ethnicity) must be documented and applied consistently; SB 1162 pay data reports must be filed annually with CRD including mean and median hourly rates by job category, race, ethnicity, and sex; job postings must include pay scale (hourly or salary range) -- not open-ended ranges', soc_controls = 'Compensation data access restricted to authorized analysts; pay equity audit conducted by independent function (not hiring managers); results privileged if conducted under attorney direction; remediation actions documented and tracked; pay data report preparation with data integrity verification; annual job posting audit for pay scale compliance' WHERE name = 'Pay Equity and Compensation Compliance Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4075bddd072a', 'Pay Equity and Compensation Compliance Analyst', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Pay Equity and Compensation Compliance Analyst — California CRD; DLSE; EEOC; OFCCP', 'Pay Equity and Compensation Compliance Analyst', 'California CRD; DLSE; EEOC; OFCCP', 'Cal. Lab. Code 1197.5 (California Equal Pay Act -- equal pay for substantially similar work); Cal. Lab. Code 432.3 (salary history ban); SB 1162 (pay data reporting to CRD for 100+ employees, pay scale disclosure in job postings for 15+ employees); Equal Pay Act of 1963 (29 USC 206(d)); Title VII (42 USC 2000e -- compensation discrimination); Lilly Ledbetter Fair Pay Act (42 USC 2000e-5(e)(3)); 41 CFR 60-2.17(b)(3) (OFCCP compensation analysis for contractors); Executive Order 14069 (advancing pay equity for federal workforce/contractors)', 'Pay equity audits must compare employees performing substantially similar work (not identical titles) using composite of skill, effort, responsibility, and working conditions; legitimate differentials (seniority, merit, quantity/quality of production, bona fide factor other than sex/race/ethnicity) must be documented and applied consistently; SB 1162 pay data reports must be filed annually with CRD including mean and median hourly rates by job category, race, ethnicity, and sex; job postings must include pay scale (hourly or salary range) -- not open-ended ranges', 'Compensation data access restricted to authorized analysts; pay equity audit conducted by independent function (not hiring managers); results privileged if conducted under attorney direction; remediation actions documented and tracked; pay data report preparation with data integrity verification; annual job posting audit for pay scale compliance', 'Pay equity audit documents, salary history ban compliance, job posting compliance documents (pay transparency component)');
UPDATE citizen_catalog SET standards_of_creation = 'Pay stubs must include all 9 elements under Lab. Code 226(a): gross wages, total hours (non-exempt), piece rates if applicable, all deductions, net wages, inclusive dates of pay period, employee name and last 4 SSN, employer name and address, all applicable hourly rates and hours at each rate; payroll registers must reconcile gross-to-net for each employee each period; overtime calculated on regular rate of pay including non-discretionary bonuses, shift differentials, and piece rates; meal/rest period premiums (Lab. Code 226.7) tracked and paid as wages; wage theft prevention notice provided at hire and within 7 days of any change (Lab. Code 2810.5)', soc_controls = 'Dual authorization for payroll processing; segregation between time entry, payroll processing, and disbursement; payroll register review and approval before payment; direct deposit authorization with employee signature; pay stub delivery verification; payroll records retained 4 years (Cal. Lab. Code 1174); reconciliation of payroll tax liability accounts monthly' WHERE name = 'Payroll Operations and Wage Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4162a332fa19', 'Payroll Operations and Wage Compliance Manager', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Payroll Operations and Wage Compliance Manager — California DLSE; IRS; California EDD; U.S. Department of Labor WHD', 'Payroll Operations and Wage Compliance Manager', 'California DLSE; IRS; California EDD; U.S. Department of Labor WHD', 'Cal. Lab. Code 200-244 (payment of wages); Cal. Lab. Code 226 (itemized wage statements -- 9 required elements); Cal. Lab. Code 204 (semi-monthly pay frequency); Cal. Lab. Code 510 (daily overtime -- 8 hours/day, 12 hours/day double time, 7th consecutive day); FLSA (29 USC 201-219); 29 CFR Part 778 (overtime computation); Cal. Lab. Code 1194 (private right of action for unpaid wages); Cal. Lab. Code 558.1 (individual liability for wage theft); Cal. Lab. Code 2810.5 (wage theft prevention notice at hire)', 'Pay stubs must include all 9 elements under Lab. Code 226(a): gross wages, total hours (non-exempt), piece rates if applicable, all deductions, net wages, inclusive dates of pay period, employee name and last 4 SSN, employer name and address, all applicable hourly rates and hours at each rate; payroll registers must reconcile gross-to-net for each employee each period; overtime calculated on regular rate of pay including non-discretionary bonuses, shift differentials, and piece rates; meal/rest period premiums (Lab. Code 226.7) tracked and paid as wages; wage theft prevention notice provided at hire and within 7 days of any change (Lab. Code 2810.5)', 'Dual authorization for payroll processing; segregation between time entry, payroll processing, and disbursement; payroll register review and approval before payment; direct deposit authorization with employee signature; pay stub delivery verification; payroll records retained 4 years (Cal. Lab. Code 1174); reconciliation of payroll tax liability accounts monthly', 'Payroll register documents, pay stub/wage statement compliance, overtime calculation documents, minimum wage compliance');
UPDATE citizen_catalog SET standards_of_creation = 'Exemption classification must be documented with duties analysis under both federal and California tests (California uses "primarily engaged" meaning 50%+ of time, vs. federal "primary duty"); salary basis must meet both federal ($684/week) and California (2x minimum wage for full-time -- currently higher than federal) thresholds; independent contractor classifications must satisfy all three prongs of ABC test; reclassification audits must include back-pay analysis; job descriptions must accurately reflect actual duties performed, not aspirational duties', soc_controls = 'Classification review at hire and upon material job change; annual audit of exempt positions against current salary thresholds (California minimum wage increases annually); documentation of duties analysis in classification file; legal review for borderline positions; independent contractor agreements reviewed against ABC test; misclassification risk register maintained' WHERE name = 'Wage and Hour Exemption Classification Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f36e09a4164a', 'Wage and Hour Exemption Classification Analyst', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Wage and Hour Exemption Classification Analyst — U.S. Department of Labor WHD; California DLSE; California CRD', 'Wage and Hour Exemption Classification Analyst', 'U.S. Department of Labor WHD; California DLSE; California CRD', 'FLSA (29 USC 213(a)(1) -- white collar exemptions); 29 CFR Part 541 (executive, administrative, professional, computer, outside sales exemptions); Cal. Lab. Code 515 (California exemption requirements -- salary basis AND duties test); IWC Wage Orders 1-17 (industry-specific overtime and exemption rules); Cal. Lab. Code 515.5 (computer professional exemption -- higher salary threshold than federal); ABC test for independent contractor classification (Cal. Lab. Code 2775 -- AB 5); Dynamex Operations West v. Superior Court (2018) 4 Cal.5th 903', 'Exemption classification must be documented with duties analysis under both federal and California tests (California uses "primarily engaged" meaning 50%+ of time, vs. federal "primary duty"); salary basis must meet both federal ($684/week) and California (2x minimum wage for full-time -- currently higher than federal) thresholds; independent contractor classifications must satisfy all three prongs of ABC test; reclassification audits must include back-pay analysis; job descriptions must accurately reflect actual duties performed, not aspirational duties', 'Classification review at hire and upon material job change; annual audit of exempt positions against current salary thresholds (California minimum wage increases annually); documentation of duties analysis in classification file; legal review for borderline positions; independent contractor agreements reviewed against ABC test; misclassification risk register maintained', 'Exempt/non-exempt classification documents, commission agreement documents, tip credit/tip pool documents');
UPDATE citizen_catalog SET standards_of_creation = 'Form W-4 collected at hire and upon employee request to change; state DE-4 for California withholding; Form 941 filed quarterly with reconciliation to payroll registers; Form 940 filed annually; Form W-2 furnished to employees by January 31, filed with SSA by January 31 (electronic) or January 31 (paper); Form 1099-NEC for independent contractors ($600+ threshold) by January 31; California DE-9 and DE-9C filed quarterly; payroll tax deposits per IRC 6302 (semi-weekly or monthly depositor rules); new hire reporting to EDD within 20 days (Cal. Unemp. Ins. Code 1088.5)', soc_controls = 'Tax deposit deadlines calendared and monitored; reconciliation of Form 941 to payroll registers quarterly; W-2/1099 reconciliation to payroll system before filing; SSN verification through SSNVS before W-2 filing; segregation between payroll processing and tax deposit functions; tax notice tracking and response system; amended return tracking; audit-ready payroll tax files maintained 4 years minimum (IRS) / 4 years (California)' WHERE name = 'Payroll Tax and Regulatory Reporting Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4d3340e2c5a6', 'Payroll Tax and Regulatory Reporting Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Payroll Tax and Regulatory Reporting Specialist — Internal Revenue Service (IRS); California EDD; California Franchise Tax Board (FTB); Social Security Administration (SSA)', 'Payroll Tax and Regulatory Reporting Specialist', 'Internal Revenue Service (IRS); California EDD; California Franchise Tax Board (FTB); Social Security Administration (SSA)', 'IRC 3101-3128 (FICA -- Social Security and Medicare); IRC 3301-3311 (FUTA); IRC 3401-3406 (federal income tax withholding); Cal. Unemp. Ins. Code 13009-13028 (California personal income tax withholding); Cal. Unemp. Ins. Code 976-984 (SDI contributions); Cal. Unemp. Ins. Code 1085-1089 (SUI/ETT rates); 26 CFR 31.6011(a)-1 through -5 (employment tax return requirements); IRC 6721-6723 (information return penalties)', 'Form W-4 collected at hire and upon employee request to change; state DE-4 for California withholding; Form 941 filed quarterly with reconciliation to payroll registers; Form 940 filed annually; Form W-2 furnished to employees by January 31, filed with SSA by January 31 (electronic) or January 31 (paper); Form 1099-NEC for independent contractors ($600+ threshold) by January 31; California DE-9 and DE-9C filed quarterly; payroll tax deposits per IRC 6302 (semi-weekly or monthly depositor rules); new hire reporting to EDD within 20 days (Cal. Unemp. Ins. Code 1088.5)', 'Tax deposit deadlines calendared and monitored; reconciliation of Form 941 to payroll registers quarterly; W-2/1099 reconciliation to payroll system before filing; SSN verification through SSNVS before W-2 filing; segregation between payroll processing and tax deposit functions; tax notice tracking and response system; amended return tracking; audit-ready payroll tax files maintained 4 years minimum (IRS) / 4 years (California)', 'Form W-4 documents, state withholding documents, payroll tax deposit documents, Form 941 quarterly returns, Form W-2 preparation, Form 1099 preparation, new hire reporting documents');
UPDATE citizen_catalog SET standards_of_creation = 'Employer must honor earnings withholding order within 10 days of service; child support orders processed per National Medical Support Notice requirements; calculation worksheet documenting disposable earnings, applicable exemptions, and withholding amount must be maintained for each pay period; multiple garnishment priority tracking required; employee notification of garnishment receipt; remittance to levying officer within 15 days of pay date; employer cannot discharge employee for single garnishment (15 USC 1674(a)); California: no discharge for any number of garnishments (Cal. Lab. Code 2929)', soc_controls = 'Garnishment receipt logging with date/time stamp; calculation verification before withholding; dual review for complex multi-garnishment situations; remittance tracking and proof of payment; confidentiality of garnishment information (restricted from management beyond need-to-know); compliance calendar for withholding and remittance deadlines; terminated employee garnishment final processing' WHERE name = 'Involuntary Wage Withholding Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1fbbe4dc7a23', 'Involuntary Wage Withholding Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Involuntary Wage Withholding Compliance Specialist — U.S. Department of Labor; California DLSE; California Franchise Tax Board; state and federal courts', 'Involuntary Wage Withholding Compliance Specialist', 'U.S. Department of Labor; California DLSE; California Franchise Tax Board; state and federal courts', 'Consumer Credit Protection Act Title III (15 USC 1671-1677 -- maximum garnishment 25% of disposable earnings or amount exceeding 30x federal minimum wage); Cal. Code Civ. Proc. 706.010-706.154 (earnings withholding orders); Cal. Fam. Code 5200-5270 (child/spousal support withholding); 42 USC 666(b) (federal child support income withholding); IRS IRC 6331 (federal tax levies); Cal. Rev. & Tax Code 18817 (FTB tax levies); 20 CFR 870 (federal student loan garnishment -- limited by recent rules); priority of garnishments: child support first, then tax levies, then creditor garnishments', 'Employer must honor earnings withholding order within 10 days of service; child support orders processed per National Medical Support Notice requirements; calculation worksheet documenting disposable earnings, applicable exemptions, and withholding amount must be maintained for each pay period; multiple garnishment priority tracking required; employee notification of garnishment receipt; remittance to levying officer within 15 days of pay date; employer cannot discharge employee for single garnishment (15 USC 1674(a)); California: no discharge for any number of garnishments (Cal. Lab. Code 2929)', 'Garnishment receipt logging with date/time stamp; calculation verification before withholding; dual review for complex multi-garnishment situations; remittance tracking and proof of payment; confidentiality of garnishment information (restricted from management beyond need-to-know); compliance calendar for withholding and remittance deadlines; terminated employee garnishment final processing', 'Garnishment/levy processing documents, child support withholding documents');
UPDATE citizen_catalog SET standards_of_creation = 'Summary Plan Description (SPD) must be furnished within 90 days of becoming participant (120 days for new plan) and contain all elements specified in ERISA 102(b) and 29 CFR 2520.102-3; Summary of Material Modifications within 210 days of end of plan year in which modification adopted; Form 5500 filed annually by last day of 7th month after plan year end (with extensions); plan documents must include all required ERISA provisions; claims procedures must provide full and fair review per 29 CFR 2560.503-1; participant fee disclosure per 29 CFR 2550.404a-5 (annual) and 408b-2 (service provider)', soc_controls = 'Fiduciary committee with documented charter and meeting minutes; investment monitoring per IPS (Investment Policy Statement); prohibited transaction screening; service provider fee benchmarking; fidelity bond per ERISA 412 (10% of plan assets, minimum $1,000, maximum $500,000 -- $1M for plans holding employer securities); plan audit for 100+ participants by independent qualified public accountant; plan document vs. operations consistency review; SPD vs. plan document consistency review' WHERE name = 'Attorney -- ERISA and Employee Benefits Law';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-dc90988f1e77', 'Attorney -- ERISA and Employee Benefits Law', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Attorney -- ERISA and Employee Benefits Law — U.S. Department of Labor Employee Benefits Security Administration (EBSA); IRS (plan qualification); Pension Benefit Guaranty Corporation (PBGC); State Bar of California', 'Attorney -- ERISA and Employee Benefits Law', 'U.S. Department of Labor Employee Benefits Security Administration (EBSA); IRS (plan qualification); Pension Benefit Guaranty Corporation (PBGC); State Bar of California', 'ERISA (29 USC 1001-1461); IRC 401(a) (qualified plan requirements); IRC 401(k) (cash or deferred arrangements); IRC 403(b) (tax-sheltered annuities); IRC 457(b) (deferred compensation -- governmental/tax-exempt); 29 CFR Part 2520 (reporting and disclosure); 29 CFR Part 2550 (fiduciary responsibility); 29 CFR Part 2560 (claims procedure); ERISA 404(a) (prudent expert standard); ERISA 406-408 (prohibited transactions); ERISA 502 (enforcement -- civil actions by participants, beneficiaries, fiduciaries, DOL)', 'Summary Plan Description (SPD) must be furnished within 90 days of becoming participant (120 days for new plan) and contain all elements specified in ERISA 102(b) and 29 CFR 2520.102-3; Summary of Material Modifications within 210 days of end of plan year in which modification adopted; Form 5500 filed annually by last day of 7th month after plan year end (with extensions); plan documents must include all required ERISA provisions; claims procedures must provide full and fair review per 29 CFR 2560.503-1; participant fee disclosure per 29 CFR 2550.404a-5 (annual) and 408b-2 (service provider)', 'Fiduciary committee with documented charter and meeting minutes; investment monitoring per IPS (Investment Policy Statement); prohibited transaction screening; service provider fee benchmarking; fidelity bond per ERISA 412 (10% of plan assets, minimum $1,000, maximum $500,000 -- $1M for plans holding employer securities); plan audit for 100+ participants by independent qualified public accountant; plan document vs. operations consistency review; SPD vs. plan document consistency review', 'ERISA compliance documents, Form 5500 annual reports, summary plan description (SPD) documents, summary of material modifications, 401(k)/403(b) plan documents, pension plan documents, fiduciary responsibility documents, prohibited transaction documents, plan audit documents');
UPDATE citizen_catalog SET standards_of_creation = 'PBGC premium filing (Form 1-ES estimated premium, Form 1 comprehensive premium) due by prescribed deadline (varies by plan size and type); reportable events (29 CFR Part 4043) filed within 30 days of event; annual funding notice to participants per ERISA 101(f) within 120 days of plan year end; enrolled actuary certification of funding per IRC 430; Schedule SB (single-employer) or Schedule MB (multiemployer) attached to Form 5500; plan termination requires 60-day advance notice to participants, PBGC, and unions', soc_controls = 'Enrolled actuary independence verification; actuarial assumption documentation and review; PBGC premium payment tracking and confirmation; reportable event monitoring system; plan asset valuation by independent appraiser for non-publicly traded assets; contribution timing compliance monitoring (quarterly contributions per IRC 430(j)); underfunding monitoring against PBGC variable-rate premium and ERISA 4010 thresholds' WHERE name = 'Pension Benefit Guaranty Corporation Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ad5040afcd5c', 'Pension Benefit Guaranty Corporation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Pension Benefit Guaranty Corporation Compliance Specialist — Pension Benefit Guaranty Corporation (PBGC); IRS Employee Plans', 'Pension Benefit Guaranty Corporation Compliance Specialist', 'Pension Benefit Guaranty Corporation (PBGC); IRS Employee Plans', 'ERISA Title IV (29 USC 1301-1461 -- plan termination insurance); PBGC premium regulations (29 CFR Part 4006 -- flat-rate and variable-rate premiums); ERISA 4010 (reporting for underfunded plans); ERISA 4041-4041A (standard and distress termination procedures); ERISA 4043 (reportable events); IRC 430 (minimum funding standards for single-employer plans); IRC 432 (multiemployer plan funding rules); Pension Protection Act of 2006 (funding reform); SECURE Act 2.0 (2022 -- updated funding and disclosure requirements)', 'PBGC premium filing (Form 1-ES estimated premium, Form 1 comprehensive premium) due by prescribed deadline (varies by plan size and type); reportable events (29 CFR Part 4043) filed within 30 days of event; annual funding notice to participants per ERISA 101(f) within 120 days of plan year end; enrolled actuary certification of funding per IRC 430; Schedule SB (single-employer) or Schedule MB (multiemployer) attached to Form 5500; plan termination requires 60-day advance notice to participants, PBGC, and unions', 'Enrolled actuary independence verification; actuarial assumption documentation and review; PBGC premium payment tracking and confirmation; reportable event monitoring system; plan asset valuation by independent appraiser for non-publicly traded assets; contribution timing compliance monitoring (quarterly contributions per IRC 430(j)); underfunding monitoring against PBGC variable-rate premium and ERISA 4010 thresholds', 'PBGC filing documents, pension plan documents, plan audit documents');
UPDATE citizen_catalog SET standards_of_creation = 'Initial general notice provided within 90 days of coverage commencement; employer must notify plan administrator of qualifying event within 30 days; election notice to qualified beneficiary within 14 days of administrator receiving notice (44-day total); election notice must contain all elements per DOL model notice; 60-day election period from later of coverage loss or notice; premium payment grace period 45 days for initial, 30 days for subsequent; Cal-COBRA notice required for employers with 2-19 employees and for 36-month extension after federal 18-month period; disabled individual extension to 29 months requires notice within 60 days of SSA determination', soc_controls = 'Qualifying event tracking system with automated deadline calculations; notice delivery tracking (certified mail or electronic with delivery confirmation); premium receipt and grace period monitoring; termination of coverage for nonpayment documented; coordination with payroll/HR separation process; Cal-COBRA transition tracking for small employer qualifying events; annual premium rate recalculation and notice' WHERE name = 'COBRA and Continuation Coverage Compliance Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3e4339db58e5', 'COBRA and Continuation Coverage Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'COBRA and Continuation Coverage Compliance Administrator — U.S. Department of Labor EBSA; IRS; California DMHC and CDI (Cal-COBRA)', 'COBRA and Continuation Coverage Compliance Administrator', 'U.S. Department of Labor EBSA; IRS; California DMHC and CDI (Cal-COBRA)', 'COBRA (26 USC 4980B; 29 USC 1161-1169; 42 USC 300bb-1 to 300bb-8); 29 CFR Part 2590 (DOL COBRA regulations); Cal. Health & Safety Code 1373.6 and Cal. Ins. Code 10128.50 (Cal-COBRA -- extends to employers with 2-19 employees and provides additional 36 months after federal COBRA exhaustion); Cal. Gov. Code 22850-22856 (CalPERS COBRA provisions); DOL Model COBRA Notices (updated)', 'Initial general notice provided within 90 days of coverage commencement; employer must notify plan administrator of qualifying event within 30 days; election notice to qualified beneficiary within 14 days of administrator receiving notice (44-day total); election notice must contain all elements per DOL model notice; 60-day election period from later of coverage loss or notice; premium payment grace period 45 days for initial, 30 days for subsequent; Cal-COBRA notice required for employers with 2-19 employees and for 36-month extension after federal 18-month period; disabled individual extension to 29 months requires notice within 60 days of SSA determination', 'Qualifying event tracking system with automated deadline calculations; notice delivery tracking (certified mail or electronic with delivery confirmation); premium receipt and grace period monitoring; termination of coverage for nonpayment documented; coordination with payroll/HR separation process; Cal-COBRA transition tracking for small employer qualifying events; annual premium rate recalculation and notice', 'COBRA administration documents, benefits enrollment documents');
UPDATE citizen_catalog SET standards_of_creation = 'HIPAA certificates of creditable coverage (group health plan to plan); Notice of Privacy Practices distributed at enrollment; group health plan must have plan amendment per 45 CFR 164.504(f) before receiving PHI from insurer; wellness program compliance per EEOC/ADA (voluntary, reasonable alternative standard); ACA employer shared responsibility reporting (Forms 1094-C, 1095-C) by applicable large employer (50+ FTEs) filed by March 31 (electronic); Mental Health Parity NQTL comparative analysis documentation maintained', soc_controls = 'PHI access restricted to minimum necessary workforce; Business Associate Agreements with all vendors handling PHI; breach notification procedures (60-day individual notice, HHS annual/immediate per 500+ threshold); encryption of electronic PHI at rest and in transit; HIPAA training for all workforce members with PHI access; privacy officer designation; physical safeguards for PHI documents; security risk assessment annually' WHERE name = 'Group Health Plan Privacy and Portability Compliance Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ed9bbc175199', 'Group Health Plan Privacy and Portability Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Group Health Plan Privacy and Portability Compliance Administrator — U.S. Department of Health and Human Services OCR (HIPAA Privacy/Security); DOL EBSA; IRS; California DMHC; California CDI', 'Group Health Plan Privacy and Portability Compliance Administrator', 'U.S. Department of Health and Human Services OCR (HIPAA Privacy/Security); DOL EBSA; IRS; California DMHC; California CDI', 'HIPAA Privacy Rule (45 CFR Parts 160, 164 Subpart E); HIPAA Security Rule (45 CFR Part 164 Subpart C); HIPAA Portability (42 USC 1320d et seq.); ACA (42 USC 18001 et seq.); Mental Health Parity and Addiction Equity Act (29 USC 1185a); Newborns'' and Mothers'' Health Protection Act (29 USC 1185); Women''s Health and Cancer Rights Act (29 USC 1185b); Cal. Health & Safety Code 1340-1399.800 (Knox-Keene Act); Cal. Ins. Code 10110-10192 (health insurance regulations); Consolidated Appropriations Act 2021 (surprise billing, transparency requirements)', 'HIPAA certificates of creditable coverage (group health plan to plan); Notice of Privacy Practices distributed at enrollment; group health plan must have plan amendment per 45 CFR 164.504(f) before receiving PHI from insurer; wellness program compliance per EEOC/ADA (voluntary, reasonable alternative standard); ACA employer shared responsibility reporting (Forms 1094-C, 1095-C) by applicable large employer (50+ FTEs) filed by March 31 (electronic); Mental Health Parity NQTL comparative analysis documentation maintained', 'PHI access restricted to minimum necessary workforce; Business Associate Agreements with all vendors handling PHI; breach notification procedures (60-day individual notice, HHS annual/immediate per 500+ threshold); encryption of electronic PHI at rest and in transit; HIPAA training for all workforce members with PHI access; privacy officer designation; physical safeguards for PHI documents; security risk assessment annually', 'HIPAA portability certificates, FSA/HSA/HRA administration documents, benefits enrollment documents');
UPDATE citizen_catalog SET standards_of_creation = 'Plan must have written QDRO determination procedures; upon receipt of DRO, plan administrator must notify participant and alternate payee within reasonable time; determination of qualified status within reasonable period; if approved, segregate alternate payee''s interest; 18-month determination period with benefit segregation; QDRO must specify: plan name, participant and alternate payee names/addresses/SSNs, amount or percentage, number of payments or period, and each plan to which it applies; QDRO cannot require plan to provide benefits not otherwise available, increase actuarial value beyond what plan provides, or require payment to alternate payee under another QDRO', soc_controls = 'QDRO receipt logging and deadline tracking; legal/compliance review of each DRO (not legal advice to parties); segregation of alternate payee benefits during determination; communication restrictions (no financial advice to alternate payee); participant and alternate payee notification tracking; coordination with recordkeeper for benefit calculation; appeal process documentation if DRO rejected' WHERE name = 'QDRO Review and Compliance Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-c7147a2d26da', 'QDRO Review and Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'QDRO Review and Compliance Administrator — U.S. Department of Labor EBSA; IRS; State family courts', 'QDRO Review and Compliance Administrator', 'U.S. Department of Labor EBSA; IRS; State family courts', 'ERISA 206(d)(3) (29 USC 1056(d)(3) -- QDRO exception to anti-alienation rule); IRC 414(p) (definition of QDRO); 29 CFR 2530.206 (DOL QDRO guidance); Cal. Fam. Code 2060 (joinder of pension plan in dissolution); Cal. Fam. Code 2610 (community property division of retirement benefits); ERISA 206(d)(3)(G) (plan administrator determination procedures -- 18-month segregation period)', 'Plan must have written QDRO determination procedures; upon receipt of DRO, plan administrator must notify participant and alternate payee within reasonable time; determination of qualified status within reasonable period; if approved, segregate alternate payee''s interest; 18-month determination period with benefit segregation; QDRO must specify: plan name, participant and alternate payee names/addresses/SSNs, amount or percentage, number of payments or period, and each plan to which it applies; QDRO cannot require plan to provide benefits not otherwise available, increase actuarial value beyond what plan provides, or require payment to alternate payee under another QDRO', 'QDRO receipt logging and deadline tracking; legal/compliance review of each DRO (not legal advice to parties); segregation of alternate payee benefits during determination; communication restrictions (no financial advice to alternate payee); participant and alternate payee notification tracking; coordination with recordkeeper for benefit calculation; appeal process documentation if DRO rejected', 'Qualified domestic relations order (QDRO) documents');
UPDATE citizen_catalog SET standards_of_creation = 'Deferral elections must be made before the year services are performed (initial election within 30 days of eligibility for new plans); plan document must be in writing and specify: time and form of payment, distribution events (separation, death, disability, change in control, unforeseen emergency, specified time/schedule -- only these 6 permitted triggers); no acceleration of payments except for limited exceptions (domestic relations orders, employment taxes, SEC compliance, plan termination under specific conditions); equity compensation (stock options, RSUs) must be valued at no less than FMV on grant date or face 409A penalties (20% additional tax plus interest from vesting)', soc_controls = 'Plan document review for 409A compliance before adoption; election form tracking with deadline enforcement; payment trigger event monitoring; FMV determination by qualified independent appraiser (IRC 409A safe harbor); annual 409A operational compliance review; W-2 Box 12 Code Y reporting for 409A failures; correction documentation per Notice 2008-113; insider trading compliance coordination for equity compensation' WHERE name = 'Nonqualified Deferred Compensation Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8c3262c2041f', 'Nonqualified Deferred Compensation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Nonqualified Deferred Compensation Compliance Specialist — Internal Revenue Service; SEC (for publicly traded companies); DOL', 'Nonqualified Deferred Compensation Compliance Specialist', 'Internal Revenue Service; SEC (for publicly traded companies); DOL', 'IRC 409A (nonqualified deferred compensation rules); 26 CFR 1.409A-1 through 1.409A-6 (Treasury regulations); IRC 457A (deferred compensation of certain tax-indifferent parties); Notice 2008-113 (correction program for 409A operational failures); IRC 3121(v)(2) (FICA timing for NQDC); Cal. Rev. & Tax Code 17501 (California conformity to 409A); SEC Rule 10b5-1 (insider trading safe harbor for equity award sales); Dodd-Frank 954 (clawback of erroneously awarded compensation -- SEC final rule 2022)', 'Deferral elections must be made before the year services are performed (initial election within 30 days of eligibility for new plans); plan document must be in writing and specify: time and form of payment, distribution events (separation, death, disability, change in control, unforeseen emergency, specified time/schedule -- only these 6 permitted triggers); no acceleration of payments except for limited exceptions (domestic relations orders, employment taxes, SEC compliance, plan termination under specific conditions); equity compensation (stock options, RSUs) must be valued at no less than FMV on grant date or face 409A penalties (20% additional tax plus interest from vesting)', 'Plan document review for 409A compliance before adoption; election form tracking with deadline enforcement; payment trigger event monitoring; FMV determination by qualified independent appraiser (IRC 409A safe harbor); annual 409A operational compliance review; W-2 Box 12 Code Y reporting for 409A failures; correction documentation per Notice 2008-113; insider trading compliance coordination for equity compensation', 'Deferred compensation documents (409A), equity compensation documents (stock options, RSUs), bonus/incentive plan documents');
UPDATE citizen_catalog SET standards_of_creation = 'Eligibility notice within 5 business days of learning of need for FMLA leave; rights and responsibilities notice (WH-381 or equivalent) with eligibility determination; designation notice (WH-382) within 5 business days of sufficient information; medical certification (WH-380-E/F) with 15-day response period; CFRA provides 12 weeks per year for specified family/medical reasons (broader "family member" definition than FMLA); PDL runs concurrently with FMLA but separately from CFRA; interactive process documentation for ADA/FEHA accommodation (meeting notes, accommodation options considered, medical documentation, outcome); fitness for duty certification only if uniformly required; paid sick leave tracking and accrual documentation', soc_controls = 'Leave tracking system with concurrent leave calculation (FMLA/CFRA/PDL/ADA/workers'' comp interactions); medical certification stored separately from personnel files; return-to-work medical clearance tracked; benefits continuation documentation during leave; position restoration tracking; no retaliation documentation; supervisor training on leave rights; leave denial documentation with legal review; interactive process file maintained separately' WHERE name = 'Leave Administration and Accommodation Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-301df6fd35cc', 'Leave Administration and Accommodation Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Leave Administration and Accommodation Compliance Specialist — U.S. Department of Labor WHD (FMLA); California CRD (CFRA/PDL); EEOC (ADA)', 'Leave Administration and Accommodation Compliance Specialist', 'U.S. Department of Labor WHD (FMLA); California CRD (CFRA/PDL); EEOC (ADA)', 'FMLA (29 USC 2601-2654); 29 CFR Part 825 (FMLA regulations); Cal. Gov. Code 12945-12945.6 (CFRA -- California Family Rights Act, expanded beyond FMLA); Cal. Gov. Code 12945 (Pregnancy Disability Leave -- up to 4 months, no minimum employee count for PDL); Cal. Lab. Code 233 (kin care -- use sick leave for family); Cal. Lab. Code 246 (paid sick leave -- 5 days/40 hours minimum); Cal. Gov. Code 12940(m)-(n) (reasonable accommodation/interactive process); ADA (42 USC 12111-12117); Cal. Lab. Code 230-230.8 (crime victim, domestic violence, jury duty, school activities, military leave)', 'Eligibility notice within 5 business days of learning of need for FMLA leave; rights and responsibilities notice (WH-381 or equivalent) with eligibility determination; designation notice (WH-382) within 5 business days of sufficient information; medical certification (WH-380-E/F) with 15-day response period; CFRA provides 12 weeks per year for specified family/medical reasons (broader "family member" definition than FMLA); PDL runs concurrently with FMLA but separately from CFRA; interactive process documentation for ADA/FEHA accommodation (meeting notes, accommodation options considered, medical documentation, outcome); fitness for duty certification only if uniformly required; paid sick leave tracking and accrual documentation', 'Leave tracking system with concurrent leave calculation (FMLA/CFRA/PDL/ADA/workers'' comp interactions); medical certification stored separately from personnel files; return-to-work medical clearance tracked; benefits continuation documentation during leave; position restoration tracking; no retaliation documentation; supervisor training on leave rights; leave denial documentation with legal review; interactive process file maintained separately', 'Leave administration documents (FMLA/CFRA/PDL/ADA), reasonable accommodation interactive process documents, pregnancy accommodation documents, religious accommodation documents, lactation accommodation documents');
UPDATE citizen_catalog SET standards_of_creation = 'All employers with 5+ employees must provide: 2 hours training to supervisors and 1 hour to non-supervisory employees within 6 months of hire/promotion and every 2 years thereafter; training must include: definition of harassment under FEHA and Title VII, statutory provisions, remedies, strategies to prevent harassment, supervisory obligation to report, practical examples, abusive conduct/bullying (AB 2053), harassment based on gender identity/expression/sexual orientation (SB 396); trainer must be attorney, HR professional with 2+ years experience, law professor, or CRD-approved instructor; training can be classroom, e-learning (interactive with assessment), or webinar (with real-time participation); training records retained 2 years minimum', soc_controls = 'Training tracking system with completion dates, next-due dates, and trainer qualifications; new hire 6-month training window tracked; promotion/new supervisor training tracked; training content reviewed for legal updates annually; attendance/completion certificates maintained; make-up training for absentees documented; training vendor contracts reviewed for content compliance; multilingual training availability verified; temporary/seasonal employee training tracked' WHERE name = 'Harassment Prevention Training Program Compliance Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e8f85a137427', 'Harassment Prevention Training Program Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Harassment Prevention Training Program Compliance Administrator — California CRD (formerly DFEH); EEOC', 'Harassment Prevention Training Program Compliance Administrator', 'California CRD (formerly DFEH); EEOC', 'Cal. Gov. Code 12950.1 (SB 1343 -- mandatory sexual harassment prevention training); 2 CCR 11024 (training requirements regulations); Cal. Gov. Code 12950 (FEHA harassment poster); EEOC Enforcement Guidance on Vicarious Employer Liability for Unlawful Harassment (1999); Cal. Gov. Code 12940(j) (harassment prohibition and employer liability); Cal. Gov. Code 12940(k) (duty to prevent harassment); AB 1825 (original 2-hour supervisor training mandate, now expanded by SB 1343)', 'All employers with 5+ employees must provide: 2 hours training to supervisors and 1 hour to non-supervisory employees within 6 months of hire/promotion and every 2 years thereafter; training must include: definition of harassment under FEHA and Title VII, statutory provisions, remedies, strategies to prevent harassment, supervisory obligation to report, practical examples, abusive conduct/bullying (AB 2053), harassment based on gender identity/expression/sexual orientation (SB 396); trainer must be attorney, HR professional with 2+ years experience, law professor, or CRD-approved instructor; training can be classroom, e-learning (interactive with assessment), or webinar (with real-time participation); training records retained 2 years minimum', 'Training tracking system with completion dates, next-due dates, and trainer qualifications; new hire 6-month training window tracked; promotion/new supervisor training tracked; training content reviewed for legal updates annually; attendance/completion certificates maintained; make-up training for absentees documented; training vendor contracts reviewed for content compliance; multilingual training availability verified; temporary/seasonal employee training tracked', 'Sexual harassment prevention training documents (SB 1343), anti-discrimination training documents, bystander intervention training documents');
UPDATE citizen_catalog SET standards_of_creation = 'Written Workplace Violence Prevention Plan (WVPP) required for all employers (exceptions: healthcare with existing plans, telework, small employer with no public access, law enforcement); WVPP must include: names of responsible persons, procedures for employee involvement, coordination with other employers at multi-employer sites, procedures to accept and respond to reports, procedures to ensure no retaliation, workplace hazard assessment, procedures to identify and evaluate workplace violence hazards, procedures for post-incident response and investigation, training procedures; violent incident log (Cal. Lab. Code 6401.9(d)) maintained for minimum 5 years; training at initial plan establishment, annually thereafter, and when new hazard identified; training records retained for 1 year, WVPP retained for 5 years, violent incident logs retained for 5 years', soc_controls = 'Plan administrator designated with authority and resources; hazard assessment documented and updated after each incident; employee reporting mechanism with documented anonymity protections; incident investigation file with root cause analysis; threat assessment team identified; coordination with law enforcement protocols; annual plan review documentation; training completion tracking per SB 553 requirements; emergency action plan integration' WHERE name = 'Workplace Violence Prevention Program Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ea20b5b28ccd', 'Workplace Violence Prevention Program Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Workplace Violence Prevention Program Administrator — Cal/OSHA; California Division of Occupational Safety and Health (DOSH)', 'Workplace Violence Prevention Program Administrator', 'Cal/OSHA; California Division of Occupational Safety and Health (DOSH)', 'SB 553 (Cal. Lab. Code 6401.9 -- Workplace Violence Prevention Plan required for nearly all California employers effective July 1, 2024); 8 CCR 3342 (healthcare workplace violence -- existing Cal/OSHA standard); Cal. Lab. Code 6401.7 (IIPP -- Injury and Illness Prevention Program, violence prevention as component); Cal. Penal Code 11160-11163.6 (reporting violent injuries); Cal. Code Regs. Title 8, new Section 3343 (SB 553 implementing regulations); OSHA General Duty Clause (29 USC 654(a)(1) -- federal parallel)', 'Written Workplace Violence Prevention Plan (WVPP) required for all employers (exceptions: healthcare with existing plans, telework, small employer with no public access, law enforcement); WVPP must include: names of responsible persons, procedures for employee involvement, coordination with other employers at multi-employer sites, procedures to accept and respond to reports, procedures to ensure no retaliation, workplace hazard assessment, procedures to identify and evaluate workplace violence hazards, procedures for post-incident response and investigation, training procedures; violent incident log (Cal. Lab. Code 6401.9(d)) maintained for minimum 5 years; training at initial plan establishment, annually thereafter, and when new hazard identified; training records retained for 1 year, WVPP retained for 5 years, violent incident logs retained for 5 years', 'Plan administrator designated with authority and resources; hazard assessment documented and updated after each incident; employee reporting mechanism with documented anonymity protections; incident investigation file with root cause analysis; threat assessment team identified; coordination with law enforcement protocols; annual plan review documentation; training completion tracking per SB 553 requirements; emergency action plan integration', 'Workplace violence prevention plan documents (SB 553), threat assessment documents, active shooter preparedness documents');
UPDATE citizen_catalog SET standards_of_creation = 'DEI programs must be documented with legitimate business justification; metrics collection must be voluntary and not compelled (to avoid reverse discrimination claims); unconscious bias training content must be evidence-based and not stereotype-reinforcing; ERG governance documents must ensure open membership regardless of protected class; diversity surveys must be anonymous with results aggregated to prevent individual identification; ESG/human capital disclosures must be accurate and not misleading (SEC anti-fraud provisions); program effectiveness measurement documented annually; DEI budget allocation and resource tracking', soc_controls = 'DEI program design reviewed by employment counsel to avoid Title VII exposure; data collected for DEI purposes stored with restricted access; survey anonymity technically verified; DEI metrics reporting aggregated (no individual identification); ERG funding equitable across groups; training vendor vetting for content accuracy and legal compliance; voluntary nature of participation documented; program modification documented when legal landscape changes' WHERE name = 'DEI Program Compliance and Reporting Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f6a0cef65a32', 'DEI Program Compliance and Reporting Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'DEI Program Compliance and Reporting Specialist — EEOC; OFCCP; California CRD; SEC (for publicly traded company ESG reporting)', 'DEI Program Compliance and Reporting Specialist', 'EEOC; OFCCP; California CRD; SEC (for publicly traded company ESG reporting)', 'Title VII (42 USC 2000e -- voluntary affirmative action programs must satisfy Weber/Johnson framework); Executive Order 11246 (affirmative action for federal contractors); EEOC Guidelines on Affirmative Action (29 CFR Part 1608 -- safe harbor for lawful voluntary programs); Cal. Corp. Code 301.3-301.4 (board diversity -- SB 826 enjoined/Crest v. Padilla but compliance culture persists); SEC Regulation S-K Item 101(c) (human capital disclosures); Nasdaq Board Diversity Rules (Listing Rule 5605(f) -- vacated by 5th Circuit 2024 but still voluntary best practice); Cal. Gov. Code 12940 (DEI programs cannot create reverse discrimination claims)', 'DEI programs must be documented with legitimate business justification; metrics collection must be voluntary and not compelled (to avoid reverse discrimination claims); unconscious bias training content must be evidence-based and not stereotype-reinforcing; ERG governance documents must ensure open membership regardless of protected class; diversity surveys must be anonymous with results aggregated to prevent individual identification; ESG/human capital disclosures must be accurate and not misleading (SEC anti-fraud provisions); program effectiveness measurement documented annually; DEI budget allocation and resource tracking', 'DEI program design reviewed by employment counsel to avoid Title VII exposure; data collected for DEI purposes stored with restricted access; survey anonymity technically verified; DEI metrics reporting aggregated (no individual identification); ERG funding equitable across groups; training vendor vetting for content accuracy and legal compliance; voluntary nature of participation documented; program modification documented when legal landscape changes', 'Diversity/equity/inclusion (DEI) program documents, employee resource group (ERG) documents, unconscious bias training documents, workplace culture survey documents, employee engagement survey documents');
UPDATE citizen_catalog SET standards_of_creation = 'EAP vendor contracts must specify scope of services, licensure of counselors (LCSW, LMFT, LPCC per Cal. Bus. & Prof. Code), confidentiality protections, utilization reporting (aggregate only -- no individual identification to employer), crisis response protocols, and coordination with ADA/FMLA leave processes; EAP referrals by supervisors must be voluntary (mandatory referral as condition of continued employment requires careful documentation); aggregate utilization reports must not identify individuals; critical incident debriefing protocols documented; self-referral vs. management-referral tracking; substance abuse referrals subject to heightened confidentiality (42 CFR Part 2)', soc_controls = 'Firewall between EAP utilization data and employment decisions; employer receives only aggregate data (utilization rates, service categories); individual session records maintained by EAP vendor, not employer; mandatory reporting exceptions documented (child abuse, elder abuse, danger to self/others); vendor licensure verification; EAP not used as substitute for performance management; integration with return-to-work and accommodation processes documented' WHERE name = 'EAP and Behavioral Health Benefit Compliance Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2d53abf14e2b', 'EAP and Behavioral Health Benefit Compliance Administrator', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'EAP and Behavioral Health Benefit Compliance Administrator — California DMHC; California BBS (Board of Behavioral Sciences); SAMHSA (federal guidance); DOL EBSA (if EAP is ERISA-covered)', 'EAP and Behavioral Health Benefit Compliance Administrator', 'California DMHC; California BBS (Board of Behavioral Sciences); SAMHSA (federal guidance); DOL EBSA (if EAP is ERISA-covered)', 'Cal. Health & Safety Code 1340 et seq. (Knox-Keene -- if EAP provides healthcare); HIPAA Privacy Rule (45 CFR 164 -- if EAP handles PHI); Mental Health Parity and Addiction Equity Act (29 USC 1185a -- if EAP provides mental health benefits beyond referral); Cal. Welf. & Inst. Code 5150 (mandatory reporting when danger to self/others); Cal. Bus. & Prof. Code 2290.5 (telehealth requirements for virtual EAP); ERISA (29 USC 1001 -- coverage depends on whether EAP is benefits-providing or referral-only); 42 CFR Part 2 (substance use disorder records confidentiality)', 'EAP vendor contracts must specify scope of services, licensure of counselors (LCSW, LMFT, LPCC per Cal. Bus. & Prof. Code), confidentiality protections, utilization reporting (aggregate only -- no individual identification to employer), crisis response protocols, and coordination with ADA/FMLA leave processes; EAP referrals by supervisors must be voluntary (mandatory referral as condition of continued employment requires careful documentation); aggregate utilization reports must not identify individuals; critical incident debriefing protocols documented; self-referral vs. management-referral tracking; substance abuse referrals subject to heightened confidentiality (42 CFR Part 2)', 'Firewall between EAP utilization data and employment decisions; employer receives only aggregate data (utilization rates, service categories); individual session records maintained by EAP vendor, not employer; mandatory reporting exceptions documented (child abuse, elder abuse, danger to self/others); vendor licensure verification; EAP not used as substitute for performance management; integration with return-to-work and accommodation processes documented', 'Employee assistance program (EAP) documents, stay interview documents');
UPDATE citizen_catalog SET standards_of_creation = 'Transition support documentation must include: preferred name and pronoun update across all systems (email, badge, directory, benefits), timeline developed with transitioning employee, restroom and facilities access per gender identity (2 CCR 11034(e)), dress code applied per gender identity, confidentiality of transition (disclosure only with employee consent), medical leave coordination if applicable (FMLA/CFRA/ADA for gender-affirming care), insurance coverage review for gender-affirming procedures; name change processed upon employee request without requiring court order for workplace use; all documentation uses employee''s affirmed name and pronouns', soc_controls = 'Transition plan access restricted to HR and employee (not shared with management without consent); prior name/gender data secured and not accessible in routine systems; benefits enrollment updated without requiring disclosure of reason; coworker communication plan developed with employee''s consent and participation; training for coworkers limited to what employee authorizes; no outing of transitioning employees; records retention addresses name change continuity; anti-retaliation monitoring' WHERE name = 'Gender Identity and Expression Workplace Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6f8ca0d66b8e', 'Gender Identity and Expression Workplace Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Gender Identity and Expression Workplace Compliance Specialist — California CRD; EEOC; Cal/OSHA (facilities)', 'Gender Identity and Expression Workplace Compliance Specialist', 'California CRD; EEOC; Cal/OSHA (facilities)', 'Cal. Gov. Code 12940 (FEHA prohibits discrimination based on gender identity, gender expression, and sexual orientation); Cal. Gov. Code 12949 (dress code/grooming standards cannot enforce gender stereotypes); 2 CCR 11030-11031 (CRD transgender employee regulations); Cal. Gov. Code 12926(r)(2) (sex includes gender identity and gender expression); Bostock v. Clayton County, 590 US ___ (2020) (Title VII covers gender identity and sexual orientation); EEOC Strategic Enforcement Plan; Cal. Educ. Code 221.5 (educational employment contexts); Cal. Health & Safety Code 103430 (name/gender change records)', 'Transition support documentation must include: preferred name and pronoun update across all systems (email, badge, directory, benefits), timeline developed with transitioning employee, restroom and facilities access per gender identity (2 CCR 11034(e)), dress code applied per gender identity, confidentiality of transition (disclosure only with employee consent), medical leave coordination if applicable (FMLA/CFRA/ADA for gender-affirming care), insurance coverage review for gender-affirming procedures; name change processed upon employee request without requiring court order for workplace use; all documentation uses employee''s affirmed name and pronouns', 'Transition plan access restricted to HR and employee (not shared with management without consent); prior name/gender data secured and not accessible in routine systems; benefits enrollment updated without requiring disclosure of reason; coworker communication plan developed with employee''s consent and participation; training for coworkers limited to what employee authorizes; no outing of transitioning employees; records retention addresses name change continuity; anti-retaliation monitoring', 'Gender transition workplace documents, reasonable accommodation interactive process documents (identity-related), employee privacy documents');
UPDATE citizen_catalog SET standards_of_creation = 'All management communications regarding unionization must comply with TIPS framework (no Threats, Interrogation, Promises, or Surveillance); NLRB-compliant campaign materials reviewed by labor counsel before distribution; election objections filed within 5 business days; ULP charges responded to within 14 days; collective bargaining proposals documented; bargaining session minutes maintained; information requests responded to timely and completely; grievance tracking and response within CBA timelines; Weingarten rights notices posted; supervisor training documented on Section 7 rights and prohibited conduct', soc_controls = 'Labor counsel review of all management communications during organizing; supervisor training records on TIPS compliance; no surveillance of union activities (including social media monitoring limitations per NLRB); information request log with response tracking; bargaining notes maintained separately from personnel files; grievance file system with access controls; strike/lockout contingency planning documented; neutrality agreement compliance monitoring if applicable; economic weapon documentation (lockout, replacement, subcontracting) with legal review' WHERE name = 'Labor Relations and Collective Bargaining Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1edef6ed19cc', 'Labor Relations and Collective Bargaining Compliance Specialist', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Labor Relations and Collective Bargaining Compliance Specialist — National Labor Relations Board (NLRB); California PERB (Public Employment Relations Board -- public sector)', 'Labor Relations and Collective Bargaining Compliance Specialist', 'National Labor Relations Board (NLRB); California PERB (Public Employment Relations Board -- public sector)', 'NLRA (29 USC 151-169); NLRA Section 7 (employee rights to organize, bargain collectively, engage in concerted activity); NLRA Section 8(a) (employer unfair labor practices -- interference, domination, discrimination, retaliation, refusal to bargain); NLRA Section 8(b) (union unfair labor practices); 29 CFR Parts 100-103 (NLRB rules); Cal. Gov. Code 3500-3511 (Meyers-Milias-Brown Act -- local public employees); Cal. Gov. Code 3512-3524 (Dills Act -- state employees); Cal. Gov. Code 3540-3549.3 (EERA -- educational employees); NLRB v. Gissel Packing Co., 395 US 575 (1969) (bargaining orders); Cemex Construction Materials Pacific, 372 NLRB No. 130 (2023) (new recognition framework)', 'All management communications regarding unionization must comply with TIPS framework (no Threats, Interrogation, Promises, or Surveillance); NLRB-compliant campaign materials reviewed by labor counsel before distribution; election objections filed within 5 business days; ULP charges responded to within 14 days; collective bargaining proposals documented; bargaining session minutes maintained; information requests responded to timely and completely; grievance tracking and response within CBA timelines; Weingarten rights notices posted; supervisor training documented on Section 7 rights and prohibited conduct', 'Labor counsel review of all management communications during organizing; supervisor training records on TIPS compliance; no surveillance of union activities (including social media monitoring limitations per NLRB); information request log with response tracking; bargaining notes maintained separately from personnel files; grievance file system with access controls; strike/lockout contingency planning documented; neutrality agreement compliance monitoring if applicable; economic weapon documentation (lockout, replacement, subcontracting) with legal review', 'Union avoidance/labor relations documents, gift/entertainment policy documents (union context)');
UPDATE citizen_catalog SET standards_of_creation = 'Code of conduct must be distributed to all employees with signed acknowledgment; conflict of interest disclosure forms completed annually and upon material change; gift/entertainment reports with dollar thresholds and pre-approval requirements; whistleblower/ethics hotline advertised and accessible (anonymous option required for SOX-covered companies); investigation tracking from receipt through resolution with documented findings; Form 700 filing by designated employees per agency conflict of interest code; FCPA compliance program with risk assessment, training, third-party due diligence, and monitoring', soc_controls = 'Ethics/compliance function reports to board or audit committee (not solely to management); investigation files accessible only to compliance and legal; whistleblower identity protection with technical safeguards; conflict of interest waiver authority defined and documented; gift tracking system with approval workflow; related-party transaction review process; annual compliance risk assessment; hotline activity reporting to board (aggregate); investigation independence from subject''s chain of command' WHERE name = 'Corporate Ethics and Conflict of Interest Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1361304f012e', 'Corporate Ethics and Conflict of Interest Compliance Officer', 'Hr Payroll Workplace Compliance', 'Hr Payroll Workplace', 'Corporate Ethics and Conflict of Interest Compliance Officer — SEC (publicly traded); DOJ Criminal Division (FCPA/anti-corruption); California Attorney General (nonprofit governance); Professional licensing boards', 'Corporate Ethics and Conflict of Interest Compliance Officer', 'SEC (publicly traded); DOJ Criminal Division (FCPA/anti-corruption); California Attorney General (nonprofit governance); Professional licensing boards', 'Sarbanes-Oxley Act Section 301 (audit committee independence), Section 406 (code of ethics for senior financial officers), Section 806 (whistleblower protection); Dodd-Frank Act Section 922 (SEC whistleblower awards); Cal. Corp. Code 310 (director conflict of interest transactions); Cal. Corp. Code 5233 (nonprofit self-dealing); Cal. Lab. Code 1102.5 (California whistleblower protection); Cal. Gov. Code 1090-1099 (conflict of interest -- public officials); Cal. Gov. Code 81000-91014 (Political Reform Act -- Form 700); FCPA (15 USC 78dd-1 to -3)', 'Code of conduct must be distributed to all employees with signed acknowledgment; conflict of interest disclosure forms completed annually and upon material change; gift/entertainment reports with dollar thresholds and pre-approval requirements; whistleblower/ethics hotline advertised and accessible (anonymous option required for SOX-covered companies); investigation tracking from receipt through resolution with documented findings; Form 700 filing by designated employees per agency conflict of interest code; FCPA compliance program with risk assessment, training, third-party due diligence, and monitoring', 'Ethics/compliance function reports to board or audit committee (not solely to management); investigation files accessible only to compliance and legal; whistleblower identity protection with technical safeguards; conflict of interest waiver authority defined and documented; gift tracking system with approval workflow; related-party transaction review process; annual compliance risk assessment; hotline activity reporting to board (aggregate); investigation independence from subject''s chain of command', 'Ethics investigation documents, conflict of interest disclosure documents, gift/entertainment policy documents, code of conduct violation investigation documents, whistleblower investigation documents');
