UPDATE citizen_catalog SET standards_of_creation = 'Rate case filings must include testimony, workpapers, cost-of-service studies, revenue requirement calculations, load forecasts, and rate design proposals per CPUC Rules of Practice and Procedure. All financial data must comply with FERC Uniform System of Accounts (18 CFR Part 101 electric, Part 201 gas). Documents must be served on all parties of record and filed electronically via CPUC Docket Office.', soc_controls = 'SOC 2 Type II (data integrity of financial projections); internal audit of revenue requirement models; segregation of duties between rate design and cost allocation; version control on all testimony drafts; retention per CPUC GO 107 (minimum 3 years after rate case decision).' WHERE name = 'Persona A.1.1: Utility Rate Case Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-bee12a59cab6', 'Persona A.1.1: Utility Rate Case Analyst', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.1.1: Utility Rate Case Analyst — California Public Utilities Commission (CPUC); Federal Energy Regulatory Commission (FERC)', 'Persona A.1.1: Utility Rate Case Analyst', 'California Public Utilities Commission (CPUC); Federal Energy Regulatory Commission (FERC)', ':; Cal. Pub. Util. Code § 454 (rate change applications; showing before commission required); Cal. Pub. Util. Code § 451 (just and reasonable rates); Cal. Pub. Util. Code § 728 (commission authority to fix rates); CPUC General Order 96-B (Industry Rules — rate filing requirements); 16 CFR Part 18 (FTC Guides for utility advertising); FERC 18 CFR Part 35 (filing of rate schedules — wholesale); CPUC Standard Practice U-27-W/E/G (rate schedule format)', 'Rate case filings must include testimony, workpapers, cost-of-service studies, revenue requirement calculations, load forecasts, and rate design proposals per CPUC Rules of Practice and Procedure. All financial data must comply with FERC Uniform System of Accounts (18 CFR Part 101 electric, Part 201 gas). Documents must be served on all parties of record and filed electronically via CPUC Docket Office.', 'SOC 2 Type II (data integrity of financial projections); internal audit of revenue requirement models; segregation of duties between rate design and cost allocation; version control on all testimony drafts; retention per CPUC GO 107 (minimum 3 years after rate case decision).', 'General Rate Case (GRC) applications, Cost of Capital (CoC) applications, rate design proposals, testimony and workpapers, advice letters (Tier 1/2/3), tariff schedule sheets, preliminary/rebuttal/supplemental testimony, settlement agreements, rate comparison exhibits');
UPDATE citizen_catalog SET standards_of_creation = 'Tariff sheets must follow prescribed format (U-27 series), include effective date, canceling sheet reference, advice letter number, and be filed via advice letter process per GO 96-B. Preliminary statements, rate schedules, rules, and sample forms must all be maintained as official tariff book. Changes require 30-day notice unless expedited.', soc_controls = 'SOC 2 Type II (change management for tariff publications); access controls on tariff editing systems; approval chain from rate analyst through regulatory affairs director; audit trail of all tariff modifications; public accessibility verification.' WHERE name = 'Persona A.1.2: Utility Tariff Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b3a52484552e', 'Persona A.1.2: Utility Tariff Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.1.2: Utility Tariff Specialist — CPUC; State Water Resources Control Board (for water tariff filings)', 'Persona A.1.2: Utility Tariff Specialist', 'CPUC; State Water Resources Control Board (for water tariff filings)', ':; Cal. Pub. Util. Code § 489 (tariff schedules filed with commission); Cal. Pub. Util. Code § 491 (tariff schedule availability to public); Cal. Pub. Util. Code § 532 (prohibited rebates/discriminatory rates); CPUC General Order 96-B (Rules for filing and changing tariffs); CPUC Standard Practice U-27-W (water tariff format); CPUC Standard Practice U-27-E (electric tariff format); CPUC Standard Practice U-27-G (gas tariff format)', 'Tariff sheets must follow prescribed format (U-27 series), include effective date, canceling sheet reference, advice letter number, and be filed via advice letter process per GO 96-B. Preliminary statements, rate schedules, rules, and sample forms must all be maintained as official tariff book. Changes require 30-day notice unless expedited.', 'SOC 2 Type II (change management for tariff publications); access controls on tariff editing systems; approval chain from rate analyst through regulatory affairs director; audit trail of all tariff modifications; public accessibility verification.', 'Tariff schedule sheets (original/revised/substitute), advice letters (Tier 1/2/3), preliminary statements, rate schedules (residential/commercial/industrial/agricultural), tariff rules, service territory maps, special condition riders, tariff supplements');
UPDATE citizen_catalog SET standards_of_creation = 'TOU rate schedules must define peak/off-peak/super-off-peak periods, include comparison tables showing impact by climate zone, provide bill protection calculations, and include opt-out mechanism documentation. Customer notifications must be bilingual (English + primary language of service territory).', soc_controls = 'SOC 2 Type II (metering data integrity for TOU calculations); customer notification tracking (proof of 1-year notice); bill protection credit calculation audit; climate zone impact analysis documentation; exemption tracking for medical baseline customers.' WHERE name = 'Persona A.1.3: Time-of-Use Rate Program Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f876aa79b04f', 'Persona A.1.3: Time-of-Use Rate Program Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.1.3: Time-of-Use Rate Program Manager — CPUC', 'Persona A.1.3: Time-of-Use Rate Program Manager', 'CPUC', ':; Cal. Pub. Util. Code § 745 (time-variant pricing authorization; default TOU for residential); Cal. Pub. Util. Code § 745(c)(1) (medical baseline/third-party notification exemptions from default TOU); Cal. Pub. Util. Code § 745(c)(4) (1-year interval data + 1-year bill protection required before default TOU); Cal. Pub. Util. Code § 745(c)(6) (opt-out rights, no penalty); Cal. Pub. Util. Code § 745(d) (hot climate zone hardship findings required); CPUC Decision 17-01-006 (TOU rate reform); CPUC Decision 18-07-006 (default TOU implementation)', 'TOU rate schedules must define peak/off-peak/super-off-peak periods, include comparison tables showing impact by climate zone, provide bill protection calculations, and include opt-out mechanism documentation. Customer notifications must be bilingual (English + primary language of service territory).', 'SOC 2 Type II (metering data integrity for TOU calculations); customer notification tracking (proof of 1-year notice); bill protection credit calculation audit; climate zone impact analysis documentation; exemption tracking for medical baseline customers.', 'TOU rate schedules, bill protection credit calculations, customer notification letters (pre-enrollment), opt-out confirmation documents, climate zone impact analyses, interval usage data reports, rate comparison summaries, exemption applications (medical baseline/vulnerable customer)');
UPDATE citizen_catalog SET standards_of_creation = 'Program enrollment documents must specify load reduction obligations, measurement & verification protocols, settlement calculations, and performance penalties. Baseline calculations must follow CAISO-approved methodologies. Aggregator contracts must specify telemetry requirements and dispatch protocols.', soc_controls = 'SOC 2 Type II (metering/telemetry data integrity); CAISO settlement reconciliation audits; baseline calculation verification; load impact protocol compliance; performance payment accuracy; customer enrollment consent tracking.' WHERE name = 'Persona A.1.4: Demand Response Program Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-bfb7ab639848', 'Persona A.1.4: Demand Response Program Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.1.4: Demand Response Program Coordinator — CPUC; California Independent System Operator (CAISO); FERC', 'Persona A.1.4: Demand Response Program Coordinator', 'CPUC; California Independent System Operator (CAISO); FERC', ':; Cal. Pub. Util. Code § 380 (resource adequacy requirements); Cal. Pub. Util. Code § 380.5 (demand response valuation); FERC Order 745 (compensation for demand response in wholesale markets); FERC Order 2222 (distributed energy resource aggregation); CAISO Tariff § 4.13 (demand response participation); CPUC Decision 16-09-056 (demand response auction mechanism); CPUC Rulemaking R.13-09-011 (demand response framework)', 'Program enrollment documents must specify load reduction obligations, measurement & verification protocols, settlement calculations, and performance penalties. Baseline calculations must follow CAISO-approved methodologies. Aggregator contracts must specify telemetry requirements and dispatch protocols.', 'SOC 2 Type II (metering/telemetry data integrity); CAISO settlement reconciliation audits; baseline calculation verification; load impact protocol compliance; performance payment accuracy; customer enrollment consent tracking.', 'Demand response program contracts, load curtailment agreements, baseline calculation worksheets, CAISO DR registration forms, aggregator participation agreements, settlement statements, load impact evaluation reports, capacity bidding program documents, critical peak pricing event notices');
UPDATE citizen_catalog SET standards_of_creation = 'Bills must itemize generation, transmission, distribution, and all surcharges separately. Must display baseline allocation, tier/TOU pricing, taxes, fees, and account balance. Estimated bills must be clearly marked. Billing adjustments must include explanation and comply with backbilling limitation rules (CPUC Rule 17/18). Proration rules apply for mid-cycle rate changes.', soc_controls = 'SOC 2 Type II (billing system data integrity); meter-to-bill reconciliation audits; backbilling limitation compliance checks; estimated bill frequency monitoring; complaint resolution tracking within CPUC-mandated timelines; PII protection for customer account data.' WHERE name = 'Persona A.2.1: Utility Billing Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3a5baad30769', 'Persona A.2.1: Utility Billing Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.2.1: Utility Billing Compliance Specialist — CPUC; State Water Resources Control Board', 'Persona A.2.1: Utility Billing Compliance Specialist', 'CPUC; State Water Resources Control Board', ':; Cal. Pub. Util. Code § 770 (commission authority over standards, measurements, service); Cal. Pub. Util. Code § 773 (meter testing and accuracy standards); Cal. Pub. Util. Code § 780 (billing complaints and corrections); Cal. Pub. Util. Code § 453 (non-discrimination in service); CPUC General Order 112-F § 117 (gas meter accuracy); CPUC General Order 95 Rule 31 (electric service requirements); CPUC Decision 12-03-054 (disconnection protections); 16 CFR Part 260 (FTC Green Guides — environmental claims on bills)', 'Bills must itemize generation, transmission, distribution, and all surcharges separately. Must display baseline allocation, tier/TOU pricing, taxes, fees, and account balance. Estimated bills must be clearly marked. Billing adjustments must include explanation and comply with backbilling limitation rules (CPUC Rule 17/18). Proration rules apply for mid-cycle rate changes.', 'SOC 2 Type II (billing system data integrity); meter-to-bill reconciliation audits; backbilling limitation compliance checks; estimated bill frequency monitoring; complaint resolution tracking within CPUC-mandated timelines; PII protection for customer account data.', 'Utility bills (electric/gas/water), billing adjustment notices, estimated billing notices, backbilling calculations, deposit requirement letters, credit/collection notices, payment arrangement agreements, billing dispute responses, rate comparison disclosures, energy usage statements');
UPDATE citizen_catalog SET standards_of_creation = 'Meter installation records must include serial number, manufacturer, capacity rating, multiplier, installation date, last calibration date, GPS coordinates, and associated account number. Calibration certificates must reference NIST-traceable standards. Test results must document pre/post accuracy within ANSI tolerance bands.', soc_controls = 'SOC 2 Type II (meter data management system integrity); calibration certificate chain of custody; NIST traceability documentation; field service work order audit trail; meter reading exception reports; tamper detection logging; chain of custody for removed meters.' WHERE name = 'Persona A.2.2: Utility Meter Technician / Metering Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-38c24e291212', 'Persona A.2.2: Utility Meter Technician / Metering Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.2.2: Utility Meter Technician / Metering Compliance Officer — CPUC; American National Standards Institute (ANSI); American Water Works Association (AWWA)', 'Persona A.2.2: Utility Meter Technician / Metering Compliance Officer', 'CPUC; American National Standards Institute (ANSI); American Water Works Association (AWWA)', ':; Cal. Pub. Util. Code § 773 (meter testing on request); Cal. Pub. Util. Code § 774 (meter testing fees); CPUC General Order 112-F § 117 (gas meter accuracy ±2%); ANSI C12.1 (Code for Electricity Metering); ANSI C12.20 (Electricity Meters — 0.2 and 0.5 Accuracy Classes); AWWA C700 Series (water meter standards); CPUC Decision 18-12-009 (advanced metering infrastructure); NIST Handbook 44 (specifications for utility meters)', 'Meter installation records must include serial number, manufacturer, capacity rating, multiplier, installation date, last calibration date, GPS coordinates, and associated account number. Calibration certificates must reference NIST-traceable standards. Test results must document pre/post accuracy within ANSI tolerance bands.', 'SOC 2 Type II (meter data management system integrity); calibration certificate chain of custody; NIST traceability documentation; field service work order audit trail; meter reading exception reports; tamper detection logging; chain of custody for removed meters.', 'Meter installation records, calibration certificates, meter test reports, meter exchange records, smart meter deployment records, AMI communication logs, meter reading exception reports, tamper investigation reports, meter accuracy dispute records');
UPDATE citizen_catalog SET standards_of_creation = 'Opt-out applications must document customer request, current meter type, replacement meter type (analog/non-communicating digital), fee schedule acknowledgment, and monthly manual meter reading schedule. Confirmation letters must itemize initial fee and ongoing monthly charges. EMF/RF concern documentation is informational only (CPUC found no health basis for opt-out but granted on customer choice grounds).', soc_controls = 'SOC 2 Type II (customer data protection); opt-out election tracking; fee assessment accuracy; manual meter reading scheduling compliance; meter exchange documentation; customer communication records retention.' WHERE name = 'Persona A.2.3: Smart Meter Opt-Out Program Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b0beb36fcd58', 'Persona A.2.3: Smart Meter Opt-Out Program Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.2.3: Smart Meter Opt-Out Program Coordinator — CPUC', 'Persona A.2.3: Smart Meter Opt-Out Program Coordinator', 'CPUC', ':; CPUC Decision 14-12-078 (smart meter opt-out — PG&E); CPUC Decision 14-04-008 (smart meter opt-out — SCE); CPUC Decision 15-01-051 (smart meter opt-out — SDG&E); CPUC Resolution E-4628 (opt-out fee schedules); Cal. Pub. Util. Code § 745(c)(4) (interval data from advanced meter); FCC 47 CFR Part 15 (RF emissions — smart meter compliance)', 'Opt-out applications must document customer request, current meter type, replacement meter type (analog/non-communicating digital), fee schedule acknowledgment, and monthly manual meter reading schedule. Confirmation letters must itemize initial fee and ongoing monthly charges. EMF/RF concern documentation is informational only (CPUC found no health basis for opt-out but granted on customer choice grounds).', 'SOC 2 Type II (customer data protection); opt-out election tracking; fee assessment accuracy; manual meter reading scheduling compliance; meter exchange documentation; customer communication records retention.', 'Smart meter opt-out applications, opt-out confirmation letters, fee schedule disclosures, meter exchange work orders, manual meter reading schedules, customer correspondence regarding RF/EMF concerns, analog meter inventory records');
UPDATE citizen_catalog SET standards_of_creation = 'Disconnection notices must provide 15 days written notice (residential), state reason for disconnection, inform of right to dispute, list payment assistance programs (CARE/FERA/LIHEAP), include contact for medical baseline certification, and be provided in English and primary language of household. Reconnection must occur within 24 hours of payment or payment arrangement. Winter moratorium protections (November-April for qualifying customers) must be documented.', soc_controls = 'SOC 2 Type II (customer account data integrity); disconnection notice timing verification; medical baseline flag audit; CARE/FERA enrollment cross-check before disconnection; winter moratorium compliance; 48-hour hold verification for disputed bills; reporting to CPUC per § 910.5.' WHERE name = 'Persona A.2.4: Utility Service Connection/Disconnection Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-db2655799c67', 'Persona A.2.4: Utility Service Connection/Disconnection Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.2.4: Utility Service Connection/Disconnection Specialist — CPUC; California Department of Community Services and Development (CSD)', 'Persona A.2.4: Utility Service Connection/Disconnection Specialist', 'CPUC; California Department of Community Services and Development (CSD)', ':; Cal. Pub. Util. Code § 779 (disconnection notice requirements); Cal. Pub. Util. Code § 779.1 (third-party notification before disconnection); Cal. Pub. Util. Code § 779.3 (medical baseline disconnection protections); Cal. Pub. Util. Code § 779.5 (disconnection of low-income customers); Cal. Pub. Util. Code § 10009 (water disconnection — Human Right to Water); Cal. Pub. Util. Code § 910.5 (disconnection reporting to Legislature); CPUC Decision 12-03-054 (Phase II disconnection protections); CPUC Decision 20-06-003 (COVID-era moratorium rules); Cal. Health & Safety Code § 116908 (water shutoff protections — SB 998)', 'Disconnection notices must provide 15 days written notice (residential), state reason for disconnection, inform of right to dispute, list payment assistance programs (CARE/FERA/LIHEAP), include contact for medical baseline certification, and be provided in English and primary language of household. Reconnection must occur within 24 hours of payment or payment arrangement. Winter moratorium protections (November-April for qualifying customers) must be documented.', 'SOC 2 Type II (customer account data integrity); disconnection notice timing verification; medical baseline flag audit; CARE/FERA enrollment cross-check before disconnection; winter moratorium compliance; 48-hour hold verification for disputed bills; reporting to CPUC per § 910.5.', 'Service connection applications, disconnection/shutoff notices, reconnection orders, 48-hour final notices, third-party notification forms, winter moratorium protection certifications, medical baseline disconnect protection certificates, payment arrangement agreements, deposit requirement calculations, service establishment deposits/refunds');
UPDATE citizen_catalog SET standards_of_creation = 'Deposit calculations must be based on estimated average monthly billing (2x maximum). Deposit refund must occur after 12 months of timely payment. Credit screening must comply with FCRA adverse action notice requirements. Alternative deposit options (payment history letter, guarantor) must be offered. Deposits earn interest at rate set annually by CPUC.', soc_controls = 'SOC 2 Type II (customer financial data protection); deposit interest accrual accuracy; refund timing compliance; FCRA adverse action notice tracking; non-discrimination audit (deposits by demographic); alternative deposit option documentation.' WHERE name = 'Persona A.2.5: Utility Deposit and Credit Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-521ac3393acb', 'Persona A.2.5: Utility Deposit and Credit Analyst', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.2.5: Utility Deposit and Credit Analyst — CPUC', 'Persona A.2.5: Utility Deposit and Credit Analyst', 'CPUC', ':; CPUC Rules 6 (electric), 7 (gas), 14 (water) — service deposits; Cal. Pub. Util. Code § 394.4 (credit check limitations); Cal. Pub. Util. Code § 453 (non-discrimination); CPUC Decision 10-07-048 (deposit and credit practices reform); Cal. Civ. Code § 1785 et seq. (Consumer Credit Reporting Agencies Act); 15 USC § 1681 (Fair Credit Reporting Act)', 'Deposit calculations must be based on estimated average monthly billing (2x maximum). Deposit refund must occur after 12 months of timely payment. Credit screening must comply with FCRA adverse action notice requirements. Alternative deposit options (payment history letter, guarantor) must be offered. Deposits earn interest at rate set annually by CPUC.', 'SOC 2 Type II (customer financial data protection); deposit interest accrual accuracy; refund timing compliance; FCRA adverse action notice tracking; non-discrimination audit (deposits by demographic); alternative deposit option documentation.', 'Deposit requirement letters, deposit refund calculations, credit screening authorization forms, FCRA adverse action notices, alternative deposit arrangements, deposit interest accrual records, guarantor agreements, deposit transfer records (service address changes)');
UPDATE citizen_catalog SET standards_of_creation = 'Applications must collect household size, income documentation or categorical eligibility certification (CalFresh, Medi-Cal, SSI/SSP, CalWORKs, LIHEAP, etc.). Self-certification permitted for initial enrollment; reverification required every 2-4 years. Single application form must allow eligibility determination for both CARE and FERA per § 739.1(f)(2). High-usage verification triggered at 400% baseline (discretionary) and 600% baseline (mandatory) per § 739.1(j).', soc_controls = 'SOC 2 Type II (PII protection for income data); enrollment penetration tracking vs. eligible population; income verification audit (random sampling); high-usage ESAP referral tracking; categorical eligibility cross-matching with state databases; discount calculation accuracy; group living facility certification.' WHERE name = 'Persona A.3.1: CARE/FERA Program Administrator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5139a33a9b4e', 'Persona A.3.1: CARE/FERA Program Administrator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.3.1: CARE/FERA Program Administrator — CPUC; California Department of Community Services and Development', 'Persona A.3.1: CARE/FERA Program Administrator', 'CPUC; California Department of Community Services and Development', ':; Cal. Pub. Util. Code § 739.1 (CARE program establishment; 30-35% discount; eligibility 200% FPL); Cal. Pub. Util. Code § 739.1(d) (CARE administrative costs; outreach, marketing, certification, verification); Cal. Pub. Util. Code § 739.1(e) (cross-enrollment with ULTS program); Cal. Pub. Util. Code § 739.1(f) (coordination with Health and Human Services; categorical eligibility); Cal. Pub. Util. Code § 739.1(h) (nonprofit group living facility eligibility); Cal. Pub. Util. Code § 739.1(j) (high-usage verification — 400%/600% of baseline); Cal. Pub. Util. Code § 739.12 (FERA — Family Electric Rate Assistance); Cal. Pub. Util. Code § 382 (low-income assistance programs generally); Cal. Pub. Util. Code § 2870 (CARE program definitions); CPUC Decision 16-11-022 (CARE/FERA program implementation)', 'Applications must collect household size, income documentation or categorical eligibility certification (CalFresh, Medi-Cal, SSI/SSP, CalWORKs, LIHEAP, etc.). Self-certification permitted for initial enrollment; reverification required every 2-4 years. Single application form must allow eligibility determination for both CARE and FERA per § 739.1(f)(2). High-usage verification triggered at 400% baseline (discretionary) and 600% baseline (mandatory) per § 739.1(j).', 'SOC 2 Type II (PII protection for income data); enrollment penetration tracking vs. eligible population; income verification audit (random sampling); high-usage ESAP referral tracking; categorical eligibility cross-matching with state databases; discount calculation accuracy; group living facility certification.', 'CARE/FERA applications, income verification documents, categorical eligibility certifications, reverification notices, high-usage verification letters, ESAP referral records, group living facility certifications, program penetration reports, Low-Income Oversight Board reports, cross-enrollment records (ULTS/Lifeline)');
UPDATE citizen_catalog SET standards_of_creation = 'LIHEAP applications must collect income verification (150% FPL for heating/cooling assistance, 60% state median for weatherization), household composition, energy burden documentation, and utility account information. Benefit calculations follow federal formula. State plan must be submitted to HHS annually. Coordination required with CARE/FERA enrollment.', soc_controls = 'SOC 2 Type II (federal PII requirements); 45 CFR Part 96 audit compliance; income eligibility verification; benefit payment accuracy; crisis intervention documentation; weatherization referral tracking; annual state plan reporting to HHS; CARE cross-enrollment.' WHERE name = 'Persona A.3.2: LIHEAP/Energy Assistance Program Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-0bf8dcedb4de', 'Persona A.3.2: LIHEAP/Energy Assistance Program Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.3.2: LIHEAP/Energy Assistance Program Coordinator — U.S. Department of Health and Human Services (LIHEAP); California Department of Community Services and Development; CPUC', 'Persona A.3.2: LIHEAP/Energy Assistance Program Coordinator', 'U.S. Department of Health and Human Services (LIHEAP); California Department of Community Services and Development; CPUC', ':; 42 USC § 8621-8630 (Low Income Home Energy Assistance Act); 45 CFR Part 96, Subpart H (LIHEAP program regulations); Cal. Pub. Util. Code § 382 (public purpose programs); Cal. Pub. Util. Code § 382.1 (Low-Income Oversight Board); Cal. Pub. Util. Code § 731 (coordination of low-income programs); Cal. Pub. Util. Code § 327 (CARE/low-income weatherization coordination); California Community Services Block Grant Act (Gov. Code § 12725 et seq.)', 'LIHEAP applications must collect income verification (150% FPL for heating/cooling assistance, 60% state median for weatherization), household composition, energy burden documentation, and utility account information. Benefit calculations follow federal formula. State plan must be submitted to HHS annually. Coordination required with CARE/FERA enrollment.', 'SOC 2 Type II (federal PII requirements); 45 CFR Part 96 audit compliance; income eligibility verification; benefit payment accuracy; crisis intervention documentation; weatherization referral tracking; annual state plan reporting to HHS; CARE cross-enrollment.', 'LIHEAP applications, income verification documents, benefit determination notices, crisis intervention authorizations, weatherization referrals, vendor payment records, utility arrearage payment records, state plan submissions (to HHS), program performance reports, Low-Income Oversight Board annual reports');
UPDATE citizen_catalog SET standards_of_creation = 'Certification requires physician/licensed practitioner signature on utility-specific medical baseline form. Must identify qualifying condition (life-support equipment, heating/cooling medical necessity, electric powered wheelchair). Annual recertification required. Baseline allocation provides additional kilowatt-hours at Tier 1 pricing. PSPS notification priority and backup power eligibility documented.', soc_controls = 'SOC 2 Type II (HIPAA-adjacent medical data protection); physician certification verification; annual recertification tracking; disconnection block flag audit; PSPS priority notification list accuracy; TOU exemption coding; backup power program eligibility documentation.' WHERE name = 'Persona A.3.3: Medical Baseline Program Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2330822fc0dc', 'Persona A.3.3: Medical Baseline Program Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.3.3: Medical Baseline Program Coordinator — CPUC', 'Persona A.3.3: Medical Baseline Program Coordinator', 'CPUC', ':; Cal. Pub. Util. Code § 739(c) (medical baseline allowance — life support, special heating/cooling needs); Cal. Pub. Util. Code § 739(d) (physician certification requirement); Cal. Pub. Util. Code § 779.3 (disconnection protection for medical baseline customers); Cal. Pub. Util. Code § 745(c)(1) (TOU exemption for medical baseline); Cal. Pub. Util. Code § 8386(d)(6)(C) (PSPS backup power for medical baseline); CPUC Decision 12-03-054 (in-person visit before disconnection); CPUC Rule 19 (medical baseline — electric); CPUC Rule 20 (medical baseline — gas)', 'Certification requires physician/licensed practitioner signature on utility-specific medical baseline form. Must identify qualifying condition (life-support equipment, heating/cooling medical necessity, electric powered wheelchair). Annual recertification required. Baseline allocation provides additional kilowatt-hours at Tier 1 pricing. PSPS notification priority and backup power eligibility documented.', 'SOC 2 Type II (HIPAA-adjacent medical data protection); physician certification verification; annual recertification tracking; disconnection block flag audit; PSPS priority notification list accuracy; TOU exemption coding; backup power program eligibility documentation.', 'Medical baseline applications, physician certification forms, annual recertification notices, medical baseline allocation calculations, disconnection protection flags, PSPS priority notification records, backup power program applications, medical baseline rate schedule assignments, life-support equipment inventory declarations');
UPDATE citizen_catalog SET standards_of_creation = 'Winter moratorium documentation must identify qualifying households (income-qualified, medical baseline, elderly). Heat event moratoriums require weather trigger documentation. Post-moratorium repayment plans must be offered. Annual disconnection reports to Legislature must include data on demographics, geography, and follow-up actions per § 910.5.', soc_controls = 'SOC 2 Type II (customer vulnerability data protection); moratorium qualification tracking; seasonal moratorium compliance calendar; extreme weather event trigger documentation; post-moratorium payment plan documentation; annual reporting data accuracy; cross-reference with medical baseline and CARE enrollment.' WHERE name = 'Persona A.3.4: Utility Shutoff Protection Specialist (Winter Moratorium / Heat Event)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a16716e5c9e4', 'Persona A.3.4: Utility Shutoff Protection Specialist (Winter Moratorium / Heat Event)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.3.4: Utility Shutoff Protection Specialist (Winter Moratorium / Heat Event) — CPUC; California Office of Emergency Services', 'Persona A.3.4: Utility Shutoff Protection Specialist (Winter Moratorium / Heat Event)', 'CPUC; California Office of Emergency Services', ':; Cal. Pub. Util. Code § 779 (disconnection notice and timing); Cal. Pub. Util. Code § 779.3 (medical baseline disconnection protection); Cal. Pub. Util. Code § 779.5 (disconnection of low-income households); CPUC Decision 12-03-054 (disconnection reform — in-person visit, payment plan offers); CPUC Decision 20-06-003 (COVID disconnection moratorium and successor rules); Cal. Pub. Util. Code § 910.5 (annual disconnection reporting to Legislature); CPUC Resolution M-4842 (extreme weather disconnection moratorium); Cal. Health & Safety Code § 116908 (SB 998 — water shutoff protections)', 'Winter moratorium documentation must identify qualifying households (income-qualified, medical baseline, elderly). Heat event moratoriums require weather trigger documentation. Post-moratorium repayment plans must be offered. Annual disconnection reports to Legislature must include data on demographics, geography, and follow-up actions per § 910.5.', 'SOC 2 Type II (customer vulnerability data protection); moratorium qualification tracking; seasonal moratorium compliance calendar; extreme weather event trigger documentation; post-moratorium payment plan documentation; annual reporting data accuracy; cross-reference with medical baseline and CARE enrollment.', 'Winter moratorium protection notices, extreme weather moratorium declarations, qualifying household certifications, post-moratorium repayment plans, annual disconnection reports (§ 910.5), disconnection statistics by demographic/geography, payment plan offers, in-person visit documentation, senior/disabled/medical baseline protection records');
UPDATE citizen_catalog SET standards_of_creation = 'NEM applications must include system capacity, inverter specifications, single-line diagram, proof of electrical inspection clearance, signed interconnection agreement, and meter configuration (bidirectional capable). 12-month true-up calculations must track net consumption/generation by TOU period. Annual net surplus compensation notices required.', soc_controls = 'SOC 2 Type II (generation data integrity); 30-day interconnection processing compliance; 5% cap tracking (legacy NEM); 12-month true-up calculation audit; net surplus compensation accuracy; CPUC monthly progress reports (§ 2827(c)(3)(C)); Rule 21 interconnection compliance.' WHERE name = 'Persona A.4.1: Net Energy Metering (NEM) Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-88e91f4a6801', 'Persona A.4.1: Net Energy Metering (NEM) Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.4.1: Net Energy Metering (NEM) Compliance Specialist — CPUC; FERC (wholesale interconnection aspects)', 'Persona A.4.1: Net Energy Metering (NEM) Compliance Specialist', 'CPUC; FERC (wholesale interconnection aspects)', ':; Cal. Pub. Util. Code § 2827 (NEM 1.0 establishment; 5% aggregate cap; standard contract/tariff); Cal. Pub. Util. Code § 2827(c) (bidirectional metering; interconnection within 30 working days); Cal. Pub. Util. Code § 2827(g) (rate structure parity — no standby charges); Cal. Pub. Util. Code § 2827(h) (12-month true-up calculation; net surplus compensation); Cal. Pub. Util. Code § 2827.1 (NEM 2.0 — successor tariff); CPUC Decision 16-01-044 (NEM 2.0 implementation); CPUC Decision 22-12-056 (NEM 3.0 / Net Billing Tariff); CPUC Rule 21 (interconnection standards); IEEE 1547 (Standard for Interconnection of Distributed Resources); UL 1741 (Inverters, Converters, Controllers — Safety)', 'NEM applications must include system capacity, inverter specifications, single-line diagram, proof of electrical inspection clearance, signed interconnection agreement, and meter configuration (bidirectional capable). 12-month true-up calculations must track net consumption/generation by TOU period. Annual net surplus compensation notices required.', 'SOC 2 Type II (generation data integrity); 30-day interconnection processing compliance; 5% cap tracking (legacy NEM); 12-month true-up calculation audit; net surplus compensation accuracy; CPUC monthly progress reports (§ 2827(c)(3)(C)); Rule 21 interconnection compliance.', 'NEM applications (1.0/2.0/3.0), interconnection agreements, system capacity certificates, electrical inspection clearances, single-line diagrams, bidirectional meter installation records, 12-month true-up statements, net surplus compensation calculations, CPUC monthly progress reports, renewable energy credit allocation records, aggregated meter election forms (§ 2827(h)(4))');
UPDATE citizen_catalog SET standards_of_creation = 'Implementation plans must address all 8 elements of § 366.2(c)(3)(A)-(H). Registration with CPUC required before furnishing service. Operating service agreement with incumbent IOU required. Dual customer notification (60-day advance) must inform of automatic enrollment and opt-out right. Rate disclosure must compare CCA rates vs. IOU rates. Diverse business enterprise reports due annually.', soc_controls = 'SOC 2 Type II (customer data handling from IOU transfers); implementation plan completeness audit; customer notification compliance (dual notice + opt-out mechanism); CPUC registration verification; resource adequacy compliance; RPS compliance tracking; Power Content Label accuracy; Brown Act compliance for public meetings; diverse procurement reporting.' WHERE name = 'Persona A.4.2: Community Choice Aggregation (CCA) Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f92baceacc67', 'Persona A.4.2: Community Choice Aggregation (CCA) Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.4.2: Community Choice Aggregation (CCA) Compliance Manager — CPUC; CAISO; California Energy Commission (CEC)', 'Persona A.4.2: Community Choice Aggregation (CCA) Compliance Manager', 'CPUC; CAISO; California Energy Commission (CEC)', ':; Cal. Pub. Util. Code § 366.2 (CCA authorization; implementation plan requirements); Cal. Pub. Util. Code § 366.2(c)(3) (implementation plan contents: organization, rates, disclosure, consumer protection); Cal. Pub. Util. Code § 366.2(c)(4) (statement of intent: universal access, reliability, equitable treatment); Cal. Pub. Util. Code § 366.2(c)(15) (dual notification requirement — 60 days before enrollment); Cal. Pub. Util. Code § 366.2(c)(13) (opt-out rights — 60 days/2 billing cycles without penalty); Cal. Pub. Util. Code § 366.2(m) (diverse business enterprise procurement reporting); Cal. Pub. Util. Code § 366.2(n) (Brown Act compliance for CCA meetings); Cal. Pub. Util. Code § 380 (resource adequacy obligations apply to CCAs); Cal. Pub. Util. Code § 399.15 (RPS obligations apply to CCAs); CPUC Decision 18-10-019 (IRP requirements for CCAs)', 'Implementation plans must address all 8 elements of § 366.2(c)(3)(A)-(H). Registration with CPUC required before furnishing service. Operating service agreement with incumbent IOU required. Dual customer notification (60-day advance) must inform of automatic enrollment and opt-out right. Rate disclosure must compare CCA rates vs. IOU rates. Diverse business enterprise reports due annually.', 'SOC 2 Type II (customer data handling from IOU transfers); implementation plan completeness audit; customer notification compliance (dual notice + opt-out mechanism); CPUC registration verification; resource adequacy compliance; RPS compliance tracking; Power Content Label accuracy; Brown Act compliance for public meetings; diverse procurement reporting.', 'CCA implementation plans, statements of intent, CPUC registration filings, operating service agreements with IOU, customer enrollment/opt-out notifications, rate comparison disclosures, Power Content Labels, resource adequacy filings, RPS compliance reports, diverse business enterprise procurement reports (§ 366.2(m)), IRP filings, load forecasts, financial audits');
UPDATE citizen_catalog SET standards_of_creation = 'Plans must address all 23 elements of § 8386(d). Must include cost-per-avoided-ignition estimates, risk-based prioritization using CPUC fire threat maps, at least 2 mitigation alternatives per risk, community outreach plans in 5+ languages (§ 8386(d)(19)(B)), and monitoring/audit procedures (§ 8386(d)(22)). Plans posted on OEIS website for 2+ months public comment.', soc_controls = 'SOC 2 Type II (risk model data integrity); OEIS approval tracking; 23-element completeness audit; fire threat map alignment; cost-per-avoided-ignition methodology review; vegetation management compliance; inspection compliance (GO 165); workforce adequacy documentation; language accessibility audit; annual compliance reporting.' WHERE name = 'Persona A.5.1: Wildfire Mitigation Plan Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3b2ebf03051a', 'Persona A.5.1: Wildfire Mitigation Plan Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.5.1: Wildfire Mitigation Plan Compliance Manager — CPUC Office of Energy Infrastructure Safety (OEIS); CPUC Wildfire Safety Division (Cal. Pub. Util. Code § 326)', 'Persona A.5.1: Wildfire Mitigation Plan Compliance Manager', 'CPUC Office of Energy Infrastructure Safety (OEIS); CPUC Wildfire Safety Division (Cal. Pub. Util. Code § 326)', ':; Cal. Pub. Util. Code § 8386 (wildfire mitigation plan requirements — 23 mandatory elements); Cal. Pub. Util. Code § 8386(b) (filing every 4 years); Cal. Pub. Util. Code § 8386(d)(1)-(23) (plan contents: personnel, objectives, preventive strategies, metrics, deenergization protocols, vegetation management, inspections, risk identification, undergrounding, workforce adequacy, disaster preparedness, monitoring/audit); Cal. Pub. Util. Code § 8386.3 (OEIS approval/denial within 9 months); Cal. Pub. Util. Code § 8386.4 (cost recovery in GRC); Cal. Pub. Util. Code § 8386.6 (qualified line clearance tree trimmers); Cal. Pub. Util. Code § 8388.5 (undergrounding program); Cal. Pub. Util. Code § 8389 (safety certification); Cal. Pub. Util. Code § 326 (Wildfire Safety Division establishment); CPUC General Order 95 (overhead electric line construction); CPUC General Order 165 (inspection requirements for electric utilities); 14 CCR § 1250-1258 (PRC fire prevention standards)', 'Plans must address all 23 elements of § 8386(d). Must include cost-per-avoided-ignition estimates, risk-based prioritization using CPUC fire threat maps, at least 2 mitigation alternatives per risk, community outreach plans in 5+ languages (§ 8386(d)(19)(B)), and monitoring/audit procedures (§ 8386(d)(22)). Plans posted on OEIS website for 2+ months public comment.', 'SOC 2 Type II (risk model data integrity); OEIS approval tracking; 23-element completeness audit; fire threat map alignment; cost-per-avoided-ignition methodology review; vegetation management compliance; inspection compliance (GO 165); workforce adequacy documentation; language accessibility audit; annual compliance reporting.', 'Wildfire mitigation plans, OEIS approval/denial decisions, safety certification applications (§ 8389), risk assessment reports, fire threat map overlays, vegetation management records, inspection records (GO 165), undergrounding program filings, community outreach documentation (multilingual), deenergization protocol documents, quarterly/annual compliance reports, cost recovery filings (GRC)');
UPDATE citizen_catalog SET standards_of_creation = 'PSPS event documentation must include weather trigger data, affected circuit identification, estimated customer count, critical facility inventory, notification timeline (48-hour, 24-hour, 1-hour, real-time), medical baseline customer contact records, and restoration timeline. Post-event reports required within specified timeframes. Community Resource Center activation records required.', soc_controls = 'SOC 2 Type II (critical infrastructure data protection); notification timeline compliance audit; medical baseline contact verification; critical facility notification confirmation; post-event report accuracy; restoration time tracking; Community Resource Center operation documentation; frequently deenergized circuit trend analysis.' WHERE name = 'Persona A.5.2: Public Safety Power Shutoff (PSPS) Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-c930cb8ba969', 'Persona A.5.2: Public Safety Power Shutoff (PSPS) Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.5.2: Public Safety Power Shutoff (PSPS) Coordinator — CPUC; OEIS; California Office of Emergency Services (Cal OES)', 'Persona A.5.2: Public Safety Power Shutoff (PSPS) Coordinator', 'CPUC; OEIS; California Office of Emergency Services (Cal OES)', ':; Cal. Pub. Util. Code § 8386(d)(6) (deenergization protocols); Cal. Pub. Util. Code § 8386(d)(7) (customer notification procedures for deenergization); Cal. Pub. Util. Code § 8386(d)(8) (frequently deenergized circuit identification); Cal. Pub. Util. Code § 8386(d)(6)(A)-(C) (first responders, health infrastructure, medical baseline protections); CPUC Resolution ESRB-8 (de-energization guidelines); CPUC Decision 19-05-042 (PSPS notification requirements); CPUC Decision 20-05-051 (PSPS reporting requirements); Cal. Gov. Code § 8550 et seq. (Emergency Services Act)', 'PSPS event documentation must include weather trigger data, affected circuit identification, estimated customer count, critical facility inventory, notification timeline (48-hour, 24-hour, 1-hour, real-time), medical baseline customer contact records, and restoration timeline. Post-event reports required within specified timeframes. Community Resource Center activation records required.', 'SOC 2 Type II (critical infrastructure data protection); notification timeline compliance audit; medical baseline contact verification; critical facility notification confirmation; post-event report accuracy; restoration time tracking; Community Resource Center operation documentation; frequently deenergized circuit trend analysis.', 'PSPS event initiation reports, weather trigger analyses, affected circuit maps, customer notification records (48hr/24hr/1hr), medical baseline customer contact logs, critical facility notifications (hospitals, fire stations, water treatment), Community Resource Center activation records, post-event reports, restoration timeline documentation, claim/reimbursement applications, frequently deenergized circuit reduction plans');
UPDATE citizen_catalog SET standards_of_creation = 'Vegetation management records must document species identification, clearance distances achieved, trim cycle compliance, hazard tree identification and removal, work crew qualifications (§ 8386.6 — qualified line clearance tree trimmers), GPS coordinates of work performed, and before/after photographic documentation. Enhanced clearance in CPUC High Fire Threat Districts (HFTD).', soc_controls = 'SOC 2 Type II (geospatial data integrity); trim cycle compliance tracking; HFTD priority compliance; worker qualification verification (per § 8386.6); clearance distance measurement audit; hazard tree removal documentation; independent evaluator review (§ 8387); photographic evidence management.' WHERE name = 'Persona A.5.3: Utility Arborist / Vegetation Management Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ddb77e5b9d0b', 'Persona A.5.3: Utility Arborist / Vegetation Management Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.5.3: Utility Arborist / Vegetation Management Compliance Specialist — CPUC; Cal Fire; OEIS', 'Persona A.5.3: Utility Arborist / Vegetation Management Compliance Specialist', 'CPUC; Cal Fire; OEIS', ':; Cal. Pub. Util. Code § 8386(d)(9) (vegetation management plans in wildfire mitigation); Cal. Pub. Util. Code § 8386.6 (qualified line clearance tree trimmer requirements); Cal. Pub. Util. Code § 8387 (independent evaluator for vegetation management); CPUC General Order 95, Rule 35 (vegetation clearance distances); Cal. Pub. Resources Code § 4292 (powerline hazard reduction — fire prevention); Cal. Pub. Resources Code § 4293 (clearance of flammable vegetation near lines); 14 CCR § 1250 et seq. (fire prevention regulations); ANSI A300 (Tree Care Operations — Standard Practices); ISA (International Society of Arboriculture) Best Management Practices', 'Vegetation management records must document species identification, clearance distances achieved, trim cycle compliance, hazard tree identification and removal, work crew qualifications (§ 8386.6 — qualified line clearance tree trimmers), GPS coordinates of work performed, and before/after photographic documentation. Enhanced clearance in CPUC High Fire Threat Districts (HFTD).', 'SOC 2 Type II (geospatial data integrity); trim cycle compliance tracking; HFTD priority compliance; worker qualification verification (per § 8386.6); clearance distance measurement audit; hazard tree removal documentation; independent evaluator review (§ 8387); photographic evidence management.', 'Vegetation management plans, trim cycle records, clearance distance measurements, hazard tree assessment reports, tree removal permits, worker qualification certificates, HFTD-specific vegetation records, before/after photographic documentation, independent evaluator reports, species-specific management protocols, right-of-way clearance records');
UPDATE citizen_catalog SET standards_of_creation = 'Inspection records must document asset ID, location (GPS), condition assessment (using standardized grading), deficiency identification with priority classification (A/B/C or equivalent), corrective action required, completion deadline, and inspector qualification. Patrol inspections (visual from ground), detailed inspections (climbing/drone), and intrusive inspections each have distinct documentation requirements.', soc_controls = 'SOC 2 Type II (asset data integrity); inspection cycle compliance tracking (GO 165 — 5-year cycle for detailed, annual patrol); deficiency resolution tracking; inspector qualification verification; contractor inspection quality audit (per § 8386(d)(22)(C)); GIS/asset management system accuracy; drone inspection data management.' WHERE name = 'Persona A.5.4: Utility Infrastructure Inspector';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e996fc32ca9f', 'Persona A.5.4: Utility Infrastructure Inspector', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.5.4: Utility Infrastructure Inspector — CPUC; OEIS', 'Persona A.5.4: Utility Infrastructure Inspector', 'CPUC; OEIS', ':; CPUC General Order 165 (inspection cycle requirements for electric utilities); CPUC General Order 95 (overhead electric line construction standards); CPUC General Order 128 (underground electric supply/communication construction); CPUC General Order 112-F (gas system safety — pipeline inspection); 49 CFR Part 192 (federal gas pipeline safety — PHMSA); 49 CFR Part 195 (federal hazardous liquid pipeline safety); Cal. Pub. Util. Code § 8386(d)(10) (inspection plans in wildfire mitigation); Cal. Pub. Util. Code § 8386(d)(22)(C) (inspection auditing); ANSI/NESC C2 (National Electrical Safety Code)', 'Inspection records must document asset ID, location (GPS), condition assessment (using standardized grading), deficiency identification with priority classification (A/B/C or equivalent), corrective action required, completion deadline, and inspector qualification. Patrol inspections (visual from ground), detailed inspections (climbing/drone), and intrusive inspections each have distinct documentation requirements.', 'SOC 2 Type II (asset data integrity); inspection cycle compliance tracking (GO 165 — 5-year cycle for detailed, annual patrol); deficiency resolution tracking; inspector qualification verification; contractor inspection quality audit (per § 8386(d)(22)(C)); GIS/asset management system accuracy; drone inspection data management.', 'Patrol inspection reports, detailed inspection reports, intrusive inspection reports, drone inspection records/images, deficiency notices, corrective action records, infrastructure replacement orders, GO 165 compliance reports, gas pipeline inspection records (PHMSA), transmission line inspection reports, substation inspection reports, distribution infrastructure condition assessments');
UPDATE citizen_catalog SET standards_of_creation = 'Easement documents must describe the servient tenement by legal description, identify the dominant tenement (utility), specify the purpose and scope of use, include width and location specifications, reference any environmental constraints, and be recorded with the county recorder. Utility easement appraisals must comply with USPAP (Uniform Standards of Professional Appraisal Practice) when compensation is involved.', soc_controls = 'SOC 2 Type II (property records integrity); easement recording verification; scope-of-use compliance audit; encroachment monitoring; CPCN compliance for new facilities; environmental clearance documentation; USPAP appraisal standards compliance.' WHERE name = 'Persona A.6.1: Utility Easement Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-cc9c67551e1d', 'Persona A.6.1: Utility Easement Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.6.1: Utility Easement Specialist — CPUC; local planning/zoning authorities', 'Persona A.6.1: Utility Easement Specialist', 'CPUC; local planning/zoning authorities', ':; Cal. Civ. Code § 801-813 (easements generally); Cal. Pub. Util. Code § 1001 (certificate of public convenience and necessity — CPCN); Cal. Pub. Util. Code § 1002 (findings required for CPCN); Cal. Civ. Code § 1240.010-1240.060 (eminent domain — public utilities); Cal. Gov. Code § 65913.7 (utility corridor mapping); Cal. Civ. Code § 845 (maintenance of easements); CPUC General Order 131-D (electric generation/transmission facility siting)', 'Easement documents must describe the servient tenement by legal description, identify the dominant tenement (utility), specify the purpose and scope of use, include width and location specifications, reference any environmental constraints, and be recorded with the county recorder. Utility easement appraisals must comply with USPAP (Uniform Standards of Professional Appraisal Practice) when compensation is involved.', 'SOC 2 Type II (property records integrity); easement recording verification; scope-of-use compliance audit; encroachment monitoring; CPCN compliance for new facilities; environmental clearance documentation; USPAP appraisal standards compliance.', 'Utility easement grants, easement legal descriptions, survey plats, CPCN applications, environmental impact assessments, eminent domain proceedings, appraisal reports, easement encroachment notices, easement maintenance records, right-of-way agreements, prescriptive easement documentation, easement abandonment/modification records');
UPDATE citizen_catalog SET standards_of_creation = 'Franchise agreements must specify service territory, term (determinate or indeterminate per § 6264), franchise fee calculations (typically % of gross revenue), street restoration requirements, undergrounding obligations, and service level commitments. Municipal franchise ordinances must be adopted by local governing body. CPUC approval required for transfers or modifications.', soc_controls = 'SOC 2 Type II (financial reporting for franchise fee calculations); franchise fee payment accuracy; service territory boundary compliance; franchise renewal tracking; street restoration compliance; undergrounding obligation tracking; municipal reporting requirements.' WHERE name = 'Persona A.6.2: Utility Franchise Agreement Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-71b2668e59f9', 'Persona A.6.2: Utility Franchise Agreement Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.6.2: Utility Franchise Agreement Manager — CPUC; local municipal authorities', 'Persona A.6.2: Utility Franchise Agreement Manager', 'CPUC; local municipal authorities', ':; Cal. Pub. Util. Code § 6001-6012 (gas/electric franchise grants by municipalities); Cal. Pub. Util. Code § 6201-6302 (franchise procedures); Cal. Pub. Util. Code § 6264 (indeterminate franchise endurance); Cal. Pub. Util. Code § 6351 (energy transporter franchises); Cal. Const. Art. XI § 9 (municipal franchise authority); Cal. Pub. Util. Code § 10013 (privatization franchise applications); Cal. Streets & Highways Code § 5896.1 (franchise fees for street work); Local municipal codes (city/county franchise ordinances)', 'Franchise agreements must specify service territory, term (determinate or indeterminate per § 6264), franchise fee calculations (typically % of gross revenue), street restoration requirements, undergrounding obligations, and service level commitments. Municipal franchise ordinances must be adopted by local governing body. CPUC approval required for transfers or modifications.', 'SOC 2 Type II (financial reporting for franchise fee calculations); franchise fee payment accuracy; service territory boundary compliance; franchise renewal tracking; street restoration compliance; undergrounding obligation tracking; municipal reporting requirements.', 'Franchise agreements/ordinances, franchise fee calculations, franchise fee payment records, service territory maps, franchise renewal applications, street restoration reports, undergrounding progress reports, franchise transfer/modification applications, municipal compliance reports, indeterminate franchise valuations');
UPDATE citizen_catalog SET standards_of_creation = 'Pole attachment applications must include structural analysis (pole loading calculations per GO 95), proposed attachment height and equipment specifications, make-ready work requirements, one-touch make-ready eligibility assessment, and fee calculation. Joint-use agreements must allocate maintenance responsibilities and specify access procedures. Shot clock timelines apply per FCC rules (45 days for existing attachments, 60 days for new poles).', soc_controls = 'SOC 2 Type II (asset inventory integrity); pole loading calculation verification; shot clock compliance tracking; make-ready cost allocation audit; joint-use agreement compliance; clearance distance verification (GO 95); annual attachment audit/true-up; unauthorized attachment detection.' WHERE name = 'Persona A.6.3: Pole Attachment Engineer / Joint-Use Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-118c7dcd4955', 'Persona A.6.3: Pole Attachment Engineer / Joint-Use Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.6.3: Pole Attachment Engineer / Joint-Use Coordinator — CPUC; FCC (for telecommunications attachments)', 'Persona A.6.3: Pole Attachment Engineer / Joint-Use Coordinator', 'CPUC; FCC (for telecommunications attachments)', ':; Cal. Pub. Util. Code § 767.5 (pole attachment regulation); 47 USC § 224 (FCC pole attachment regulation); 47 CFR § 1.1401-1.1424 (FCC pole attachment rules); CPUC General Order 95 (overhead line construction — clearances, loading); CPUC General Order 128 (underground construction); CPUC Decision 98-10-058 (pole attachment rates — California); ANSI/NESC C2 (National Electrical Safety Code — pole loading standards); CPUC Rulemaking R.17-06-028 (pole attachment modernization)', 'Pole attachment applications must include structural analysis (pole loading calculations per GO 95), proposed attachment height and equipment specifications, make-ready work requirements, one-touch make-ready eligibility assessment, and fee calculation. Joint-use agreements must allocate maintenance responsibilities and specify access procedures. Shot clock timelines apply per FCC rules (45 days for existing attachments, 60 days for new poles).', 'SOC 2 Type II (asset inventory integrity); pole loading calculation verification; shot clock compliance tracking; make-ready cost allocation audit; joint-use agreement compliance; clearance distance verification (GO 95); annual attachment audit/true-up; unauthorized attachment detection.', 'Pole attachment applications, structural/loading analyses, make-ready estimates, joint-use agreements, pole inspection records, attachment inventories, rate calculations, unauthorized attachment notices, one-touch make-ready notifications, pole replacement/transfer records, conduit occupancy records, shot clock compliance documentation');
UPDATE citizen_catalog SET standards_of_creation = 'Underground conversion project documents must include engineering design plans per GO 128, cost allocation between utility/municipality/property owners (Rule 20A = utility-funded, 20B = applicant-funded, 20C = government-initiated), environmental review (CEQA), permitting, construction schedules, and as-built records. HFTD undergrounding prioritized per § 8388.5.', soc_controls = 'SOC 2 Type II (project cost data integrity); Rule 20A/B/C allocation compliance; GO 128 construction standard compliance; CEQA environmental review documentation; project cost tracking; as-built record accuracy; HFTD prioritization compliance per § 8388.5; municipal coordination documentation.' WHERE name = 'Persona A.6.4: Underground Utility District Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b0d6079fd04a', 'Persona A.6.4: Underground Utility District Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.6.4: Underground Utility District Coordinator — CPUC; local municipalities', 'Persona A.6.4: Underground Utility District Coordinator', 'CPUC; local municipalities', ':; Cal. Pub. Util. Code § 8388.5 (expedited undergrounding program); Cal. Pub. Util. Code § 320 (Rule 20A/B/C undergrounding); CPUC Tariff Rule 20 (overhead-to-underground conversion); Cal. Gov. Code § 5896.1 (street work coordination); Cal. Streets & Highways Code § 5896 et seq. (street improvement districts); CPUC General Order 128 (underground construction standards); Local municipal underground utility district ordinances', 'Underground conversion project documents must include engineering design plans per GO 128, cost allocation between utility/municipality/property owners (Rule 20A = utility-funded, 20B = applicant-funded, 20C = government-initiated), environmental review (CEQA), permitting, construction schedules, and as-built records. HFTD undergrounding prioritized per § 8388.5.', 'SOC 2 Type II (project cost data integrity); Rule 20A/B/C allocation compliance; GO 128 construction standard compliance; CEQA environmental review documentation; project cost tracking; as-built record accuracy; HFTD prioritization compliance per § 8388.5; municipal coordination documentation.', 'Underground utility district formation ordinances, Rule 20A/B/C cost allocation documents, engineering design plans, CEQA environmental reviews, construction permits, cost estimates, progress reports, as-built drawings, inspection records (GO 128 compliance), trench sharing agreements, HFTD undergrounding prioritization records, property owner assessment calculations');
UPDATE citizen_catalog SET standards_of_creation = 'Make-ready infrastructure documents must specify panel capacity, transformer requirements, conduit sizing, and OCPP (Open Charge Point Protocol) interoperability per § 740.20. Site selection must demonstrate equitable access with priority for disadvantaged communities per § 740.16. Data reporting must include utilization rates, energy dispensed, and uptime metrics. Federal NEVI compliance requires CCS connectors, 150kW minimum, 97% uptime.', soc_controls = 'SOC 2 Type II (charging data integrity); OCPP interoperability testing; disadvantaged community siting equity analysis; utilization data reporting accuracy; NEVI compliance (if federally funded); make-ready infrastructure inspection; accessibility compliance (ADA); cost recovery tracking.' WHERE name = 'Persona A.6.5: Electric Vehicle Charging Infrastructure Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4676f3fc5c3e', 'Persona A.6.5: Electric Vehicle Charging Infrastructure Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.6.5: Electric Vehicle Charging Infrastructure Specialist — CPUC; California Energy Commission (CEC); California Air Resources Board (CARB)', 'Persona A.6.5: Electric Vehicle Charging Infrastructure Specialist', 'CPUC; California Energy Commission (CEC); California Air Resources Board (CARB)', ':; Cal. Pub. Util. Code § 740.12 (EV charging infrastructure programs); Cal. Pub. Util. Code § 740.13 (charging station definitions; make-ready infrastructure); Cal. Pub. Util. Code § 740.16 (equitable access; disadvantaged communities); Cal. Pub. Util. Code § 740.19 (utility-side infrastructure cost recovery); Cal. Pub. Util. Code § 740.20 (OCPP interoperability; data reporting; accessibility); Cal. Pub. Util. Code § 740.2 (EV infrastructure policy evaluation); Cal. Pub. Util. Code § 740.15 (grid integration technologies); Cal. Civ. Code § 1947.6 (tenant EV charging rights); Cal. Civ. Code § 4745 (HOA EV charging rights); 42 USC § 18741 (NEVI Formula Program — federal EV infrastructure); FHWA 23 CFR Part 680 (NEVI minimum standards)', 'Make-ready infrastructure documents must specify panel capacity, transformer requirements, conduit sizing, and OCPP (Open Charge Point Protocol) interoperability per § 740.20. Site selection must demonstrate equitable access with priority for disadvantaged communities per § 740.16. Data reporting must include utilization rates, energy dispensed, and uptime metrics. Federal NEVI compliance requires CCS connectors, 150kW minimum, 97% uptime.', 'SOC 2 Type II (charging data integrity); OCPP interoperability testing; disadvantaged community siting equity analysis; utilization data reporting accuracy; NEVI compliance (if federally funded); make-ready infrastructure inspection; accessibility compliance (ADA); cost recovery tracking.', 'EV charging program applications, make-ready infrastructure designs, site selection analyses (equity), OCPP interoperability certifications, utilization/uptime reports, energy dispensed records, cost recovery filings, NEVI compliance documentation, disadvantaged community benefit analyses, grid impact studies, tenant/HOA charging installation records, rate schedule designs (EV-specific)');
UPDATE citizen_catalog SET standards_of_creation = 'Water rate studies must include cost-of-service analysis, revenue requirement calculation, rate design (uniform/tiered/budget-based), affordability analysis, and Prop 218 notice procedures (for public agencies). CPUC-regulated utilities follow GO 96-B advice letter process. Conservation pricing signals must comply with Cal. Water Code § 370-374.', soc_controls = 'SOC 2 Type II (financial data integrity); cost-of-service methodology compliance (AWWA M1); Prop 218 notice/protest procedures (public agencies); rate comparability analysis; low-income water rate assistance tracking; conservation pricing effectiveness.' WHERE name = 'Persona A.7.1: Water Utility Rate Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7cb4dd6e894e', 'Persona A.7.1: Water Utility Rate Analyst', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.7.1: Water Utility Rate Analyst — CPUC (investor-owned water utilities); State Water Resources Control Board (SWRCB); local agencies', 'Persona A.7.1: Water Utility Rate Analyst', 'CPUC (investor-owned water utilities); State Water Resources Control Board (SWRCB); local agencies', ':; Cal. Pub. Util. Code § 454 (rate change authority — water); Cal. Pub. Util. Code § 701 (CPUC general authority); CPUC Standard Practice U-27-W (water tariff format); Cal. Water Code § 370-374 (water rate setting for special districts); Cal. Const. Art. XIII D § 6 (Proposition 218 — water rate voter approval for public agencies); Cal. Gov. Code § 53750-53758 (Proposition 26 — fees/charges); AWWA M1 (Principles of Water Rates, Fees, and Charges); AWWA M35 (Revenue Requirements)', 'Water rate studies must include cost-of-service analysis, revenue requirement calculation, rate design (uniform/tiered/budget-based), affordability analysis, and Prop 218 notice procedures (for public agencies). CPUC-regulated utilities follow GO 96-B advice letter process. Conservation pricing signals must comply with Cal. Water Code § 370-374.', 'SOC 2 Type II (financial data integrity); cost-of-service methodology compliance (AWWA M1); Prop 218 notice/protest procedures (public agencies); rate comparability analysis; low-income water rate assistance tracking; conservation pricing effectiveness.', 'Water rate case applications, cost-of-service studies, revenue requirement analyses, rate design proposals, Prop 218 notices and protest tallies (public agencies), water affordability analyses, tiered rate structure documents, water conservation pricing analyses, advice letters, tariff schedule sheets');
UPDATE citizen_catalog SET standards_of_creation = 'Written disconnection policy must be posted on utility website and provided at service initiation per § 116910. 60-day delinquency minimum before any shutoff action. Written notice must be 7 days before proposed shutoff date; 48-hour final notice required. Notice must be in English, Spanish, Chinese, Tagalog, Vietnamese, Korean (and primary language of territory). Alternative payment plans required per § 116914 (amortization of arrearage, alternative payment schedule, bill reduction). Medical certificate prevents shutoff for 12 months.', soc_controls = 'SOC 2 Type II (customer data protection); 60-day delinquency threshold verification; notice timing compliance; multilingual notice audit; alternative payment plan offering documentation; medical certification tracking; 24-hour reconnection compliance; disconnection policy posting verification; annual reporting to SWRCB.' WHERE name = 'Persona A.7.2: Water Utility Shutoff Protection Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-bb68b0d2f14b', 'Persona A.7.2: Water Utility Shutoff Protection Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.7.2: Water Utility Shutoff Protection Specialist — SWRCB; CPUC (for investor-owned)', 'Persona A.7.2: Water Utility Shutoff Protection Specialist', 'SWRCB; CPUC (for investor-owned)', ':; Cal. Health & Safety Code § 116908 (SB 998 — Water Shutoff Protection Act); Cal. Health & Safety Code § 116910 (written disconnection policy required); Cal. Health & Safety Code § 116912 (60-day delinquency before shutoff; 7-day written notice + 48-hour final); Cal. Health & Safety Code § 116914 (alternative payment plans required); Cal. Health & Safety Code § 116916 (reconnection within 24 hours); Cal. Water Code § 106.3 (Human Right to Water — state policy); Cal. Pub. Util. Code § 10009 (water shutoff for private utilities); CPUC Decision 12-03-054 (disconnection protections — applies to water IOUs); 42 USC § 300f et seq. (Safe Drinking Water Act)', 'Written disconnection policy must be posted on utility website and provided at service initiation per § 116910. 60-day delinquency minimum before any shutoff action. Written notice must be 7 days before proposed shutoff date; 48-hour final notice required. Notice must be in English, Spanish, Chinese, Tagalog, Vietnamese, Korean (and primary language of territory). Alternative payment plans required per § 116914 (amortization of arrearage, alternative payment schedule, bill reduction). Medical certificate prevents shutoff for 12 months.', 'SOC 2 Type II (customer data protection); 60-day delinquency threshold verification; notice timing compliance; multilingual notice audit; alternative payment plan offering documentation; medical certification tracking; 24-hour reconnection compliance; disconnection policy posting verification; annual reporting to SWRCB.', 'Written disconnection policies, 7-day disconnection notices (multilingual), 48-hour final notices, medical certificates (12-month shutoff protection), alternative payment plan agreements, arrearage amortization schedules, reconnection orders, low-income water rate assistance applications, annual disconnection reports to SWRCB, customer complaint records');
UPDATE citizen_catalog SET standards_of_creation = 'Gas safety plans must include leak detection protocols, pipeline integrity management programs, emergency response procedures, and operator qualification records. Incident reports per 49 CFR § 191.5 (telephonic) and § 191.9 (written) within prescribed timeframes. GO 112-F compliance documentation for all construction, operation, and maintenance activities. Annual reports to CPUC per § 955.', soc_controls = 'SOC 2 Type II (pipeline integrity data); PHMSA compliance audit; GO 112-F inspection cycle compliance; leak survey documentation; operator qualification tracking; emergency response drill records; annual safety reporting accuracy; DigAlert/USA North compliance.' WHERE name = 'Persona A.8.1: Gas Utility Safety Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-5a4c422f1df8', 'Persona A.8.1: Gas Utility Safety Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona A.8.1: Gas Utility Safety Compliance Officer — CPUC Safety and Enforcement Division; Pipeline and Hazardous Materials Safety Administration (PHMSA)', 'Persona A.8.1: Gas Utility Safety Compliance Officer', 'CPUC Safety and Enforcement Division; Pipeline and Hazardous Materials Safety Administration (PHMSA)', ':; 49 CFR Part 192 (Transportation of Natural and Other Gas by Pipeline — federal minimum safety standards); 49 CFR Part 191 (Transportation of Natural and Other Gas by Pipeline — annual/incident reporting); Cal. Pub. Util. Code § 955 (gas safety reporting); Cal. Pub. Util. Code § 957 (gas safety plans); Cal. Pub. Util. Code § 961 (gas safety expenditure accountability); CPUC General Order 112-F (Rules Governing Gas System Safety); CPUC General Order 58-B (maintenance of gas plant); API 1160 (Managing System Integrity for Hazardous Liquid Pipelines); ASME B31.8 (Gas Transmission and Distribution Piping Systems); Cal. Gov. Code § 4216-4216.9 (DigAlert/USA North — underground facility marking)', 'Gas safety plans must include leak detection protocols, pipeline integrity management programs, emergency response procedures, and operator qualification records. Incident reports per 49 CFR § 191.5 (telephonic) and § 191.9 (written) within prescribed timeframes. GO 112-F compliance documentation for all construction, operation, and maintenance activities. Annual reports to CPUC per § 955.', 'SOC 2 Type II (pipeline integrity data); PHMSA compliance audit; GO 112-F inspection cycle compliance; leak survey documentation; operator qualification tracking; emergency response drill records; annual safety reporting accuracy; DigAlert/USA North compliance.', 'Gas safety plans, pipeline integrity management program documents, leak survey reports, incident reports (PHMSA), operator qualification records, emergency response plans, GO 112-F compliance records, cathodic protection records, pipeline patrol reports, valve maintenance records, DigAlert locate request records, gas leak repair records, annual safety reports to CPUC');
UPDATE citizen_catalog SET standards_of_creation = 'Franchise applications must demonstrate technical, financial, and legal qualifications. Franchise agreements specify build-out requirements, service area, PEG access obligations, customer service standards, and franchise fee calculation methodology. DIVCA state video franchise applications filed with CPUC. Renewal governed by 47 USC § 546 (informal/formal proceedings).', soc_controls = 'SOC 2 Type II (subscriber data protection); franchise fee calculation audit; build-out compliance tracking; PEG access obligation compliance; customer service standard monitoring; annual franchise compliance reports to LFA; DIVCA registration and annual reports.' WHERE name = 'Persona B.1.1: Cable Franchise Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e2e4b06a8821', 'Persona B.1.1: Cable Franchise Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.1.1: Cable Franchise Compliance Manager — FCC; local franchising authorities (LFAs); CPUC (California DIVCA)', 'Persona B.1.1: Cable Franchise Compliance Manager', 'FCC; local franchising authorities (LFAs); CPUC (California DIVCA)', ':; 47 USC § 541 (cable franchise requirements); 47 USC § 542 (franchise fees — max 5% of gross revenues); 47 USC § 543 (cable rate regulation); 47 USC § 546 (franchise renewal); Cal. Gov. Code § 53066 (local cable franchise authority); Cal. Gov. Code § 53066.2 (non-discrimination in franchise awards); Cal. Gov. Code § 53066.3 (level playing field for additional franchises); Cal. Gov. Code § 5800-5970 (DIVCA — Digital Infrastructure and Video Competition Act); 47 CFR § 76.31 (franchise standards); 47 CFR § 76.41 (franchise renewal procedures)', 'Franchise applications must demonstrate technical, financial, and legal qualifications. Franchise agreements specify build-out requirements, service area, PEG access obligations, customer service standards, and franchise fee calculation methodology. DIVCA state video franchise applications filed with CPUC. Renewal governed by 47 USC § 546 (informal/formal proceedings).', 'SOC 2 Type II (subscriber data protection); franchise fee calculation audit; build-out compliance tracking; PEG access obligation compliance; customer service standard monitoring; annual franchise compliance reports to LFA; DIVCA registration and annual reports.', 'Cable franchise agreements, DIVCA state video franchise applications, franchise fee payment calculations, build-out compliance reports, franchise renewal applications, service area maps, franchise transfer applications, annual franchise compliance reports, franchise fee audit reports, competitive equity assessments');
UPDATE citizen_catalog SET standards_of_creation = 'Broadcasters must elect must-carry or retransmission consent by October 1 every 3 years. Election notices must be in writing to all MVPDs in market. Retransmission consent agreements must be negotiated in good faith per 47 USC § 325(b)(3)(C). Must-carry channel assignments must comply with channel positioning rules. Program access complaints documented per 47 USC § 548.', soc_controls = 'SOC 2 Type II (contract data integrity); election cycle tracking (triennial); good faith negotiation documentation; channel positioning compliance; retransmission consent agreement terms audit; blackout event documentation and consumer notification.' WHERE name = 'Persona B.1.2: Must-Carry / Retransmission Consent Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-c880f3692914', 'Persona B.1.2: Must-Carry / Retransmission Consent Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.1.2: Must-Carry / Retransmission Consent Specialist — FCC', 'Persona B.1.2: Must-Carry / Retransmission Consent Specialist', 'FCC', ':; 47 USC § 534 (must-carry obligations — commercial stations); 47 USC § 535 (must-carry obligations — noncommercial educational stations); 47 USC § 325(b) (retransmission consent requirement); 47 CFR § 76.55-76.65 (must-carry rules); 47 CFR § 76.64 (retransmission consent); 47 USC § 548 (program access — cable-affiliated programming); FCC Media Bureau orders on good faith negotiation', 'Broadcasters must elect must-carry or retransmission consent by October 1 every 3 years. Election notices must be in writing to all MVPDs in market. Retransmission consent agreements must be negotiated in good faith per 47 USC § 325(b)(3)(C). Must-carry channel assignments must comply with channel positioning rules. Program access complaints documented per 47 USC § 548.', 'SOC 2 Type II (contract data integrity); election cycle tracking (triennial); good faith negotiation documentation; channel positioning compliance; retransmission consent agreement terms audit; blackout event documentation and consumer notification.', 'Must-carry/retransmission consent election notices, retransmission consent agreements, good faith negotiation records, channel lineup/positioning documents, market area certifications, program access complaints, carriage dispute filings, blackout event notifications, significantly viewed station certifications');
UPDATE citizen_catalog SET standards_of_creation = 'PEG access agreements specify channel capacity, equipment grants, capital support, operating support, I-Net (institutional network) requirements, and technical standards. PEG operators must maintain content logs, first-come-first-served scheduling policies, and non-censorship compliance with First Amendment principles. Capital and operating funding tracked against franchise agreement benchmarks.', soc_controls = 'SOC 2 Type II (programming data integrity); channel capacity compliance; funding obligation tracking; content scheduling fairness audit; equipment/capital grant verification; First Amendment/non-censorship compliance; annual reporting to LFA.' WHERE name = 'Persona B.1.3: PEG (Public/Educational/Government) Access Channel Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-fc93d84fc258', 'Persona B.1.3: PEG (Public/Educational/Government) Access Channel Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.1.3: PEG (Public/Educational/Government) Access Channel Manager — Local franchising authorities; FCC', 'Persona B.1.3: PEG (Public/Educational/Government) Access Channel Manager', 'Local franchising authorities; FCC', ':; 47 USC § 531 (PEG access channel requirements); 47 USC § 541(a)(4)(B) (franchise authority to require PEG); Cal. Gov. Code § 53066 (local franchise PEG obligations); Cal. Gov. Code § 5870 (DIVCA PEG fee obligations); 47 CFR § 76.1500 (franchise authority enforcement of PEG); Local franchise agreements (PEG-specific provisions)', 'PEG access agreements specify channel capacity, equipment grants, capital support, operating support, I-Net (institutional network) requirements, and technical standards. PEG operators must maintain content logs, first-come-first-served scheduling policies, and non-censorship compliance with First Amendment principles. Capital and operating funding tracked against franchise agreement benchmarks.', 'SOC 2 Type II (programming data integrity); channel capacity compliance; funding obligation tracking; content scheduling fairness audit; equipment/capital grant verification; First Amendment/non-censorship compliance; annual reporting to LFA.', 'PEG access agreements, channel capacity reports, PEG funding calculations, equipment grant records, content scheduling logs, capital improvement plans, programming reports, PEG usage statistics, I-Net operation records, annual PEG compliance reports');
UPDATE citizen_catalog SET standards_of_creation = 'DBS providers must carry all local broadcast stations requesting carriage in each local market where they carry any station. Distant signal importation limited by significantly viewed station rules. License renewal applications per FCC Form 312. Must maintain technical compliance with EIRP limits and orbital slot assignments.', soc_controls = 'SOC 2 Type II (subscriber data); local-into-local carriage compliance; distant signal authorization tracking; FCC license renewal calendar; technical parameter compliance; subscriber address verification for signal eligibility.' WHERE name = 'Persona B.1.4: Satellite TV (DBS) Licensing Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-94838364ed2c', 'Persona B.1.4: Satellite TV (DBS) Licensing Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.1.4: Satellite TV (DBS) Licensing Compliance Specialist — FCC', 'Persona B.1.4: Satellite TV (DBS) Licensing Compliance Specialist', 'FCC', ':; 47 USC § 338 (DBS carriage of local stations); 47 USC § 339 (distant signal limitations); 47 USC § 340 (significantly viewed stations); 47 CFR Part 25 (satellite communications); 47 CFR § 76.66 (DBS must-carry); 47 USC § 342 (local-into-local service deadlines); Satellite Television Extension and Localism Act (STELAR)', 'DBS providers must carry all local broadcast stations requesting carriage in each local market where they carry any station. Distant signal importation limited by significantly viewed station rules. License renewal applications per FCC Form 312. Must maintain technical compliance with EIRP limits and orbital slot assignments.', 'SOC 2 Type II (subscriber data); local-into-local carriage compliance; distant signal authorization tracking; FCC license renewal calendar; technical parameter compliance; subscriber address verification for signal eligibility.', 'DBS license applications/renewals (FCC Form 312), local carriage election records, distant signal authorization documents, significantly viewed station certifications, technical compliance reports, subscriber market designation records, STELAR compliance documentation');
UPDATE citizen_catalog SET standards_of_creation = 'Written privacy notices must be provided at service initiation and annually. Must specify: types of PII collected, purposes, duration of retention, third-party disclosure practices, and subscriber access/correction rights per § 551(a)(1)-(6). Government access requires court order showing clear and convincing evidence per § 551(h). Destruction of PII required when no longer necessary per § 551(e). Civil remedy of minimum $100/day/violation + punitive damages + attorney fees per § 551(f).', soc_controls = 'SOC 2 Type II (subscriber PII protection); annual privacy notice delivery tracking; consent management system; government access request documentation (court orders required); PII retention schedule compliance; data destruction verification upon service termination; CCPA/CPRA compliance (opt-out, deletion requests); data breach response plan.' WHERE name = 'Persona B.2.1: Cable Subscriber Privacy Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6e5378df5484', 'Persona B.2.1: Cable Subscriber Privacy Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.2.1: Cable Subscriber Privacy Compliance Officer — FCC; California Attorney General (CCPA/CPRA)', 'Persona B.2.1: Cable Subscriber Privacy Compliance Officer', 'FCC; California Attorney General (CCPA/CPRA)', ':; 47 USC § 551 (Cable subscriber privacy — Cable Communications Policy Act); 47 USC § 551(a) (written privacy notice at time of service + annually); 47 USC § 551(b) (collection limitations — only for legitimate business purposes); 47 USC § 551(c) (disclosure limitations — requires consent or court order); 47 USC § 551(d) (subscriber access to own records; correction rights); 47 USC § 551(e) (destruction of PII upon termination); 47 USC § 551(f) (civil remedy — $100/day minimum + punitive damages + attorneys'' fees); Cal. Civ. Code § 1798.100 et seq. (CCPA/CPRA); Cal. Gov. Code § 53054.2-53055.3 (cable customer protection standards); Cal. Civ. Code § 1798.82 (data breach notification)', 'Written privacy notices must be provided at service initiation and annually. Must specify: types of PII collected, purposes, duration of retention, third-party disclosure practices, and subscriber access/correction rights per § 551(a)(1)-(6). Government access requires court order showing clear and convincing evidence per § 551(h). Destruction of PII required when no longer necessary per § 551(e). Civil remedy of minimum $100/day/violation + punitive damages + attorney fees per § 551(f).', 'SOC 2 Type II (subscriber PII protection); annual privacy notice delivery tracking; consent management system; government access request documentation (court orders required); PII retention schedule compliance; data destruction verification upon service termination; CCPA/CPRA compliance (opt-out, deletion requests); data breach response plan.', 'Cable subscriber privacy notices (initial + annual), subscriber consent forms, government access requests and court orders, PII retention schedules, data destruction certificates, subscriber record access/correction requests, data breach notifications, CCPA/CPRA disclosure requests, third-party data sharing agreements, privacy impact assessments');
UPDATE citizen_catalog SET standards_of_creation = 'Law enforcement request processing requires legal process verification (warrant vs. subpoena vs. NSL vs. court order), scope limitation to authorized data, customer notification (unless gag order), preservation request compliance (90 days per § 2703(f)). California CalECPA requires warrant for all electronic communications content — more protective than federal law. Detailed logging of every request, response, and legal authority cited.', soc_controls = 'SOC 2 Type II (data access controls); legal process verification workflow; scope limitation audit; customer notification tracking (unless gag order); preservation request tracking (90-day renewal); CalECPA compliance (warrant requirement); transparency reporting (annual); insider access audit.' WHERE name = 'Persona B.2.2: ISP Law Enforcement Request Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3b8b4e56a3d8', 'Persona B.2.2: ISP Law Enforcement Request Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.2.2: ISP Law Enforcement Request Compliance Specialist — FCC; DOJ; courts', 'Persona B.2.2: ISP Law Enforcement Request Compliance Specialist', 'FCC; DOJ; courts', ':; 18 USC § 2703 (Stored Communications Act — required disclosure to government); 18 USC § 2703(a) (content — requires warrant); 18 USC § 2703(b) (opened email/subscriber records — subpoena or court order); 18 USC § 2703(c) (transactional records — subpoena or court order); 18 USC § 2703(d) (court order standard — specific and articulable facts); 18 USC § 2703(f) (preservation requests — 90 days, renewable); 18 USC § 2702 (voluntary disclosure limitations); 18 USC § 2709 (National Security Letters); Carpenter v. United States, 585 U.S. 296 (2018) (warrant required for CSLI); 18 USC § 3121-3127 (pen register/trap and trace); Cal. Penal Code § 1546-1546.4 (CalECPA — California Electronic Communications Privacy Act)', 'Law enforcement request processing requires legal process verification (warrant vs. subpoena vs. NSL vs. court order), scope limitation to authorized data, customer notification (unless gag order), preservation request compliance (90 days per § 2703(f)). California CalECPA requires warrant for all electronic communications content — more protective than federal law. Detailed logging of every request, response, and legal authority cited.', 'SOC 2 Type II (data access controls); legal process verification workflow; scope limitation audit; customer notification tracking (unless gag order); preservation request tracking (90-day renewal); CalECPA compliance (warrant requirement); transparency reporting (annual); insider access audit.', 'Warrants, subpoenas, court orders (§ 2703(d)), National Security Letters, preservation requests (§ 2703(f)), pen register/trap & trace orders, emergency disclosure requests (§ 2702), customer notification letters, gag order compliance records, CalECPA compliance documentation, transparency reports, legal process response logs, data production records');
UPDATE citizen_catalog SET standards_of_creation = 'Broadband availability filings must report service capability at location-level granularity (not census block) per BDC rules. Speed tiers, technology types, and pricing must be accurately reported. Consumer challenge process allows location-specific corrections. Biannual filing deadlines. BEAD funding applications require compliance with NTIA minimum standards.', soc_controls = 'SOC 2 Type II (location data integrity); biannual filing deadline compliance; location-level accuracy verification; consumer challenge response tracking; speed tier verification; technology classification accuracy; BEAD compliance documentation.' WHERE name = 'Persona B.3.1: Broadband Deployment Compliance Analyst (FCC Form 477/BDC)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-16c245dbefac', 'Persona B.3.1: Broadband Deployment Compliance Analyst (FCC Form 477/BDC)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.3.1: Broadband Deployment Compliance Analyst (FCC Form 477/BDC) — FCC; National Telecommunications and Information Administration (NTIA)', 'Persona B.3.1: Broadband Deployment Compliance Analyst (FCC Form 477/BDC)', 'FCC; National Telecommunications and Information Administration (NTIA)', ':; 47 USC § 642 (Broadband DATA Act — Broadband Serviceable Location Fabric); 47 CFR § 1.7001-1.7006 (Broadband Data Collection — BDC); FCC Form 477 (legacy broadband deployment reporting); FCC Broadband Data Collection (BDC) system (replaced Form 477); 47 USC § 1302 (advanced telecommunications capability deployment); FCC Broadband Speed Benchmark (currently 100/20 Mbps); NTIA Internet for All initiative (BEAD Program); Cal. Gov. Code § 11546.46 (California State Digital Equity Plan)', 'Broadband availability filings must report service capability at location-level granularity (not census block) per BDC rules. Speed tiers, technology types, and pricing must be accurately reported. Consumer challenge process allows location-specific corrections. Biannual filing deadlines. BEAD funding applications require compliance with NTIA minimum standards.', 'SOC 2 Type II (location data integrity); biannual filing deadline compliance; location-level accuracy verification; consumer challenge response tracking; speed tier verification; technology classification accuracy; BEAD compliance documentation.', 'FCC BDC filings, broadband availability maps (location-level), speed tier declarations, technology type classifications, consumer challenge responses, BEAD grant applications, broadband deployment plans, infrastructure deployment records, coverage verification test results, biannual filing certifications');
UPDATE citizen_catalog SET standards_of_creation = 'ACP enrollment requires eligibility verification through National Verifier or approved alternative verification. Eligible households receive up to $30/month discount ($75 for Tribal lands). Providers must certify no data caps below threshold. California LifeLine provides additional state-level discount. Digital equity plans must address adoption barriers (affordability, skills, access, relevance, safety).', soc_controls = 'SOC 2 Type II (subscriber PII for eligibility); National Verifier enrollment accuracy; benefit payment reconciliation; duplicate enrollment prevention; subscriber consent documentation; annual reporting to FCC/USAC; de-enrollment notification compliance; digital equity plan performance metrics.' WHERE name = 'Persona B.3.2: Digital Equity / Affordable Connectivity Program (ACP) Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b09acf7bd31b', 'Persona B.3.2: Digital Equity / Affordable Connectivity Program (ACP) Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.3.2: Digital Equity / Affordable Connectivity Program (ACP) Specialist — FCC; NTIA; California Public Utilities Commission', 'Persona B.3.2: Digital Equity / Affordable Connectivity Program (ACP) Specialist', 'FCC; NTIA; California Public Utilities Commission', ':; 47 USC § 1752 (Affordable Connectivity Program — Infrastructure Investment and Jobs Act); 47 CFR Part 54, Subpart R (ACP rules); FCC Lifeline Program (47 CFR Part 54, Subpart E); Cal. Pub. Util. Code § 871-884 (California LifeLine / ULTS); Cal. Gov. Code § 11546.46 (State Digital Equity Plan); NTIA Digital Equity Act Programs; Cal. Pub. Util. Code § 281 (California Advanced Services Fund — CASF); Cal. Pub. Util. Code § 281.5 (CASF Broadband Adoption Account)', 'ACP enrollment requires eligibility verification through National Verifier or approved alternative verification. Eligible households receive up to $30/month discount ($75 for Tribal lands). Providers must certify no data caps below threshold. California LifeLine provides additional state-level discount. Digital equity plans must address adoption barriers (affordability, skills, access, relevance, safety).', 'SOC 2 Type II (subscriber PII for eligibility); National Verifier enrollment accuracy; benefit payment reconciliation; duplicate enrollment prevention; subscriber consent documentation; annual reporting to FCC/USAC; de-enrollment notification compliance; digital equity plan performance metrics.', 'ACP enrollment applications, eligibility verification records, National Verifier responses, benefit payment records, subscriber consent forms, de-enrollment notifications, California LifeLine applications, CASF grant applications/reports, digital equity plan documents, adoption survey results, program performance reports');
UPDATE citizen_catalog SET standards_of_creation = 'RDOF/CAF recipients must deploy broadband meeting minimum speed/latency standards to 100% of required locations within build-out timeline (40% by year 3, 60% by year 4, 80% by year 5, 100% by year 6). Annual FCC/USAC reporting on deployment progress. Speed and latency testing per FCC-approved methodology. Letters of credit or performance bonds required. Non-compliance results in support reduction per § 54.320.', soc_controls = 'SOC 2 Type II (deployment data integrity); build-out milestone tracking; speed/latency test verification; annual USAC filing compliance; letter of credit maintenance; location-level deployment documentation; non-compliance penalty tracking; financial audit per § 54.320.' WHERE name = 'Persona B.3.3: RDOF/CAF Broadband Funding Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1b8f6b305f02', 'Persona B.3.3: RDOF/CAF Broadband Funding Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.3.3: RDOF/CAF Broadband Funding Compliance Specialist — FCC; Universal Service Administrative Company (USAC)', 'Persona B.3.3: RDOF/CAF Broadband Funding Compliance Specialist', 'FCC; Universal Service Administrative Company (USAC)', ':; 47 USC § 254 (Universal Service Fund); 47 CFR Part 54, Subpart D (Connect America Fund — CAF); FCC Rural Digital Opportunity Fund (RDOF) — FCC 20-5; FCC Enhanced A-CAM (Alternative Connect America Cost Model); 47 CFR § 54.316 (build-out obligations and reporting); 47 CFR § 54.320 (compliance measures — non-compliance penalties); 47 CFR § 54.804 (RDOF long-form application requirements); USAC annual reporting requirements', 'RDOF/CAF recipients must deploy broadband meeting minimum speed/latency standards to 100% of required locations within build-out timeline (40% by year 3, 60% by year 4, 80% by year 5, 100% by year 6). Annual FCC/USAC reporting on deployment progress. Speed and latency testing per FCC-approved methodology. Letters of credit or performance bonds required. Non-compliance results in support reduction per § 54.320.', 'SOC 2 Type II (deployment data integrity); build-out milestone tracking; speed/latency test verification; annual USAC filing compliance; letter of credit maintenance; location-level deployment documentation; non-compliance penalty tracking; financial audit per § 54.320.', 'RDOF/CAF award documents, long-form applications, build-out milestone reports, speed/latency test results, annual USAC filings, location-level deployment records, letters of credit, performance bonds, non-compliance notices, support payment records, deployment mapping documentation, financial audit reports');
UPDATE citizen_catalog SET standards_of_creation = 'Fiber deployment permits must include route design, construction method (aerial/underground/micro-trench), environmental review (CEQA categorical exemption or MND), traffic control plans, utility coordination (DigAlert/USA North 811), pole attachment applications, and conduit sharing obligations. As-built records with GPS coordinates required. Restoration requirements specified by local ordinance.', soc_controls = 'SOC 2 Type II (GIS infrastructure data); permit timeline tracking; DigAlert compliance verification; construction inspection records; environmental clearance documentation; as-built record accuracy; restoration compliance; pole attachment approval tracking; franchise/right-of-way fee payment.' WHERE name = 'Persona B.3.4: Fiber-to-Home Permit and Construction Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-03e88d3d9d8c', 'Persona B.3.4: Fiber-to-Home Permit and Construction Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.3.4: Fiber-to-Home Permit and Construction Compliance Manager — FCC; state/local permitting authorities; Caltrans (state highways)', 'Persona B.3.4: Fiber-to-Home Permit and Construction Compliance Manager', 'FCC; state/local permitting authorities; Caltrans (state highways)', ':; 47 USC § 253 (removal of barriers to entry — state/local); 47 USC § 332(c)(7) (limitations on local zoning for telecommunications); FCC Declaratory Ruling 18-133 (one-touch make-ready); Cal. Gov. Code § 65964.2 (micro-trenching permitting); Cal. Pub. Util. Code § 767.5 (pole attachment for fiber); Cal. Streets & Highways Code § 1450-1470 (encroachment permits); Caltrans Encroachment Permit Manual; California Government Code § 4216 (underground facility marking — DigAlert); Local right-of-way permitting ordinances', 'Fiber deployment permits must include route design, construction method (aerial/underground/micro-trench), environmental review (CEQA categorical exemption or MND), traffic control plans, utility coordination (DigAlert/USA North 811), pole attachment applications, and conduit sharing obligations. As-built records with GPS coordinates required. Restoration requirements specified by local ordinance.', 'SOC 2 Type II (GIS infrastructure data); permit timeline tracking; DigAlert compliance verification; construction inspection records; environmental clearance documentation; as-built record accuracy; restoration compliance; pole attachment approval tracking; franchise/right-of-way fee payment.', 'Fiber deployment permits (local/state), encroachment permits (Caltrans), micro-trenching permits, environmental review documents (CEQA), traffic control plans, DigAlert locate requests and responses, pole attachment applications, conduit sharing agreements, as-built drawings, construction inspection records, restoration completion records, franchise/ROW fee payment records');
UPDATE citizen_catalog SET standards_of_creation = 'Broadband Facts Labels must disclose typical download/upload speeds, latency, pricing (introductory and standard), data caps, fees, and network management practices. "Up to" speed claims must be achievable by substantial proportion of subscribers. Speed testing methodology must follow FCC-approved protocols. Compliance with California UCL/FAL requires substantiation for all advertising claims.', soc_controls = 'SOC 2 Type II (speed test data integrity); Broadband Facts Label accuracy; speed advertising claim substantiation; FTC substantiation documentation; network management practice disclosure; pricing transparency verification; speed test sampling methodology.' WHERE name = 'Persona B.4.1: Broadband Speed Advertising Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9abec47e1f89', 'Persona B.4.1: Broadband Speed Advertising Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.4.1: Broadband Speed Advertising Compliance Specialist — FCC; Federal Trade Commission (FTC); California Attorney General', 'Persona B.4.1: Broadband Speed Advertising Compliance Specialist', 'FCC; Federal Trade Commission (FTC); California Attorney General', ':; FCC Open Internet Order (2024 Restoring Internet Freedom); FCC Broadband Consumer Labels Rule (47 CFR § 8.1); FCC Broadband Facts Label (FCC 22-86); 15 USC § 45 (FTC Act — unfair or deceptive practices); 16 CFR Part 255 (FTC Endorsement Guides); Cal. Bus. & Prof. Code § 17200 (Unfair Competition Law); Cal. Bus. & Prof. Code § 17500 (False Advertising Law); FCC Measuring Broadband America program; NTIA/FCC speed test methodologies', 'Broadband Facts Labels must disclose typical download/upload speeds, latency, pricing (introductory and standard), data caps, fees, and network management practices. "Up to" speed claims must be achievable by substantial proportion of subscribers. Speed testing methodology must follow FCC-approved protocols. Compliance with California UCL/FAL requires substantiation for all advertising claims.', 'SOC 2 Type II (speed test data integrity); Broadband Facts Label accuracy; speed advertising claim substantiation; FTC substantiation documentation; network management practice disclosure; pricing transparency verification; speed test sampling methodology.', 'Broadband Facts Labels, speed advertising materials, speed test results and methodologies, network management practice disclosures, pricing disclosures (introductory/standard), data cap documentation, FTC advertising substantiation files, consumer complaint records, Measuring Broadband America data, speed tier verification tests');
UPDATE citizen_catalog SET standards_of_creation = 'ISPs must designate DMCA agent with Copyright Office and on website. Takedown notices must meet § 512(c)(3) requirements (identification of copyrighted work, identification of infringing material, good faith statement, accuracy under penalty of perjury). Counter-notifications must meet § 512(g)(3) requirements. ISPs must implement repeat infringer policy per § 512(i). 10-14 business day put-back timeline after counter-notification.', soc_controls = 'SOC 2 Type II (user data protection); DMCA agent registration verification; takedown notice completeness review; response time tracking; counter-notification processing; repeat infringer tracking; put-back timeline compliance; misrepresentation documentation (§ 512(f)).' WHERE name = 'Persona B.4.2: DMCA Takedown Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7bf65adaea01', 'Persona B.4.2: DMCA Takedown Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.4.2: DMCA Takedown Compliance Specialist — U.S. Copyright Office; courts', 'Persona B.4.2: DMCA Takedown Compliance Specialist', 'U.S. Copyright Office; courts', ':; 17 USC § 512 (DMCA Safe Harbor — ISP limitations on liability); 17 USC § 512(c) (takedown upon notification); 17 USC § 512(f) (misrepresentation in takedown notices); 17 USC § 512(g) (counter-notification and put-back); 17 USC § 512(i) (repeat infringer policy required); 37 CFR Part 201 (Copyright Office regulations); DMCA designated agent registration (Copyright Office)', 'ISPs must designate DMCA agent with Copyright Office and on website. Takedown notices must meet § 512(c)(3) requirements (identification of copyrighted work, identification of infringing material, good faith statement, accuracy under penalty of perjury). Counter-notifications must meet § 512(g)(3) requirements. ISPs must implement repeat infringer policy per § 512(i). 10-14 business day put-back timeline after counter-notification.', 'SOC 2 Type II (user data protection); DMCA agent registration verification; takedown notice completeness review; response time tracking; counter-notification processing; repeat infringer tracking; put-back timeline compliance; misrepresentation documentation (§ 512(f)).', 'DMCA designated agent registrations, takedown notices, counter-notifications, put-back orders, repeat infringer records, ISP repeat infringer policies, takedown processing logs, misrepresentation claims, copyright holder communications, subscriber notification records');
UPDATE citizen_catalog SET standards_of_creation = 'Electronic service providers must report CSAM to NCMEC CyberTipline within specific timeframes (as soon as reasonably possible). Reports must include subscriber information, IP address, upload timestamp, and preserve evidence for 90 days per § 2258A(h). ISPs must not notify subscribers about reports to prevent evidence destruction. Hash-matching technology (PhotoDNA) implementation where technically feasible.', soc_controls = 'SOC 2 Type II (evidence chain of custody); CyberTipline reporting timeline compliance; evidence preservation (90-day minimum); subscriber non-notification compliance; hash-matching technology deployment; employee training documentation; law enforcement cooperation records; evidence handling chain of custody.' WHERE name = 'Persona B.4.3: NCMEC / Child Exploitation Reporting Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-4f0f9ff06e1e', 'Persona B.4.3: NCMEC / Child Exploitation Reporting Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.4.3: NCMEC / Child Exploitation Reporting Compliance Officer — National Center for Missing & Exploited Children (NCMEC); DOJ', 'Persona B.4.3: NCMEC / Child Exploitation Reporting Compliance Officer', 'National Center for Missing & Exploited Children (NCMEC); DOJ', ':; 18 USC § 2258A (mandatory reporting of apparent child sexual abuse material — CSAM); 18 USC § 2258B (ISP immunity for good faith reporting); 18 USC § 2258C (NCMEC provision of hash values to ISPs); 18 USC § 2252A (production/distribution of CSAM); 18 USC § 2256 (definitions — sexually explicit conduct involving minors); 18 USC § 1466A (obscene visual representation of child sexual abuse); 34 USC § 21116 (NCMEC CyberTipline); Cal. Penal Code § 311-312.7 (California CSAM statutes)', 'Electronic service providers must report CSAM to NCMEC CyberTipline within specific timeframes (as soon as reasonably possible). Reports must include subscriber information, IP address, upload timestamp, and preserve evidence for 90 days per § 2258A(h). ISPs must not notify subscribers about reports to prevent evidence destruction. Hash-matching technology (PhotoDNA) implementation where technically feasible.', 'SOC 2 Type II (evidence chain of custody); CyberTipline reporting timeline compliance; evidence preservation (90-day minimum); subscriber non-notification compliance; hash-matching technology deployment; employee training documentation; law enforcement cooperation records; evidence handling chain of custody.', 'NCMEC CyberTipline reports, evidence preservation records, hash-matching detection logs, law enforcement referral records, employee training records, evidence chain of custody documentation, technology implementation records, annual compliance reports, subscriber identification records (for reporting purposes), internal investigation records');
UPDATE citizen_catalog SET standards_of_creation = 'AUPs must clearly define prohibited uses, network management practices, throttling/deprioritization policies, data cap terms, and enforcement mechanisms. California SB 822 prohibits blocking, throttling, paid prioritization, and zero-rating that harms competition. Network management disclosures must be included in Broadband Facts Labels. Terms of service must be conspicuously posted and provided at service initiation.', soc_controls = 'SOC 2 Type II (network data integrity); AUP posting and accessibility verification; network management practice documentation; SB 822 compliance audit; data cap enforcement accuracy; throttling/deprioritization logging; customer notification of policy changes; enforcement action documentation.' WHERE name = 'Persona B.4.4: ISP Acceptable Use Policy / Network Management Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ef344fb9646b', 'Persona B.4.4: ISP Acceptable Use Policy / Network Management Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.4.4: ISP Acceptable Use Policy / Network Management Compliance Specialist — FCC; FTC', 'Persona B.4.4: ISP Acceptable Use Policy / Network Management Compliance Specialist', 'FCC; FTC', ':; FCC Restoring Internet Freedom Order (2017) — transparency rule retained; 47 CFR § 8.1 (ISP transparency requirements); FCC Broadband Facts Label Rule (FCC 22-86); 15 USC § 45 (FTC Act — unfair practices); Cal. Civ. Code § 3100-3104 (SB 822 — California Net Neutrality Act); Cal. Bus. & Prof. Code § 17200 (UCL); 47 USC § 230 (Communications Decency Act — content moderation protections); RFC 2474/3168 (IETF traffic management standards — informational)', 'AUPs must clearly define prohibited uses, network management practices, throttling/deprioritization policies, data cap terms, and enforcement mechanisms. California SB 822 prohibits blocking, throttling, paid prioritization, and zero-rating that harms competition. Network management disclosures must be included in Broadband Facts Labels. Terms of service must be conspicuously posted and provided at service initiation.', 'SOC 2 Type II (network data integrity); AUP posting and accessibility verification; network management practice documentation; SB 822 compliance audit; data cap enforcement accuracy; throttling/deprioritization logging; customer notification of policy changes; enforcement action documentation.', 'Acceptable use policies, terms of service, network management practice disclosures, Broadband Facts Labels, data cap policies, throttling/deprioritization records, zero-rating program terms, SB 822 compliance assessments, customer notification records (policy changes), enforcement action records, network traffic management logs');
UPDATE citizen_catalog SET standards_of_creation = 'Pole/conduit sharing applications follow same standards as A.6.3. Broadband-specific considerations include fiber strand assignment, conduit occupancy calculations, and OTMR eligibility (simple attachments in communications space only). Access to rights-of-way must be non-discriminatory per § 253. Conduit sharing agreements must specify capacity, maintenance, and access protocols.', soc_controls = 'SOC 2 Type II (infrastructure inventory data); OTMR eligibility assessment; access non-discrimination audit; conduit capacity tracking; pole loading calculation verification; shot clock compliance; make-ready cost allocation.' WHERE name = 'Persona B.5.1: Broadband Infrastructure Sharing Coordinator (Pole/Conduit)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-6c21d4efa2af', 'Persona B.5.1: Broadband Infrastructure Sharing Coordinator (Pole/Conduit)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.5.1: Broadband Infrastructure Sharing Coordinator (Pole/Conduit) — FCC; CPUC', 'Persona B.5.1: Broadband Infrastructure Sharing Coordinator (Pole/Conduit)', 'FCC; CPUC', ':; 47 USC § 224 (FCC pole attachment regulation); 47 CFR § 1.1401-1.1424 (FCC pole attachment rules); Cal. Pub. Util. Code § 767.5 (California pole attachment regulation); FCC Declaratory Ruling 18-133 (one-touch make-ready — OTMR); CPUC Decision 98-10-058 (California pole attachment rates); CPUC Rulemaking R.17-06-028 (modernization); 47 USC § 253 (removal of barriers to entry); Cal. Gov. Code § 4216 (DigAlert — conduit marking)', 'Pole/conduit sharing applications follow same standards as A.6.3. Broadband-specific considerations include fiber strand assignment, conduit occupancy calculations, and OTMR eligibility (simple attachments in communications space only). Access to rights-of-way must be non-discriminatory per § 253. Conduit sharing agreements must specify capacity, maintenance, and access protocols.', 'SOC 2 Type II (infrastructure inventory data); OTMR eligibility assessment; access non-discrimination audit; conduit capacity tracking; pole loading calculation verification; shot clock compliance; make-ready cost allocation.', 'Pole/conduit access applications, OTMR notifications, infrastructure sharing agreements, conduit occupancy records, pole loading analyses, make-ready cost estimates, strand assignment records, access non-discrimination certifications, shot clock compliance logs, joint trench coordination records');
UPDATE citizen_catalog SET standards_of_creation = 'Municipal broadband proposals require feasibility study (market demand, engineering design, financial model, competitive analysis), legal authority analysis, funding structure documentation (bonds, grants, PPP), business plan, and public approval (if required by charter or Prop 26). CASF grant applications follow CPUC formatting requirements. Open access network designs must specify wholesale/retail terms.', soc_controls = 'SOC 2 Type II (subscriber data if retail service); feasibility study methodology audit; financial model assumptions verification; bond covenant compliance; CASF grant compliance; public meeting documentation (Brown Act); competitive neutrality assessment.' WHERE name = 'Persona B.5.2: Municipal Broadband Program Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f7a3e0b117e2', 'Persona B.5.2: Municipal Broadband Program Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.5.2: Municipal Broadband Program Manager — FCC; CPUC; local municipal authority', 'Persona B.5.2: Municipal Broadband Program Manager', 'FCC; CPUC; local municipal authority', ':; 47 USC § 253 (removal of barriers — no state preemption of municipal broadband where not explicit); Cal. Gov. Code § 11546.46 (state digital equity plan — municipal role); Cal. Pub. Util. Code § 281 (CASF funding available to public entities); Government Finance Officers Association (GFOA) best practices (municipal finance); Cal. Gov. Code § 53750-53758 (Proposition 26 — fees for municipal broadband); Cal. Const. Art. XVI § 18 (public entity debt limitations); Municipal broadband feasibility study standards', 'Municipal broadband proposals require feasibility study (market demand, engineering design, financial model, competitive analysis), legal authority analysis, funding structure documentation (bonds, grants, PPP), business plan, and public approval (if required by charter or Prop 26). CASF grant applications follow CPUC formatting requirements. Open access network designs must specify wholesale/retail terms.', 'SOC 2 Type II (subscriber data if retail service); feasibility study methodology audit; financial model assumptions verification; bond covenant compliance; CASF grant compliance; public meeting documentation (Brown Act); competitive neutrality assessment.', 'Municipal broadband feasibility studies, business plans, financial models, funding applications (CASF/BEAD), bond offering documents, public hearing records, open access agreements, service level agreements, subscriber contracts, construction progress reports, financial performance reports, competitive analysis documents');
UPDATE citizen_catalog SET standards_of_creation = 'Installation records must document equipment serial numbers, cable routing, signal levels (per SCTE/ANSI specifications), grounding/bonding per NEC Article 820, customer equipment authorization, and work completion sign-off. CableCARD installations tracked. Service termination must offer customer option to purchase or retain home wiring per § 76.802.', soc_controls = 'SOC 2 Type II (customer premises data); NEC compliance verification; signal level documentation; equipment inventory tracking; CableCARD activation/deactivation logging; customer authorization records; work order completion audit.' WHERE name = 'Persona B.5.3: Cable Equipment Installation / Home Wiring Compliance Technician';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-91cdb9cda639', 'Persona B.5.3: Cable Equipment Installation / Home Wiring Compliance Technician', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.5.3: Cable Equipment Installation / Home Wiring Compliance Technician — FCC; local building authorities', 'Persona B.5.3: Cable Equipment Installation / Home Wiring Compliance Technician', 'FCC; local building authorities', ':; 47 CFR § 76.800-76.806 (cable home wiring rules); 47 CFR § 76.802 (disposition of home wiring upon service termination); 47 CFR § 76.804 (home run wiring ownership); FCC CableCARD rules (47 CFR § 76.1200 series); National Electrical Code (NEC) Article 820 (community antenna television and radio distribution systems); NEC Article 830 (network-powered broadband communications); SCTE (Society of Cable Telecommunications Engineers) Standards; Cal. Health & Safety Code § 17920 (building standards)', 'Installation records must document equipment serial numbers, cable routing, signal levels (per SCTE/ANSI specifications), grounding/bonding per NEC Article 820, customer equipment authorization, and work completion sign-off. CableCARD installations tracked. Service termination must offer customer option to purchase or retain home wiring per § 76.802.', 'SOC 2 Type II (customer premises data); NEC compliance verification; signal level documentation; equipment inventory tracking; CableCARD activation/deactivation logging; customer authorization records; work order completion audit.', 'Installation work orders, signal level test results, equipment installation records (serial numbers), grounding/bonding inspection records, CableCARD activation records, customer authorization forms, service completion sign-offs, home wiring disposition records (termination), equipment return/recovery records');
UPDATE citizen_catalog SET standards_of_creation = 'IPTV/OTT services must comply with VPPA (18 USC § 2710) requiring written consent before disclosing viewing records. Auto-renewal disclosures must comply with Cal. Civ. Code § 1694.5 (clear terms, affirmative consent, easy cancellation). Children''s content subject to COPPA. CCPA/CPRA governs data collection, sale, and deletion. Advertising must comply with FTC substantiation requirements.', soc_controls = 'SOC 2 Type II (subscriber viewing data protection); VPPA consent management; auto-renewal disclosure compliance; COPPA verification (age gates, parental consent); CCPA/CPRA opt-out/deletion processing; advertising claim substantiation; cancellation process audit.' WHERE name = 'Persona B.6.1: IPTV/OTT Regulatory Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-9d0dbdc8ded4', 'Persona B.6.1: IPTV/OTT Regulatory Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.6.1: IPTV/OTT Regulatory Compliance Specialist — FCC; FTC; California AG', 'Persona B.6.1: IPTV/OTT Regulatory Compliance Specialist', 'FCC; FTC; California AG', ':; FCC classification (IPTV generally not Title VI cable service); 47 USC § 522(6) (cable service definition — IPTV may or may not qualify); 15 USC § 45 (FTC Act — unfair/deceptive practices apply to OTT); Cal. Civ. Code § 1798.100 et seq. (CCPA/CPRA — OTT data collection); Cal. Civ. Code § 1799.1-1799.2 (Video Privacy Protection — state analog); 18 USC § 2710 (Video Privacy Protection Act — VPPA); Cal. Bus. & Prof. Code § 17200 (UCL — advertising practices); Cal. Civ. Code § 1694.5 (automatic renewal/free trial — auto-renewal law); FTC Negative Option Rule (16 CFR Part 425); COPPA (Children''s Online Privacy Protection Act — 15 USC § 6501)', 'IPTV/OTT services must comply with VPPA (18 USC § 2710) requiring written consent before disclosing viewing records. Auto-renewal disclosures must comply with Cal. Civ. Code § 1694.5 (clear terms, affirmative consent, easy cancellation). Children''s content subject to COPPA. CCPA/CPRA governs data collection, sale, and deletion. Advertising must comply with FTC substantiation requirements.', 'SOC 2 Type II (subscriber viewing data protection); VPPA consent management; auto-renewal disclosure compliance; COPPA verification (age gates, parental consent); CCPA/CPRA opt-out/deletion processing; advertising claim substantiation; cancellation process audit.', 'Terms of service, privacy policies, VPPA consent records, auto-renewal disclosures, cancellation confirmation records, COPPA compliance documentation (parental consent), CCPA/CPRA disclosure requests, viewing data handling policies, advertising compliance files, subscriber billing records, free trial conversion documentation');
UPDATE citizen_catalog SET standards_of_creation = 'Billing dispute responses must be in writing, reference specific charges, provide calculation basis, and inform customer of escalation rights (LFA complaint, FCC complaint, small claims court). Truth-in-billing requires clear identification of service provider, all charges described clearly, and contact information for disputes. Delinquency fees capped per state law.', soc_controls = 'SOC 2 Type II (billing data integrity); dispute resolution timeline tracking; credit reporting accuracy; delinquency fee compliance; truth-in-billing audit; escalation path documentation; refund processing accuracy; Broadband Facts Label pricing consistency.' WHERE name = 'Persona B.6.2: Cable/ISP Billing Dispute Resolution Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2695638ad941', 'Persona B.6.2: Cable/ISP Billing Dispute Resolution Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona B.6.2: Cable/ISP Billing Dispute Resolution Specialist — FCC; FTC; CPUC; local franchising authorities', 'Persona B.6.2: Cable/ISP Billing Dispute Resolution Specialist', 'FCC; FTC; CPUC; local franchising authorities', ':; 47 USC § 544 (FCC cable rate regulation authority); 47 CFR § 76.309 (customer service standards — billing); Cal. Gov. Code § 53088.2 (video provider customer service — California); Cal. Gov. Code § 53088.7 (delinquency fee cap — $4.75); Cal. Civ. Code § 1785 et seq. (credit reporting limitations); FCC Broadband Facts Label Rule (billing transparency); Local franchise customer service standards; FCC Truth-in-Billing Rules (47 CFR § 64.2400 series)', 'Billing dispute responses must be in writing, reference specific charges, provide calculation basis, and inform customer of escalation rights (LFA complaint, FCC complaint, small claims court). Truth-in-billing requires clear identification of service provider, all charges described clearly, and contact information for disputes. Delinquency fees capped per state law.', 'SOC 2 Type II (billing data integrity); dispute resolution timeline tracking; credit reporting accuracy; delinquency fee compliance; truth-in-billing audit; escalation path documentation; refund processing accuracy; Broadband Facts Label pricing consistency.', 'Billing dispute complaints, dispute investigation records, billing adjustment calculations, customer correspondence, credit reporting corrections, delinquency fee assessments, refund processing records, LFA/FCC complaint responses, truth-in-billing compliance records, Broadband Facts Label pricing reconciliation');
UPDATE citizen_catalog SET standards_of_creation = 'Mail fraud investigation files must document the scheme to defraud, the use of mails in furtherance of the scheme (mailing element), intent to defraud, victim statements, financial loss documentation, and chain of custody for physical evidence. 39 USC § 3005 administrative cases require showing false representation + use of mail. Reports to DOJ for prosecution must meet federal prosecution standards (USAM 9-43.000).', soc_controls = 'SOC 2 Type II (evidence data integrity); chain of custody documentation; evidence storage and preservation; case file management; witness statement authentication; financial analysis documentation; prosecution referral tracking; victim notification compliance.' WHERE name = 'Persona C.1.1: USPS Postal Inspector (Mail Fraud Investigation)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-92f8ad38007b', 'Persona C.1.1: USPS Postal Inspector (Mail Fraud Investigation)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.1.1: USPS Postal Inspector (Mail Fraud Investigation) — U.S. Postal Inspection Service (USPIS); DOJ', 'Persona C.1.1: USPS Postal Inspector (Mail Fraud Investigation)', 'U.S. Postal Inspection Service (USPIS); DOJ', ':; 18 USC § 1341 (mail fraud — use of mails to defraud); 18 USC § 1342 (fictitious name or address); 18 USC § 1343 (wire fraud — companion statute); 18 USC § 1345 (injunctions against mail fraud); 18 USC § 1346 (honest services fraud through mail); 39 USC § 3005 (false representations using mail — administrative proceedings); 39 USC § 3007 (detention of mail for temporary restraining order); 39 CFR Part 233 (Inspection Service authority); USPIS Inspector''s Handbook', 'Mail fraud investigation files must document the scheme to defraud, the use of mails in furtherance of the scheme (mailing element), intent to defraud, victim statements, financial loss documentation, and chain of custody for physical evidence. 39 USC § 3005 administrative cases require showing false representation + use of mail. Reports to DOJ for prosecution must meet federal prosecution standards (USAM 9-43.000).', 'SOC 2 Type II (evidence data integrity); chain of custody documentation; evidence storage and preservation; case file management; witness statement authentication; financial analysis documentation; prosecution referral tracking; victim notification compliance.', 'Mail fraud investigation reports, evidence chain of custody records, victim complaint forms, financial loss calculations, prosecution referral packages, 39 USC § 3005 administrative complaint filings, temporary restraining orders (§ 3007), fictitious name/address investigation reports, witness statements, case disposition records');
UPDATE citizen_catalog SET standards_of_creation = 'Mail theft reports must document the type of mail stolen (first class, package, certified, etc.), method of theft (from mailbox, porch, postal vehicle, postal facility), victim identification, identity theft nexus if applicable, and loss valuation. Package theft reports require tracking number documentation. Arrow key theft triggers enhanced investigation per 18 USC § 1704. Postal employee theft (§ 1709) requires internal affairs coordination.', soc_controls = 'SOC 2 Type II (victim PII protection); evidence chain of custody; theft pattern analysis documentation; identity theft referral tracking; victim notification; arrow key recovery tracking; postal employee investigation protocols; inter-agency coordination records.' WHERE name = 'Persona C.1.2: Mail Theft Investigation Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e45cb7394951', 'Persona C.1.2: Mail Theft Investigation Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.1.2: Mail Theft Investigation Specialist — USPIS; FBI (for identity theft component); local law enforcement', 'Persona C.1.2: Mail Theft Investigation Specialist', 'USPIS; FBI (for identity theft component); local law enforcement', ':; 18 USC § 1708 (theft or receipt of stolen mail); 18 USC § 1702 (obstruction of correspondence); 18 USC § 1703 (delay or destruction of mail by postal employee); 18 USC § 1704 (keys or locks of mail receptacles); 18 USC § 1705 (destruction of letter boxes or mail); 18 USC § 1706 (injury to mail bags); 18 USC § 1709 (theft of mail by postal employee); 18 USC § 1028 (identity theft — mail-facilitated); 18 USC § 1028A (aggravated identity theft); Cal. Penal Code § 530.5 (identity theft — California); 39 CFR § 233.1 (Inspection Service jurisdiction)', 'Mail theft reports must document the type of mail stolen (first class, package, certified, etc.), method of theft (from mailbox, porch, postal vehicle, postal facility), victim identification, identity theft nexus if applicable, and loss valuation. Package theft reports require tracking number documentation. Arrow key theft triggers enhanced investigation per 18 USC § 1704. Postal employee theft (§ 1709) requires internal affairs coordination.', 'SOC 2 Type II (victim PII protection); evidence chain of custody; theft pattern analysis documentation; identity theft referral tracking; victim notification; arrow key recovery tracking; postal employee investigation protocols; inter-agency coordination records.', 'Mail theft reports (USPIS), package theft reports, identity theft referrals, arrow key theft investigation records, postal employee theft investigations (§ 1709), victim notification records, theft pattern analysis reports, evidence preservation records, restitution documentation, inter-agency coordination records, surveillance records');
UPDATE citizen_catalog SET standards_of_creation = 'Mailbox tampering investigations must document the type of mailbox (curbside, cluster box unit, wall-mounted, P.O. Box), method of tampering (physical damage, lock defeat, unauthorized access), evidence of mail removed, and photographic documentation. Mailbox restriction violations (non-postal matter in mailbox) documented per § 1725. Cluster box unit damage reports coordinated with USPS delivery operations.', soc_controls = 'SOC 2 Type II (victim data); photographic evidence management; cluster box unit security audit; lock and key control tracking; mailbox specification compliance (Publication 508); theft pattern geographic analysis.' WHERE name = 'Persona C.1.3: Mailbox Access / Tampering Investigator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-3f2c8cfea5ef', 'Persona C.1.3: Mailbox Access / Tampering Investigator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.1.3: Mailbox Access / Tampering Investigator — USPIS', 'Persona C.1.3: Mailbox Access / Tampering Investigator', 'USPIS', ':; 18 USC § 1705 (destruction of letter boxes or mail); 18 USC § 1708 (theft or receipt of stolen mail — includes from mailbox); 18 USC § 1725 (postage unpaid matter deposited in mailbox — mailbox restriction rule); 39 CFR § 232.1 (conduct on postal property); USPS Domestic Mail Manual (DMM) § 508.3 (mailbox access restrictions); USPS Publication 508 (mailbox specifications); 39 USC § 1725 (mailbox restrictions); Local ordinances re: cluster box unit (CBU) installation', 'Mailbox tampering investigations must document the type of mailbox (curbside, cluster box unit, wall-mounted, P.O. Box), method of tampering (physical damage, lock defeat, unauthorized access), evidence of mail removed, and photographic documentation. Mailbox restriction violations (non-postal matter in mailbox) documented per § 1725. Cluster box unit damage reports coordinated with USPS delivery operations.', 'SOC 2 Type II (victim data); photographic evidence management; cluster box unit security audit; lock and key control tracking; mailbox specification compliance (Publication 508); theft pattern geographic analysis.', 'Mailbox tampering investigation reports, photographic evidence, lock/key inventory records, cluster box unit security inspection records, mailbox restriction violation notices, mailbox specification compliance records, geographic pattern analysis reports, victim complaint records, repair/replacement orders');
UPDATE citizen_catalog SET standards_of_creation = 'Certified mail receipts (PS Form 3800) must document article number, sender, addressee, and date of mailing. Return receipts (PS Form 3811 / electronic) must capture signature of recipient, date delivered, and delivery address. Restricted delivery (PS Form 3849) limits delivery to named addressee or authorized agent. Electronic return receipts provide digital signature capture and timestamp. Legal service by certified mail requires compliance with jurisdiction-specific rules on sufficiency.', soc_controls = 'SOC 2 Type II (tracking data integrity); article number tracking verification; signature authentication; delivery scan accuracy; electronic return receipt system integrity; legal service sufficiency documentation; retention of certified mail records per applicable statute of limitations.' WHERE name = 'Persona C.2.1: Certified Mail / Return Receipt Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-884defc4a621', 'Persona C.2.1: Certified Mail / Return Receipt Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.2.1: Certified Mail / Return Receipt Compliance Specialist — USPS; courts (for legal service requirements)', 'Persona C.2.1: Certified Mail / Return Receipt Compliance Specialist', 'USPS; courts (for legal service requirements)', ':; USPS Domestic Mail Manual (DMM) § 503 (Extra Services — Certified Mail); DMM § 503.2 (Certified Mail — proof of mailing + delivery record); DMM § 503.3 (Return Receipt — signature proof of delivery); DMM § 503.4 (Restricted Delivery — delivery only to addressee); Fed. R. Civ. P. 4(e)(1) (service by mail — where authorized by state law); Cal. Code Civ. Proc. § 415.30 (service by mail with acknowledgment); Cal. Code Civ. Proc. § 1013 (service by mail — extending time); Cal. Civ. Code § 1946.2(c) (landlord rent increase notice — certified mail); Cal. Prob. Code § 1215 (notice by mail in probate proceedings); Cal. Health & Safety Code § 116912 (water shutoff — certified mail)', 'Certified mail receipts (PS Form 3800) must document article number, sender, addressee, and date of mailing. Return receipts (PS Form 3811 / electronic) must capture signature of recipient, date delivered, and delivery address. Restricted delivery (PS Form 3849) limits delivery to named addressee or authorized agent. Electronic return receipts provide digital signature capture and timestamp. Legal service by certified mail requires compliance with jurisdiction-specific rules on sufficiency.', 'SOC 2 Type II (tracking data integrity); article number tracking verification; signature authentication; delivery scan accuracy; electronic return receipt system integrity; legal service sufficiency documentation; retention of certified mail records per applicable statute of limitations.', 'Certified mail receipts (PS Form 3800), return receipts (PS Form 3811), electronic return receipts, restricted delivery records (PS Form 3849), delivery confirmation records, certified mail logs (sender records), legal service proof of mailing, insurance claims for certified mail, undeliverable certified mail records, signature image records');
UPDATE citizen_catalog SET standards_of_creation = 'Registered mail requires continuous chain of custody documentation from acceptance to delivery. Each handoff must be signed and recorded. Sealing must use approved security tape/seals. Insurance coverage documented up to $50,000 (domestic). Registry dispatch records maintained at each handling facility. International registered items follow UPU tracking standards.', soc_controls = 'SOC 2 Type II (chain of custody integrity); continuous signature chain verification; seal integrity inspection; dispatch record reconciliation; insurance coverage accuracy; loss/damage investigation procedures; facility security compliance.' WHERE name = 'Persona C.2.2: Registered Mail Security Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-dd866328cb1f', 'Persona C.2.2: Registered Mail Security Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.2.2: Registered Mail Security Specialist — USPS; Universal Postal Union (UPU — international registered mail)', 'Persona C.2.2: Registered Mail Security Specialist', 'USPS; Universal Postal Union (UPU — international registered mail)', ':; USPS DMM § 503.1 (Registered Mail — highest level of security); USPS Handbook RE-5 (Registered Mail); 39 CFR § 111.3 (Registered Mail security chain); UPU Convention Article 13 (international registered items); USPS Publication 542 (Registered Mail Security); 18 USC § 1707 (theft of property used by postal service); 18 USC § 1709 (theft of mail by officer/employee)', 'Registered mail requires continuous chain of custody documentation from acceptance to delivery. Each handoff must be signed and recorded. Sealing must use approved security tape/seals. Insurance coverage documented up to $50,000 (domestic). Registry dispatch records maintained at each handling facility. International registered items follow UPU tracking standards.', 'SOC 2 Type II (chain of custody integrity); continuous signature chain verification; seal integrity inspection; dispatch record reconciliation; insurance coverage accuracy; loss/damage investigation procedures; facility security compliance.', 'Registered mail acceptance receipts, chain of custody signature logs, dispatch records, delivery receipts, seal integrity inspection records, insurance declarations, loss/damage investigation reports, registry cage security inspection records, international registered mail customs forms, UPU tracking records');
UPDATE citizen_catalog SET standards_of_creation = 'Change of address forms require verified identity (photo ID for in-person, credit card validation for online, confirmation letter sent to both old and new addresses). COA records retained for 18 months of mail forwarding plus 6 months inactive. NCOA database access requires USPS licensing agreement and permitted purpose certification. Fraudulent COA investigated as potential identity theft.', soc_controls = 'SOC 2 Type II (address data integrity); identity verification compliance; dual-address confirmation letter tracking; NCOA licensee audit; fraudulent COA detection and investigation; data retention schedule compliance; confirmation letter delivery verification.' WHERE name = 'Persona C.3.1: USPS Change of Address (COA) Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-b4c4cede2f65', 'Persona C.3.1: USPS Change of Address (COA) Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.3.1: USPS Change of Address (COA) Compliance Specialist — USPS; USPIS', 'Persona C.3.1: USPS Change of Address (COA) Compliance Specialist', 'USPS; USPIS', ':; 39 CFR § 265.6(d)(4) (Change of Address information — restricted disclosure); USPS PS Form 3575 (Change of Address form); USPS NCOA (National Change of Address) database licensing; 18 USC § 1708 (theft of mail — COA fraud as method); 18 USC § 1028 (identity document fraud — fraudulent COA); USPS Administrative Support Manual § 159 (COA processing); Fair Credit Reporting Act § 607(b) (identity verification for COA-related products); USPS Identity Verification requirements for online COA', 'Change of address forms require verified identity (photo ID for in-person, credit card validation for online, confirmation letter sent to both old and new addresses). COA records retained for 18 months of mail forwarding plus 6 months inactive. NCOA database access requires USPS licensing agreement and permitted purpose certification. Fraudulent COA investigated as potential identity theft.', 'SOC 2 Type II (address data integrity); identity verification compliance; dual-address confirmation letter tracking; NCOA licensee audit; fraudulent COA detection and investigation; data retention schedule compliance; confirmation letter delivery verification.', 'Change of address forms (PS Form 3575), identity verification records, confirmation letters (old and new address), NCOA license agreements, NCOA update records, fraudulent COA investigation files, mail forwarding records, temporary/permanent COA distinction records, business COA authorization records');
UPDATE citizen_catalog SET standards_of_creation = 'CMRA operators must file PS Form 1583-A with local USPS for each customer. Customers must complete PS Form 1583 with two forms of valid ID. CMRA addresses must include "PMB" or "#" designation — cannot represent as "Suite" or "Apt." CMRA operators must maintain customer identification records for 2 years after service termination. USPS can audit CMRA compliance at any time.', soc_controls = 'SOC 2 Type II (customer identity data protection); PS Form 1583 identity verification audit; address designation compliance (PMB/#); USPS audit readiness; customer record retention (2 years post-termination); suspicious activity reporting; California BPC § 17538.5 registration.' WHERE name = 'Persona C.3.2: Private Mailbox (PMB/CMRA) Operator Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-d988e339ff69', 'Persona C.3.2: Private Mailbox (PMB/CMRA) Operator Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.3.2: Private Mailbox (PMB/CMRA) Operator Compliance Manager — USPS; state business licensing authorities', 'Persona C.3.2: Private Mailbox (PMB/CMRA) Operator Compliance Manager', 'USPS; state business licensing authorities', ':; 39 CFR § 111.5 (Commercial Mail Receiving Agency — CMRA requirements); USPS DMM § 508.4 (CMRA operator requirements); USPS PS Form 1583 (Application for Delivery of Mail Through Agent); USPS PS Form 1583-A (CMRA verification record); 18 USC § 1342 (use of fictitious names — CMRA as potential vehicle); Cal. Bus. & Prof. Code § 17538.5 (CMRA operator registration — California); State business address disclosure requirements', 'CMRA operators must file PS Form 1583-A with local USPS for each customer. Customers must complete PS Form 1583 with two forms of valid ID. CMRA addresses must include "PMB" or "#" designation — cannot represent as "Suite" or "Apt." CMRA operators must maintain customer identification records for 2 years after service termination. USPS can audit CMRA compliance at any time.', 'SOC 2 Type II (customer identity data protection); PS Form 1583 identity verification audit; address designation compliance (PMB/#); USPS audit readiness; customer record retention (2 years post-termination); suspicious activity reporting; California BPC § 17538.5 registration.', 'PS Form 1583 applications, PS Form 1583-A verification records, customer identity documents (copies), CMRA operator registration (California BPC § 17538.5), address designation compliance records, USPS audit records, customer termination records, suspicious activity reports, mail volume records, authorized recipient lists');
UPDATE citizen_catalog SET standards_of_creation = 'Bulk mail permits require annual mailing fee payment and postage deposit account. Mail pieces must meet minimum piece count (200 pieces or 50 lbs), be presorted per DMM specifications, bear Intelligent Mail Barcode, and be prepared per USPS tray/sack/pallet standards. Address lists must be CASS-certified and NCOA-processed within 95 days. Mail.dat or Mail.XML documentation required for electronic submissions.', soc_controls = 'SOC 2 Type II (mailing list data integrity); permit fee payment tracking; presort accuracy verification; CASS certification currency; NCOA processing compliance (95-day window); IMb uniqueness verification; BMEU acceptance/rejection tracking; postage payment accuracy.' WHERE name = 'Persona C.4.1: Bulk Mail / Business Mail Permit Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-29e9ca34bfa5', 'Persona C.4.1: Bulk Mail / Business Mail Permit Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.4.1: Bulk Mail / Business Mail Permit Compliance Manager — USPS; USPS Business Mail Entry Unit (BMEU)', 'Persona C.4.1: Bulk Mail / Business Mail Permit Compliance Manager', 'USPS; USPS Business Mail Entry Unit (BMEU)', ':; USPS DMM § 705 (Machinable/Automation Mail standards); USPS DMM § 243 (First-Class Mail presort); USPS DMM § 243/245 (USPS Marketing Mail — formerly Standard Mail); 39 USC § 3622 (Postal Regulatory Commission — rate system); 39 CFR Part 111 (general mail classification standards); USPS Publication 417 (Nonprofit Standard Mail Eligibility); USPS Mail.dat/Mail.XML technical specifications; Intelligent Mail Barcode (IMb) technical specifications; CASS (Coding Accuracy Support System) certification; NCOA processing requirements', 'Bulk mail permits require annual mailing fee payment and postage deposit account. Mail pieces must meet minimum piece count (200 pieces or 50 lbs), be presorted per DMM specifications, bear Intelligent Mail Barcode, and be prepared per USPS tray/sack/pallet standards. Address lists must be CASS-certified and NCOA-processed within 95 days. Mail.dat or Mail.XML documentation required for electronic submissions.', 'SOC 2 Type II (mailing list data integrity); permit fee payment tracking; presort accuracy verification; CASS certification currency; NCOA processing compliance (95-day window); IMb uniqueness verification; BMEU acceptance/rejection tracking; postage payment accuracy.', 'Bulk mail permit applications, annual fee payment records, postage deposit account statements, presort documentation, Mail.dat/Mail.XML files, CASS certification reports, NCOA processing certifications, mailing statements (PS Form 3602/3602-N/3602-R), tray/sack labels, postage verification records, BMEU acceptance/rejection records, Intelligent Mail Barcode documentation');
UPDATE citizen_catalog SET standards_of_creation = 'Nonprofit mail authorization requires PS Form 3624, IRS determination letter, articles of incorporation/bylaws, financial statements demonstrating nonprofit purpose. Content restrictions: cooperative mailing (advertising for non-member commercial products) limited. Travel/insurance/financial product advertising not eligible for nonprofit rates. Each originating post office must have separate authorization. USPS may audit content compliance at any time.', soc_controls = 'SOC 2 Type II (organizational data); IRS status verification; content eligibility audit; originating post office authorization tracking; cooperative mailing limitation compliance; annual reverification; revenue source documentation (nonprofit purpose test).' WHERE name = 'Persona C.4.2: Nonprofit Mail Permit Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-13721e82c157', 'Persona C.4.2: Nonprofit Mail Permit Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.4.2: Nonprofit Mail Permit Compliance Specialist — USPS; IRS (for nonprofit status verification)', 'Persona C.4.2: Nonprofit Mail Permit Compliance Specialist', 'USPS; IRS (for nonprofit status verification)', ':; 39 USC § 3626 (reduced rates for nonprofit organizations); USPS DMM § 703.1 (Nonprofit Standard Mail/Marketing Mail eligibility); USPS Publication 417 (Nonprofit Standard Mail Eligibility); USPS PS Form 3624 (Application to Mail at Nonprofit USPS Marketing Mail Prices); 26 USC § 501(c)(3) (IRS tax-exempt status — qualifying organizations); 39 CFR § 111.4 (nonprofit mail eligibility requirements); USPS Authorization to Mail at Nonprofit Prices (at each originating post office)', 'Nonprofit mail authorization requires PS Form 3624, IRS determination letter, articles of incorporation/bylaws, financial statements demonstrating nonprofit purpose. Content restrictions: cooperative mailing (advertising for non-member commercial products) limited. Travel/insurance/financial product advertising not eligible for nonprofit rates. Each originating post office must have separate authorization. USPS may audit content compliance at any time.', 'SOC 2 Type II (organizational data); IRS status verification; content eligibility audit; originating post office authorization tracking; cooperative mailing limitation compliance; annual reverification; revenue source documentation (nonprofit purpose test).', 'PS Form 3624 applications, IRS determination letters, articles of incorporation, bylaws, financial statements, USPS authorization certificates, content eligibility review records, cooperative mailing compliance records, originating post office authorization lists, revenue source documentation, USPS content audit records');
UPDATE citizen_catalog SET standards_of_creation = 'Direct mail campaigns must include sender identification, return address, and opt-out mechanism. DNC compliance requires scrubbing against federal and California state DNC registries before telemarketing follow-up. CAN-SPAM applies to email components of integrated mail/email campaigns. CCPA/CPRA requires opt-out of sale for mailing list data. Shine the Light requires disclosure of personal information shared for direct marketing upon request.', soc_controls = 'SOC 2 Type II (mailing list PII protection); DNC registry scrub documentation; opt-out processing compliance; mailing list source documentation; CCPA/CPRA opt-out tracking; Shine the Light disclosure processing; return address accuracy; suppression list management.' WHERE name = 'Persona C.4.3: Direct Mail Compliance Specialist (CAN-SPAM / DNC / State Laws)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1e719112f940', 'Persona C.4.3: Direct Mail Compliance Specialist (CAN-SPAM / DNC / State Laws)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.4.3: Direct Mail Compliance Specialist (CAN-SPAM / DNC / State Laws) — FTC; FCC (telemarketing DNC); state attorneys general', 'Persona C.4.3: Direct Mail Compliance Specialist (CAN-SPAM / DNC / State Laws)', 'FTC; FCC (telemarketing DNC); state attorneys general', ':; 15 USC § 7701-7713 (CAN-SPAM Act — applies to commercial email, not physical mail, but affects integrated campaigns); 16 CFR Part 316 (CAN-SPAM Rule); 47 USC § 227 (Telephone Consumer Protection Act — Do Not Call); 47 CFR § 64.1200 (FCC telemarketing/DNC rules); 16 CFR Part 310 (FTC Telemarketing Sales Rule); Cal. Bus. & Prof. Code § 17529-17529.9 (California anti-spam statute); Cal. Bus. & Prof. Code § 17590-17593 (California DNC list); Cal. Civ. Code § 1798.83 (Shine the Light — marketing disclosure); Cal. Civ. Code § 1798.100 et seq. (CCPA/CPRA — sale of personal information); USPS DMM § 601.10 (mailpiece design — required content)', 'Direct mail campaigns must include sender identification, return address, and opt-out mechanism. DNC compliance requires scrubbing against federal and California state DNC registries before telemarketing follow-up. CAN-SPAM applies to email components of integrated mail/email campaigns. CCPA/CPRA requires opt-out of sale for mailing list data. Shine the Light requires disclosure of personal information shared for direct marketing upon request.', 'SOC 2 Type II (mailing list PII protection); DNC registry scrub documentation; opt-out processing compliance; mailing list source documentation; CCPA/CPRA opt-out tracking; Shine the Light disclosure processing; return address accuracy; suppression list management.', 'Direct mail campaign compliance checklists, DNC registry scrub records, opt-out/suppression list records, mailing list acquisition documentation, CCPA/CPRA opt-out records, Shine the Light disclosure responses, return mail analysis, campaign content review records, integrated email/mail campaign compliance records, mailing list vendor agreements');
UPDATE citizen_catalog SET standards_of_creation = 'Election mail must bear Tag 191 (green tag) for ballot tracking. USPS processes ballot mail as First-Class regardless of postage paid. UOCAVA ballots require special handling (45-day mailing deadline). Ballot tracking through Intelligent Mail Barcode enables USPS Informed Delivery and state ballot tracking. All election mail pieces must include required election official return address. Chain of custody documentation from print shop through delivery.', soc_controls = 'SOC 2 Type II (ballot chain of custody integrity); Tag 191 application verification; UOCAVA mailing deadline compliance; ballot tracking system accuracy; chain of custody from printer to delivery; election mail processing priority compliance; post-election reconciliation.' WHERE name = 'Persona C.4.4: Election Mail Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-bfbb9f5daae1', 'Persona C.4.4: Election Mail Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.4.4: Election Mail Compliance Specialist — USPS; state election officials; FEC', 'Persona C.4.4: Election Mail Compliance Specialist', 'USPS; state election officials; FEC', ':; 39 USC § 3406 (ballots and other election mail); USPS Publication 631 (Election Mail Guide); USPS Publication 632 (State and Local Election Mail — User''s Guide); 52 USC § 20301-20310 (UOCAVA — military/overseas voter mail); 52 USC § 21081-21089 (HAVA — ballot handling standards); Cal. Elec. Code § 3000-3027 (Vote by Mail — California); Cal. Elec. Code § 18500-18578 (election fraud statutes); USPS Tag 191 (green tag — official election mail); USPS Ballot Mail Process', 'Election mail must bear Tag 191 (green tag) for ballot tracking. USPS processes ballot mail as First-Class regardless of postage paid. UOCAVA ballots require special handling (45-day mailing deadline). Ballot tracking through Intelligent Mail Barcode enables USPS Informed Delivery and state ballot tracking. All election mail pieces must include required election official return address. Chain of custody documentation from print shop through delivery.', 'SOC 2 Type II (ballot chain of custody integrity); Tag 191 application verification; UOCAVA mailing deadline compliance; ballot tracking system accuracy; chain of custody from printer to delivery; election mail processing priority compliance; post-election reconciliation.', 'Election mail preparation records, Tag 191 application records, ballot mail tracking records (IMb), UOCAVA mailing compliance records, ballot chain of custody logs, election mail volume reports, mail processing priority verification records, post-election reconciliation reports, ballot return envelope processing records, election official coordination records');
UPDATE citizen_catalog SET standards_of_creation = 'Census mail operations require coordination between Census Bureau and USPS on address list accuracy (MAF/DSF reconciliation), mail piece design (multi-language requirements), delivery tracking, and undeliverable-as-addressed (UAA) processing. Census mail is penalty mail (postage-free). Address verification critical for census coverage. Non-response follow-up tracking.', soc_controls = 'SOC 2 Type II (census response data confidentiality per 13 USC § 9); MAF/DSF reconciliation accuracy; delivery verification; UAA processing documentation; multi-language compliance; non-response tracking; address confidentiality.' WHERE name = 'Persona C.4.5: Census Mail Compliance Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-f130c8adc6a1', 'Persona C.4.5: Census Mail Compliance Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.4.5: Census Mail Compliance Coordinator — U.S. Census Bureau; USPS', 'Persona C.4.5: Census Mail Compliance Coordinator', 'U.S. Census Bureau; USPS', ':; 13 USC § 141 (decennial census); 13 USC § 221 (refusal or neglect to answer census questions); 13 USC § 9 (confidentiality of census information); 39 USC § 3001(d) (penalty mail for census); USPS/Census Bureau Memorandum of Understanding; OMB Directive 15 (race/ethnicity categories); Census Master Address File (MAF) / USPS Delivery Sequence File (DSF)', 'Census mail operations require coordination between Census Bureau and USPS on address list accuracy (MAF/DSF reconciliation), mail piece design (multi-language requirements), delivery tracking, and undeliverable-as-addressed (UAA) processing. Census mail is penalty mail (postage-free). Address verification critical for census coverage. Non-response follow-up tracking.', 'SOC 2 Type II (census response data confidentiality per 13 USC § 9); MAF/DSF reconciliation accuracy; delivery verification; UAA processing documentation; multi-language compliance; non-response tracking; address confidentiality.', 'Census mail delivery records, MAF/DSF reconciliation records, undeliverable-as-addressed processing records, non-response follow-up tracking, address verification documentation, multi-language mail piece compliance records, Census Bureau/USPS coordination records, coverage improvement records');
UPDATE citizen_catalog SET standards_of_creation = 'Mail cover requests must specify the individual/address to be covered, the reason (criminal investigation, national security, or fugitive location), the information sought, and the requesting agency. Authorization must come from Chief Postal Inspector or designee. Duration limited to 30 days (renewable). Only exterior information recorded (no opening of sealed mail without warrant). Records retained 8 years per § 233.3(g).', soc_controls = 'SOC 2 Type II (surveillance data protection); authorization chain verification; duration compliance (30-day limit + renewals); scope limitation (exterior only — no content); Privacy Act compliance; 8-year retention schedule; requesting agency credential verification; target notification (post-investigation, if required).' WHERE name = 'Persona C.5.1: Mail Cover Request Analyst';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a4a40625eeb3', 'Persona C.5.1: Mail Cover Request Analyst', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.5.1: Mail Cover Request Analyst — USPIS; requesting law enforcement agencies', 'Persona C.5.1: Mail Cover Request Analyst', 'USPIS; requesting law enforcement agencies', ':; 39 CFR § 233.3 (mail covers — authorization and procedures); 39 CFR § 233.3(c) (Chief Postal Inspector or designee authorization required); 39 CFR § 233.3(d) (information recordable — name/address of sender/addressee, postmark, class of mail); 39 CFR § 233.3(e) (duration — 30 days, renewable); 39 CFR § 233.3(f) (national security mail covers — additional procedures); 39 CFR § 233.3(g) (record retention — 8 years after termination); Fourth Amendment (no opening of mail — exterior only); Privacy Act of 1974 (5 USC § 552a)', 'Mail cover requests must specify the individual/address to be covered, the reason (criminal investigation, national security, or fugitive location), the information sought, and the requesting agency. Authorization must come from Chief Postal Inspector or designee. Duration limited to 30 days (renewable). Only exterior information recorded (no opening of sealed mail without warrant). Records retained 8 years per § 233.3(g).', 'SOC 2 Type II (surveillance data protection); authorization chain verification; duration compliance (30-day limit + renewals); scope limitation (exterior only — no content); Privacy Act compliance; 8-year retention schedule; requesting agency credential verification; target notification (post-investigation, if required).', 'Mail cover request forms, Chief Postal Inspector/designee authorization records, mail cover data collection logs (sender/addressee/postmark), duration/renewal records, requesting agency credentials, termination records, 8-year retention compliance records, national security mail cover additional authorization records, Privacy Act compliance records');
UPDATE citizen_catalog SET standards_of_creation = 'Postal money order investigation documents must record money order serial number, amount, purchaser identification, payee information, cashing location, and security feature verification. Structuring investigations (splitting purchases to avoid $3,000 threshold) require pattern documentation. Counterfeit money order identification uses security features (watermark, Benjamin Franklin thread, color-shifting ink). SARs filed for suspicious transactions.', soc_controls = 'SOC 2 Type II (financial transaction data integrity); serial number tracking; security feature verification procedures; BSA compliance (CTR/SAR filings); structuring pattern analysis; counterfeit detection training records; inter-agency referral tracking.' WHERE name = 'Persona C.5.2: Postal Money Order Fraud Investigator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-e03b9b85ef6b', 'Persona C.5.2: Postal Money Order Fraud Investigator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.5.2: Postal Money Order Fraud Investigator — USPIS; FinCEN', 'Persona C.5.2: Postal Money Order Fraud Investigator', 'USPIS; FinCEN', ':; 18 USC § 1341 (mail fraud — fraudulent money orders through mail); 18 USC § 500 (money orders — forging/counterfeiting); 18 USC § 1017 (government seals wrongfully used — postal money orders); 31 USC § 5331 (cash reporting for money orders $3,000+); 31 CFR § 1010.100 (BSA definition of money order); 31 CFR § 1010.415 (purchases of bank drafts/cashier''s checks/money orders $3,000-$10,000); 31 CFR § 1010.311 (Currency Transaction Reports — $10,000+); USPS Publication 370 (Postal Money Order verification); FinCEN Suspicious Activity Report (SAR) requirements', 'Postal money order investigation documents must record money order serial number, amount, purchaser identification, payee information, cashing location, and security feature verification. Structuring investigations (splitting purchases to avoid $3,000 threshold) require pattern documentation. Counterfeit money order identification uses security features (watermark, Benjamin Franklin thread, color-shifting ink). SARs filed for suspicious transactions.', 'SOC 2 Type II (financial transaction data integrity); serial number tracking; security feature verification procedures; BSA compliance (CTR/SAR filings); structuring pattern analysis; counterfeit detection training records; inter-agency referral tracking.', 'Money order purchase records, money order cashing records, counterfeit money order analysis reports, SAR filings, CTR filings, structuring investigation records, security feature verification records, serial number tracking logs, victim restitution records, inter-agency referral records, counterfeit detection training records');
UPDATE citizen_catalog SET standards_of_creation = 'Undeliverable mail processing follows prescribed escalation: return to sender (if return address), forwarding (if COA on file), dead letter office (Mail Recovery Center) if neither. Mail Recovery Center must open dead mail to identify sender/addressee. Valuable enclosures held per § 3004 (notification attempts before disposition). Unclaimed mail auctioned after prescribed holding period per § 946.', soc_controls = 'SOC 2 Type II (PII in dead mail); opening authorization protocols; valuable enclosure inventory and safekeeping; notification attempt documentation; holding period compliance; auction/disposal records; statistical tracking of dead mail volume and causes.' WHERE name = 'Persona C.5.3: Dead Letter / Undeliverable Mail Processing Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-ccaea054542e', 'Persona C.5.3: Dead Letter / Undeliverable Mail Processing Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.5.3: Dead Letter / Undeliverable Mail Processing Specialist — USPS Mail Recovery Center (Atlanta, GA)', 'Persona C.5.3: Dead Letter / Undeliverable Mail Processing Specialist', 'USPS Mail Recovery Center (Atlanta, GA)', ':; 39 USC § 3003 (dead mail — mail undeliverable and without return address); 39 USC § 3004 (dead mail with valuable enclosures); 39 USC § 3006 (unlawful matter — detention and disposal); 39 CFR § 946 (disposal of unclaimed/abandoned property); USPS DMM § 507.1 (Undeliverable-As-Addressed mail processing); USPS Publication 390 (Nixie Operations Handbook); USPS Handbook DM-901 (Mail Recovery Center operations)', 'Undeliverable mail processing follows prescribed escalation: return to sender (if return address), forwarding (if COA on file), dead letter office (Mail Recovery Center) if neither. Mail Recovery Center must open dead mail to identify sender/addressee. Valuable enclosures held per § 3004 (notification attempts before disposition). Unclaimed mail auctioned after prescribed holding period per § 946.', 'SOC 2 Type II (PII in dead mail); opening authorization protocols; valuable enclosure inventory and safekeeping; notification attempt documentation; holding period compliance; auction/disposal records; statistical tracking of dead mail volume and causes.', 'Undeliverable mail processing records, dead mail opening authorization records, valuable enclosure inventory logs, sender/addressee notification attempt records, holding period compliance records, auction/disposal records, Mail Recovery Center processing statistics, nixie code classification records');
UPDATE citizen_catalog SET standards_of_creation = 'Carrier compliance documents must include FMCSA operating authority, USDOT number, insurance coverage certificates (minimum $750K-$5M depending on cargo), tariff/rate schedules, claims processing procedures (Carmack Amendment — 120 days to acknowledge, 120 days to resolve), and driver qualification files. California-specific requirements for intrastate operations.', soc_controls = 'SOC 2 Type II (shipment data integrity); FMCSA authority verification; insurance coverage maintenance; claims processing timeline compliance (Carmack Amendment); driver qualification file audits; vehicle inspection records; hours of service compliance; package tracking system accuracy.' WHERE name = 'Persona C.6.1: Private Carrier Compliance Manager (FedEx/UPS/DHL)';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-47cdf7839d66', 'Persona C.6.1: Private Carrier Compliance Manager (FedEx/UPS/DHL)', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.6.1: Private Carrier Compliance Manager (FedEx/UPS/DHL) — FMCSA; DOT; state commerce commissions; FTC', 'Persona C.6.1: Private Carrier Compliance Manager (FedEx/UPS/DHL)', 'FMCSA; DOT; state commerce commissions; FTC', ':; 49 USC § 13501-14915 (Motor Carrier regulatory framework); 49 CFR Part 375 (Transportation of Household Goods); 49 CFR Part 390-397 (Federal Motor Carrier Safety Regulations); 49 USC § 14706 (Carmack Amendment — carrier liability for loss/damage); 49 CFR Part 370 (Principles and Practices for the Investigation and Voluntary Disposition of Loss and Damage Claims); Cal. Pub. Util. Code § 5101-5432 (household goods carriers — California); Cal. Veh. Code § 34500 et seq. (commercial vehicle safety); FTC Mailorder Rule (16 CFR Part 435 — shipping time compliance); Cal. Civ. Code § 1722 (delivery obligations)', 'Carrier compliance documents must include FMCSA operating authority, USDOT number, insurance coverage certificates (minimum $750K-$5M depending on cargo), tariff/rate schedules, claims processing procedures (Carmack Amendment — 120 days to acknowledge, 120 days to resolve), and driver qualification files. California-specific requirements for intrastate operations.', 'SOC 2 Type II (shipment data integrity); FMCSA authority verification; insurance coverage maintenance; claims processing timeline compliance (Carmack Amendment); driver qualification file audits; vehicle inspection records; hours of service compliance; package tracking system accuracy.', 'FMCSA operating authority certificates, USDOT registration, insurance coverage certificates, tariff/rate schedules, claims processing records, driver qualification files, vehicle inspection reports, hours of service logs (ELD), package tracking records, delivery confirmation records, loss/damage claim files, bill of lading documents');
UPDATE citizen_catalog SET standards_of_creation = 'Last-mile delivery compliance requires delivery time commitment documentation, proof of delivery records (photo, signature, GPS), package condition documentation, hazmat screening for restricted items, and delivery attempt records. FTC 30-day rule requires shipment within stated timeframe or notification + opt-out. California AB 5 implications for gig delivery workers (employment classification test). ADA accessibility for delivery instructions.', soc_controls = 'SOC 2 Type II (customer delivery data protection); FTC 30-day shipping compliance; delivery attempt documentation; proof of delivery accuracy (GPS + photo); hazmat screening compliance; package condition tracking; worker classification audit (AB 5); delivery time commitment tracking.' WHERE name = 'Persona C.6.2: Last-Mile Delivery Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-8bf8c164aa7a', 'Persona C.6.2: Last-Mile Delivery Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.6.2: Last-Mile Delivery Compliance Specialist — FTC; CPSC (product safety); DOT; state consumer protection', 'Persona C.6.2: Last-Mile Delivery Compliance Specialist', 'FTC; CPSC (product safety); DOT; state consumer protection', ':; 16 CFR Part 435 (FTC Mail/Internet/Telephone Order Rule — 30-day shipping); 15 USC § 45 (FTC Act — unfair/deceptive delivery practices); 49 CFR Part 172 (hazmat marking/labeling for carriers); Cal. Civ. Code § 1722-1723 (delivery obligations — California); Cal. Bus. & Prof. Code § 17200 (UCL — deceptive delivery promises); Amazon Delivery Service Partner (DSP) compliance standards (private); Gig economy worker classification (Cal. Lab. Code § 2775 — AB 5); ADA accessibility requirements for delivery (28 CFR Part 36)', 'Last-mile delivery compliance requires delivery time commitment documentation, proof of delivery records (photo, signature, GPS), package condition documentation, hazmat screening for restricted items, and delivery attempt records. FTC 30-day rule requires shipment within stated timeframe or notification + opt-out. California AB 5 implications for gig delivery workers (employment classification test). ADA accessibility for delivery instructions.', 'SOC 2 Type II (customer delivery data protection); FTC 30-day shipping compliance; delivery attempt documentation; proof of delivery accuracy (GPS + photo); hazmat screening compliance; package condition tracking; worker classification audit (AB 5); delivery time commitment tracking.', 'Delivery tracking records, proof of delivery records (photo/signature/GPS), delivery attempt notices, FTC 30-day rule compliance records, delivery exception reports, hazmat screening records, worker classification documentation (employee vs. contractor), delivery time commitment records, package condition reports, customer complaint records, accessibility accommodation records');
UPDATE citizen_catalog SET standards_of_creation = 'Package theft reports must document carrier and tracking number, delivery confirmation status (GPS/photo), theft report filing (police report, USPIS complaint, carrier claim), estimated value, contents description, and victim identification. Carrier claims follow carrier-specific procedures (USPS PS Form 1000, FedEx/UPS online claim). Insurance claims require value documentation.', soc_controls = 'SOC 2 Type II (victim PII protection); police report documentation; carrier claim filing verification; insurance documentation; delivery verification (GPS/photo contradiction analysis); pattern analysis (geographic clustering); inter-carrier coordination for serial offenders.' WHERE name = 'Persona C.6.3: Package Theft Report / Investigation Coordinator';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-222a06be5233', 'Persona C.6.3: Package Theft Report / Investigation Coordinator', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.6.3: Package Theft Report / Investigation Coordinator — USPIS (if USPS); local law enforcement; carrier security departments', 'Persona C.6.3: Package Theft Report / Investigation Coordinator', 'USPIS (if USPS); local law enforcement; carrier security departments', ':; 18 USC § 1708 (mail theft — USPS packages); 18 USC § 659 (theft from interstate shipments — private carriers); Cal. Penal Code § 530.5 (identity theft via stolen packages); Cal. Penal Code § 484-490.5 (theft statutes — value-based classification); Cal. Penal Code § 496 (receiving stolen property); Local porch piracy ordinances; Carrier terms of service (claim filing procedures); Cal. Civ. Code § 2200 (carrier liability for goods)', 'Package theft reports must document carrier and tracking number, delivery confirmation status (GPS/photo), theft report filing (police report, USPIS complaint, carrier claim), estimated value, contents description, and victim identification. Carrier claims follow carrier-specific procedures (USPS PS Form 1000, FedEx/UPS online claim). Insurance claims require value documentation.', 'SOC 2 Type II (victim PII protection); police report documentation; carrier claim filing verification; insurance documentation; delivery verification (GPS/photo contradiction analysis); pattern analysis (geographic clustering); inter-carrier coordination for serial offenders.', 'Package theft reports (police/carrier), carrier claim forms (USPS PS Form 1000, FedEx/UPS claims), delivery confirmation records, GPS/photo proof of delivery, insurance claim documentation, victim statements, pattern analysis reports, surveillance evidence, inter-agency referral records, restitution records');
UPDATE citizen_catalog SET standards_of_creation = 'Customs declarations must accurately describe contents, declare value, specify country of origin, and classify by HS tariff code. CN 22 (PS Form 2976) for items under 4 lbs/$400; CN 23 (PS Form 2976-A) for heavier/higher value items. Electronic customs data (EAD) required for all international mail per USPS/CBP mandate. De minimis threshold of $800 (below which no duty assessed per TFTEA). Prohibited/restricted items list compliance.', soc_controls = 'SOC 2 Type II (customs data integrity); customs declaration accuracy audit; electronic advance data (EAD) transmission compliance; prohibited/restricted item screening; HS tariff classification accuracy; de minimis threshold compliance; CBP examination cooperation records.' WHERE name = 'Persona C.7.1: International Mail Customs Declaration Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-98b14b743b21', 'Persona C.7.1: International Mail Customs Declaration Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.7.1: International Mail Customs Declaration Specialist — USPS; U.S. Customs and Border Protection (CBP); Universal Postal Union (UPU)', 'Persona C.7.1: International Mail Customs Declaration Specialist', 'USPS; U.S. Customs and Border Protection (CBP); Universal Postal Union (UPU)', ':; 19 USC § 1484 (CBP entry requirements); 19 CFR Part 145 (mail importations); USPS PS Form 2976 (Customs Declaration CN 22 — small items); USPS PS Form 2976-A (Customs Declaration CN 23 — larger items); UPU Convention (international postal standards); 19 CFR § 145.11 (mail subject to customs examination); 19 CFR § 145.12 (duty assessment on mail articles); USPS DMM § 604 (Postage Payment Methods — international); USPS Publication 141 (Global Express Guaranteed Service Guide); Trade Facilitation and Trade Enforcement Act of 2015 (TFTEA — de minimis threshold $800)', 'Customs declarations must accurately describe contents, declare value, specify country of origin, and classify by HS tariff code. CN 22 (PS Form 2976) for items under 4 lbs/$400; CN 23 (PS Form 2976-A) for heavier/higher value items. Electronic customs data (EAD) required for all international mail per USPS/CBP mandate. De minimis threshold of $800 (below which no duty assessed per TFTEA). Prohibited/restricted items list compliance.', 'SOC 2 Type II (customs data integrity); customs declaration accuracy audit; electronic advance data (EAD) transmission compliance; prohibited/restricted item screening; HS tariff classification accuracy; de minimis threshold compliance; CBP examination cooperation records.', 'Customs declaration forms (CN 22/CN 23, PS Forms 2976/2976-A), electronic advance data (EAD) transmission records, CBP examination records, duty assessment notices, prohibited item seizure records, restricted item permits/licenses, HS tariff classification records, country-of-origin declarations, commercial invoice documentation, de minimis threshold compliance records');
UPDATE citizen_catalog SET standards_of_creation = 'Hazmat shipping documentation must include proper shipping name, UN/NA number, hazard class, packing group, quantity, and emergency contact per 49 CFR § 172. Publication 52 specifies which hazmat is mailable (with limitations) and which is nonmailable. Special provisions for consumer commodities (ORM-D/Limited Quantity), lithium batteries, perfume, dry ice, and medical specimens. Air-eligible hazmat requires ICAO/IATA compliance.', soc_controls = 'SOC 2 Type II (shipping records integrity); hazmat classification accuracy; Publication 52 compliance verification; DOT HMR compliance (49 CFR 171-180); packaging certification; marking/labeling accuracy; air eligibility verification; training record maintenance; incident/spill reporting.' WHERE name = 'Persona C.7.2: Hazardous Materials Shipping by Mail Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-7cd5ae940299', 'Persona C.7.2: Hazardous Materials Shipping by Mail Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.7.2: Hazardous Materials Shipping by Mail Compliance Officer — USPS; PHMSA (Pipeline and Hazardous Materials Safety Administration); DOT', 'Persona C.7.2: Hazardous Materials Shipping by Mail Compliance Officer', 'USPS; PHMSA (Pipeline and Hazardous Materials Safety Administration); DOT', ':; USPS Publication 52 (Hazardous, Restricted, and Perishable Mail); 49 CFR Parts 171-180 (DOT Hazardous Materials Regulations — HMR); 49 USC § 5101-5128 (Federal Hazardous Materials Transportation Law); USPS DMM § 601.10 (mailpiece content restrictions); 18 USC § 1716 (injurious articles as nonmailable); ICAO Technical Instructions (air transport of dangerous goods); IATA Dangerous Goods Regulations (air carriers); USPS Publication 52, Part 3 (mailable hazmat with exceptions)', 'Hazmat shipping documentation must include proper shipping name, UN/NA number, hazard class, packing group, quantity, and emergency contact per 49 CFR § 172. Publication 52 specifies which hazmat is mailable (with limitations) and which is nonmailable. Special provisions for consumer commodities (ORM-D/Limited Quantity), lithium batteries, perfume, dry ice, and medical specimens. Air-eligible hazmat requires ICAO/IATA compliance.', 'SOC 2 Type II (shipping records integrity); hazmat classification accuracy; Publication 52 compliance verification; DOT HMR compliance (49 CFR 171-180); packaging certification; marking/labeling accuracy; air eligibility verification; training record maintenance; incident/spill reporting.', 'Hazmat shipping declarations, UN/NA classification records, packaging certification records, marking and labeling compliance records, air eligibility determination records, training certificates (49 CFR § 172.704), incident/spill reports, Publication 52 compliance checklists, lithium battery shipping declarations, dangerous goods acceptance checklists, medical specimen shipping records');
UPDATE citizen_catalog SET standards_of_creation = 'PO Box applications require two forms of ID (one with photo), proof of address (for verification purposes), and payment for applicable fee group (1-5 based on post office location). Business PO Box applications require business documentation. Key issuance tracked by serial number. Box caller service requires additional authorization. Premium PO Box service (Street Addressing) allows use of street address format.', soc_controls = 'SOC 2 Type II (customer identity data); ID verification compliance; key issuance tracking; fee payment accuracy; box assignment records; premium street addressing authorization; abandoned box processing.' WHERE name = 'Persona C.8.1: PO Box Application and Administration Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-c38bc8c33a34', 'Persona C.8.1: PO Box Application and Administration Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.8.1: PO Box Application and Administration Specialist — USPS', 'Persona C.8.1: PO Box Application and Administration Specialist', 'USPS', ':; USPS DMM § 508.4 (PO Box service); USPS PS Form 1583 (if agent receiving mail — CMRA cross-reference); USPS PS Form 1538 (PO Box Application); 39 CFR § 111.3 (delivery services); USPS Publication 700 (PO Box Service); 18 USC § 1708 (mail theft from PO Boxes); 18 USC § 1704 (theft of mail receptacle keys); USPS Identification requirements (two forms of ID, one with photo)', 'PO Box applications require two forms of ID (one with photo), proof of address (for verification purposes), and payment for applicable fee group (1-5 based on post office location). Business PO Box applications require business documentation. Key issuance tracked by serial number. Box caller service requires additional authorization. Premium PO Box service (Street Addressing) allows use of street address format.', 'SOC 2 Type II (customer identity data); ID verification compliance; key issuance tracking; fee payment accuracy; box assignment records; premium street addressing authorization; abandoned box processing.', 'PO Box applications (PS Form 1538), identity verification records, key issuance records, fee payment records, box assignment records, box caller authorization records, premium street addressing authorizations, abandoned box processing records, business documentation (for business PO Boxes), authorized user lists');
UPDATE citizen_catalog SET standards_of_creation = 'Administrative complaints under § 3005 must demonstrate false representation + use of mail to obtain money or property. Mail detention (§ 3007) requires AUSA/DOJ coordination for TRO. Prohibitory orders (§ 3008) must be processed within USPS timelines. All administrative proceedings follow APA requirements. Case files must include evidence, witness statements, and legal analysis.', soc_controls = 'SOC 2 Type II (case file integrity); APA procedural compliance; evidence preservation; hearing timeline tracking; mail detention authorization chain; prohibitory order processing; appeal rights notification; case disposition documentation.' WHERE name = 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a7e8e15e80d4', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer — USPIS', 'Persona C.8.2: USPS Inspection Service Administrative Compliance Officer', 'USPIS', ':; 39 USC § 3005 (false representations — administrative proceedings); 39 USC § 3007 (detention of mail — temporary restraining order); 39 USC § 3008 (prohibitory orders — sexually explicit mail); 39 USC § 3010 (mailing of sexually explicit material to minors); 39 USC § 3011 (judicial enforcement); 39 CFR Part 952 (Administrative Proceedings); 39 CFR Part 959 (false representation/lottery proceedings); 39 CFR § 233.1 (USPIS general authority); Administrative Procedure Act (5 USC § 551 et seq.)', 'Administrative complaints under § 3005 must demonstrate false representation + use of mail to obtain money or property. Mail detention (§ 3007) requires AUSA/DOJ coordination for TRO. Prohibitory orders (§ 3008) must be processed within USPS timelines. All administrative proceedings follow APA requirements. Case files must include evidence, witness statements, and legal analysis.', 'SOC 2 Type II (case file integrity); APA procedural compliance; evidence preservation; hearing timeline tracking; mail detention authorization chain; prohibitory order processing; appeal rights notification; case disposition documentation.', 'Administrative complaint filings (§ 3005), temporary restraining orders (§ 3007), prohibitory order applications (§ 3008), hearing records, evidence files, witness statements, legal analysis memoranda, case disposition orders, appeal records, mail detention records, consent agreements, civil penalty assessments');
UPDATE citizen_catalog SET standards_of_creation = 'Periodicals mail authorization requires PS Form 3526 (Statement of Ownership) filed annually with USPS and published in the periodical. Must demonstrate: known office of publication, general/requester publication status, subscriber list legitimacy, advertising-to-editorial ratio compliance (Periodicals with 75%+ advertising may lose eligibility), and regular frequency of issuance. Pending Periodicals (temporary authorization) requires separate application.', soc_controls = 'SOC 2 Type II (circulation data integrity); annual PS Form 3526 filing compliance; advertising ratio monitoring; publication frequency verification; subscriber list legitimacy audit; pending-to-authorized conversion tracking.' WHERE name = 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-2dce73a685a8', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist — USPS', 'Persona C.8.3: Newspaper/Periodical Mail Permit Specialist', 'USPS', ':; 39 USC § 3626 (periodical class postage rates); USPS DMM § 207 (Periodicals — eligibility and standards); USPS PS Form 3526 (Statement of Ownership, Management, and Circulation); 39 CFR § 111.3 (Periodicals classification); USPS Publication 501 (Media Mail and Library Rate eligibility); First Amendment considerations (publisher/periodical access to mail system); USPS DMM § 707 (Periodicals preparation)', 'Periodicals mail authorization requires PS Form 3526 (Statement of Ownership) filed annually with USPS and published in the periodical. Must demonstrate: known office of publication, general/requester publication status, subscriber list legitimacy, advertising-to-editorial ratio compliance (Periodicals with 75%+ advertising may lose eligibility), and regular frequency of issuance. Pending Periodicals (temporary authorization) requires separate application.', 'SOC 2 Type II (circulation data integrity); annual PS Form 3526 filing compliance; advertising ratio monitoring; publication frequency verification; subscriber list legitimacy audit; pending-to-authorized conversion tracking.', 'Periodicals authorization applications, PS Form 3526 (Statement of Ownership — annual), circulation verification records, advertising ratio calculations, publication frequency documentation, subscriber list records, pending Periodicals applications, content eligibility review records, postage payment records, publication sample copies');
UPDATE citizen_catalog SET standards_of_creation = 'Courier services must maintain local business licenses, vehicle insurance (commercial auto if using CMVs), and comply with worker classification laws (AB 5 ABC test for California). Interstate operations require FMCSA operating authority and USDOT number. Driver qualification files required for CMV operators. Vehicle inspection and maintenance records per DOT requirements.', soc_controls = 'SOC 2 Type II (customer shipment data); business license currency; insurance coverage verification; worker classification audit; FMCSA compliance (if interstate); vehicle inspection compliance; driver qualification file maintenance.' WHERE name = 'Persona C.9.1: Courier/Messenger Service License Compliance Manager';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-a43d69ca07c1', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager — State/local licensing authorities; FMCSA (if interstate)', 'Persona C.9.1: Courier/Messenger Service License Compliance Manager', 'State/local licensing authorities; FMCSA (if interstate)', ':; Cal. Bus. & Prof. Code § 3100-3105 (no specific courier licensing in CA — general business license); Cal. Veh. Code § 34500 et seq. (commercial vehicle safety — if applicable); 49 USC § 13501 (federal motor carrier jurisdiction — interstate); 49 CFR Part 390 (Federal Motor Carrier Safety Regulations — if CMV); Cal. Lab. Code § 2775 (ABC test — worker classification); Local business license requirements; Cal. Ins. Code § 11580 (vehicle insurance requirements); 49 CFR Part 387 (minimum insurance for motor carriers)', 'Courier services must maintain local business licenses, vehicle insurance (commercial auto if using CMVs), and comply with worker classification laws (AB 5 ABC test for California). Interstate operations require FMCSA operating authority and USDOT number. Driver qualification files required for CMV operators. Vehicle inspection and maintenance records per DOT requirements.', 'SOC 2 Type II (customer shipment data); business license currency; insurance coverage verification; worker classification audit; FMCSA compliance (if interstate); vehicle inspection compliance; driver qualification file maintenance.', 'Business license records, vehicle insurance certificates, FMCSA operating authority (if interstate), USDOT registration, driver qualification files, vehicle inspection reports, maintenance records, worker classification documentation, delivery records, customer contracts, route documentation');
UPDATE citizen_catalog SET standards_of_creation = 'Overnight/express carriers require FAA Part 121/135 air carrier certificate, TSA-approved security program, FMCSA operating authority for ground operations, and DOT hazmat compliance for applicable shipments. Carmack Amendment governs ground segment liability; Montreal Convention governs international air segment. Known Shipper programs per TSA requirements. Declaration of value limits liability unless higher coverage purchased.', soc_controls = 'SOC 2 Type II (shipment tracking data integrity); FAA certificate compliance; TSA security program audit; FMCSA safety rating maintenance; hazmat compliance; Carmack Amendment claims processing; international liability regime compliance; known shipper program administration.' WHERE name = 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist';
INSERT OR IGNORE INTO citizen_catalog (id, name, domain, industry, description, professional_title, governing_body, governing_guidelines, standards_of_creation, soc_controls, document_types) VALUES ('citizen-1b5d85650529', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist', 'Utilities Cable Postal Compliance', 'Utilities Cable Postal', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist — FAA (air transport); FMCSA (ground transport); DOT; TSA (security)', 'Persona C.9.2: Overnight/Express Carrier Regulatory Compliance Specialist', 'FAA (air transport); FMCSA (ground transport); DOT; TSA (security)', ':; 49 USC § 41101 (air carrier certificate requirement); 14 CFR Part 121 (operating requirements — domestic air carriers); 14 CFR Part 135 (commuter and on-demand operations); 49 USC § 44901 (TSA screening requirements); 49 CFR Part 1548 (indirect air carrier security); 49 CFR Part 172 (hazmat transportation); 49 USC § 14706 (Carmack Amendment — ground segment liability); 49 USC § 40120 (FAA preemption of state regulation of air carriers); Montreal Convention (international air carriage liability); Warsaw Convention (legacy international air carriage)', 'Overnight/express carriers require FAA Part 121/135 air carrier certificate, TSA-approved security program, FMCSA operating authority for ground operations, and DOT hazmat compliance for applicable shipments. Carmack Amendment governs ground segment liability; Montreal Convention governs international air segment. Known Shipper programs per TSA requirements. Declaration of value limits liability unless higher coverage purchased.', 'SOC 2 Type II (shipment tracking data integrity); FAA certificate compliance; TSA security program audit; FMCSA safety rating maintenance; hazmat compliance; Carmack Amendment claims processing; international liability regime compliance; known shipper program administration.', 'FAA air carrier certificates, TSA security programs, FMCSA operating authority, hazmat transportation documents, known shipper records, claims processing records (Carmack/Montreal Convention), declaration of value records, security screening records, delivery tracking records, customs documentation (international), insurance certificates');
